// ── Fernet-compatible E2EE (matches Python cryptography.fernet) ──────────────

function b64urlDecode(str) {
    str = str.replace(/-/g, '+').replace(/_/g, '/');
    while (str.length % 4) str += '=';
    const bin = atob(str);
    return Uint8Array.from(bin, c => c.charCodeAt(0));
}

function b64urlEncode(bytes) {
    let str = '';
    for (let i = 0; i < bytes.length; i++) str += String.fromCharCode(bytes[i]);
    return btoa(str).replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

function concatU8(arrays) {
    const total = arrays.reduce((n, a) => n + a.length, 0);
    const out = new Uint8Array(total);
    let off = 0;
    for (const a of arrays) { out.set(a, off); off += a.length; }
    return out;
}

const _e2eKeyCache = new Map();

async function deriveE2EKeys(targetId) {
    if (_e2eKeyCache.has(targetId)) return _e2eKeyCache.get(targetId);
    const salt = new TextEncoder().encode("TENSHI_E2E_SALT_" + targetId);
    const keyBytes = new Uint8Array(await crypto.subtle.digest('SHA-256', salt));
    const keys = { signingKey: keyBytes.slice(0, 16), encryptKey: keyBytes.slice(16, 32) };
    _e2eKeyCache.set(targetId, keys);
    return keys;
}

async function fernetEncrypt(plaintext, targetId) {
    try {
        const { signingKey, encryptKey } = await deriveE2EKeys(targetId);

        const iv = crypto.getRandomValues(new Uint8Array(16));
        const now = Math.floor(Date.now() / 1000);
        const ts = new Uint8Array(8);
        new DataView(ts.buffer).setUint32(4, now, false);

        const plain = new TextEncoder().encode(plaintext);
        const padLen = 16 - (plain.length % 16);
        const padded = new Uint8Array(plain.length + padLen);
        padded.set(plain);
        padded.fill(padLen, plain.length);

        const aesKey = await crypto.subtle.importKey('raw', encryptKey, {name:'AES-CBC'}, false, ['encrypt']);
        const ct = new Uint8Array(await crypto.subtle.encrypt({name:'AES-CBC', iv}, aesKey, padded));

        const data = concatU8([new Uint8Array([0x80]), ts, iv, ct]);

        const hmacKey = await crypto.subtle.importKey('raw', signingKey, {name:'HMAC', hash:'SHA-256'}, false, ['sign']);
        const sig = new Uint8Array(await crypto.subtle.sign('HMAC', hmacKey, data));

        return b64urlEncode(concatU8([data, sig]));
    } catch(e) {
        console.error('E2EE encrypt error', e);
        return null;
    }
}

async function fernetDecrypt(token, targetId) {
    try {
        const { signingKey, encryptKey } = await deriveE2EKeys(targetId);

        const raw = b64urlDecode(token);
        if (raw[0] !== 0x80) return null;

        const data = raw.slice(0, raw.length - 32);
        const sig  = raw.slice(raw.length - 32);

        const hmacKey = await crypto.subtle.importKey('raw', signingKey, {name:'HMAC', hash:'SHA-256'}, false, ['verify']);
        const valid = await crypto.subtle.verify('HMAC', hmacKey, sig, data);
        if (!valid) return null;

        const iv = raw.slice(9, 25);
        const ct = raw.slice(25, raw.length - 32);

        const aesKey = await crypto.subtle.importKey('raw', encryptKey, {name:'AES-CBC'}, false, ['decrypt']);
        const decrypted = new Uint8Array(await crypto.subtle.decrypt({name:'AES-CBC', iv}, aesKey, ct));

        // Remove PKCS7 padding
        const pad = decrypted[decrypted.length - 1];
        return new TextDecoder().decode(decrypted.slice(0, decrypted.length - pad));
    } catch(e) {
        return null;
    }
}

