// Auto-detect production domain: if on tenshi.lol, connect to api.tenshi.lol
const IS_PROD = window.location.hostname.includes("tenshi.lol");
const API_URL = IS_PROD ? "https://api.tenshi.lol" : "http://127.0.0.1:8080"; 
let currentUser = null;
let isAdmin = false;
let currentTarget = null;
let currentChatInterval = null;

// Mock UUID for HWID
if (!localStorage.getItem('hwid')) {
    localStorage.setItem('hwid', 'WEB-' + Math.random().toString(36).substr(2, 9));
}
let hwid = localStorage.getItem('hwid');

// Register PWA Service Worker
if ('serviceWorker' in navigator) {
    window.addEventListener('load', () => {
        navigator.serviceWorker.register('sw.js').catch(err => console.log('SW failed', err));
    });
}

async function apiRequest(action, payload = {}) {
    payload.action = action;
    payload.hwid = hwid;
    // Allow explicit username (e.g. forgot-password) without being overwritten by currentUser.
    if (currentUser && payload.username === undefined) {
        payload.username = currentUser;
    }
    
    try {
        const res = await fetch(API_URL, {
            method: 'POST',
            body: JSON.stringify(payload),
            headers: {'Content-Type': 'application/json'}
        });
        return await res.json();
    } catch(err) {
        console.error("API Request Failed", err);
        const linkStyle = 'color:var(--accent-blue);text-decoration:underline;';
        return {status: 'error', message: 'Connection blocked — accept both certificates first: <a href="https://www.tenshi.lol" target="_blank" style="' + linkStyle + '">www.tenshi.lol</a> and <a href="' + API_URL + '" target="_blank" style="' + linkStyle + '">api.tenshi.lol</a>, then try again.'};
    }
}

/** Escape for HTML attribute values (double-quoted). */
function _escAttr(s) {
    if (s == null || s === undefined) return '';
    return String(s)
        .replace(/&/g, '&amp;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;')
        .replace(/</g, '&lt;');
}

/** Escape for text/HTML body content. */
function _escHtml(s) {
    if (s == null || s === undefined) return '';
    return String(s)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;');
}

function _syncTopbarChannelLabel(title) {
    const el = document.getElementById('topbar-channel-label');
    if (el && title != null) el.textContent = title;
}

function _setDmRefreshVisible(show) {
    const b = document.getElementById('dm-refresh-btn');
    if (b) b.style.display = show ? 'flex' : 'none';
}

async function _tenshiDmRefresh() {
    const img = document.querySelector('#dm-refresh-btn .tenshi-spin-target');
    if (img) img.classList.add('tenshi-logo-spin');
    try {
        await pollMessages();
        await _refreshStoryFeed();
        await _loadTempStreaks();
    } catch (e) {
        console.warn('[Tenshi] refresh', e);
    } finally {
        setTimeout(() => { if (img) img.classList.remove('tenshi-logo-spin'); }, 720);
    }
}

/** Friends list + story rail (used by broken references to renderFriendsMainView). */
function renderFriendsMainView() {
    loadFriendsView();
}

async function finalizeStripeCheckoutFromUrl() {
    const params = new URLSearchParams(window.location.search);
    const sid = params.get('session_id');
    if (!sid || !currentUser) return;
    try {
        const fin = await apiRequest('FINISH_STRIPE_CHECKOUT', { stripe_session_id: sid });
        if (fin.status === 'success') notify(fin.message || 'Payment complete', { icon: '✓', type: 'success' });
        else if (fin.message) notify(fin.message, { type: 'warning' });
    } catch {}
    const u = new URL(window.location.href);
    u.searchParams.delete('session_id');
    window.history.replaceState({}, '', u.pathname + (u.search ? u.search : '') + u.hash);
}

async function tenshiCreateStripeCheckout(kind, extra = {}) {
    const origin = window.location.origin;
    const path = window.location.pathname || '/hub.html';
    const payload = {
        checkout_kind: kind,
        success_url: origin + path + '?session_id={CHECKOUT_SESSION_ID}',
        cancel_url: origin + path,
        ...extra,
    };
    const r = await apiRequest('CREATE_STRIPE_CHECKOUT', payload);
    if (r.status === 'success' && r.url) {
        window.location.href = r.url;
        return true;
    }
    notify(r.message || 'Checkout unavailable', { type: 'error' });
    return false;
}

// Password hashing via WebCrypto SHA-256 (hex string output).
async function simpleHash(str) {
    const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
    return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2,'0')).join('');
}

// Legacy djb2 hash — kept only so old code that references it doesn't break at parse time.
function _legacyHash(str) {
    let hash = 0;
    for (let i = 0, len = str.length; i < len; i++) {
        let chr = str.charCodeAt(i);
        hash = (hash << 5) - hash + chr;
        hash |= 0; 
    }
    return hash.toString();
}

async function register() {
    const u = document.getElementById('username').value;
    const p = document.getElementById('password').value;
    const c = document.getElementById('contact').value;
    if (!u || !p || !c) {
        document.getElementById('auth-status').innerText = "Please provide Username, Password, and Contact (Email/Phone)";
        return;
    }
    
    // Hash password before sending
    const pwd_hash = await simpleHash(p);
    let payload = { username: u, pwd_hash: pwd_hash };
    if (c.includes('@')) payload.email = c;
    else payload.phone = c;
    
    document.getElementById('auth-status').innerText = "Registering onto Secure Network...";
    let res = await apiRequest('REGISTER', payload);
    
    if (res.status === 'success') {
        document.getElementById('auth-status').style.color = "#23a559";
        document.getElementById('auth-status').innerHTML = "Created! Please verify device logic by pressing Login.";
    } else {
        document.getElementById('auth-status').innerHTML = res.message;
    }
}

async function login() {
    const u = document.getElementById('username').value;
    const p = document.getElementById('password').value;
    if (!u || !p) {
        document.getElementById('auth-status').innerText = "Please provide Username and Password";
        return;
    }
    
    const pwd_hash = await simpleHash(p);
    document.getElementById('auth-status').innerText = "Authenticating...";
    document.getElementById('auth-status').style.color = "yellow";
    
    let res = await apiRequest('LOGIN', { username: u, pwd_hash: pwd_hash });
    
    if (res.status === 'success') {
        currentUser = u;
        isAdmin = res.is_admin || false;
        localStorage.setItem('tenshi_user', u);
        loadHub();
    } else if (res.message === "NEW DEVICE DETECTED. Please Link Hardware." || res.message === "Hardware ID Mismatch") {
        currentUser = u;
        document.getElementById('login-box').style.display = 'none';
        document.getElementById('payment-box').style.display = 'block';
        
        // Dynamically set price based on whether account exists
        // If it's pure hardware mismatch on existing account = $5 link
        // If it's a first-time Web login/reg = $10 license
        if (res.message === "Hardware ID Mismatch") {
            document.getElementById('price-display').innerText = "$5.00";
            document.getElementById('license-desc').innerText = "Device Linking Fee (App Owner)";
        } else {
            document.getElementById('price-display').innerText = "$10.00";
            document.getElementById('license-desc').innerText = "One-Time Web Portal License";
        }
        // Auto-apply any promo code already locked to this account
        if (res.promo_price) {
            document.getElementById('price-display').innerText = res.promo_price;
            document.getElementById('price-display').style.color = "#23a559";
            document.getElementById('promo-code').value = "(Promo locked to your account)";
            document.getElementById('promo-code').disabled = true;
        }
    } else {
        document.getElementById('auth-status').innerHTML = res.message;
        document.getElementById('auth-status').style.color = "red";
    }
}

async function applyPromo() {
    let code = document.getElementById('promo-code').value.trim();
    document.getElementById('pay-status').innerText = "Validating code...";
    document.getElementById('pay-status').style.color = "yellow";
    let res = await apiRequest('VALIDATE_PROMO', { code: code });
    if (res.status === 'success') {
        document.getElementById('price-display').innerText = res.price;
        document.getElementById('price-display').style.color = res.color || "#23a559";
        document.getElementById('pay-status').innerText = res.message || "Promo applied!";
        document.getElementById('pay-status').style.color = "#23a559";
    } else {
        document.getElementById('pay-status').innerText = res.message || "Invalid Promo Code";
        document.getElementById('pay-status').style.color = "red";
    }
}

async function payAndLink() {
    let price = document.getElementById('price-display').innerText;
    let p = document.getElementById('password').value;
    let pwd_hash = await simpleHash(p);

    if (price === "$0.00") {
        // Free via promo — skip payment, link immediately
        document.getElementById('pay-status').innerText = "Activating free access...";
        document.getElementById('pay-status').style.color = "#23a559";
        let res = await apiRequest('LINK_DEVICE', { pwd_hash: pwd_hash });
        if (res.status === 'success') {
            loadHub();
        } else {
            document.getElementById('pay-status').innerText = res.message || "Failed to provision link.";
            document.getElementById('pay-status').style.color = "red";
        }
        return;
    }

    document.getElementById('pay-status').innerText = "Processing Payment Gateway for " + price + "...";
    setTimeout(async () => {
        let res = await apiRequest('LINK_DEVICE', { pwd_hash: pwd_hash });
        if (res.status === 'success') {
            loadHub();
        } else {
            document.getElementById('pay-status').innerText = res.message || "Failed to provision link.";
        }
    }, 1500); // Simulate transaction
}

function loadHub() {
    const urlParams = new URLSearchParams(window.location.search);
    const joinServer = urlParams.get('joinServer');

    document.getElementById('auth-view').style.display = 'none';
    const appScreen = document.getElementById('app-screen');
    appScreen.style.display = 'flex';

    // Switch per-user localStorage data
    _switchUserData(currentUser);
    finalizeStripeCheckoutFromUrl().catch(() => {});

    // Update topbar avatar with first letter of username
    const av = document.getElementById('topbar-avatar');
    const sbav = document.getElementById('statusbar-avatar');
    const sbname = document.getElementById('statusbar-username');
    if (av) av.textContent = (currentUser || 'U')[0].toUpperCase();
    if (sbav) sbav.textContent = (currentUser || 'U')[0].toUpperCase();
    if (sbname) sbname.textContent = currentUser || 'User';

    // Show admin rail button for admins
    const adminRailBtn = document.getElementById('rail-admin-btn');
    if (isAdmin && adminRailBtn) adminRailBtn.style.display = 'block';

    buildCountrySelect();
    fetchServersJoined(joinServer);
    if (!joinServer) loadFriendsView();
}

// ── Admin Panel ───────────────────────────────────────────────
let _adminUsers = [];

async function loadAdminPanel() {
    stopMedia();
    if (currentChatInterval) clearInterval(currentChatInterval);
    currentManagingServer = null;
    _clearHubMemberPanel('<div style="padding:16px;color:var(--text-muted);font-size:12px;text-align:center;">Member list is available in hubs.</div>');
    _setDmRefreshVisible(false);
    currentTarget = null;
    document.getElementById('current-chat').innerText = '🛡️ Admin Panel';
    _syncTopbarChannelLabel('🛡️ Admin');
    document.getElementById('sidebar-header').innerText = 'ADMIN';

    // Sidebar nav
    document.getElementById('dynamic-list').innerHTML = `
        <div class="channel-item" onclick="adminShowTab('users')"   id="atab-users"   style="font-weight:600;">👥 Users</div>
        <div class="channel-item" onclick="adminShowTab('broadcast')" id="atab-broadcast">📢 Broadcast</div>`;

    document.getElementById('message-container').innerHTML =
        '<div style="padding:24px;color:#aaa;font-size:13px;">Loading…</div>';

    const [statsRes, usersRes] = await Promise.all([
        apiRequest('GET_ADMIN_STATS'),
        apiRequest('GET_ALL_USERS'),
    ]);

    _adminUsers = usersRes.users || [];
    _adminRenderUsers('', statsRes);
}

function adminShowTab(tab) {
    document.querySelectorAll('[id^="atab-"]').forEach(el => el.style.fontWeight = '');
    const el = document.getElementById('atab-' + tab);
    if (el) el.style.fontWeight = '600';

    if (tab === 'users')     _adminRenderUsers('');
    if (tab === 'broadcast') _adminRenderBroadcast();
}

function _adminRenderUsers(filter, statsRes) {
    const stats = statsRes || {};
    const users = filter
        ? _adminUsers.filter(u => u.username.toLowerCase().includes(filter.toLowerCase()) || (u.email||'').toLowerCase().includes(filter.toLowerCase()))
        : _adminUsers;

    const esc = s => (s||'').replace(/</g,'&lt;').replace(/"/g,'&quot;');
    const statsHtml = statsRes ? `
        <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:20px;">
            ${[
                ['👥 Total Users',   stats.total_users   ?? '—'],
                ['🟢 Online Now',    stats.online_users  ?? '—'],
                ['🏠 Servers',       stats.total_servers ?? '—'],
                ['💬 Queued Msgs',   stats.total_messages ?? '—'],
            ].map(([label, val]) => `
                <div style="background:rgba(0,0,0,0.3);border:1px solid var(--glass-border);border-radius:10px;padding:12px 18px;min-width:110px;text-align:center;">
                    <div style="font-size:22px;font-weight:700;color:white;">${val}</div>
                    <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">${label}</div>
                </div>`).join('')}
        </div>` : '';

    const rowsHtml = users.length === 0
        ? '<div style="color:var(--text-muted);font-size:13px;padding:20px 0;">No users found.</div>'
        : users.map(u => `
        <div style="display:flex;align-items:center;gap:10px;padding:10px 12px;background:rgba(0,0,0,0.2);border-radius:8px;border:1px solid var(--glass-border);flex-wrap:wrap;">
            <div style="width:8px;height:8px;border-radius:50%;background:${u.online?'#23a559':'#747f8d'};flex-shrink:0;"></div>
            <div style="flex:1;min-width:120px;">
                <div style="font-weight:600;color:white;font-size:13px;">
                    ${esc(u.username)}
                    ${u.is_admin  ? '<span style="font-size:10px;background:#5865F2;color:white;padding:1px 5px;border-radius:4px;margin-left:4px;">admin</span>' : ''}
                    ${u.banned    ? '<span style="font-size:10px;background:#ed4245;color:white;padding:1px 5px;border-radius:4px;margin-left:4px;">banned</span>' : ''}
                    ${u.verified  ? '<span style="font-size:10px;background:#23a559;color:white;padding:1px 5px;border-radius:4px;margin-left:4px;">✓</span>' : ''}
                </div>
                <div style="font-size:11px;color:var(--text-muted);">
                    ${esc(u.email)||'no email'}
                    · ${u.server_count} server${u.server_count!==1?'s':''}
                    · ${u.friend_count} friend${u.friend_count!==1?'s':''}
                    · ${u.hwid_count} device${u.hwid_count!==1?'s':''}
                    ${u.connections.length ? '· 🔗 '+u.connections.join(', ') : ''}
                </div>
            </div>
            <div style="display:flex;gap:6px;flex-shrink:0;">
                ${u.banned
                    ? `<button onclick="adminUnban('${esc(u.username)}')" style="background:#23a559;color:white;border:none;padding:5px 12px;border-radius:6px;cursor:pointer;font-size:12px;min-height:32px;touch-action:manipulation;">Unban</button>`
                    : `<button onclick="adminBan('${esc(u.username)}')"   style="background:#ed4245;color:white;border:none;padding:5px 12px;border-radius:6px;cursor:pointer;font-size:12px;min-height:32px;touch-action:manipulation;">Ban</button>`}
                <button onclick="adminDelete('${esc(u.username)}')" style="background:rgba(237,66,69,0.2);color:#ed4245;border:1px solid #ed4245;padding:5px 10px;border-radius:6px;cursor:pointer;font-size:12px;min-height:32px;touch-action:manipulation;">🗑</button>
            </div>
        </div>`).join('');

    document.getElementById('message-container').innerHTML = `
        <div style="padding:20px;max-width:900px;display:flex;flex-direction:column;gap:16px;">
            ${statsHtml}
            <div style="display:flex;align-items:center;gap:10px;">
                <input id="admin-search" oninput="_adminRenderUsers(this.value)"
                    placeholder="Search users or emails…"
                    style="flex:1;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;padding:9px 12px;border-radius:8px;font-size:14px;">
                <span style="color:var(--text-muted);font-size:13px;white-space:nowrap;">${users.length} / ${_adminUsers.length}</span>
            </div>
            <div style="display:flex;flex-direction:column;gap:8px;">${rowsHtml}</div>
        </div>`;
}

function _adminRenderBroadcast() {
    document.getElementById('message-container').innerHTML = `
        <div style="padding:20px;max-width:600px;display:flex;flex-direction:column;gap:14px;">
            <h3 style="color:white;margin:0;font-size:16px;">📢 System Broadcast</h3>
            <p style="color:var(--text-muted);font-size:13px;margin:0;">Sends a system message to every user's message queue. Appears as <strong>[Admin]</strong> in their chat.</p>
            <textarea id="admin-bc-text" rows="4" maxlength="500"
                style="background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;padding:10px;border-radius:8px;font-size:14px;resize:vertical;font-family:inherit;"
                placeholder="Broadcast message…"></textarea>
            <div style="display:flex;align-items:center;gap:12px;">
                <button onclick="adminBroadcast()" style="background:var(--accent-blue);color:white;border:none;padding:10px 24px;border-radius:8px;font-size:14px;font-weight:600;cursor:pointer;min-height:44px;touch-action:manipulation;">Send to All</button>
                <span id="admin-bc-status" style="color:var(--text-muted);font-size:13px;"></span>
            </div>
        </div>`;
}

async function adminBan(target) {
    if (!confirm(`Ban "${target}"? They will be locked out immediately.`)) return;
    const res = await apiRequest('BAN_USER', { target });
    if (res.status === 'success') {
        const u = _adminUsers.find(x => x.username === target);
        if (u) u.banned = true;
        _adminRenderUsers(document.getElementById('admin-search')?.value || '');
    } else { alert(res.message || 'Failed'); }
}

async function adminUnban(target) {
    const res = await apiRequest('UNBAN_USER', { target });
    if (res.status === 'success') {
        const u = _adminUsers.find(x => x.username === target);
        if (u) u.banned = false;
        _adminRenderUsers(document.getElementById('admin-search')?.value || '');
    } else { alert(res.message || 'Failed'); }
}

async function adminDelete(target) {
    if (!confirm(`Permanently delete account "${target}"? This cannot be undone.`)) return;
    const res = await apiRequest('DELETE_USER', { target });
    if (res.status === 'success') {
        _adminUsers = _adminUsers.filter(u => u.username !== target);
        _adminRenderUsers(document.getElementById('admin-search')?.value || '');
    } else { alert(res.message || 'Failed'); }
}

async function adminBroadcast() {
    const text = document.getElementById('admin-bc-text')?.value?.trim();
    const statusEl = document.getElementById('admin-bc-status');
    if (!text) { if (statusEl) { statusEl.style.color='#f04747'; statusEl.innerText='Message is empty.'; } return; }
    if (statusEl) { statusEl.style.color='var(--text-muted)'; statusEl.innerText='Sending…'; }
    const res = await apiRequest('ADMIN_BROADCAST', { content: text });
    if (statusEl) {
        statusEl.style.color = res.status === 'success' ? '#23a559' : '#f04747';
        statusEl.innerText = res.message || (res.status === 'success' ? 'Sent!' : 'Failed');
    }
    if (res.status === 'success') {
        const ta = document.getElementById('admin-bc-text');
        if (ta) ta.value = '';
    }
}

// Keep old names as aliases so any cached references don't break
const banUser   = adminBan;
const unbanUser = adminUnban;

