let currentManagingServer = null;

function _hubMemberAvatarMarkup(m, sizePx) {
    const sz = sizePx || 32;
    const un = m.username || '';
    const initial = ((m.display_name || un || '?')[0] || '?').toUpperCase();
    const bg = _escAttr(m.banner_color || m.profile_color || '#5865F2');
    const av = m.avatar;
    if (av) {
        return `<img src="${_escAttr(av)}" alt="" width="${sz}" height="${sz}" style="width:${sz}px;height:${sz}px;border-radius:50%;object-fit:cover;flex-shrink:0;" onerror="this.outerHTML='<div class=\\'member-avatar\\' style=\\'width:${sz}px;height:${sz}px;background:${bg};\\'>${initial}</div>'">`;
    }
    return `<div class="member-avatar" style="width:${sz}px;height:${sz}px;background:${bg};">${initial}</div>`;
}

function _resetMemberPanelHeader() {
    const sum = document.getElementById('member-panel-summary');
    if (sum) {
        const dict = _i18n[_currentLang] || _i18n.en;
        sum.textContent = dict.members || 'Members';
    }
}

function _clearHubMemberPanel(message) {
    const container = document.getElementById('member-list-content');
    if (!container) return;
    _resetMemberPanelHeader();
    const msg = message || '<div style="padding:16px;color:var(--text-muted);font-size:12px;text-align:center;">Select a hub to see members</div>';
    container.innerHTML = msg;
}

async function refreshHubMemberPanel(serverId, ownerUsername) {
    const container = document.getElementById('member-list-content');
    const title = document.getElementById('member-panel-summary');
    if (!container || _optimizeMode) return;
    if (!serverId) { _clearHubMemberPanel(); return; }
    const res = await apiRequest('GET_SERVER_MEMBERS', { server_id: serverId });
    if (res.status !== 'success' || !Array.isArray(res.members)) {
        container.innerHTML = '<div style="padding:16px;color:var(--text-muted);font-size:12px;text-align:center;">Could not load members</div>';
        return;
    }
    const members = res.members;
    if (title) title.textContent = `Members — ${members.length}`;
    const owner = ownerUsername || '';
    const ownerRows = members.filter(x => x.username === owner);
    const otherRows = members.filter(x => x.username !== owner);

    function memberRowHtml(m, isOwner) {
        const un = m.username;
        const dn = m.display_name || un;
        const nameColor = m.hub_role_name_color || m.username_color || '#ffffff';
        const crown = isOwner ? ' <span title="Owner" style="font-size:11px;">👑</span>' : '';
        const st = m.online ? 'online' : 'offline';
        return `<div class="member-item" style="opacity:${m.online ? '1' : '0.55'};cursor:pointer;"
            onclick="_showUserProfileCard('${_escAttr(un)}')"
            oncontextmenu="event.preventDefault();showUserContextMenu(event,'${_escAttr(un)}')">
            <div style="position:relative;flex-shrink:0;">
                ${_hubMemberAvatarMarkup(m, 32)}
                <div class="status-dot ${st}" style="width:8px;height:8px;position:absolute;bottom:-1px;right:-1px;border:2px solid var(--panel-bg);border-radius:50%;"></div>
            </div>
            <div style="flex:1;overflow:hidden;min-width:0;margin-left:8px;">
                <div style="display:flex;align-items:center;gap:2px;">
                    <span style="font-size:13px;font-weight:500;color:${_escAttr(nameColor)};overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${_escAttr(dn)}</span>${crown}
                </div>
            </div>
        </div>`;
    }
    let html = '';
    if (owner && ownerRows.length) {
        html += `<div class="member-panel-header" style="margin:0;border-top:none;">Owner — ${ownerRows.length}</div>`;
        html += ownerRows.map(m => memberRowHtml(m, true)).join('');
    }
    const restCount = owner ? otherRows.length : members.length;
    if (restCount > 0) {
        const sub = owner ? otherRows : members;
        html += `<div class="member-panel-header" style="margin-top:${owner && ownerRows.length ? '10' : '0'}px;">Members — ${restCount}</div>`;
        html += sub.map(m => memberRowHtml(m, false)).join('');
    } else if (!html) {
        html = '<div style="padding:16px;color:var(--text-muted);font-size:12px;text-align:center;">No members</div>';
    }
    container.innerHTML = html;
}

function openRoleManager() {
    if(!currentManagingServer) return;
    document.getElementById('role-modal').style.display = 'block';
    let sel = document.getElementById('channel-select');
    sel.innerHTML = '';
    for(let c in currentManagingServer.channels) {
        sel.innerHTML += `<option value="${c}">${c}</option>`;
    }
    
    let rlist = document.getElementById('role-list');
    rlist.innerHTML = '';
    for(let r in currentManagingServer.roles) {
        let name = currentManagingServer.roles[r].name;
        rlist.innerHTML += `<div style="margin:5px 0;"><input type="checkbox" id="role_${r}" value="${r}"> ${name}</div>`;
    }
}

async function saveRoles() {
    let channel = document.getElementById('channel-select').value;
    let allowed_roles = [];
    for(let r in currentManagingServer.roles) {
        let cb = document.getElementById('role_' + r);
        if(cb && cb.checked) allowed_roles.push(r);
    }
    
    let res = await fetch(API_URL, {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({
            action: 'UPDATE_CHANNEL_ROLES',
            username: currentUser,
            server_id: currentManagingServer.id,
            channel_name: channel,
            allowed_roles: allowed_roles,
            locked: allowed_roles.length > 0
        })
    });
    let data = await res.json();
    if(data.status === 'success') {
        alert("Channel Locked Successfully!");
        document.getElementById('role-modal').style.display = 'none';
    } else {
        alert("Failed: " + data.message);
    }
}

function loadServerView(serverJsonStr) {
    let serverObj = JSON.parse(serverJsonStr);
    currentManagingServer = serverObj;
    _setDmRefreshVisible(false);
    const rg = document.getElementById('roles-gear-btn');
    if (rg) rg.style.display = '';
    document.getElementById('sidebar-header').innerHTML = `${serverObj.name} <span style="float:right; cursor:pointer;" onclick="openRoleManager()">⚙️</span>`;

    let list = document.getElementById('dynamic-list');
    let html = '';

    // Server info header
    const memberCount = Object.keys(serverObj.members || {}).length;
    html += `<div style="display:flex; align-items:center; gap:10px; padding:12px 16px; border-bottom:1px solid var(--glass-border);">`;
    html += `<div style="width:36px; height:36px; border-radius:50%; background:var(--accent-blue); display:flex; align-items:center; justify-content:center; font-size:16px; font-weight:bold; color:white; flex-shrink:0;">${(serverObj.icon || serverObj.name[0])}</div>`;
    html += `<div><div style="font-weight:bold; color:white; font-size:14px;">${serverObj.name}</div><div style="font-size:11px; color:var(--text-muted);">${memberCount} member${memberCount !== 1 ? 's' : ''}</div></div>`;
    html += `</div>`;

    // Separate channels by type
    const textChannels = [];
    const voiceChannels = [];
    for (let cName in serverObj.channels) {
        const cInfo = serverObj.channels[cName];
        const cType = (typeof cInfo === 'object' ? cInfo.type : cInfo) || 'text';
        if (cType === 'voice') voiceChannels.push(cName);
        else textChannels.push(cName);
    }

    // Text Channels category
    if (textChannels.length > 0) {
        html += `<div class="channel-category" onclick="this.classList.toggle('collapsed'); this.nextElementSibling.style.display = this.classList.contains('collapsed') ? 'none' : 'block';" style="cursor:pointer; user-select:none;">`;
        html += `<span style="font-size:9px; margin-right:4px; display:inline-block; transition:transform 0.15s;">▼</span> TEXT CHANNELS</div>`;
        html += `<div class="channel-category-items">`;
        for (const cName of textChannels) {
            const cInfo = serverObj.channels[cName];
            const isLocked = (typeof cInfo === 'object' && cInfo.locked) ? '🔒 ' : '';
            html += `<div class="channel-item" style="color:#ccc;" onclick="openChannel('${serverObj.id}', '${cName}', 'text')">${isLocked}# ${cName}</div>`;
        }
        html += `</div>`;
    }

    // Voice Channels category
    if (voiceChannels.length > 0) {
        html += `<div class="channel-category" onclick="this.classList.toggle('collapsed'); this.nextElementSibling.style.display = this.classList.contains('collapsed') ? 'none' : 'block';" style="cursor:pointer; user-select:none;">`;
        html += `<span style="font-size:9px; margin-right:4px; display:inline-block; transition:transform 0.15s;">▼</span> VOICE CHANNELS</div>`;
        html += `<div class="channel-category-items">`;
        for (const cName of voiceChannels) {
            const cInfo = serverObj.channels[cName];
            const isLocked = (typeof cInfo === 'object' && cInfo.locked) ? '🔒 ' : '';
            html += `<div class="channel-item" style="color:#23a559;" onclick="openChannel('${serverObj.id}', '${cName}', 'voice')">${isLocked}🔊 ${cName}</div>`;
        }
        html += `</div>`;
    }

    list.innerHTML = html;

    // Show welcome screen in chat area
    const channelCount = textChannels.length + voiceChannels.length;
    const roleCount = Object.keys(serverObj.roles || {}).length;
    document.getElementById('current-chat').innerText = 'Select a chat';
    _syncTopbarChannelLabel('Select a chat');
    document.getElementById('video-container').style.display = 'none';
    document.getElementById('message-container').style.display = 'block';
    document.getElementById('message-container').innerHTML = `
        <div style="display:flex; flex-direction:column; align-items:center; justify-content:center; height:100%; color:var(--text-muted); text-align:center; padding:40px;">
            <div style="font-size:48px; margin-bottom:16px;">${serverObj.icon || '📢'}</div>
            <h2 style="color:white; margin:0 0 8px;">Welcome to ${serverObj.name}</h2>
            <p style="margin:0 0 24px; font-size:14px;">Select a channel to get started.</p>
            <div style="display:flex; gap:16px; font-size:13px; color:var(--text-muted);">
                <span>${memberCount} Member${memberCount !== 1 ? 's' : ''}</span>
                <span>${channelCount} Channel${channelCount !== 1 ? 's' : ''}</span>
                <span>${roleCount} Role${roleCount !== 1 ? 's' : ''}</span>
            </div>
        </div>`;
    if (currentChatInterval) clearInterval(currentChatInterval);
    refreshHubMemberPanel(serverObj.id, serverObj.owner || '');
}

let localMediaStream = null;
let mediaSendInterval = null;
let mediaPollInterval = null;

function stopMedia() {
    if(localMediaStream) {
        localMediaStream.getTracks().forEach(t => t.stop());
        localMediaStream = null;
    }
    if(mediaSendInterval) clearInterval(mediaSendInterval);
    if(mediaPollInterval) clearInterval(mediaPollInterval);
    
    // Hide video container, show chat
    let vc = document.getElementById('video-container');
    let mc = document.getElementById('message-container');
    if (vc) vc.style.display = 'none';
    if (mc) mc.style.display = 'block';
    
    // Clear remotes
    let rv = document.getElementById('remote-videos');
    if(rv) {
        // Keep only the local video div
        let localVidDiv = rv.lastElementChild;
        rv.innerHTML = '';
        if (localVidDiv) rv.appendChild(localVidDiv);
    }
}

// ── Voice & Video quality settings ────────────────────────────
const _vqPresets = {
    'Low':   { w:320,  h:240,  fps:10, jpegQ:0.35 },
    'Medium':{ w:480,  h:360,  fps:15, jpegQ:0.55 },
    'High':  { w:640,  h:480,  fps:24, jpegQ:0.70 },
    '720p':  { w:1280, h:720,  fps:30, jpegQ:0.80 },
    '1080p': { w:1920, h:1080, fps:30, jpegQ:0.85 },
};

let _vqSettings = JSON.parse(localStorage.getItem('tenshi_vq') || 'null') || {
    preset: 'Medium', echoCancellation: true, noiseSuppression: true, autoGainControl: true,
};

function _saveVQ() { localStorage.setItem('tenshi_vq', JSON.stringify(_vqSettings)); }

async function startMediaStream(channelName) {
    try {
        const p = _vqPresets[_vqSettings.preset] || _vqPresets['Medium'];
        localMediaStream = await navigator.mediaDevices.getUserMedia({
            video: { width:{ideal:p.w}, height:{ideal:p.h}, frameRate:{ideal:p.fps} },
            audio: { echoCancellation:_vqSettings.echoCancellation, noiseSuppression:_vqSettings.noiseSuppression, autoGainControl:_vqSettings.autoGainControl },
        });
        document.getElementById('local-video').srcObject = localMediaStream;

        mediaSendInterval = setInterval(() => {
            let video = document.getElementById('local-video');
            let canvas = document.getElementById('hidden-canvas');
            if(video && canvas && localMediaStream) {
                canvas.width = p.w;
                canvas.height = p.h;
                let ctx = canvas.getContext('2d');
                ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
                let base64Frame = canvas.toDataURL('image/jpeg', p.jpegQ);

                fetch(API_URL, {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                        action: 'SEND_VIDEO_FRAME',
                        username: currentUser,
                        channel: channelName,
                        frame: base64Frame
                    })
                }).catch(e => {});
            }
        }, Math.round(1000 / p.fps));
        
        mediaPollInterval = setInterval(async () => {
            let res = await apiRequest('POLL_VIDEO', {channel: channelName});
            if(res && res.status === 'success') {
                let remoteContainer = document.getElementById('remote-videos');
                if(!remoteContainer) return;
                
                for(let user in res.frames) {
                    let img = document.getElementById('remote-vid-' + user);
                    if(!img) {
                        let wrap = document.createElement('div');
                        wrap.style.textAlign = 'center';
                        img = document.createElement('img');
                        img.id = 'remote-vid-' + user;
                        img.style.width = '480px';
                        img.style.borderRadius = '10px';
                        img.style.border = '2px solid var(--accent-blue)';
                        wrap.innerHTML = `<h4 style="color:white; margin:5px;">${user}</h4>`;
                        wrap.appendChild(img);
                        remoteContainer.appendChild(wrap);
                    }
                    img.src = res.frames[user];
                }
            }
        }, 200);
    } catch(e) {
        console.error("Media error", e);
        document.getElementById('message-container').innerHTML += '<div style="color:red; text-align:center;">Camera access denied or unavailable. Please use HTTPS or localhost to enable Webcams.</div>';
    }
}

function _cleanupVoiceEnhancement(key) {
    const entry = _voiceEnhancementContexts.get(key);
    if (entry) {
        try { entry.ctx.close(); } catch {}
        _voiceEnhancementContexts.delete(key);
    }
}

function _cleanupAllVoiceEnhancements() {
    for (const [key, entry] of _voiceEnhancementContexts) {
        try { entry.ctx.close(); } catch {}
    }
    _voiceEnhancementContexts.clear();
}

// ── Text-to-Speech Settings ──────────────────────────────────
let _ttsSettings = JSON.parse(localStorage.getItem('tenshi_tts') || 'null') || {
    enabled: false,
    notifications: false,
    voiceName: '',
    rate: 1.0,
    pitch: 1.0,
};

function _saveTTSSettings() {
    _ttsSettings.enabled = document.getElementById('tts-enabled')?.checked || false;
    _ttsSettings.notifications = document.getElementById('tts-notifs')?.checked || false;
    _ttsSettings.voiceName = document.getElementById('tts-voice')?.value || '';
    _ttsSettings.rate = parseFloat(document.getElementById('tts-rate')?.value || 1.0);
    _ttsSettings.pitch = parseFloat(document.getElementById('tts-pitch')?.value || 1.0);
    localStorage.setItem('tenshi_tts', JSON.stringify(_ttsSettings));
}

function _populateTTSVoices() {
    const sel = document.getElementById('tts-voice');
    if (!sel) return;

    function _fill() {
        const voices = speechSynthesis.getVoices();
        if (!voices.length) return;
        sel.innerHTML = voices.map(v =>
            `<option value="${v.name}" ${v.name === _ttsSettings.voiceName ? 'selected' : ''}>` +
            `${v.name} (${v.lang})${v.default ? ' ★' : ''}</option>`
        ).join('');
        // Auto-select a good default if none saved
        if (!_ttsSettings.voiceName) {
            const preferred = voices.find(v => v.lang.startsWith('en') && v.name.includes('Google')) ||
                             voices.find(v => v.lang.startsWith('en') && v.default) ||
                             voices.find(v => v.lang.startsWith('en')) ||
                             voices[0];
            if (preferred) {
                sel.value = preferred.name;
                _ttsSettings.voiceName = preferred.name;
                _saveTTSSettings();
            }
        }
    }

    _fill();
    // Chrome loads voices asynchronously
    if (speechSynthesis.onvoiceschanged !== undefined) {
        speechSynthesis.onvoiceschanged = _fill;
    }
}

function _previewTTS() {
    const text = 'Hello! This is how I sound on Tenshi. You can change my voice, speed, and pitch in settings. This also tests your speaker volume.';
    _speakText(text);
}

function _testSpeakerWithTTS() {
    _speakText('Testing speakers. One, two, three. If you can hear this, your audio output is working correctly.');
}

function _speakText(text) {
    if (!('speechSynthesis' in window)) return;
    speechSynthesis.cancel(); // stop any current speech
    const utter = new SpeechSynthesisUtterance(text);
    utter.rate = _ttsSettings.rate;
    utter.pitch = _ttsSettings.pitch;
    utter.volume = 1.0;
    // Find the selected voice
    const voices = speechSynthesis.getVoices();
    const voice = voices.find(v => v.name === _ttsSettings.voiceName);
    if (voice) utter.voice = voice;
    speechSynthesis.speak(utter);
}

// Read a message aloud (called when new DM arrives)
function _ttsReadMessage(sender, message) {
    if (!_ttsSettings.enabled) return;
    if (!message || message.startsWith('[') || message.length > 300) return; // skip system messages & long ones
    _speakText(`${sender} says: ${message}`);
}

// Read a notification aloud
function _ttsReadNotification(text) {
    if (!_ttsSettings.notifications) return;
    _speakText(text);
}

function _getMediaConstraints(wantVideo) {
    const saved = JSON.parse(localStorage.getItem('tenshi_devices') || '{}');
    const p = _vqPresets[_vqSettings.preset] || _vqPresets['Medium'];
    const audio = {
        echoCancellation: _vqSettings.echoCancellation,
        noiseSuppression: _vqSettings.noiseSuppression,
        autoGainControl: _vqSettings.autoGainControl,
    };
    if (saved.mic) audio.deviceId = { ideal: saved.mic };
    const video = wantVideo ? { width:{ideal:p.w}, height:{ideal:p.h}, frameRate:{ideal:p.fps} } : false;
    if (wantVideo && saved.camera) video.deviceId = { ideal: saved.camera };
    return { audio, video };
}

let _voiceChannelPollInterval = null;
let _voiceChannelName = null;
let _voiceServerId = null;

// ── Single-call enforcement ──────────────────────────────────
function _isInAnyCall() {
    return !!_voiceChannelName || !!_activeCall;
}

function _saveCallState(state) {
    if (state) localStorage.setItem('tenshi_active_call', JSON.stringify(state));
    else localStorage.removeItem('tenshi_active_call');
}

function _getSavedCallState() {
    try { return JSON.parse(localStorage.getItem('tenshi_active_call')); } catch { return null; }
}

async function startMediaStream(channelName, serverId) {
    // Auto-disconnect from any existing call before joining
    if (_activeCall) {
        endDMCall();
        await new Promise(r => setTimeout(r, 500)); // Wait for cleanup
    }
    if (_voiceChannelName && (_voiceChannelName !== channelName || _voiceServerId !== serverId)) {
        await _leaveVoiceChannelAsync();
    }
    _voiceChannelName = channelName;
    _voiceServerId = serverId;
    _saveCallState({ type: 'voice_channel', serverId, channelName });

    // Unlock audio playback (user gesture context)
    try {
        const ctx = new (window.AudioContext || window.webkitAudioContext)();
        if (ctx.state === 'suspended') await ctx.resume();
        ctx.close();
    } catch {}

    // Play join sound
    playNotif('join');

    // Get audio only — camera stays off, user enables it manually
    try {
        localMediaStream = await navigator.mediaDevices.getUserMedia({ audio: {
            echoCancellation: _vqSettings.echoCancellation,
            noiseSuppression: _vqSettings.noiseSuppression,
            autoGainControl: _vqSettings.autoGainControl
        }});
        // Apply noise suppression filter
        if (localMediaStream) _applyNoiseFilter(localMediaStream, _vqSettings.noiseMode || 'rnnoise');
    } catch(e) {
        console.warn('Mic access denied:', e);
    }

    // Build participant UI in video container (same style as DM calls)
    const vc = document.getElementById('video-container');
    if (!vc) return;
    vc.style.display = 'block';

    // Mobile: full-screen takeover — hide tab bar + topbar, add call header
    if (window.innerWidth <= 600) {
        const tabBar = document.getElementById('mobile-tab-bar');
        if (tabBar) tabBar.style.display = 'none';
        // Add call header with channel name as back button
        if (!document.getElementById('mobile-call-header')) {
            const hdr = document.createElement('div');
            hdr.id = 'mobile-call-header';
            hdr.style.cssText = 'display:flex;align-items:center;padding:14px 16px;gap:12px;flex-shrink:0;border-bottom:1px solid rgba(255,255,255,0.06);background:rgba(0,0,0,0.3);';
            hdr.innerHTML = `
                <button onclick="_leaveVoiceChannel()" style="background:none;border:none;color:white;font-size:18px;cursor:pointer;padding:4px;">←</button>
                <div style="flex:1;">
                    <div style="color:white;font-size:16px;font-weight:700;">${_escAttr(_voiceChannelName || 'Voice Channel')}</div>
                    <div style="color:#23a559;font-size:12px;">Connected</div>
                </div>
            `;
            vc.insertBefore(hdr, vc.firstChild);
        }
    }

    const remoteDiv = document.getElementById('remote-videos');
    if (remoteDiv) {
        const myInitial = (currentUser || 'U')[0].toUpperCase();
        const myAvatar = localStorage.getItem('tenshi_avatar') || '';
        const avatarInner = myAvatar
            ? `<img src="${myAvatar}" style="width:60px;height:60px;border-radius:50%;object-fit:cover;">`
            : `<div style="width:60px;height:60px;border-radius:50%;background:var(--accent-blue);display:flex;align-items:center;justify-content:center;font-size:28px;font-weight:bold;color:white;">${myInitial}</div>`;
        remoteDiv.innerHTML = `
            <div id="vc-participant-me" style="display:flex;flex-direction:column;align-items:center;gap:6px;">
                <div style="color:var(--accent-blue);font-size:13px;font-weight:600;">${_escAttr(currentUser)}</div>
                <div id="vc-box-me" style="position:relative;width:140px;height:140px;border-radius:16px;transition:box-shadow 0.15s;cursor:pointer;" oncontextmenu="_showVcUserMenu(event,'${_escAttr(currentUser)}','${_escAttr(currentUser)}');return false;" onclick="_vcToggleFullscreen(this)">
                    <video id="local-video" autoplay muted playsinline style="width:140px;height:140px;border-radius:16px;border:3px solid var(--accent-blue);background:black;object-fit:cover;display:none;"></video>
                    <div id="vc-avatar-me" style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(30,31,35,0.95);border-radius:16px;border:3px solid var(--accent-blue);">
                        ${avatarInner}
                    </div>
                </div>
                <div id="vc-mic-me" style="font-size:11px;color:#23a559;">🎤 Unmuted</div>
                <div style="width:140px;margin-top:2px;">
                    <div style="background:rgba(255,255,255,0.1);border-radius:4px;height:4px;overflow:hidden;">
                        <div id="vc-mic-level" style="height:100%;width:0%;background:var(--accent-blue);transition:width 0.1s;border-radius:4px;"></div>
                    </div>
                    ${_vqSettings.manualNoiseSuppression ? `<div style="display:flex;align-items:center;gap:4px;margin-top:4px;justify-content:center;">
                        <span style="font-size:9px;color:var(--text-muted);">Suppression:</span>
                        <input id="vc-threshold-num" type="number" min="0" max="100" value="${_myVoiceThreshold}" style="width:42px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;padding:3px 4px;border-radius:4px;font-size:11px;text-align:center;" oninput="_setMyThreshold(this.value)">
                        <span style="font-size:9px;color:var(--text-muted);">%</span>
                    </div>` : ''}
                </div>
            </div>
        `;
    }

    // Wire disconnect button for voice channel
    const dcBtn = document.querySelector('[onclick*="leaveVoiceWithPresence"]');
    if (dcBtn) dcBtn.setAttribute('onclick', '_leaveVoiceChannel()');

    // Reset camera button state
    const camBtn = document.getElementById('voice-cam-btn');
    if (camBtn) camBtn.textContent = '📵 Camera Off';

    // Block default browser right-click menu on voice channel area
    const _rvDiv = document.getElementById('remote-videos');
    if (_rvDiv) {
        _rvDiv.addEventListener('contextmenu', (e) => {
            // Only block if clicking on a participant box
            const userBox = e.target.closest('[data-vc-user]') || e.target.closest('#vc-box-me') || e.target.closest('#vc-participant-me');
            if (userBox) e.preventDefault();
        });
    }

    // Start speaking detection (mic level bar + glow)
    _startVcSpeakingDetection();

    _injectVcAccessibilityUI(serverId, channelName);

    // Poll for other users in the voice channel
    if (_voiceChannelPollInterval) clearInterval(_voiceChannelPollInterval);
    _voiceChannelPollInterval = setInterval(() => _pollVoiceChannelUsers(serverId, channelName), 1500);
    _pollVoiceChannelUsers(serverId, channelName);
}

let _vcPreviousUsers = new Set();

async function _pollVoiceChannelUsers(serverId, channelName) {
    // Guard against stale polls after leaving/switching channels
    if (!_voiceChannelName || _voiceChannelName !== channelName || _voiceServerId !== serverId) return;
    try {
        const res = await apiRequest('GET_SERVER_MEMBERS', { server_id: serverId });
        if (res.status !== 'success') return;
        // Re-check after await — channel may have changed during the API call
        if (!_voiceChannelName || _voiceChannelName !== channelName) return;
        const members = res.members || [];
        const inChannel = members.filter(m => m.voice_channel === channelName && m.username !== currentUser);

        const remoteDiv = document.getElementById('remote-videos');
        if (!remoteDiv) return;

        // Detect join/leave for sound notifications
        const currentUsers = new Set(inChannel.map(m => m.username));
        for (const u of _vcPreviousUsers) {
            if (!currentUsers.has(u)) playNotif('leave');
        }
        for (const u of currentUsers) {
            if (!_vcPreviousUsers.has(u)) playNotif('join');
        }
        _vcPreviousUsers = currentUsers;

        // Start signal polling for WebRTC (once)
        _startVcSignalPolling();

        // Remove users who left + disconnect their WebRTC
        // But only if the WebRTC connection is not still active (prevents false disconnects)
        remoteDiv.querySelectorAll('[data-vc-user]').forEach(el => {
            const u = el.dataset.vcUser;
            if (!inChannel.find(m => m.username === u)) {
                const peer = _vcPeerConnections[u];
                const peerAlive = peer && peer.pc && (peer.pc.iceConnectionState === 'connected' || peer.pc.iceConnectionState === 'completed');
                if (peerAlive) {
                    // Peer still connected via WebRTC — server poll might be lagging, keep connection
                    console.log('[VC] Keeping peer ' + u + ' (WebRTC still connected, server poll may be stale)');
                } else {
                    el.remove();
                    _vcDisconnectPeer(u);
                }
            }
        });

        // Add new users (skip self — we have vc-participant-me)
        inChannel.forEach(m => {
            if (m.username === currentUser) return;
            if (remoteDiv.querySelector(`[data-vc-user="${m.username}"]`)) return;
            const initial = (m.display_name || m.username)[0].toUpperCase();
            const color = m.hub_role_name_color || m.banner_color || '#23a559';
            const box = document.createElement('div');
            box.dataset.vcUser = m.username;
            box.style.cssText = 'display:flex;flex-direction:column;align-items:center;gap:6px;';
            const safeUser = _escAttr(m.username);
            const avatarContent = m.avatar
                ? `<img src="${m.avatar}" style="width:60px;height:60px;border-radius:50%;object-fit:cover;">`
                : `<div style="width:60px;height:60px;border-radius:50%;background:${color};display:flex;align-items:center;justify-content:center;font-size:28px;font-weight:bold;color:white;">${initial}</div>`;
            box.innerHTML = `
                <div style="color:${color};font-size:13px;font-weight:600;">${_escAttr(m.display_name || m.username)}</div>
                <div style="position:relative;width:140px;height:140px;border-radius:16px;cursor:pointer;" oncontextmenu="_showVcUserMenu(event,'${safeUser}','${_escAttr(m.display_name||m.username)}');return false;" onclick="_vcToggleFullscreen(this)">
                    <video id="vc-video-${safeUser}" autoplay playsinline style="width:140px;height:140px;border-radius:16px;border:3px solid ${color};background:black;object-fit:cover;display:none;"></video>
                    <div id="vc-avatar-${safeUser}" style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(30,31,35,0.95);border-radius:16px;border:3px solid ${color};">
                        ${avatarContent}
                    </div>
                </div>
                <div id="vc-mic-${safeUser}" style="font-size:11px;color:var(--text-muted);">🎤 Unmuted</div>
            `;
            // Insert before "me" box or append
            const meBox = document.getElementById('vc-participant-me');
            if (meBox) remoteDiv.insertBefore(box, meBox);
            else remoteDiv.appendChild(box);

            // Pre-create audio element now (during user gesture context) to avoid autoplay block
            if (!document.getElementById('vc-audio-' + m.username)) {
                const audioEl = document.createElement('audio');
                audioEl.id = 'vc-audio-' + m.username;
                audioEl.autoplay = true;
                document.body.appendChild(audioEl);
            }
            // Only the lower username initiates to avoid glare
            if (currentUser.toLowerCase() < m.username.toLowerCase() && !_vcPeerConnections[m.username]) {
                _vcConnectToPeer(m.username);
            }
        });

        // Update voice channel user lists in sidebar
        const allVoiceUsers = members.filter(m => m.voice_channel);
        const mc = document.getElementById('message-container');
        if (mc) {
            // Find all voice channel items and update user lists beneath them
            mc.querySelectorAll('.channel-item').forEach(chEl => {
                const onclick = chEl.getAttribute('onclick') || '';
                const voiceMatch = onclick.match(/openChannel\('([^']+)','([^']+)','voice'\)/);
                if (!voiceMatch) return;
                const chName = voiceMatch[2];
                // Remove old user list
                let userList = chEl.nextElementSibling;
                if (userList && userList.classList.contains('vc-user-list')) userList.remove();
                // Find users in this channel
                const usersHere = allVoiceUsers.filter(m => m.voice_channel === chName);
                if (currentUser && (channelName === chName)) {
                    // Add self if not in list (merge server row when present so role colors apply)
                    if (!usersHere.find(m => m.username === currentUser)) {
                        const selfRow = members.find(x => x.username === currentUser);
                        if (selfRow) {
                            usersHere.push({
                                ...selfRow,
                                avatar: selfRow.avatar || localStorage.getItem('tenshi_avatar') || '',
                            });
                        } else {
                            usersHere.push({
                                username: currentUser,
                                display_name: currentUser,
                                avatar: localStorage.getItem('tenshi_avatar') || '',
                                banner_color: '#5865F2',
                            });
                        }
                    }
                }
                if (!usersHere.length) return;
                userList = document.createElement('div');
                userList.classList.add('vc-user-list');
                userList.style.cssText = 'padding:2px 0 4px 28px;';
                usersHere.forEach(u => {
                    const av = _hubMemberAvatarMarkup(u, 18);
                    const nm = u.hub_role_name_color || u.username_color || '#949BA4';
                    userList.innerHTML += `<div style="display:flex;align-items:center;gap:6px;padding:2px 8px;font-size:11px;">
                        ${av}
                        <span style="color:${_escAttr(nm)};">${_escAttr(u.display_name || u.username)}</span>
                    </div>`;
                });
                chEl.insertAdjacentElement('afterend', userList);
            });
        }
    } catch {}
}

let _vcUserVolumes = {};

function _vcSetUserVolume(username, vol) {
    _vcUserVolumes[username] = parseInt(vol);
    const audioEl = document.getElementById('vc-audio-' + username);
    if (audioEl) audioEl.volume = Math.min(vol / 100, 2.0);
}

function _vcToggleUserMute(username) {
    const audioEl = document.getElementById('vc-audio-' + username);
    if (audioEl) audioEl.muted = !audioEl.muted;
}

let _vcSpeakingInterval = null;

function _startVcSpeakingDetection() {
    if (_vcSpeakingInterval) clearInterval(_vcSpeakingInterval);
    if (!localMediaStream) return;
    try {
        const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        if (audioCtx.state === 'suspended') audioCtx.resume();
        const source = audioCtx.createMediaStreamSource(localMediaStream);
        const analyser = audioCtx.createAnalyser();
        analyser.fftSize = 256;
        analyser.smoothingTimeConstant = 0.5;
        source.connect(analyser);
        const data = new Uint8Array(analyser.frequencyBinCount);
        _vcSpeakingInterval = setInterval(() => {
            if (!localMediaStream || !_voiceChannelName) {
                clearInterval(_vcSpeakingInterval); _vcSpeakingInterval = null;
                audioCtx.close();
                return;
            }
            analyser.getByteFrequencyData(data);
            const avg = data.reduce((a, b) => a + b, 0) / data.length;
            const levelBar = document.getElementById('vc-mic-level');
            if (levelBar) levelBar.style.width = Math.min(avg / 60 * 100, 100) + '%';
            const speaking = avg > _myVoiceThreshold && !_isMuted;
            const box = document.getElementById('vc-box-me');
            if (box) {
                box.style.boxShadow = speaking ? '0 0 20px var(--accent-blue), 0 0 40px rgba(88,101,242,0.3)' : 'none';
            }
            // Update mic status text
            const micMe = document.getElementById('vc-mic-me');
            if (micMe && !_isMuted) {
                micMe.textContent = speaking ? '🎤 Speaking' : '🎤 Unmuted';
                micMe.style.color = speaking ? '#23a559' : 'var(--text-muted)';
            }
            window._vcIsSpeaking = speaking;
        }, 100);
    } catch(e) { console.warn('VC speaking detection failed:', e); }
}

function _leaveVoiceChannel() {
    _leaveVoiceChannelAsync().catch(() => {});
}

async function _leaveVoiceChannelAsync() {
    playNotif('leave');
    if (_voiceChannelPollInterval) { clearInterval(_voiceChannelPollInterval); _voiceChannelPollInterval = null; }
    if (_vcSpeakingInterval) { clearInterval(_vcSpeakingInterval); _vcSpeakingInterval = null; }
    _vcDisconnectAllPeers();
    if (localMediaStream) { localMediaStream.getTracks().forEach(t => t.stop()); localMediaStream = null; }
    const serverId = _voiceServerId;
    // AWAIT the leave so a subsequent join won't race with it
    try { await apiRequest('LEAVE_VOICE_CHANNEL', {}); } catch {}
    if (serverId) _loadVoicePresence(serverId);
    const vc = document.getElementById('video-container');
    if (vc) vc.style.display = 'none';
    // Mobile: restore tab bar and remove call header
    const callHdr = document.getElementById('mobile-call-header');
    if (callHdr) callHdr.remove();
    if (window.innerWidth <= 600) {
        const tabBar = document.getElementById('mobile-tab-bar');
        if (tabBar) tabBar.style.display = '';
    }
    document.querySelectorAll('.vc-user-list').forEach(el => el.remove());
    _voiceChannelName = null;
    _voiceServerId = null;
    _vcPreviousUsers = new Set();
    _lastHeartbeatVcUsers = new Set();
    _saveCallState(null);
}

// ── Hub voice channel WebRTC streaming ────────────────────────
const _vcPeerConnections = {}; // username -> { pc, signalInterval }
let _vcSignalPollInterval = null;
let _vcSpeechRec = null;
let _vcCaptionsPublishing = false;

async function _vcConnectToPeer(targetUser) {
    if (_vcPeerConnections[targetUser]) return; // Already connected
    if (!localMediaStream) return;

    console.log('[VC-WebRTC] Connecting to ' + targetUser);
    const pc = new RTCPeerConnection(_getRtcConfig());
    const entry = { pc, iceQueue: [] };
    _vcPeerConnections[targetUser] = entry;

    // Add local audio tracks
    localMediaStream.getTracks().forEach(track => {
        pc.addTrack(track, localMediaStream);
    });

    // Handle incoming remote audio AND video
    pc.ontrack = (event) => {
        console.log('[VC-WebRTC] ontrack from ' + targetUser + ': ' + event.track.kind);
        if (event.track.kind === 'video') {
            const videoStream = event.streams[0] || new MediaStream([event.track]);
            const videoEl = document.getElementById('vc-video-' + targetUser);
            const avatarEl = document.getElementById('vc-avatar-' + targetUser);
            if (videoEl) {
                videoEl.srcObject = videoStream;
                videoEl.style.display = 'block';
                if (avatarEl) avatarEl.style.display = 'none';
                console.log('[VC-WebRTC] Video attached for', targetUser);
            }
            // When remote disables camera, track goes mute — listen for it
            event.track.onmute = () => {
                if (videoEl) videoEl.style.display = 'none';
                if (avatarEl) avatarEl.style.display = 'flex';
            };
            event.track.onunmute = () => {
                if (videoEl) { videoEl.style.display = 'block'; videoEl.srcObject = videoStream; }
                if (avatarEl) avatarEl.style.display = 'none';
            };
        }
        if (event.track.kind === 'audio') {
            const rawVcStream = event.streams[0] || new MediaStream([event.track]);
            // Apply voice enhancement filter for natural sound
            const enhancedVcStream = _applyVoiceEnhancement(rawVcStream, 'vc-' + targetUser);
            let audioEl = document.getElementById('vc-audio-' + targetUser);
            if (!audioEl) {
                audioEl = document.createElement('audio');
                audioEl.id = 'vc-audio-' + targetUser;
                audioEl.autoplay = true;
                audioEl.playsInline = true;
                document.body.appendChild(audioEl);
            }
            audioEl.srcObject = enhancedVcStream;
            // Respect deafen state — don't override user's deafen on renegotiation
            audioEl.muted = _isDeafened;
            const vol = _isDeafened ? 0 : (_vcUserVolumes[targetUser] ?? 60);
            audioEl.volume = Math.min(vol / 100, 2.0);
            // Set speaker output if saved
            const savedDevices = JSON.parse(localStorage.getItem('tenshi_devices') || '{}');
            if (savedDevices.speaker && audioEl.setSinkId) {
                audioEl.setSinkId(savedDevices.speaker).catch(() => {});
            }
            // Aggressive play retry — autoplay is often blocked on mobile
            const _tryPlay = () => {
                audioEl.play().then(() => {
                    console.log('[VC-WebRTC] Audio playing for', targetUser);
                }).catch(e => {
                    console.warn('[VC] play() blocked for', targetUser, '- retrying on interaction');
                    ['click','touchstart','keydown','touchend'].forEach(evt =>
                        document.addEventListener(evt, () => audioEl.play().catch(()=>{}), { once: true })
                    );
                    setTimeout(() => audioEl.play().catch(()=>{}), 500);
                    setTimeout(() => audioEl.play().catch(()=>{}), 1500);
                    setTimeout(() => audioEl.play().catch(()=>{}), 3000);
                    setTimeout(() => audioEl.play().catch(()=>{}), 6000);
                });
            };
            _tryPlay();

            // Speaking detection — use the voice enhancement's built-in analyser (avoids double AudioContext)
            try {
                const enhKey = 'vc-' + targetUser;
                const enhancement = _voiceEnhancementContexts.get(enhKey);
                let analyser, freqData, ownCtx = null;
                if (enhancement && enhancement.analyser) {
                    analyser = enhancement.analyser;
                    freqData = enhancement.freqData;
                    console.log('[VC] Using enhancement analyser for', targetUser);
                } else {
                    // Fallback: own AudioContext from enhanced stream (not raw — avoids stream conflict)
                    ownCtx = new (window.AudioContext || window.webkitAudioContext)();
                    if (ownCtx.state === 'suspended') ownCtx.resume();
                    const src = ownCtx.createMediaStreamSource(enhancedVcStream);
                    analyser = ownCtx.createAnalyser();
                    analyser.fftSize = 256;
                    analyser.smoothingTimeConstant = 0.5;
                    src.connect(analyser);
                    freqData = new Uint8Array(analyser.frequencyBinCount);
                }
                const speakInterval = setInterval(() => {
                    if (!_vcPeerConnections[targetUser]) { clearInterval(speakInterval); if (ownCtx) ownCtx.close(); _cleanupVoiceEnhancement(enhKey); return; }
                    analyser.getByteFrequencyData(freqData);
                    const avg = freqData.reduce((a, b) => a + b, 0) / freqData.length;
                    const speaking = avg > 8;
                    const box = document.querySelector(`[data-vc-user="${targetUser}"] > div:nth-child(2)`) || document.querySelector(`[data-vc-user="${targetUser}"]`);
                    if (box) box.style.boxShadow = speaking ? '0 0 20px #23a559, 0 0 40px rgba(35,165,89,0.3)' : 'none';
                    const micStatus = document.getElementById('vc-mic-' + targetUser);
                    if (micStatus) {
                        micStatus.textContent = speaking ? '🎤 Speaking' : '🎤 Unmuted';
                        micStatus.style.color = speaking ? '#23a559' : 'var(--text-muted)';
                    }
                }, 100);
            } catch(e) { console.warn('[VC] Speaking detection failed for', targetUser, e); }

            console.log('[VC-WebRTC] Audio connected: ' + targetUser);
        }
    };

    // Send ICE candidates via VC-specific signal channel
    pc.onicecandidate = (event) => {
        if (event.candidate) {
            apiRequest('VC_SIGNAL', { target: targetUser, signal_type: 'ice', data: event.candidate.toJSON() }).catch(() => {});
        }
    };

    pc.oniceconnectionstatechange = () => {
        console.log('[VC-WebRTC] ICE(' + targetUser + '): ' + pc.iceConnectionState);
        if (pc.iceConnectionState === 'failed') {
            // Connection truly failed — disconnect and retry
            _vcDisconnectPeer(targetUser);
            // Retry after 3s
            setTimeout(() => {
                if (_voiceChannelName && !_vcPeerConnections[targetUser]) {
                    _vcConnectToPeer(targetUser);
                }
            }, 3000);
        }
        // 'disconnected' is temporary — don't tear down, WebRTC will attempt recovery
    };

    // Create and send offer
    try {
        const offer = await pc.createOffer();
        await pc.setLocalDescription(offer);
        await apiRequest('VC_SIGNAL', { target: targetUser, signal_type: 'offer', data: { type: offer.type, sdp: offer.sdp } });
        console.log('[VC-WebRTC] Offer sent to ' + targetUser);
    } catch(e) {
        console.error('[VC-WebRTC] Offer failed:', e);
    }
}

function _vcDisconnectPeer(targetUser) {
    const entry = _vcPeerConnections[targetUser];
    if (!entry) return;
    try { entry.pc.close(); } catch {}
    delete _vcPeerConnections[targetUser];
    const audioEl = document.getElementById('vc-audio-' + targetUser);
    if (audioEl) { audioEl.pause(); audioEl.srcObject = null; audioEl.remove(); }
    console.log('[VC-WebRTC] Disconnected from ' + targetUser);
}

function _renderVcCaption(data) {
    const bar = document.getElementById('vc-caption-bar');
    const textEl = document.getElementById('vc-caption-text');
    if (!bar || !textEl) return;
    const who = _escAttr(data.from || '?');
    const line = _escAttr(data.text || '');
    textEl.innerHTML = '<span style="color:#9ec5ff;font-weight:700;margin-right:6px;">' + who + '</span>' + line;
    bar.style.display = 'flex';
    clearTimeout(bar._hideT);
    bar._hideT = setTimeout(() => { bar.style.display = 'none'; }, 8200);
    if (typeof speechSynthesis !== 'undefined' && localStorage.getItem('tenshi_tts_vc') === '1' && line) {
        try {
            const u = new SpeechSynthesisUtterance((data.text || '').slice(0, 500));
            u.rate = 1;
            speechSynthesis.cancel();
            speechSynthesis.speak(u);
        } catch {}
    }
}

function _toggleVcLiveCaptions(serverId, channelName, on, quiet = false) {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) {
        notify('Speech recognition is not supported in this browser.', { type: 'warning' });
        return;
    }
    if (!on) {
        _vcCaptionsPublishing = false;
        try { _vcSpeechRec && _vcSpeechRec.stop(); } catch {}
        _vcSpeechRec = null;
        const liveCbOff = document.getElementById('vc-caption-live-checkbox');
        if (liveCbOff) liveCbOff.checked = false;
        if (!quiet) notify('Live captions paused.', { icon: '📝' });
        return;
    }
    _vcCaptionsPublishing = true;
    if (_vcSpeechRec) {
        try { _vcSpeechRec.stop(); } catch {}
        _vcSpeechRec = null;
    }
    const rec = new SR();
    rec.continuous = true;
    rec.interimResults = false;
    rec.lang = navigator.language || 'en-US';
    let lastEmit = '';
    rec.onresult = (ev) => {
        let chunk = '';
        for (let i = ev.resultIndex; i < ev.results.length; i++) {
            if (ev.results[i].isFinal) chunk += ev.results[i][0].transcript;
        }
        chunk = (chunk || '').trim();
        if (!chunk || chunk === lastEmit || !_voiceChannelName) return;
        lastEmit = chunk;
        apiRequest('VC_BROADCAST_CAPTION', { server_id: serverId, channel: channelName, text: chunk }).catch(() => {});
    };
    rec.onerror = () => {};
    try {
        rec.start();
        notify('Publishing live captions…', { icon: '📝' });
        _vcSpeechRec = rec;
    } catch (e) {
        notify('Unable to start speech recognition.', { type: 'error' });
        _vcCaptionsPublishing = false;
    }
}

function _injectVcAccessibilityUI(serverId, channelName) {
    const vc = document.getElementById('video-container');
    if (!vc || document.getElementById('vc-a11y-strip')) return;
    const wrap = document.createElement('div');
    wrap.id = 'vc-a11y-strip';
    wrap.style.cssText = 'width:100%;max-width:720px;margin:14px auto 0;padding:0 10px;display:flex;flex-direction:column;gap:8px;';
    wrap.innerHTML = `
<div id="vc-caption-bar" style="display:none;min-height:38px;width:100%;border-radius:10px;background:rgba(0,0,0,.75);padding:10px 12px;color:#eaeaea;font-size:14px;line-height:1.35;box-sizing:border-box;align-items:center;">
  <span id="vc-caption-text"></span>
</div>
<div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;align-items:center;">
  <label style="display:flex;align-items:center;gap:6px;font-size:12px;color:var(--text-muted);cursor:pointer;">
    <input type="checkbox" id="vc-caption-live-checkbox"> Live captions (mic → channel)
  </label>
  <label style="display:flex;align-items:center;gap:6px;font-size:12px;color:var(--text-muted);cursor:pointer;">
    <input type="checkbox" id="vc-tts-checkbox"> Speak captions (TTS)
  </label>
</div>`;
    vc.appendChild(wrap);
    const liveCb = document.getElementById('vc-caption-live-checkbox');
    const ttsCb = document.getElementById('vc-tts-checkbox');
    if (ttsCb) {
        ttsCb.checked = localStorage.getItem('tenshi_tts_vc') === '1';
        ttsCb.onchange = () => localStorage.setItem('tenshi_tts_vc', ttsCb.checked ? '1' : '0');
    }
    if (liveCb) {
        liveCb.checked = !!_vcCaptionsPublishing;
        liveCb.onchange = () => _toggleVcLiveCaptions(serverId, channelName, liveCb.checked);
    }
}

function _vcDisconnectAllPeers() {
    for (const user of Object.keys(_vcPeerConnections)) {
        _cleanupVoiceEnhancement('vc-' + user);
        _vcDisconnectPeer(user);
    }
    if (_vcSignalPollInterval) { clearInterval(_vcSignalPollInterval); _vcSignalPollInterval = null; }
    _toggleVcLiveCaptions('', '', false, true);
    document.getElementById('vc-a11y-strip')?.remove();
    document.querySelectorAll('[id^="vc-audio-"]').forEach(el => el.remove());
}

function _startVcSignalPolling() {
    if (_vcSignalPollInterval) return;
    _vcSignalPollInterval = setInterval(async () => {
        if (!_voiceChannelName) { clearInterval(_vcSignalPollInterval); _vcSignalPollInterval = null; return; }
        try {
            const res = await apiRequest('VC_POLL_SIGNAL');
            if (res.status !== 'success' || !res.signals?.length) return;
            for (const signal of res.signals) {
                const fromUser = signal.from;
                if (signal.type === 'offer') {
                    // Someone sent us an offer — close any existing connection first
                    if (_vcPeerConnections[fromUser]) {
                        try { _vcPeerConnections[fromUser].pc.close(); } catch {}
                        delete _vcPeerConnections[fromUser];
                    }
                    const pc = new RTCPeerConnection(_getRtcConfig());
                    const entry = { pc, iceQueue: [] };
                    _vcPeerConnections[fromUser] = entry;
                    if (localMediaStream) {
                        localMediaStream.getTracks().forEach(track => pc.addTrack(track, localMediaStream));
                    }
                    pc.ontrack = (event) => {
                        console.log('[VC-WebRTC] ontrack from ' + fromUser + ': ' + event.track.kind);
                        if (event.track.kind === 'video') {
                            const videoStream = event.streams[0] || new MediaStream([event.track]);
                            const videoEl = document.getElementById('vc-video-' + fromUser);
                            const avatarEl = document.getElementById('vc-avatar-' + fromUser);
                            if (videoEl) {
                                videoEl.srcObject = videoStream;
                                videoEl.style.display = 'block';
                                if (avatarEl) avatarEl.style.display = 'none';
                            }
                            event.track.onmute = () => { if (videoEl) videoEl.style.display = 'none'; if (avatarEl) avatarEl.style.display = 'flex'; };
                            event.track.onunmute = () => { if (videoEl) { videoEl.style.display = 'block'; videoEl.srcObject = videoStream; } if (avatarEl) avatarEl.style.display = 'none'; };
                        }
                        if (event.track.kind === 'audio') {
                            const stream = event.streams[0] || new MediaStream([event.track]);
                            let audioEl = document.getElementById('vc-audio-' + fromUser);
                            if (!audioEl) {
                                audioEl = document.createElement('audio');
                                audioEl.id = 'vc-audio-' + fromUser;
                                audioEl.autoplay = true;
                                document.body.appendChild(audioEl);
                            }
                            audioEl.srcObject = stream;
                            // Respect deafen state
                            audioEl.muted = _isDeafened;
                            const vol = _isDeafened ? 0 : (_vcUserVolumes[fromUser] ?? 60);
                            audioEl.volume = Math.min(vol / 100, 2.0);
                            audioEl.play().catch(e => { console.warn('[VC] play() blocked:', e); document.addEventListener('click', () => audioEl.play().catch(()=>{}), { once: true }); });
                        }
                    };
                    pc.onicecandidate = (event) => {
                        if (event.candidate) {
                            apiRequest('VC_SIGNAL', { target: fromUser, signal_type: 'ice', data: event.candidate.toJSON() }).catch(() => {});
                        }
                    };
                    pc.oniceconnectionstatechange = () => {
                        console.log('[VC-WebRTC] ICE(' + fromUser + '): ' + pc.iceConnectionState);
                        if (pc.iceConnectionState === 'failed') {
                            _vcDisconnectPeer(fromUser);
                        }
                    };
                    await pc.setRemoteDescription(new RTCSessionDescription(signal.data));
                    // Flush queued ICE candidates
                    for (const ic of entry.iceQueue) {
                        try { await pc.addIceCandidate(new RTCIceCandidate(ic)); } catch {}
                    }
                    entry.iceQueue = [];
                    const answer = await pc.createAnswer();
                    await pc.setLocalDescription(answer);
                    await apiRequest('VC_SIGNAL', { target: fromUser, signal_type: 'answer', data: { type: answer.type, sdp: answer.sdp } });
                    console.log('[VC-WebRTC] Answered offer from ' + fromUser);

                } else if (signal.type === 'answer') {
                    const entry = _vcPeerConnections[fromUser];
                    if (entry?.pc) {
                        await entry.pc.setRemoteDescription(new RTCSessionDescription(signal.data));
                        // Flush queued ICE candidates
                        if (entry.iceQueue) {
                            for (const ic of entry.iceQueue) {
                                try { await entry.pc.addIceCandidate(new RTCIceCandidate(ic)); } catch {}
                            }
                            entry.iceQueue = [];
                        }
                        console.log('[VC-WebRTC] Got answer from ' + fromUser);
                    }

                } else if (signal.type === 'ice') {
                    const entry = _vcPeerConnections[fromUser];
                    if (entry?.pc) {
                        if (entry.pc.remoteDescription) {
                            try { await entry.pc.addIceCandidate(new RTCIceCandidate(signal.data)); } catch {}
                        } else {
                            if (!entry.iceQueue) entry.iceQueue = [];
                            entry.iceQueue.push(signal.data);
                        }
                    }
                } else if (signal.type === 'caption') {
                    _renderVcCaption(signal.data || {});
                } else if (signal.type === 'force_stop_stream') {
                    if (_screenStream) {
                        toggleScreenShare();
                        alert(`${signal.data?.by || 'An admin'} stopped your screen share.`);
                    }
                } else if (signal.type === 'force_mute') {
                    if (localMediaStream) {
                        localMediaStream.getAudioTracks().forEach(t => t.enabled = false);
                        _isMuted = true;
                        const micEl = document.getElementById('vc-mic-me');
                        if (micEl) { micEl.textContent = '🔇 Muted by ' + (signal.data?.by || 'admin'); micEl.style.color = '#ed4245'; }
                    }
                } else if (signal.type === 'force_cam_off') {
                    if (localMediaStream) {
                        localMediaStream.getVideoTracks().forEach(t => t.enabled = false);
                        const camBtn = document.getElementById('voice-cam-btn');
                        if (camBtn) camBtn.textContent = '📵 Camera Off';
                        const avatar = document.getElementById('vc-avatar-me') || document.getElementById('call-avatar-me');
                        if (avatar) avatar.style.display = 'flex';
                    }
                }
            }
        } catch {}
    }, 500);
}

// Legacy stubs
function _startAudioStream() {}
function _stopAudioStream() { _vcDisconnectAllPeers(); }

// Message cache: preserves chat history when switching channels/DMs
const _msgCache = {};

function _saveCurrentMessages() {
    if (!currentTarget) return;
    const container = document.getElementById('message-container');
    if (container) _msgCache[currentTarget] = container.innerHTML;
}

function _restoreMessages(target) {
    const container = document.getElementById('message-container');
    if (_msgCache[target]) {
        container.innerHTML = _msgCache[target];
        container.scrollTop = container.scrollHeight;
    } else {
        container.innerHTML = '';
    }
}

function openChannel(serverId, channelName, type) {
    stopMedia();
    // Save current chat messages before switching
    _saveCurrentMessages();
    _setDmRefreshVisible(false);

    currentTarget = "srv:" + serverId + ":" + channelName;
    document.getElementById('current-chat').innerText = (type==="voice"?"🔊 ":"# ") + channelName;
    _syncTopbarChannelLabel((type === 'voice' ? '🔊 ' : '# ') + channelName);

    // Highlight active channel in left panel
    document.querySelectorAll('#left-panel-list .channel-item').forEach(el => el.classList.remove('active'));
    document.querySelectorAll('#left-panel-list .channel-item').forEach(el => {
        if (el.textContent.trim().replace(/^[#🔊🔒]\s*/, '') === channelName) el.classList.add('active');
    });

    // Close mobile panel so chat is visible; user can reopen via hamburger
    if (typeof closeMobilePanel === 'function') closeMobilePanel();

    if (type === "voice") {
        document.getElementById('message-container').style.display = 'none';
        document.getElementById('video-container').style.display = 'block';
        startMediaStream(channelName);
        if (currentChatInterval) clearInterval(currentChatInterval);
        return;
    }

    document.getElementById('video-container').style.display = 'none';
    document.getElementById('message-container').style.display = 'block';
    // Restore cached messages for this channel
    _restoreMessages(currentTarget);
    if (currentChatInterval) clearInterval(currentChatInterval);
    currentChatInterval = setInterval(pollMessages, 3000);
    pollMessages();
}

async function fetchFriends() {
    await _loadTempStreaks().catch(() => {});
    let res = await apiRequest('GET_RELATIONSHIPS');
    if (res.status !== 'success') return;
    let flist = document.getElementById('dynamic-list');
    if (!flist) return;
    let html = '';
    html += `<div id="story-feed-bar" class="story-feed-bar"></div>`;
    html += `<div class="friends-snap-toolbar">
        <button type="button" class="friends-temp-launch" onclick="_openTempCapture()" title="Send a temp snap">📷</button>
        <input type="text" id="add-friend-inp" class="friends-add-friend-inp" placeholder="Add friend by username" autocomplete="off">
        <button type="button" class="friends-add-friend-btn" onclick="(function(){const v=document.getElementById('add-friend-inp')?.value?.trim();if(v)apiRequest('ADD_FRIEND',{target:v}).then(r=>{alert(r.message||'Done');if(r.status==='success')fetchFriends();});})();">Add</button>
    </div>`;
    res.friends.forEach(f => {
        const streak = _getStreakDisplay(f);
        html += `<div class="channel-item" onclick="openChat('${_escAttr(f)}')" style="display:flex;justify-content:space-between;gap:8px;"><span style="overflow:hidden;text-overflow:ellipsis;">💬 ${_escAttr(f)}</span>${streak}</div>`;
    });
    html += `<div style="padding:10px 12px;"><button onclick="let f=document.getElementById('quick-chat-inp').value;if(f)openChat(f)" style="width:100%;padding:10px;background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.08);border-radius:10px;color:var(--text-muted);font-size:12px;cursor:pointer;">Quick open chat ↵</button><input id="quick-chat-inp" type="text" placeholder="Username or email to chat" style="width:100%;margin-top:8px;padding:10px;background:rgba(0,0,0,0.35);border:1px solid rgba(255,255,255,0.08);border-radius:10px;color:white;font-size:13px;box-sizing:border-box;" onkeydown="if(event.key==='Enter'){openChat(this.value.trim());}"></div>`;
    flist.innerHTML = html;
    _refreshStoryFeed();
}

function openChat(user) {
    stopMedia();
    // Save current chat messages before switching
    _saveCurrentMessages();
    currentTarget = user;
    document.getElementById('current-chat').innerText = "💬 Chat with " + user;
    _syncTopbarChannelLabel('💬 ' + user);
    const isDmUser = user && user !== 'AI' && !user.includes('@') && !user.startsWith('srv:');
    _setDmRefreshVisible(!!isDmUser);
    // Restore cached messages for this DM
    _restoreMessages(currentTarget);
    // Close mobile panel so chat is visible
    if (typeof closeMobilePanel === 'function') closeMobilePanel();
    if (currentChatInterval) clearInterval(currentChatInterval);
    currentChatInterval = setInterval(pollMessages, 3000);
    pollMessages();
}

async function pollMessages() {
    if (!currentTarget) return;
    let res = await apiRequest('POLL_MESSAGES');
    if (res.status === 'success' && res.messages) {
        let chatbox = document.getElementById('message-container');
        for (const msg of res.messages) {
            // Check for Global Admin Broadcast
            if (msg.target_type === "broadcast" || msg.sender === "SYSTEM") {
                showGlobalNotification(msg.content);
            }

            if (msg.sender === currentTarget || (msg.target_type === 'dm' && msg.target_id === currentUser)) {
                let displayContent = msg.content;
                const decrypted = await fernetDecrypt(msg.content, currentTarget);
                if (decrypted !== null) {
                    displayContent = decrypted;
                } else if (msg.content && msg.content.length > 50) {
                    displayContent = "[Desktop E2EE Msg - Download App to Read]";
                }
                let m = document.createElement('div');
                m.className = 'msg';
                m.innerText = displayContent;
                chatbox.appendChild(m);
                chatbox.scrollTop = chatbox.scrollHeight;
            }
        }
    }
    
    // Also Poll Status (Typing/Online)
    if (currentTarget && currentTarget !== "AI") {
        let serverId = currentTarget.startsWith("srv:") ? currentTarget.split(":")[1] : null;
        let statusRes = await apiRequest('GET_SERVER_STATUS', { server_id: serverId || "SYSTEM" });
        if (statusRes.status === 'success') {
            let ti = document.getElementById('typing-indicator');
            let typers = statusRes.typing.filter(u => u !== currentUser);
            if (typers.length > 0) {
                ti.innerText = typers.join(", ") + (typers.length > 1 ? " are typing..." : " is typing...");
            } else {
                ti.innerText = "";
            }
        }
    }
}

function showGlobalNotification(text) {
    // Check if duplicate
    if (window.lastNotification === text) return;
    window.lastNotification = text;

    let toast = document.createElement('div');
    toast.style = "position:fixed; top:20px; right:20px; background:var(--accent-blue); color:white; padding:15px 25px; border-radius:12px; z-index:1000; box-shadow:0 10px 30px rgba(0,0,0,0.5); font-weight:bold; animation: slideIn 0.5s forwards;";
    toast.innerHTML = `📢 ${text}`;
    document.body.appendChild(toast);
    setTimeout(() => {
        toast.style.animation = "slideOut 0.5s forwards";
        setTimeout(() => toast.remove(), 500);
    }, 5000);
}

async function sendMessage() {
    if (!currentTarget) return alert("Select a chat first");
    let inp = document.getElementById('msg-input');
    let content = inp.value;
    if (!content) return;
    inp.value = '';
    
    // Add to local UI
    let mc = document.getElementById('message-container');
    let selfm = document.createElement('div');
    selfm.className = 'msg self';
    selfm.innerText = content;
    mc.appendChild(selfm);
    mc.scrollTop = mc.scrollHeight;
    
    let res;
    if (currentTarget === "AI") {
        mc.innerHTML += `<div class="msg" id="ai-thinking" style="color:gray;">Claude is thinking...</div>`;
        mc.scrollTop = mc.scrollHeight;
        res = await apiRequest('AI_CHAT', { content: content });
        document.getElementById('ai-thinking')?.remove();
        if (res.status === 'success') {
            let aim = document.createElement('div');
            aim.className = 'msg';
            aim.innerText = res.response;
            mc.appendChild(aim);
            // Refresh conversation sidebar to show updated list
            _aiLoadConversationList();
        } else if (res.status === 'needs_subscription') {
            const hint = document.createElement('div');
            hint.className = 'msg';
            hint.innerHTML = '<span style="color:#f0b132;">⚠️ ' + _escAttr(res.message || 'Personal AI Assistant subscription required.') + '</span>';
            const btnWrap = document.createElement('div');
            btnWrap.style.marginTop = '8px';
            const b = document.createElement('button');
            b.textContent = 'Subscribe with Stripe';
            b.style.cssText = 'padding:10px 14px;border-radius:10px;border:none;background:#635BFF;color:white;font-weight:600;cursor:pointer;';
            b.onclick = () => tenshiCreateStripeCheckout('ai_assistant');
            btnWrap.appendChild(b);
            hint.appendChild(btnWrap);
            mc.appendChild(hint);
        } else if (res.status === 'error' && res.message?.includes('Connection blocked')) {
            let errm = document.createElement('div');
            errm.className = 'msg';
            errm.innerHTML = '<span style="color:#f0b132;">⚠️ Cannot reach the server. Please accept the certificate at <a href="https://api.tenshi.lol" target="_blank" style="color:var(--accent-blue);">api.tenshi.lol</a> first, then try again.</span>';
            mc.appendChild(errm);
        } else {
            let errm = document.createElement('div');
            errm.style.color = "red";
            errm.innerText = "[AI Error] " + res.message;
            mc.appendChild(errm);
        }
        mc.scrollTop = mc.scrollHeight;
    } else {
        // Server expects E2EE encrypted blob for DM, raw for email.
        let type = currentTarget.includes('@') ? 'email' : 'dm';
        let encContent = content;
        if (type === 'dm') {
            const enc = await fernetEncrypt(content, currentTarget);
            if (enc) encContent = enc;
        }
        let payload = {
            target_type: type,
            target_id: currentTarget,
            content: encContent,
            is_snapchat: false,
            timestamp: new Date().toISOString()
        };
        res = await apiRequest('SEND_MESSAGE', payload);
    }
    
    if(res && res.status !== 'success'){
        let errm = document.createElement('div');
        errm.style.color = "red";
        errm.innerText = "[Failed to route] " + res.message;
        mc.appendChild(errm);
    }
}

// ════════════════════════════════════════════════════════════
//  TENSHI v3.0 — Background Themes & Storage Preference
// ════════════════════════════════════════════════════════════

// ── Background Theme Engine ───────────────────────────────
const THEMES = ['cosmic','ocean','aurora','ember','midnight','lavender','forest','sunset'];
const THEME_NAMES = {
    cosmic:   'Cosmic',
    ocean:    'Ocean Deep',
    aurora:   'Northern Lights',
    ember:    'Solar Ember',
    midnight: 'Midnight',
    lavender: 'Lavender Dream',
    forest:   'Forest',
    sunset:   'Sunset'
};

function applyTheme(name) {
    // Remove all theme classes
    THEMES.forEach(t => document.body.classList.remove('theme-' + t));
    // Remove any custom bg override
    const existing = document.getElementById('custom-bg-style');
    if (existing) existing.remove();

    if (name && name !== 'cosmic') {
        document.body.classList.add('theme-' + name);
    }
    localStorage.setItem('tenshi_theme', name || 'cosmic');

    // Update active state in UI if settings are open
    document.querySelectorAll('.theme-swatch').forEach(el => {
        el.classList.toggle('active', el.dataset.theme === name);
    });
}

function applyCustomBackground(type, color1, color2, direction) {
    THEMES.forEach(t => document.body.classList.remove('theme-' + t));
    let css = '';
    if (type === 'gradient') {
        css = `.glass-background{background:linear-gradient(${direction},${color1},${color2})!important;}
               .glow-orb{opacity:0!important;}`;
    } else if (type === 'solid') {
        css = `.glass-background{background:${color1}!important;}
               .glow-orb{opacity:0!important;}`;
    } else if (type === 'glass') {
        css = `.glass-background{background:radial-gradient(circle,${color1}22,${color2}11)!important;}`;
    }
    let el = document.getElementById('custom-bg-style') || document.createElement('style');
    el.id = 'custom-bg-style';
    el.textContent = css;
    document.head.appendChild(el);
    localStorage.setItem('tenshi_custom_bg', JSON.stringify({type, color1, color2, direction}));
    localStorage.removeItem('tenshi_theme');
}

function restoreThemeOnLoad() {
    const customBg = localStorage.getItem('tenshi_custom_bg');
    if (customBg) {
        try {
            const {type, color1, color2, direction} = JSON.parse(customBg);
            applyCustomBackground(type, color1, color2, direction);
            return;
        } catch(e) {}
    }
    const saved = localStorage.getItem('tenshi_theme') || 'cosmic';
    applyTheme(saved);
}

// Run on page load
restoreThemeOnLoad();

// Render the theme picker grid (called when settings Appearance tab opens)
function renderThemePicker(container) {
    const currentTheme = localStorage.getItem('tenshi_theme') || 'cosmic';
    let html = `<h3 style="color:white;margin-bottom:16px;font-size:15px;font-weight:700;">Choose Background</h3>
    <div class="theme-grid">`;
    THEMES.forEach(name => {
        html += `<div class="theme-swatch swatch-${name} ${currentTheme === name ? 'active' : ''}"
                      data-theme="${name}" onclick="applyTheme('${name}')">
                     <span>${THEME_NAMES[name]}</span>
                 </div>`;
    });
    html += `</div>`;

    // Custom background creator
    html += `<div class="bg-creator">
        <h4>Custom Background</h4>
        <div class="bg-type-tabs">
            <div class="bg-type-tab active" data-bgtype="gradient" onclick="selectBgType(this,'gradient')">Gradient</div>
            <div class="bg-type-tab" data-bgtype="solid" onclick="selectBgType(this,'solid')">Solid Color</div>
            <div class="bg-type-tab" data-bgtype="glass" onclick="selectBgType(this,'glass')">Glass Glow</div>
        </div>
        <div class="color-row">
            <label>Color 1</label>
            <input type="color" id="bg-color1" value="#5865F2" oninput="previewBg()">
            <span id="bg-color1-hex" style="color:#aaa;font-size:12px;">#5865F2</span>
        </div>
        <div class="color-row" id="bg-color2-row">
            <label>Color 2</label>
            <input type="color" id="bg-color2" value="#ed4245" oninput="previewBg()">
            <span id="bg-color2-hex" style="color:#aaa;font-size:12px;">#ed4245</span>
        </div>
        <select class="gradient-dir-select" id="bg-direction" onchange="previewBg()">
            <option value="135deg">↘ Diagonal (default)</option>
            <option value="to bottom">↓ Top to Bottom</option>
            <option value="to right">→ Left to Right</option>
            <option value="to top right">↗ Bottom-Left to Top-Right</option>
            <option value="circle">◎ Radial</option>
        </select>
        <div class="bg-preview" id="bg-preview-box"></div>
        <button class="apply-bg-btn" onclick="applyCustomBgFromUI()">Apply Custom Background</button>
    </div>`;

    container.innerHTML = html;
    previewBg();
}

let _currentBgType = 'gradient';
function selectBgType(el, type) {
    _currentBgType = type;
    el.closest('.bg-type-tabs').querySelectorAll('.bg-type-tab').forEach(t => t.classList.remove('active'));
    el.classList.add('active');
    // Hide color2 + direction for solid
    const c2row = document.getElementById('bg-color2-row');
    const dirSel = document.getElementById('bg-direction');
    if (c2row) c2row.style.display = type === 'solid' ? 'none' : 'flex';
    if (dirSel) dirSel.style.display = type === 'solid' ? 'none' : 'block';
    previewBg();
}

function previewBg() {
    const c1 = document.getElementById('bg-color1')?.value || '#5865F2';
    const c2 = document.getElementById('bg-color2')?.value || '#ed4245';
    const dir = document.getElementById('bg-direction')?.value || '135deg';
    const preview = document.getElementById('bg-preview-box');
    const h1 = document.getElementById('bg-color1-hex');
    const h2 = document.getElementById('bg-color2-hex');
    if (h1) h1.textContent = c1;
    if (h2) h2.textContent = c2;
    if (!preview) return;
    if (_currentBgType === 'solid') {
        preview.style.background = c1;
    } else if (_currentBgType === 'gradient') {
        const fn = dir === 'circle' ? `radial-gradient(circle,${c1},${c2})` : `linear-gradient(${dir},${c1},${c2})`;
        preview.style.background = fn;
    } else {
        preview.style.background = `radial-gradient(circle,${c1}44,${c2}22)`;
    }
}

function applyCustomBgFromUI() {
    const c1 = document.getElementById('bg-color1')?.value || '#5865F2';
    const c2 = document.getElementById('bg-color2')?.value || '#ed4245';
    const dir = document.getElementById('bg-direction')?.value || '135deg';
    applyCustomBackground(_currentBgType, c1, c2, dir);
    // Deselect all theme swatches
    document.querySelectorAll('.theme-swatch').forEach(el => el.classList.remove('active'));
}

// ── Storage Preference (Registration Form) ────────────────
// storagePreference is read by register() when sending REGISTER request
let storagePreference = localStorage.getItem('tenshi_storage_pref') || 'cloud';

function selectStorageOption(pref) {
    storagePreference = pref;
    localStorage.setItem('tenshi_storage_pref', pref);
    document.querySelectorAll('.storage-option').forEach(el => {
        el.classList.toggle('selected', el.dataset.pref === pref);
    });
    // Show relevant warning
    const cloudWarn = document.getElementById('storage-warn-cloud');
    const localWarn = document.getElementById('storage-warn-local');
    if (cloudWarn) cloudWarn.style.display = pref === 'cloud' ? 'block' : 'none';
    if (localWarn) localWarn.style.display = pref === 'local' ? 'block' : 'none';
}

// Inject storage choice HTML into registration panel
function injectStorageChoice() {
    const regPanel = document.getElementById('register-panel') || document.getElementById('reg-panel');
    if (!regPanel || document.getElementById('storage-choice-block')) return;

    const block = document.createElement('div');
    block.id = 'storage-choice-block';
    block.innerHTML = `
    <p style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:var(--text-muted);margin:16px 0 8px;">Data Storage</p>
    <div class="storage-choice">
        <label class="storage-option ${storagePreference==='cloud'?'selected':''}" data-pref="cloud" onclick="selectStorageOption('cloud')">
            <input type="radio" name="storage" value="cloud" ${storagePreference==='cloud'?'checked':''}>
            <span class="storage-option-icon">☁️</span>
            <div class="storage-option-text">
                <strong>Tenshi Cloud</strong>
                <small>Synced across devices. Accessible anywhere.</small>
            </div>
        </label>
        <label class="storage-option ${storagePreference==='local'?'selected':''}" data-pref="local" onclick="selectStorageOption('local')">
            <input type="radio" name="storage" value="local" ${storagePreference==='local'?'checked':''}>
            <span class="storage-option-icon">💾</span>
            <div class="storage-option-text">
                <strong>This Device Only</strong>
                <small>Messages stay local. No cloud sync.</small>
            </div>
        </label>
    </div>
    <div id="storage-warn-cloud" class="storage-warning cloud" style="${storagePreference==='cloud'?'':'display:none'}">
        ⚠️ Your account profile and friend list will be stored on Tenshi servers.
        All messages are end-to-end encrypted — Tenshi cannot read them.
        You can delete your account at any time.
    </div>
    <div id="storage-warn-local" class="storage-warning local" style="${storagePreference==='local'?'':'display:none'}">
        ⚠️ Messages will only be stored on this device. If you lose access to this device,
        your message history cannot be recovered. You cannot log in from other devices
        without the Device Linking process. Your account profile is still stored server-side
        for authentication.
    </div>`;

    // Insert before submit button (before the last button in the panel)
    const buttons = regPanel.querySelectorAll('button');
    if (buttons.length > 0) {
        regPanel.insertBefore(block, buttons[buttons.length - 1]);
    } else {
        regPanel.appendChild(block);
    }
}

// ── Override register() to include storage preference ─────
// Store original, wrap it
const _origRegister = typeof register === 'function' ? register : null;
window.register = async function() {
    // Patch: add storage_pref to the next REGISTER call by temporarily
    // monkey-patching apiRequest for one call
    const _origApi = window.apiRequest;
    window.apiRequest = async function(action, payload = {}) {
        if (action === 'REGISTER') {
            payload.storage_pref = storagePreference;
        }
        const result = await _origApi(action, payload);
        window.apiRequest = _origApi; // restore
        return result;
    };
    if (_origRegister) return _origRegister();
};

