// ── Auth Tab Switching ────────────────────────────────────────
function switchTab(tab) {
    const signInPanel = document.getElementById('signin-panel');
    const regPanel    = document.getElementById('register-panel');
    const forgotPanel = document.getElementById('forgot-password-panel');
    const authTabs = document.querySelector('.auth-tabs');
    const tabSignin   = document.getElementById('tab-signin');
    const tabRegister = document.getElementById('tab-register');

    if (forgotPanel) forgotPanel.style.display = 'none';
    if (authTabs) authTabs.style.display = '';

    if (tab === 'signin') {
        signInPanel.style.display = '';
        regPanel.style.display = 'none';
        tabSignin.classList.add('active');
        tabRegister.classList.remove('active');
    } else {
        signInPanel.style.display = 'none';
        regPanel.style.display = '';
        tabRegister.classList.add('active');
        tabSignin.classList.remove('active');
        setTimeout(injectStorageChoice, 50);
    }
}

function showForgotPasswordPanel() {
    const signInPanel = document.getElementById('signin-panel');
    const regPanel = document.getElementById('register-panel');
    const forgotPanel = document.getElementById('forgot-password-panel');
    const authTabs = document.querySelector('.auth-tabs');
    if (!forgotPanel) return;
    if (signInPanel) signInPanel.style.display = 'none';
    if (regPanel) regPanel.style.display = 'none';
    if (authTabs) authTabs.style.display = 'none';
    forgotPanel.style.display = 'block';
    document.getElementById('tab-signin')?.classList.remove('active');
    document.getElementById('tab-register')?.classList.remove('active');
    loadTurnstile();
    const el = document.getElementById('forgot-turnstile');
    if (window.turnstile && el && !el.dataset.rendered) {
        try {
            turnstile.render('#forgot-turnstile', {
                sitekey: '0x4AAAAAAC3jvazfhjvZhtgW',
                theme: 'dark',
                appearance: 'interaction-only',
                retry: 'never',
                'error-callback': function() { console.warn('[Turnstile] Forgot-password challenge failed'); }
            });
            el.dataset.rendered = '1';
        } catch (e) { console.warn('[Turnstile]', e); }
    }
}

function hideForgotPasswordPanel() {
    switchTab('signin');
}

async function forgotPasswordSendCode() {
    const idEl = document.getElementById('forgot-identifier');
    const st = document.getElementById('forgot-status');
    const raw = (idEl?.value || '').trim();
    if (!raw) {
        if (st) { st.style.color = '#ed4245'; st.textContent = 'Enter your username or email.'; }
        return;
    }
    let cf = document.querySelector('#forgot-turnstile [name=cf-turnstile-response]')?.value || '';
    if (!cf && window.turnstile && document.getElementById('forgot-turnstile')) {
        try {
            cf = await new Promise((resolve) => {
                window.turnstile.execute('#forgot-turnstile', {
                    callback: resolve,
                    'error-callback': () => resolve(''),
                });
                setTimeout(() => resolve(''), 8000);
            });
        } catch { cf = ''; }
    }
    if (st) { st.style.color = 'yellow'; st.textContent = 'Sending…'; }
    const r = await apiRequest('RECOVER_PASSWORD', { username: raw, cf_token: cf });
    if (st) {
        st.style.color = r.status === 'success' ? '#23a559' : '#ed4245';
        st.textContent = r.message || '';
    }
    if (window.turnstile && document.getElementById('forgot-turnstile'))
        try { turnstile.reset('#forgot-turnstile'); } catch {}
}

async function forgotPasswordComplete() {
    const raw = (document.getElementById('forgot-identifier')?.value || '').trim();
    const code = (document.getElementById('forgot-code')?.value || '').trim();
    const pw = document.getElementById('forgot-new-password')?.value || '';
    const st = document.getElementById('forgot-status');
    if (!raw || !code || !pw) {
        if (st) { st.style.color = '#ed4245'; st.textContent = 'Enter username/email, verification code from email, and new password.'; }
        return;
    }
    if (pw.length < 6) {
        if (st) { st.style.color = '#ed4245'; st.textContent = 'Password must be at least 6 characters.'; }
        return;
    }
    const pwd_hash = await simpleHash(pw);
    if (st) { st.style.color = 'yellow'; st.textContent = 'Updating…'; }
    const r = await apiRequest('RESET_PASSWORD', { username: raw, recovery_code: code, new_pwd_hash: pwd_hash });
    if (st) {
        st.style.color = r.status === 'success' ? '#23a559' : '#ed4245';
        st.textContent = r.message || '';
    }
    if (r.status === 'success')
        setTimeout(() => hideForgotPasswordPanel(), 1800);
}

// ── SSO Configuration ─────────────────────────────────────────
// Fill in your OAuth app credentials before deploying.
const SSO_CONFIG = {
    google: {
        client_id: 'YOUR_GOOGLE_CLIENT_ID.apps.googleusercontent.com',
        auth_url:  'https://accounts.google.com/o/oauth2/v2/auth',
        token_url: 'https://oauth2.googleapis.com/token',
        scope:     'openid email profile',
    },
    microsoft: {
        client_id: 'YOUR_MICROSOFT_CLIENT_ID',
        auth_url:  'https://login.microsoftonline.com/common/oauth2/v2.0/authorize',
        token_url: 'https://login.microsoftonline.com/common/oauth2/v2.0/token',
        scope:     'openid email profile User.Read',
    },
    apple: {
        // Apple requires response_mode=fragment for popup-based id_token delivery.
        // Register a Services ID (not App ID) at developer.apple.com.
        client_id: 'YOUR_APPLE_SERVICES_ID',
        auth_url:  'https://appleid.apple.com/auth/authorize',
        scope:     'name email',
    },
};

// ── PKCE helpers ──────────────────────────────────────────────
function _ssoRandB64url(byteLen) {
    const buf = new Uint8Array(byteLen);
    crypto.getRandomValues(buf);
    return btoa(String.fromCharCode(...buf)).replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
}
async function _pkceChallenge(verifier) {
    const data = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(verifier));
    return btoa(String.fromCharCode(...new Uint8Array(data))).replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
}

// ── SSO Login (PKCE for Google/Microsoft, hybrid flow for Apple) ──
async function ssoLogin(provider) {
    const cfg = SSO_CONFIG[provider];
    const statusEl = document.getElementById('auth-status');

    if (!cfg || cfg.client_id.startsWith('YOUR_')) {
        const t = _i18n[_currentLang] || _i18n.en;
        if (statusEl) { statusEl.style.color='#f04747'; statusEl.innerText=t.sso_not_configured; }
        return;
    }

    const redirectUri = `${window.location.origin}/oauth-callback.html`;
    const state       = `${provider}:${_ssoRandB64url(24)}`;

    const _t = _i18n[_currentLang] || _i18n.en;
    if (statusEl) { statusEl.style.color='#a1a5b6'; statusEl.innerText=_t.opening_sso; }

    let authUrl;
    if (provider === 'apple') {
        // Apple hybrid flow: returns id_token in URL fragment, no code exchange needed.
        const nonce = _ssoRandB64url(16);
        sessionStorage.setItem('sso_nonce_apple', nonce);
        const p = new URLSearchParams({
            response_type: 'code id_token',
            response_mode: 'fragment',
            client_id: cfg.client_id,
            redirect_uri: redirectUri,
            scope: cfg.scope,
            state,
            nonce,
        });
        authUrl = `${cfg.auth_url}?${p}`;
    } else {
        // Google / Microsoft: PKCE authorization-code flow.
        const verifier   = _ssoRandB64url(32);
        const challenge  = await _pkceChallenge(verifier);
        sessionStorage.setItem(`sso_cv_${provider}`, verifier);
        const p = new URLSearchParams({
            response_type: 'code',
            client_id: cfg.client_id,
            redirect_uri: redirectUri,
            scope: cfg.scope,
            state,
            code_challenge: challenge,
            code_challenge_method: 'S256',
        });
        authUrl = `${cfg.auth_url}?${p}`;
    }

    sessionStorage.setItem('sso_state', state);
    const popup = window.open(authUrl, 'tenshi_sso', 'width=520,height=620,popup=yes');

    function onMessage(e) {
        if (e.data?.type !== 'sso_callback') return;
        window.removeEventListener('message', onMessage);

        const { provider: cbProvider, code, id_token, state: cbState } = e.data;
        if (cbState !== sessionStorage.getItem('sso_state')) {
            const _t2 = _i18n[_currentLang] || _i18n.en;
            if (statusEl) { statusEl.style.color='#f04747'; statusEl.innerText=_t2.sso_state_mismatch; }
            return;
        }

        (async () => {
            let tokens = { id_token };

            if (provider !== 'apple' && code) {
                // Exchange auth code for tokens using PKCE verifier.
                const tokenRes = await fetch(cfg.token_url, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
                    body: new URLSearchParams({
                        grant_type:    'authorization_code',
                        client_id:     cfg.client_id,
                        code,
                        redirect_uri:  redirectUri,
                        code_verifier: sessionStorage.getItem(`sso_cv_${provider}`) || '',
                    }),
                });
                if (!tokenRes.ok) {
                    const _t3 = _i18n[_currentLang] || _i18n.en;
                    if (statusEl) { statusEl.style.color='#f04747'; statusEl.innerText=_t3.sso_token_failed; }
                    return;
                }
                tokens = await tokenRes.json();
            }

            if (statusEl) { statusEl.style.color='#a1a5b6'; statusEl.innerText=(_i18n[_currentLang]||_i18n.en).verifying; }

            const res = await apiRequest('SSO_AUTH', {
                provider,
                id_token:     tokens.id_token || '',
                access_token: tokens.access_token || '',
            });

            if (res.status === 'success') {
                currentUser = res.username;
                isAdmin     = res.is_admin || false;
                localStorage.setItem('tenshi_user', currentUser);
                loadHub();
            } else {
                if (statusEl) { statusEl.style.color='#f04747'; statusEl.innerHTML = res.message || 'SSO login failed.'; }
            }
        })();
    }
    window.addEventListener('message', onMessage);
}

// ── Register (new IDs from v3 HTML) ──────────────────────────
async function registerNew() {
    const u = (document.getElementById('reg-username')?.value || '').trim();
    const p = (document.getElementById('reg-password')?.value || '').trim();
    const e = (document.getElementById('reg-email')?.value || '').trim();
    const cc = document.getElementById('country-code')?.value || '';
    const ph = (document.getElementById('reg-phone')?.value || '').trim();
    const statusEl = document.getElementById('reg-status');

    if (!u || !p) {
        if (statusEl) statusEl.innerText = 'Username and password are required.';
        return;
    }

    const pwd_hash = await simpleHash(p);
    const payload = { username: u, pwd_hash };
    if (e) payload.email = e;
    if (ph) payload.phone = cc + ph;

    if (statusEl) { statusEl.style.color = 'yellow'; statusEl.innerText = 'Creating account…'; }
    const res = await apiRequest('REGISTER', payload);

    if (res.status === 'success') {
        currentUser = u;
        // Show verification panel if server requires it
        document.getElementById('login-box').style.display = 'none';
        const vbox = document.getElementById('verify-box');
        if (vbox) vbox.style.display = 'flex';
    } else {
        if (statusEl) { statusEl.style.color = '#f25f5c'; statusEl.innerHTML = res.message || 'Registration failed.'; }
    }
}

// ── Verify & Login ────────────────────────────────────────────
async function verifyAndLogin() {
    const code = (document.getElementById('verify-code')?.value || '').trim();
    const statusEl = document.getElementById('verify-status');
    if (!code || code.length !== 6) {
        if (statusEl) { statusEl.style.color = '#f25f5c'; statusEl.innerText = 'Enter the 6-digit code.'; }
        return;
    }
    if (statusEl) { statusEl.style.color = 'yellow'; statusEl.innerText = 'Verifying…'; }
    const res = await apiRequest('VERIFY_CODE', { username: currentUser, code });
    if (res.status === 'success') {
        isAdmin = res.is_admin || false;
        loadHub();
    } else {
        if (statusEl) { statusEl.style.color = '#f25f5c'; statusEl.innerHTML = res.message || 'Invalid code.'; }
    }
}

// ── Resend Verification Code ──────────────────────────────────
async function resendCode() {
    const statusEl = document.getElementById('verify-status');
    if (statusEl) { statusEl.style.color = 'yellow'; statusEl.innerText = 'Resending…'; }
    const res = await apiRequest('RESEND_CODE', { username: currentUser });
    if (statusEl) {
        statusEl.style.color = res.status === 'success' ? '#23a559' : '#f25f5c';
        statusEl.innerText = res.message || (res.status === 'success' ? 'Code resent!' : 'Failed to resend.');
    }
}

