// ── Video expand / fullscreen / resize ───────────────────────
function _vcToggleFullscreen(el) {
    const video = el.querySelector('video');
    if (!video || video.style.display === 'none') return;
    // Check if already expanded
    const existing = document.getElementById('vc-video-overlay');
    if (existing) { _vcCloseOverlay(); return; }
    _vcOpenOverlay(video);
}

function _vcOpenOverlay(srcVideo) {
    const isMobile = window.innerWidth <= 600;
    const overlay = document.createElement('div');
    overlay.id = 'vc-video-overlay';
    overlay.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,0.95);display:flex;align-items:center;justify-content:center;flex-direction:column;';
    // Clone video stream into a new video element that fills screen
    const video = document.createElement('video');
    video.autoplay = true;
    video.playsInline = true;
    video.setAttribute('playsinline', '');
    video.setAttribute('webkit-playsinline', '');
    video.muted = srcVideo.muted;
    video.srcObject = srcVideo.srcObject;
    video.style.cssText = `max-width:100vw;max-height:${isMobile?'85vh':'92vh'};width:100%;height:auto;object-fit:contain;border-radius:0;border:none;transition:max-width 0.15s,max-height 0.15s;flex:1;`;
    // Size slider + controls
    const controls = document.createElement('div');
    controls.style.cssText = `position:fixed;bottom:0;left:0;right:0;display:flex;align-items:center;gap:${isMobile?'8px':'12px'};background:rgba(0,0,0,0.85);padding:${isMobile?'14px 16px':'10px 20px'};padding-bottom:${isMobile?'calc(14px + env(safe-area-inset-bottom))':'10px'};border-top:1px solid rgba(255,255,255,0.08);z-index:100000;justify-content:center;flex-wrap:wrap;`;
    controls.innerHTML = `
        <div style="display:flex;align-items:center;gap:8px;flex:1;min-width:${isMobile?'100%':'0'};">
            <span style="color:var(--text-muted);font-size:${isMobile?'13px':'12px'};white-space:nowrap;">🔍 Size</span>
            <input type="range" min="20" max="100" value="100" style="flex:1;accent-color:var(--accent-blue);height:${isMobile?'28px':'auto'};"
                oninput="document.querySelector('#vc-video-overlay video').style.maxWidth=this.value+'vw';document.querySelector('#vc-video-overlay video').style.maxHeight=(this.value*${isMobile?0.85:0.92}).toFixed(0)+'vh';document.getElementById('vc-size-label').textContent=this.value+'%'">
            <span id="vc-size-label" style="color:white;font-size:${isMobile?'14px':'12px'};min-width:36px;text-align:center;">100%</span>
        </div>
        <div style="display:flex;gap:8px;">
            <button onclick="_vcGoFullscreen()" style="background:rgba(255,255,255,0.1);color:white;border:none;padding:${isMobile?'10px 16px':'6px 12px'};border-radius:8px;cursor:pointer;font-size:${isMobile?'14px':'12px'};white-space:nowrap;">⛶ Fullscreen</button>
            <button onclick="_vcCloseOverlay()" style="background:rgba(237,66,69,0.2);color:#ed4245;border:none;padding:${isMobile?'10px 16px':'6px 12px'};border-radius:8px;cursor:pointer;font-size:${isMobile?'14px':'12px'};white-space:nowrap;">✕ Close</button>
        </div>
    `;
    // Close on clicking the dark background (not video or controls)
    overlay.addEventListener('click', (e) => { if (e.target === overlay) _vcCloseOverlay(); });
    // ESC to close
    overlay._escHandler = (e) => { if (e.key === 'Escape') _vcCloseOverlay(); };
    document.addEventListener('keydown', overlay._escHandler);
    // Double-tap on mobile to toggle fullscreen
    if (isMobile) {
        let lastTap = 0;
        video.addEventListener('touchend', (e) => {
            const now = Date.now();
            if (now - lastTap < 300) { _vcGoFullscreen(); e.preventDefault(); }
            lastTap = now;
        });
    }
    overlay.appendChild(video);
    overlay.appendChild(controls);
    document.body.appendChild(overlay);
    video.play().catch(() => {});
}

function _vcGoFullscreen() {
    const overlay = document.getElementById('vc-video-overlay');
    if (!overlay) return;
    const video = overlay.querySelector('video');
    if (!video) return;
    // iOS Safari: use webkitEnterFullscreen on video element
    if (video.webkitEnterFullscreen) {
        try { video.webkitEnterFullscreen(); return; } catch {}
    }
    // Standard fullscreen API
    if (video.requestFullscreen) {
        video.requestFullscreen().catch(() => {
            overlay.requestFullscreen().catch(() => {});
        });
    } else if (video.webkitRequestFullscreen) {
        video.webkitRequestFullscreen();
    }
}

function _vcCloseOverlay() {
    const overlay = document.getElementById('vc-video-overlay');
    if (!overlay) return;
    if (overlay._escHandler) document.removeEventListener('keydown', overlay._escHandler);
    // Exit browser fullscreen if active
    if (document.fullscreenElement) document.exitFullscreen().catch(() => {});
    else if (document.webkitFullscreenElement) document.webkitExitFullscreen();
    const video = overlay.querySelector('video');
    if (video) { video.srcObject = null; }
    overlay.remove();
}

function _toggleScreenExpand(boxId) {
    const box = document.getElementById(boxId);
    if (!box) return;
    const isExpanded = box.dataset.expanded === 'true';
    if (isExpanded) {
        box.style.width = '240px';
        box.style.height = '135px';
        box.dataset.expanded = 'false';
    } else {
        box.style.width = '640px';
        box.style.height = '360px';
        box.dataset.expanded = 'false';
        box.dataset.expanded = 'true';
    }
}

// ── Camera toggle ─────────────────────────────────────────────
async function toggleCamera() {
    if (!localMediaStream) return;
    let tracks = localMediaStream.getVideoTracks();

    if (!tracks.length) {
        // No video tracks (audio-only fallback) — request camera now
        try {
            // First try saved device, then fall back to any camera
            let videoConstraint = _getMediaConstraints(true).video;
            let camStream;
            try {
                camStream = await navigator.mediaDevices.getUserMedia({ video: videoConstraint });
            } catch {
                // Saved device failed — try any camera
                camStream = await navigator.mediaDevices.getUserMedia({ video: true });
            }
            const camTrack = camStream.getVideoTracks()[0];
            if (!camTrack) return;
            localMediaStream.addTrack(camTrack);
            // Add to DM call peer connection
            if (_peerConnection) {
                _peerConnection.addTrack(camTrack, localMediaStream);
                if (_peerConnection.signalingState === 'stable') {
                    const offer = await _peerConnection.createOffer();
                    await _peerConnection.setLocalDescription(offer);
                    await apiRequest('CALL_SIGNAL', {
                        target: _activeCall.target,
                        signal_type: 'offer',
                        data: { type: offer.type, sdp: offer.sdp }
                    });
                }
            }
            // Add to hub voice channel peer connections + renegotiate
            if (_vcPeerConnections) {
                for (const [user, entry] of Object.entries(_vcPeerConnections)) {
                    if (entry.pc) {
                        try {
                            entry.pc.addTrack(camTrack, localMediaStream);
                            // Renegotiate so remote receives the new video track
                            if (entry.pc.signalingState === 'stable') {
                                const offer = await entry.pc.createOffer();
                                await entry.pc.setLocalDescription(offer);
                                await apiRequest('VC_SIGNAL', { target: user, signal_type: 'offer', data: { type: offer.type, sdp: offer.sdp } });
                            }
                        } catch(e) { console.warn('[VC] addTrack/renegotiate failed for', user, e); }
                    }
                }
            }
            const videoEl = document.getElementById('local-video');
            if (videoEl) { videoEl.srcObject = localMediaStream; videoEl.style.display = 'block'; }
            const btn = document.getElementById('voice-cam-btn');
            if (btn) btn.textContent = '📷 Camera';
            // Hide avatar overlay (works for both DM calls and hub voice)
            const avatar = document.getElementById('call-avatar-me') || document.getElementById('vc-avatar-me');
            if (avatar) avatar.style.display = 'none';
            return;
        } catch(e) {
            console.warn('Camera access denied:', e);
            return;
        }
    }

    const enabled = !tracks[0].enabled;
    tracks.forEach(t => t.enabled = enabled);
    const btn = document.getElementById('voice-cam-btn');
    if (btn) btn.textContent = enabled ? '📷 Camera' : '📵 Camera Off';
    // Show/hide video element and avatar (works for both DM and hub voice)
    const videoEl = document.getElementById('local-video');
    if (videoEl) {
        videoEl.style.display = enabled ? 'block' : 'none';
        if (enabled) videoEl.srcObject = localMediaStream;
    }
    const avatar = document.getElementById('call-avatar-me') || document.getElementById('vc-avatar-me');
    if (avatar) avatar.style.display = enabled ? 'none' : 'flex';
}

// ── Media consent state ──────────────────────────────────────
let _pendingMediaFile = null;
let _pendingMediaTarget = null;

async function _checkMediaConsent(target, file) {
    const isServer = target.startsWith('srv:');
    if (isServer) return true; // Server scanning handled server-side
    if (target === 'AI' || target.includes('@')) return true; // AI chat and email — no consent needed
    // Check consent with server
    const res = await apiRequest('CHECK_MEDIA_CONSENT', { target_id: target });
    if (res.status === 'success') {
        if (!res.consent_required) return true; // Both verified or both already accepted
        if (res.sender_accepted) return true; // We already accepted, waiting on them
        // Show modal
        _pendingMediaFile = file;
        _pendingMediaTarget = target;
        const modal = document.getElementById('media-consent-modal');
        if (modal) modal.style.display = 'flex';
        return false; // Block upload until accepted
    }
    return true; // Fallback: allow
}

async function _acceptMediaConsent() {
    const modal = document.getElementById('media-consent-modal');
    const status = document.getElementById('media-consent-status');
    const res = await apiRequest('ACCEPT_MEDIA_CONSENT', { target_id: _pendingMediaTarget });
    if (res.status === 'success') {
        if (modal) modal.style.display = 'none';
        if (res.both_accepted) {
            // Both accepted — proceed with upload by re-triggering
            if (_pendingMediaFile) {
                _processImageUpload(_pendingMediaFile);
            }
        } else {
            if (status) { status.style.color = '#f0b132'; status.textContent = 'Waiting for the other user to accept...'; }
            setTimeout(() => { if (modal) modal.style.display = 'none'; }, 2000);
            showGlobalNotification('Media consent sent. The other user needs to accept too.');
        }
    }
    _pendingMediaFile = null;
    _pendingMediaTarget = null;
}

async function _declineMediaConsent() {
    await apiRequest('DECLINE_MEDIA_CONSENT', { target_id: _pendingMediaTarget });
    const modal = document.getElementById('media-consent-modal');
    if (modal) modal.style.display = 'none';
    _pendingMediaFile = null;
    _pendingMediaTarget = null;
    showGlobalNotification('Media declined. This conversation is text-only.');
}

// ── Process image upload (shared between direct upload and post-consent) ──
function _processImageUpload(file) {
    if (!file || !currentTarget) return;
    const img = new Image();
        img.onload = async function() {
            const canvas = document.createElement('canvas');
            const maxW = 800, maxH = 600;
            let w = img.width, h = img.height;
            if (w > maxW) { h = h * maxW / w; w = maxW; }
            if (h > maxH) { w = w * maxH / h; h = maxH; }
            canvas.width = w;
            canvas.height = h;
            canvas.getContext('2d').drawImage(img, 0, 0, w, h);
            const dataUrl = canvas.toDataURL('image/jpeg', 0.75);
            // Send as a special image message
            const content = `[IMG]${dataUrl}[/IMG]`;
            const isServer = currentTarget.startsWith('srv:');
            const isDM = !currentTarget.includes('@') && !isServer && currentTarget !== 'AI';
            let encContent = content;
            if (isDM) {
                const enc = await fernetEncrypt(content, currentTarget);
                if (enc) encContent = enc;
            }
            // Extract raw base64 for server-side minor safety scan (DMs only)
            const rawB64 = isDM ? dataUrl.replace(/^data:image\/[^;]+;base64,/, '') : '';
            let res;
            if (isServer) {
                const parts = currentTarget.split(':');
                res = await apiRequest('SEND_MESSAGE', { target_type: 'server', target_id: parts[1], channel: parts.slice(2).join(':'), content: encContent });
            } else {
                const payload = {
                    target_type: currentTarget.includes('@') ? 'email' : 'dm', target_id: currentTarget,
                    content: encContent, is_temp: false,
                    timestamp: new Date().toISOString()
                };
                if (rawB64) payload.image_b64 = rawB64;
                res = await apiRequest('SEND_MESSAGE', payload);
            }
            if (res.status === 'success') {
                const chatbox = document.getElementById(isServer ? 'server-chat-messages' : 'message-container');
                const empty = chatbox?.querySelector('.ch-empty');
                if (empty) empty.remove();
                const m = document.createElement('div');
                m.className = 'msg self';
                m.innerHTML = `<img src="${dataUrl}" style="max-width:300px;max-height:200px;border-radius:8px;cursor:pointer;" onclick="window.open(this.src)">`;
                if (chatbox) { chatbox.appendChild(m); chatbox.scrollTop = chatbox.scrollHeight; }
            } else if (res.message) {
                alert(res.message);
            }
        };
        img.src = URL.createObjectURL(file);
}

function uploadChatImage() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = async function() {
        const file = input.files[0];
        if (!file || !currentTarget) return;
        if (file.size > 12 * 1024 * 1024) { alert('File must be under 12MB'); return; }
        const allowed = await _checkMediaConsent(currentTarget, file);
        if (!allowed) return;
        _processImageUpload(file);
    };
    input.click();
}

// ── Clipboard Paste: images & videos into chat ────────────────
function _initPasteHandler() {
    document.addEventListener('paste', async (e) => {
        if (!currentTarget) return;
        const items = e.clipboardData?.items;
        if (!items) return;
        for (const item of items) {
            // Handle pasted images
            if (item.type.startsWith('image/')) {
                e.preventDefault();
                const file = item.getAsFile();
                if (!file || file.size > 12 * 1024 * 1024) { alert('Image must be under 12MB'); return; }
                const img = new Image();
                img.onload = async function() {
                    const canvas = document.createElement('canvas');
                    const maxW = 800, maxH = 600;
                    let w = img.width, h = img.height;
                    if (w > maxW) { h = h * maxW / w; w = maxW; }
                    if (h > maxH) { w = w * maxH / h; h = maxH; }
                    canvas.width = w; canvas.height = h;
                    canvas.getContext('2d').drawImage(img, 0, 0, w, h);
                    const dataUrl = canvas.toDataURL('image/jpeg', 0.75);
                    const content = `[IMG]${dataUrl}[/IMG]`;
                    const isServer = currentTarget.startsWith('srv:');
                    const isDM = !currentTarget.includes('@') && !isServer && currentTarget !== 'AI';
                    let encContent = content;
                    if (isDM) {
                        const enc = await fernetEncrypt(content, currentTarget);
                        if (enc) encContent = enc;
                    }
                    const rawB64 = isDM ? dataUrl.replace(/^data:image\/[^;]+;base64,/, '') : '';
                    let res;
                    if (isServer) {
                        const parts = currentTarget.split(':');
                        res = await apiRequest('SEND_MESSAGE', { target_type: 'server', target_id: parts[1], channel: parts.slice(2).join(':'), content: encContent });
                    } else {
                        const payload = {
                            target_type: currentTarget.includes('@') ? 'email' : 'dm', target_id: currentTarget,
                            content: encContent, is_temp: false,
                            timestamp: new Date().toISOString()
                        };
                        if (rawB64) payload.image_b64 = rawB64;
                        res = await apiRequest('SEND_MESSAGE', payload);
                    }
                    if (res.status === 'success') {
                        const mc = document.getElementById(isServer ? 'server-chat-messages' : 'message-container');
                        const empty = mc?.querySelector('.ch-empty'); if (empty) empty.remove();
                        const m = document.createElement('div');
                        m.className = 'msg self';
                        m.innerHTML = `<img src="${dataUrl}" style="max-width:300px;max-height:200px;border-radius:8px;cursor:pointer;" onclick="window.open(this.src)">`;
                        if (mc) { mc.appendChild(m); mc.scrollTop = mc.scrollHeight; }
                    } else if (res.message) {
                        alert(res.message);
                    }
                };
                img.src = URL.createObjectURL(file);
                return;
            }
            // Handle pasted videos
            if (item.type.startsWith('video/')) {
                e.preventDefault();
                const file = item.getAsFile();
                if (!file || file.size > 12 * 1024 * 1024) { alert('Video must be under 12MB'); return; }
                const reader = new FileReader();
                reader.onload = async function(ev) {
                    const dataUrl = ev.target.result;
                    const content = `[VID]${dataUrl}[/VID]`;
                    const isServer = currentTarget.startsWith('srv:');
                    const isDM = !currentTarget.includes('@') && !isServer && currentTarget !== 'AI';
                    let encContent = content;
                    if (isDM) {
                        const enc = await fernetEncrypt(content, currentTarget);
                        if (enc) encContent = enc;
                    }
                    // For video DMs, extract a frame for scanning (video can't be scanned directly)
                    let res;
                    if (isServer) {
                        const parts = currentTarget.split(':');
                        res = await apiRequest('SEND_MESSAGE', { target_type: 'server', target_id: parts[1], channel: parts.slice(2).join(':'), content: encContent });
                    } else {
                        const payload = {
                            target_type: currentTarget.includes('@') ? 'email' : 'dm', target_id: currentTarget,
                            content: encContent, is_temp: false,
                            timestamp: new Date().toISOString()
                        };
                        res = await apiRequest('SEND_MESSAGE', payload);
                    }
                    if (res.status === 'success') {
                        const mc = document.getElementById(isServer ? 'server-chat-messages' : 'message-container');
                        const empty = mc?.querySelector('.ch-empty'); if (empty) empty.remove();
                        const m = document.createElement('div');
                        m.className = 'msg self';
                        m.innerHTML = `<video src="${dataUrl}" controls playsinline style="max-width:300px;max-height:200px;border-radius:8px;"></video>`;
                        if (mc) { mc.appendChild(m); mc.scrollTop = mc.scrollHeight; }
                    } else if (res.message) {
                        alert(res.message);
                    }
                };
                reader.readAsDataURL(file);
                return;
            }
        }
    });
}
// Init paste handler on load
document.addEventListener('DOMContentLoaded', () => _initPasteHandler(), { once: true });

// ── File Upload (via SendGB — free file hosting, no server storage used) ──
async function uploadFile(input) {
    const file = input ? input.files[0] : null;
    if (input) input.value = '';
    // Redirect to SendGB for all file sharing
    _openSendGB();
}

function _openSendGB() {
    const link = 'https://www.sendgb.com/';
    const msg = 'Tenshi uses SendGB for free file sharing — up to 5GB per transfer!\n\n1. Upload your file on SendGB\n2. Copy the share link\n3. Paste the link in chat\n\nOpen SendGB now?';
    if (confirm(msg)) window.open(link, '_blank', 'noopener');
}

function renderFileMessage(content) {
    // Legacy [FILE:...] format — render as plain link
    const m = content.match(/^\[FILE:([^:]+):([^:]+):(.{0,20})/);
    if (!m) return null;
    const name = decodeURIComponent(m[1]);
    return `<span style="color:var(--text-muted);font-size:13px;">📎 ${name} <em>(legacy upload — file data not available)</em></span>`;
}

// ── Link Preview ──────────────────────────────────────────────
function renderLinkPreview(text) {
    const urlRe = /(https?:\/\/[^\s<>"]+)/g;
    return text.replace(urlRe, url => {
        // SECURITY: Use _escAttr to prevent XSS via crafted URLs in onclick
        const safeUrl = _escAttr(url);
        const display = url.length > 60 ? _escAttr(url.slice(0,60)) + '…' : safeUrl;
        return `<span>${safeUrl}</span><div class="link-preview" data-href="${safeUrl}" onclick="window.open(this.dataset.href,'_blank')">🔗 <span style="color:#7289da;">${display}</span></div>`;
    });
}

// ── Message Search ────────────────────────────────────────────
function toggleMsgSearch() {
    const bar = document.getElementById('msg-search-bar');
    if (!bar) return;
    const open = bar.style.display !== 'none';
    bar.style.display = open ? 'none' : 'block';
    if (!open) document.getElementById('msg-search-input')?.focus();
}

async function searchMessages(query) {
    if (!query.trim()) { document.getElementById('msg-search-results').innerHTML = ''; return; }
    const res = await apiRequest('SEARCH_MESSAGES', { query });
    const el = document.getElementById('msg-search-results');
    if (!el) return;
    if (res.status !== 'success' || !res.results.length) {
        el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:4px 0;">No results</div>';
        return;
    }
    el.innerHTML = res.results.map(r => `
        <div style="padding:6px 8px;border-radius:6px;background:rgba(255,255,255,0.05);margin-bottom:4px;cursor:pointer;" onclick="openChat('${_escAttr(r.sender)}')">
            <span style="color:var(--accent-blue);font-size:12px;font-weight:600;">${_escAttr(tag(r.sender))}</span>
            <span style="color:var(--text-muted);font-size:11px;margin-left:6px;">${new Date(r.timestamp*1000).toLocaleTimeString()}</span>
            <div style="color:white;font-size:13px;margin-top:2px;">${_escAttr((r.content||'').slice(0,80))}${r.content.length>80?'…':''}</div>
        </div>`).join('');
}

// ── Command Palette ───────────────────────────────────────────
function toggleCommandPalette() {
    const el = document.getElementById('command-palette');
    if (!el) return;
    const open = el.style.display !== 'none';
    el.style.display = open ? 'none' : 'flex';
    if (!open) { document.getElementById('cmd-input').value = ''; handleCmdInput(''); document.getElementById('cmd-input').focus(); }
}
function closeCommandPalette() {
    const el = document.getElementById('command-palette');
    if (el) el.style.display = 'none';
}
function handleCmdInput(q) {
    const results = document.getElementById('cmd-results');
    if (!results) return;
    const query = q.toLowerCase();
    const cmds = [
        { label: '💬 Direct Messages', action: `loadFriendsView();closeCommandPalette();` },
        { label: '⚙️ Open Settings', action: `document.getElementById('settings-overlay').style.display='flex';closeCommandPalette();` },
        { label: '🔇 Toggle Mute', action: `toggleMute();closeCommandPalette();` },
        { label: '🎧 Toggle Deafen', action: `toggleDeafen();closeCommandPalette();` },
        { label: '🖥️ Screen Share', action: `toggleScreenShare();closeCommandPalette();` },
        { label: '📋 Compact Mode', action: `toggleCompactMode();closeCommandPalette();` },
        { label: '👥 New Group Chat', action: `document.getElementById('group-chat-modal').style.display='flex';closeCommandPalette();` },
        { label: '🔍 Search Messages', action: `toggleMsgSearch();closeCommandPalette();` },
        { label: '🚪 Log Out', action: `closeCommandPalette();doLogout();` },
    ];
    const filtered = query ? cmds.filter(c => c.label.toLowerCase().includes(query)) : cmds;
    results.innerHTML = filtered.map(c =>
        `<div class="cmd-item" onclick="${c.action}">${c.label}</div>`
    ).join('') || '<div style="padding:12px 20px;color:var(--text-muted);font-size:13px;">No commands found</div>';
}
document.addEventListener('keydown', e => {
    if ((e.ctrlKey || e.metaKey) && e.key === 'k') { e.preventDefault(); toggleCommandPalette(); }
    if (e.key === 'Escape') {
        closeCommandPalette();
        const srvModal = document.getElementById('server-settings-modal');
        if (srvModal && srvModal.style.display === 'flex') srvModal.style.display = 'none';
        const settingsOvl = document.getElementById('settings-overlay');
        if (settingsOvl && settingsOvl.style.display === 'block') settingsOvl.style.display = 'none';
        const gcModal = document.getElementById('group-chat-modal');
        if (gcModal && gcModal.style.display === 'flex') gcModal.style.display = 'none';
    }
});

