let _isCompact = localStorage.getItem('tenshi_compact') === '1';
function toggleCompactMode() {
    _isCompact = !_isCompact;
    localStorage.setItem('tenshi_compact', _isCompact ? '1' : '0');
    document.body.classList.toggle('compact', _isCompact);
}
if (_isCompact) document.body.classList.add('compact');

