// ── Create Hub ──────────────────────────────────────────────
function previewServerImg(input, previewId) {
    const file = input.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = e => {
        const el = document.getElementById(previewId);
        if (el) {
            el.innerHTML = '';
            el.style.backgroundImage = `url(${e.target.result})`;
            el.style.backgroundSize = 'cover';
            el.style.backgroundPosition = 'center';
        }
    };
    reader.readAsDataURL(file);
}

function _fileToBase64(inputId, maxW = 256, maxH = 256) {
    return new Promise(resolve => {
        const input = document.getElementById(inputId);
        if (!input || !input.files[0]) { resolve(''); return; }
        const img = new Image();
        img.onload = () => {
            const canvas = document.createElement('canvas');
            let w = img.width, h = img.height;
            // For icons: crop to square
            if (maxW === maxH) {
                const s = Math.min(w, h);
                const sx = (w - s) / 2, sy = (h - s) / 2;
                canvas.width = maxW; canvas.height = maxH;
                canvas.getContext('2d').drawImage(img, sx, sy, s, s, 0, 0, maxW, maxH);
            } else {
                // For banners: cover fit
                if (w > maxW) { h = h * maxW / w; w = maxW; }
                if (h > maxH) { w = w * maxH / h; h = maxH; }
                canvas.width = maxW; canvas.height = maxH;
                const scale = Math.max(maxW / img.width, maxH / img.height);
                const dw = img.width * scale, dh = img.height * scale;
                canvas.getContext('2d').drawImage(img, (maxW - dw) / 2, (maxH - dh) / 2, dw, dh);
            }
            resolve(canvas.toDataURL('image/jpeg', 0.6));
        };
        img.onerror = () => resolve('');
        img.src = URL.createObjectURL(input.files[0]);
    });
}

async function createServer() {
    const name = document.getElementById('cs-name')?.value.trim();
    const invite = document.getElementById('cs-invite')?.value.trim() || '';
    const statusEl = document.getElementById('cs-status');
    if (!name) { if (statusEl) statusEl.innerText = 'Please enter a server name.'; return; }

    if (statusEl) { statusEl.style.color = 'yellow'; statusEl.innerText = 'Creating server...'; }

    const serverImage = await _fileToBase64('cs-image-input', 64, 64);
    const serverBanner = await _fileToBase64('cs-banner-input', 400, 130);

    // Check for template
    const templateIdx = document.getElementById('cs-name').dataset.templateIdx;
    let templateChannels = null, templateRoles = null;
    if (templateIdx !== undefined && SERVER_TEMPLATES[templateIdx]) {
        const t = SERVER_TEMPLATES[templateIdx];
        templateChannels = t.channels;
        templateRoles = t.roles;
    }

    // Hub safety settings (permanent)
    const nsfwAllowed = document.getElementById('cs-nsfw-allowed')?.checked || false;
    const bullyPrevention = document.getElementById('cs-bully-prevention')?.checked || false;
    const aiModeration = document.getElementById('cs-ai-moderation')?.checked || false;

    // Warn about permanent settings
    let warnings = [];
    if (nsfwAllowed) warnings.push('NSFW content will be ALLOWED');
    if (!bullyPrevention) warnings.push('Bully prevention will be OFF');
    if (!aiModeration) warnings.push('AI moderation will be OFF (only reported content scanned)');
    if (warnings.length > 0) {
        if (!confirm(`⚠️ These settings are PERMANENT and cannot be changed after creation:\n\n• ${warnings.join('\n• ')}\n\nAre you sure you want to create this hub?`)) return;
    }

    const res = await apiRequest('CREATE_SERVER', {
        server_name: name,
        server_image: serverImage,
        server_banner: serverBanner,
        invite_link: invite,
        template_channels: templateChannels,
        template_roles: templateRoles,
        nsfw_allowed: nsfwAllowed,
        bully_prevention: bullyPrevention,
        ai_moderation: aiModeration
    });

    if (res.status === 'success') {
        document.getElementById('create-server-modal').style.display = 'none';
        // Reset form
        document.getElementById('cs-name').value = '';
        document.getElementById('cs-name').dataset.templateIdx = '';
        document.getElementById('cs-invite').value = '';
        const imgPrev = document.getElementById('cs-image-preview');
        if (imgPrev) { imgPrev.innerHTML = '<span style="color:#5865F2;font-size:28px;">📷</span>'; imgPrev.style.backgroundImage = ''; }
        const banPrev = document.getElementById('cs-banner-preview');
        if (banPrev) { banPrev.innerHTML = '<span style="color:#5865F2;font-size:13px;">🖼️ Upload Banner</span>'; banPrev.style.backgroundImage = ''; }
        if (statusEl) statusEl.innerText = '';
        _cachedJoinedServers = null; // Clear cache so new hub appears
        _cachedJoinedServersTime = 0;
        fetchServersJoined();
        loadMobileHome();
    } else {
        if (statusEl) { statusEl.style.color = '#f04747'; statusEl.textContent = res.message || 'Failed to create server.'; }
    }
}

async function createGroupChat() {
    const name = document.getElementById('gc-name')?.value.trim() || 'Group Chat';
    const raw = document.getElementById('gc-members')?.value || '';
    const members = raw.split(',').map(m => m.trim()).filter(Boolean);
    const statusEl = document.getElementById('gc-status');
    if (!members.length) { if (statusEl) statusEl.innerText = 'Add at least one member.'; return; }
    const res = await apiRequest('CREATE_GROUP_CHAT', { group_name: name, members });
    if (res.status === 'success') {
        document.getElementById('group-chat-modal').style.display = 'none';
        fetchServersJoined(); // Refresh server list to show new group
    } else {
        if (statusEl) statusEl.innerText = res.message || 'Failed to create group.';
    }
}

