                    <div style="color:var(--text-muted);font-size:10px;margin-top:3px;">${(maxBytes - usedBytes) > 0 ? ((maxBytes - usedBytes) / (1024*1024)).toFixed(1) + ' MB remaining' : 'Storage full!'}</div>
