                            <button onclick="apiRequest('DELETE_HUB_EMOJI',{server_id:'${_srvSettingsId}',name:'${_escAttr(e.name)}'}).then(()=>showSrvTab('emojis'))" style="background:rgba(237,66,69,0.2);color:#ed4245;border:none;padding:2px 6px;border-radius:4px;cursor:pointer;font-size:9px;margin-top:4px;">Delete</button>
