// ── User Context Menu (right-click or long-press on any username) ──
// Global long-press support for mobile — triggers context menu on hold
document.addEventListener('DOMContentLoaded', () => {
    let _lpTimer = null;
    let _lpTriggered = false;
    document.addEventListener('touchstart', (e) => {
        _lpTriggered = false;
        // Don't intercept sliders, inputs, buttons, selects, textareas
        const tag = e.target.tagName;
        if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT' || tag === 'BUTTON' || e.target.closest('button') || e.target.closest('label')) return;
        const el = e.target.closest('[oncontextmenu]') || e.target.closest('[data-vc-user]') || e.target.closest('#vc-box-me') || e.target.closest('.msg[data-sender]') || e.target.closest('.email-list-item');
        if (!el) return;
        _lpTimer = setTimeout(() => {
            _lpTriggered = true;
            e.preventDefault();
            const touch = e.touches[0];
            const fakeEvent = { preventDefault:()=>{}, stopPropagation:()=>{}, stopImmediatePropagation:()=>{}, clientX: touch.clientX, clientY: touch.clientY, target: e.target };
            // VC user box
            const vcUser = el.closest('[data-vc-user]');
            const vcMe = el.closest('#vc-box-me') || el.closest('#vc-participant-me');
            if (vcUser) {
                _showVcUserMenu(fakeEvent, vcUser.dataset.vcUser, vcUser.dataset.vcUser);
            } else if (vcMe) {
                _showVcUserMenu(fakeEvent, currentUser, currentUser);
            } else if (el.classList.contains('msg') && el.dataset.sender) {
                // Message long-press — show message context menu
                const msgId = el.dataset.msgId || '';
                const sender = el.dataset.sender;
                if (msgId) {
                    _showMessageContextMenu(fakeEvent, msgId, sender, sender === currentUser);
                } else {
                    showUserContextMenu(fakeEvent, sender);
                }
            } else {
                // Try to extract username from oncontextmenu attribute
                const ctx = el.getAttribute('oncontextmenu') || '';
                const m = ctx.match(/showUserContextMenu\(event,'([^']+)'\)/);
                if (m) showUserContextMenu(fakeEvent, m[1]);
                const m2 = ctx.match(/_showVcUserMenu\(event,'([^']+)'/);
                if (m2) _showVcUserMenu(fakeEvent, m2[1], m2[1]);
            }
        }, 500); // 500ms hold = long press
    }, { passive: false });
    document.addEventListener('touchend', () => { clearTimeout(_lpTimer); });
    document.addEventListener('touchmove', () => { clearTimeout(_lpTimer); });
});

function showUserContextMenu(event, targetUser) {
    if (event) { event.preventDefault(); event.stopPropagation(); }
    document.querySelector('.user-ctx-menu')?.remove();

    const isSelf = targetUser === currentUser;
    const serverId = currentManagingServer?.id;
    // Check if this user is actually a friend — check sidebar AND cached friend list
    const friendEls = document.querySelectorAll('.channel-item[onclick*="openChat"]');
    let isFriend = false;
    friendEls.forEach(el => { if (el.getAttribute('onclick')?.includes(targetUser)) isFriend = true; });
    // Also check the friends list rendered on the page
    if (!isFriend) {
        document.querySelectorAll('[onclick*="openChat"]').forEach(el => { if (el.getAttribute('onclick')?.includes("'" + targetUser + "'")) isFriend = true; });
    }
    // Also check the friend online status cache
    if (!isFriend && typeof _friendOnlineStatus !== 'undefined' && _friendOnlineStatus[targetUser] !== undefined) isFriend = true;
    // Check if we're currently in a DM with this user
    const inDMWithUser = currentTarget === targetUser;

    const isMobile = window.innerWidth <= 600;
    const menu = document.createElement('div');
    menu.className = 'user-ctx-menu';

    if (isMobile) {
        menu.style.cssText = 'position:fixed;bottom:0;left:0;right:0;z-index:9999;background:var(--panel-bg,#1e1f22);border-radius:16px 16px 0 0;padding:6px 0;padding-bottom:calc(8px + env(safe-area-inset-bottom));box-shadow:0 -8px 32px rgba(0,0,0,0.6);max-height:70vh;overflow-y:auto;-webkit-overflow-scrolling:touch;';
    } else {
        menu.style.cssText = 'position:fixed;z-index:500;background:var(--panel-bg,#1e1f22);border:1px solid var(--glass-border);border-radius:10px;padding:6px 0;min-width:220px;box-shadow:0 8px 32px rgba(0,0,0,0.6);max-height:calc(100vh - 20px);overflow-y:auto;';
        let x = event.clientX, y = event.clientY;
        if (x + 230 > window.innerWidth) x = window.innerWidth - 240;
        if (y + 400 > window.innerHeight) y = Math.max(10, window.innerHeight - 410);
        menu.style.left = x + 'px';
        menu.style.top = y + 'px';
    }

    const safe = _escAttr(targetUser);
    const divider = '<div style="border-top:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>';

    let html = `
        <div style="padding:10px 14px;display:flex;align-items:center;gap:10px;border-bottom:1px solid rgba(255,255,255,0.06);margin-bottom:4px;">
            <div style="width:32px;height:32px;border-radius:50%;background:var(--accent-blue);display:flex;align-items:center;justify-content:center;font-weight:bold;color:white;font-size:14px;">${targetUser[0].toUpperCase()}</div>
            <div>
                <div style="color:white;font-weight:bold;font-size:14px;">${safe}</div>
                <div style="color:var(--text-muted);font-size:11px;">${isFriend ? '✓ Friend' : 'User'}</div>
            </div>
        </div>`;

    if (!isSelf) {
        // Always show message + profile
        html += `<div class="ctx-item" onclick="openChat('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">💬 Message</div>`;
        html += `<div class="ctx-item" onclick="viewUserProfile('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">👤 View Profile</div>`;

        // Call buttons — only if friend or already in DM with them
        if (isFriend || inDMWithUser) {
            html += `<div class="ctx-item" onclick="openChat('${safe}');setTimeout(()=>startDMCall(false),300);this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">📞 Voice Call</div>`;
            html += `<div class="ctx-item" onclick="openChat('${safe}');setTimeout(()=>startDMCall(true),300);this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">📹 Video Call</div>`;
        }

        html += divider;

        // Friend actions — show appropriate one
        if (isFriend) {
            html += `<div class="ctx-item" onclick="removeFriend('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">➖ Remove Friend</div>`;
        } else {
            html += `<div class="ctx-item" onclick="apiRequest('ADD_FRIEND',{target:'${safe}'}).then(r=>alert(r.message||'Done'));this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">➕ Add Friend</div>`;
        }

        // Server-specific actions — only when viewing a server
        if (serverId) {
            html += divider;
            html += `<div style="padding:4px 14px;font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px;">Server</div>`;
            const isOwner = currentManagingServer?.owner === currentUser;
            if (isOwner || isAdmin) {
                html += `<div class="ctx-item" onclick="kickUser('${safe}','${serverId}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">👢 Kick</div>`;
                html += `<div class="ctx-item" style="color:#ed4245;" onclick="showBanDialog('${safe}','${serverId}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">🔨 Ban</div>`;
                html += `<div class="ctx-item" onclick="muteUserInServer('${safe}','${serverId}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">🔇 Mute</div>`;
                html += `<div class="ctx-item" onclick="assignRolePrompt('${safe}','${serverId}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">🏷️ Assign Role</div>`;
            }
        }

        // Admin actions — only if current user is admin
        if (isAdmin) {
            html += divider;
            html += `<div style="padding:4px 14px;font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px;">Admin</div>`;
            html += `<div class="ctx-item" onclick="adminBan('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">🔨 Global Ban</div>`;
            html += `<div class="ctx-item" onclick="adminWipe('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();" style="color:#ed4245;">⚠ Wipe Account</div>`;
        }

        html += divider;
        html += `<div class="ctx-item" onclick="followUser('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">➕ Follow</div>`;
        html += `<div class="ctx-item" onclick="unfollowUser('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">➖ Unfollow</div>`;
        html += `<div class="ctx-item" onclick="showUserNote('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">📝 Set Note</div>`;
        html += `<div class="ctx-item" onclick="showMutualServers('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">🏠 Mutual Servers</div>`;
        html += `<div class="ctx-item" onclick="viewUserStory('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">📖 View Story</div>`;
        html += divider;
        html += `<div class="ctx-item" style="color:#ed4245;" onclick="flagContent('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">🚩 Report User</div>`;
        html += `<div class="ctx-item" style="color:#ed4245;" onclick="blockUser('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">🚫 Block</div>`;
        html += `<div class="ctx-item" onclick="navigator.clipboard.writeText('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">📋 Copy Username</div>`;
    } else {
        // Self — only relevant actions
        html += `<div class="ctx-item" onclick="toggleSettings();this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">⚙️ Settings</div>`;
        html += `<div class="ctx-item" onclick="showSettingsTab('profile');toggleSettings();this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">👤 Edit Profile</div>`;
        html += `<div class="ctx-item" onclick="setCustomStatus();this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">💬 Set Status</div>`;
        html += `<div class="ctx-item" onclick="navigator.clipboard.writeText('${safe}');this.closest('.user-ctx-menu').remove();document.querySelector('.user-ctx-overlay')?.remove();">📋 Copy Username</div>`;
    }

    if (isMobile) {
        html = `<div style="width:36px;height:4px;background:rgba(255,255,255,0.2);border-radius:2px;margin:4px auto 8px;"></div>` + html;
    }
    menu.innerHTML = html;
    document.body.appendChild(menu);
    if (isMobile) {
        const overlay = document.createElement('div');
        overlay.className = 'user-ctx-overlay';
        overlay.style.cssText = 'position:fixed;inset:0;z-index:9998;background:rgba(0,0,0,0.4);';
        overlay.onclick = () => { menu.remove(); overlay.remove(); };
        document.body.appendChild(overlay);
    } else {
        setTimeout(() => document.addEventListener('click', function rem() { menu.remove(); document.removeEventListener('click', rem); }, { once: true }), 50);
    }
}

// ── Profile Picture ───────────────────────────────────────────
function _uploadBannerImage() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = async function() {
        const file = input.files[0];
        if (!file) return;
        if (file.size > 12 * 1024 * 1024) { _showToast('File must be under 12MB', 'error'); return; }
        const img = new Image();
        img.onload = function() { _showBannerCropUI(img); };
        img.src = URL.createObjectURL(file);
    };
    input.click();
}

function _showBannerCropUI(img) {
    const old = document.getElementById('banner-crop-overlay');
    if (old) old.remove();

    const overlay = document.createElement('div');
    overlay.id = 'banner-crop-overlay';
    overlay.style.cssText = 'position:fixed;inset:0;z-index:100000;background:rgba(0,0,0,0.85);display:flex;align-items:center;justify-content:center;padding:16px;animation:fadeIn 0.2s;';

    const isMobile = window.innerWidth <= 600;
    const cropW = isMobile ? window.innerWidth - 32 : 640;
    const cropH = Math.round(cropW * 9 / 16); // 16:9 aspect ratio

    overlay.innerHTML = `
        <div style="background:var(--bg-secondary,#2b2d31);border-radius:14px;overflow:hidden;max-width:700px;width:100%;box-shadow:0 12px 40px rgba(0,0,0,0.5);">
            <div style="padding:16px 20px;border-bottom:1px solid rgba(255,255,255,0.06);display:flex;align-items:center;justify-content:space-between;">
                <div style="color:white;font-size:16px;font-weight:700;">Resize Banner (16:9)</div>
                <button onclick="document.getElementById('banner-crop-overlay').remove()" style="background:none;border:none;color:var(--text-muted);font-size:20px;cursor:pointer;">✕</button>
            </div>
            <div style="padding:20px;display:flex;flex-direction:column;gap:12px;">
                <div style="position:relative;width:100%;aspect-ratio:16/9;overflow:hidden;border-radius:10px;border:2px solid rgba(88,101,242,0.3);background:black;cursor:grab;" id="banner-crop-area">
                    <img id="banner-crop-img" src="${img.src}" style="position:absolute;user-select:none;-webkit-user-drag:none;" draggable="false">
                </div>
                <div style="display:flex;align-items:center;gap:12px;">
                    <span style="color:var(--text-muted);font-size:12px;">🔍 Zoom</span>
                    <input type="range" id="banner-crop-zoom" min="100" max="300" value="100" style="flex:1;accent-color:var(--accent-blue);" oninput="_updateBannerCrop()">
                    <span id="banner-crop-zoom-val" style="color:white;font-size:12px;min-width:36px;">100%</span>
                </div>
                <div style="color:var(--text-muted);font-size:11px;">Drag the image to reposition. Any image size is accepted — resize it here to 16:9 (1920×1080) format.</div>
                <div style="display:flex;gap:8px;justify-content:flex-end;">
                    <button onclick="document.getElementById('banner-crop-overlay').remove()" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:10px 20px;border-radius:8px;cursor:pointer;font-size:14px;">Cancel</button>
                    <button onclick="_saveBannerCrop()" style="background:var(--accent-blue);color:white;border:none;padding:10px 20px;border-radius:8px;cursor:pointer;font-size:14px;font-weight:600;">Save Banner</button>
                </div>
            </div>
        </div>`;

    document.body.appendChild(overlay);
    overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

    // Initialize crop positioning
    const cropArea = document.getElementById('banner-crop-area');
    const cropImg = document.getElementById('banner-crop-img');
    if (!cropArea || !cropImg) return;

    // Fit image to cover the crop area
    const areaRect = cropArea.getBoundingClientRect();
    const areaW = areaRect.width;
    const areaH = areaRect.height;

    let scale = Math.max(areaW / img.naturalWidth, areaH / img.naturalHeight);
    let baseScale = scale;
    let imgW = img.naturalWidth * scale;
    let imgH = img.naturalHeight * scale;
    let offsetX = (areaW - imgW) / 2;
    let offsetY = (areaH - imgH) / 2;

    const updateImg = () => {
        cropImg.style.width = imgW + 'px';
        cropImg.style.height = imgH + 'px';
        cropImg.style.left = offsetX + 'px';
        cropImg.style.top = offsetY + 'px';
    };
    updateImg();

    // Drag to reposition
    let dragging = false, dragStartX = 0, dragStartY = 0, startOX = 0, startOY = 0;
    cropArea.onmousedown = cropArea.ontouchstart = (e) => {
        e.preventDefault();
        dragging = true;
        cropArea.style.cursor = 'grabbing';
        const pt = e.touches ? e.touches[0] : e;
        dragStartX = pt.clientX; dragStartY = pt.clientY;
        startOX = offsetX; startOY = offsetY;
    };
    document.addEventListener('mousemove', cropArea._moveHandler = (e) => {
        if (!dragging) return;
        const pt = e.touches ? e.touches[0] : e;
        offsetX = startOX + (pt.clientX - dragStartX);
        offsetY = startOY + (pt.clientY - dragStartY);
        // Clamp to keep crop area covered
        offsetX = Math.min(0, Math.max(areaW - imgW, offsetX));
        offsetY = Math.min(0, Math.max(areaH - imgH, offsetY));
        updateImg();
    });
    document.addEventListener('touchmove', cropArea._moveHandler, { passive: false });
    document.addEventListener('mouseup', cropArea._upHandler = () => {
        dragging = false;
        if (cropArea) cropArea.style.cursor = 'grab';
    });
    document.addEventListener('touchend', cropArea._upHandler);

    // Zoom slider
    window._updateBannerCrop = () => {
        const zoom = parseInt(document.getElementById('banner-crop-zoom').value);
        document.getElementById('banner-crop-zoom-val').textContent = zoom + '%';
        const newScale = baseScale * (zoom / 100);
        const centerX = areaW / 2;
        const centerY = areaH / 2;
        // Scale from center of crop area
        const oldImgW = imgW, oldImgH = imgH;
        imgW = img.naturalWidth * newScale;
        imgH = img.naturalHeight * newScale;
        offsetX = centerX - (centerX - offsetX) * (imgW / oldImgW);
        offsetY = centerY - (centerY - offsetY) * (imgH / oldImgH);
        // Clamp
        offsetX = Math.min(0, Math.max(areaW - imgW, offsetX));
        offsetY = Math.min(0, Math.max(areaH - imgH, offsetY));
        updateImg();
    };

    // Save crop
    window._saveBannerCrop = async () => {
        const canvas = document.createElement('canvas');
        canvas.width = 960; canvas.height = 540; // 16:9 at reasonable resolution
        const ctx = canvas.getContext('2d');
        // Map crop area coordinates to canvas
        const scaleToCanvas = 960 / areaW;
        const sx = -offsetX / (imgW / img.naturalWidth);
        const sy = -offsetY / (imgH / img.naturalHeight);
        const sw = areaW / (imgW / img.naturalWidth);
        const sh = areaH / (imgH / img.naturalHeight);
        ctx.drawImage(img, sx, sy, sw, sh, 0, 0, 960, 540);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
        const btn = document.querySelector('#banner-crop-overlay button:last-child');
        if (btn) { btn.disabled = true; btn.textContent = '⏳ Uploading...'; }
        const res = await apiRequest('UPDATE_PROFILE', { banner_image: dataUrl });
        if (res.status === 'success') {
            // Update preview
            const preview = document.getElementById('profile-banner-preview');
            if (preview) preview.style.background = `url(${dataUrl}) center/cover`;
            localStorage.setItem('tenshi_banner_image', dataUrl);
            const s = document.getElementById('pf-banner-status');
            if (s) s.textContent = '✅ Banner uploaded!';
            _showToast('Banner updated!');
        } else {
            _showToast(res.message || 'Failed to upload banner', 'error');
        }
        document.getElementById('banner-crop-overlay')?.remove();
        // Cleanup handlers
        document.removeEventListener('mousemove', cropArea._moveHandler);
        document.removeEventListener('touchmove', cropArea._moveHandler);
        document.removeEventListener('mouseup', cropArea._upHandler);
        document.removeEventListener('touchend', cropArea._upHandler);
    };
}

async function _removeBanner() {
    const res = await apiRequest('UPDATE_PROFILE', { banner_image: '' });
    if (res.status === 'success') {
        const preview = document.getElementById('profile-banner-preview');
        const color = localStorage.getItem('tenshi_banner_color') || '#2b2d31';
        if (preview) preview.style.background = color;
        localStorage.removeItem('tenshi_banner_image');
        const s = document.getElementById('pf-banner-status');
        if (s) s.textContent = 'No banner';
        _showToast('Banner removed');
    }
}

function changeProfilePicture() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = async function() {
        const file = input.files[0];
        if (!file) return;
        if (file.size > 12 * 1024 * 1024) { alert('File must be under 12MB'); return; }
        // Resize to 256x256 and compress as JPEG to keep payload small
        const img = new Image();
        img.onload = async function() {
            const canvas = document.createElement('canvas');
            const size = 256;
            canvas.width = size;
            canvas.height = size;
            const ctx = canvas.getContext('2d');
            // Crop to square (center)
            const s = Math.min(img.width, img.height);
            const sx = (img.width - s) / 2;
            const sy = (img.height - s) / 2;
            ctx.drawImage(img, sx, sy, s, s, 0, 0, size, size);
            const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
            const res = await apiRequest('UPDATE_PROFILE', { avatar: dataUrl });
            if (res.status === 'success') {
                _setAvatarEverywhere(dataUrl);
                alert('Profile picture updated!');
            } else { alert(res.message || 'Failed to update'); }
        };
        img.src = URL.createObjectURL(file);
    };
    input.click();
}

function _setAvatarEverywhere(dataUrl) {
    const topbar = document.getElementById('topbar-avatar');
    const tab = document.getElementById('tab-avatar');
    if (topbar) {
        topbar.textContent = '';
        topbar.style.backgroundImage = `url(${dataUrl})`;
        topbar.style.backgroundSize = 'cover';
        topbar.style.backgroundPosition = 'center';
    }
    if (tab) {
        tab.textContent = '';
        tab.style.backgroundImage = `url(${dataUrl})`;
        tab.style.backgroundSize = 'cover';
        tab.style.backgroundPosition = 'center';
    }
    localStorage.setItem('tenshi_avatar', dataUrl);
}

// ── User Profile Card (popup) ─────────────────────────────────
async function _showUserProfileCard(username) {
    // Remove existing card
    const old = document.getElementById('user-profile-card');
    if (old) old.remove();

    const res = await apiRequest('GET_PROFILE', { target: username });
    if (res.status !== 'success') return;

    const p = res;
    const initial = (username || '?')[0].toUpperCase();
    const bannerColor = p.banner_color || '#2b2d31';
    const profileColor = p.profile_color || '#5865F2';
    const usernameColor = p.username_color || '#ffffff';
    const statusColor = p.status_color || '#23a559';
    const bio = p.bio || '';
    const pronouns = p.pronouns || '';
    const customStatus = p.custom_status || '';
    const userStatus = p.user_status || 'Online';
    const avatar = p.avatar || '';
    const badges = p.badges || [];
    const createdAt = p.created_at || '';
    const connections = p.connections || {};
    const displayName = p.display_name || '';
    const socialLinks = p.social_links || {};
    const bannerImage = p.banner_image || '';

    const avatarHtml = avatar
        ? `<img src="${_escAttr(avatar)}" style="width:80px;height:80px;border-radius:50%;border:4px solid ${bannerColor};object-fit:cover;">`
        : `<div style="width:80px;height:80px;border-radius:50%;border:4px solid ${bannerColor};background:${profileColor};display:flex;align-items:center;justify-content:center;font-size:36px;font-weight:bold;color:white;">${initial}</div>`;

    const badgeHtml = badges.length ? `<div style="display:flex;gap:4px;flex-wrap:wrap;margin-top:6px;">${badges.map(b => {
        if (b === 'verified') return '<span class="verified-badge" title="Identity Verified">✓ Verified</span>';
        if (b === 'beta') return '<span style="font-size:11px;font-weight:600;padding:2px 8px;border-radius:12px;color:#f0b132;background:rgba(240,177,50,0.15);" title="Beta Tester">🧪 Beta</span>';
        return `<span style="font-size:14px;" title="${_escAttr(b)}">${_escAttr(b)}</span>`;
    }).join('')}</div>` : '';

    const connectionHtml = Object.keys(connections).length ? `
        <div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.06);">
            <div style="font-size:10px;font-weight:700;text-transform:uppercase;color:var(--text-muted);margin-bottom:4px;">Connections</div>
            <div style="display:flex;gap:6px;flex-wrap:wrap;">
                ${Object.entries(connections).map(([k, v]) => v ? `<span style="font-size:11px;background:rgba(255,255,255,0.06);padding:2px 8px;border-radius:4px;color:var(--text-muted);">${_escAttr(k)}</span>` : '').join('')}
            </div>
        </div>` : '';

    const card = document.createElement('div');
    card.id = 'user-profile-card';
    card.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);z-index:999;display:flex;align-items:center;justify-content:center;padding:16px;';
    card.innerHTML = `
        <div style="width:340px;max-width:100%;border-radius:12px;overflow:hidden;box-shadow:0 8px 32px rgba(0,0,0,0.5);">
            <!-- Banner (16:9 aspect) -->
            <div style="width:100%;aspect-ratio:16/9;max-height:${bannerImage ? '140' : '80'}px;background:${bannerImage ? `url(${_escAttr(bannerImage)}) center/cover` : bannerColor};"></div>
            <!-- Avatar + Info -->
            <div style="background:var(--bg-secondary, #2b2d31);padding:0 16px 16px;position:relative;">
                <div style="margin-top:-40px;margin-bottom:8px;">
                    ${avatarHtml}
                </div>
                <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
                    ${displayName ? `<span style="color:${usernameColor};font-size:18px;font-weight:bold;">${_escAttr(displayName)}</span><span style="color:var(--text-muted);font-size:12px;">${_escAttr(username)}</span>` : `<span style="color:${usernameColor};font-size:18px;font-weight:bold;">${_escAttr(username)}</span>`}
                    ${pronouns ? `<span style="color:var(--text-muted);font-size:12px;">${_escAttr(pronouns)}</span>` : ''}
                </div>
                ${badgeHtml}
                ${customStatus ? `<div style="margin-top:6px;font-size:12px;color:var(--text-muted);font-style:italic;">${_escAttr(customStatus)}</div>` : ''}
                <div style="display:flex;align-items:center;gap:6px;margin-top:6px;">
                    <div style="width:8px;height:8px;border-radius:50%;background:${statusColor};flex-shrink:0;"></div>
                    <span style="font-size:12px;color:${statusColor};">${_escAttr(userStatus)}</span>
                </div>
                ${bio ? `
                <div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.06);">
                    <div style="font-size:10px;font-weight:700;text-transform:uppercase;color:var(--text-muted);margin-bottom:4px;">About Me</div>
                    <div style="font-size:13px;color:#dcddde;line-height:1.5;white-space:pre-wrap;">${_escAttr(bio)}</div>
                </div>` : ''}
                ${connectionHtml}
                ${Object.keys(socialLinks).length ? `
                <div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.06);">
                    <div style="font-size:10px;font-weight:700;text-transform:uppercase;color:var(--text-muted);margin-bottom:4px;">Social Links</div>
                    <div style="display:flex;flex-wrap:wrap;gap:4px;">
                        ${Object.entries(socialLinks).map(([k,v]) => v ? `<span style="font-size:11px;background:rgba(255,255,255,0.06);padding:3px 8px;border-radius:4px;color:var(--accent-blue);cursor:pointer;" title="${_escAttr(v)}">${_escAttr(k)}</span>` : '').join('')}
                    </div>
                </div>` : ''}
                ${p.current_activity ? `
                <div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.06);">
                    <div style="font-size:10px;font-weight:700;text-transform:uppercase;color:var(--text-muted);margin-bottom:4px;">Activity</div>
                    <div style="font-size:12px;color:#23a559;">🎮 ${_escAttr(p.current_activity)}${p.current_game?' — '+_escAttr(p.current_game):''}</div>
                </div>` : ''}
                ${p.platforms && Object.keys(p.platforms).length ? `
                <div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.06);">
                    <div style="font-size:10px;font-weight:700;text-transform:uppercase;color:var(--text-muted);margin-bottom:4px;">Platforms</div>
                    <div style="display:flex;flex-wrap:wrap;gap:4px;">${Object.entries(p.platforms||{}).map(([k,v])=>`<span style="font-size:11px;background:rgba(88,101,242,0.15);color:var(--accent-blue);padding:2px 8px;border-radius:4px;">${_escAttr(k)}: ${_escAttr(v)}</span>`).join('')}</div>
                </div>` : ''}
                ${(p.followers_count||p.following_count) ? `
                <div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.06);display:flex;gap:12px;">
                    <div style="font-size:12px;color:var(--text-muted);"><strong style="color:white;">${p.followers_count||0}</strong> Followers</div>
                    <div style="font-size:12px;color:var(--text-muted);"><strong style="color:white;">${p.following_count||0}</strong> Following</div>
                </div>` : ''}
                ${createdAt ? `
                <div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.06);">
                    <div style="font-size:10px;font-weight:700;text-transform:uppercase;color:var(--text-muted);margin-bottom:4px;">Member Since</div>
                    <div style="font-size:12px;color:var(--text-muted);">${_escAttr(createdAt)}</div>
                </div>` : ''}
                <div style="display:flex;gap:6px;margin-top:12px;flex-wrap:wrap;">
                    <button onclick="document.getElementById('user-profile-card').remove();openChat('${_escAttr(username)}')" style="flex:1;background:var(--accent-blue);color:white;border:none;padding:8px;border-radius:8px;cursor:pointer;font-size:12px;font-weight:600;">💬 Message</button>
                    <button onclick="viewUserStory('${_escAttr(username)}')" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 14px;border-radius:8px;cursor:pointer;font-size:12px;">📖 Story</button>
                    ${username !== currentUser ? `<button onclick="_requestAge('${_escAttr(username)}',this)" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 14px;border-radius:8px;cursor:pointer;font-size:12px;" title="Request to see this user's age">🎂 Age</button>` : ''}
                    <button onclick="document.getElementById('user-profile-card').remove()" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 14px;border-radius:8px;cursor:pointer;font-size:12px;">Close</button>
                </div>
            </div>
        </div>
    `;
    card.onclick = (e) => { if (e.target === card) card.remove(); };
    document.body.appendChild(card);
}

// ── Age Request System ───────────────────────────────────
async function _requestAge(target, btn) {
    if (btn) { btn.disabled = true; btn.textContent = '⏳'; }
    const r = await apiRequest('REQUEST_AGE', { target });
    if (btn) { btn.disabled = false; btn.textContent = '🎂 Age'; }
    if (r.status === 'success') {
        _showToast('Age request sent to ' + target);
    } else {
        _showToast(r.message || 'Failed to send request', 'error');
    }
}

function _showAgeRequestPopup(msg) {
    // Remove existing age popup to prevent stacking
    const old = document.getElementById('age-request-popup');
    if (old) old.remove();

    const popup = document.createElement('div');
    popup.id = 'age-request-popup';
    popup.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.7);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px;animation:fadeIn 0.2s;';
    popup.innerHTML = `
        <div style="background:var(--bg-secondary,#2b2d31);border-radius:14px;padding:24px;max-width:360px;width:100%;box-shadow:0 8px 32px rgba(0,0,0,0.6);text-align:center;">
            <div style="font-size:36px;margin-bottom:12px;">🎂</div>
            <div style="color:white;font-size:16px;font-weight:700;margin-bottom:6px;">Age Request</div>
            <div style="color:var(--text-muted);font-size:13px;margin-bottom:20px;line-height:1.5;">
                <strong style="color:white;">${_escAttr(msg.sender||'')}</strong> is requesting to see your age.<br>
                <span style="font-size:11px;">Only your age (not birthday) will be shared.</span>
            </div>
            <div style="display:flex;gap:10px;">
                <button onclick="_respondAgeRequest('${msg.request_id}',true)" style="flex:1;background:#23a559;color:white;border:none;padding:12px;border-radius:10px;cursor:pointer;font-weight:700;font-size:14px;">Share Age</button>
                <button onclick="_respondAgeRequest('${msg.request_id}',false)" style="flex:1;background:rgba(255,255,255,0.08);color:white;border:none;padding:12px;border-radius:10px;cursor:pointer;font-weight:600;font-size:14px;">Decline</button>
            </div>
        </div>
    `;
    popup.onclick = (e) => { if (e.target === popup) popup.remove(); };
    document.body.appendChild(popup);
}

async function _respondAgeRequest(requestId, accept) {
    const popup = document.getElementById('age-request-popup');
    if (popup) popup.remove();
    const r = await apiRequest('RESPOND_AGE_REQUEST', { request_id: requestId, accept });
    if (accept) {
        _showToast(r.status === 'success' ? 'Age shared.' : (r.message || 'Failed'));
    } else {
        _showToast('Request declined.');
    }
}

function _showAgeResponsePopup(msg) {
    if (msg.accepted) {
        _showToast(msg.content || `${msg.sender} shared their age: ${msg.age}`, 'success', 6000);
    } else {
        _showToast(msg.content || `${msg.sender} declined your age request.`, 'info', 4000);
    }
}

// (legacy _showToast removed — see unified `notify()` and shim earlier in the file)

// Restore avatar on load
function _restoreAvatar() {
    const saved = localStorage.getItem('tenshi_avatar');
    if (saved) _setAvatarEverywhere(saved);
}
setTimeout(_restoreAvatar, 500);

function createChannelPrompt(serverId, type) {
    const old = document.getElementById('create-channel-modal');
    if (old) old.remove();

    const typeLabel = type === 'voice' ? 'Voice' : type === 'ticket' ? 'Ticket' : type === 'live' ? 'Live' : 'Text';
    const modal = document.createElement('div');
    modal.id = 'create-channel-modal';
    modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px;';
    modal.innerHTML = `
        <div style="background:var(--bg-secondary,#2b2d31);border-radius:14px;padding:24px;max-width:400px;width:100%;box-shadow:0 8px 32px rgba(0,0,0,0.5);">
            <h3 style="color:white;margin:0 0 4px;font-size:16px;">Create ${typeLabel} Channel</h3>
            <p style="color:var(--text-muted);font-size:12px;margin:0 0 16px;">Enter a name for the new ${typeLabel.toLowerCase()} channel.</p>
            <input id="new-channel-name" type="text" placeholder="Channel name" maxlength="32" autofocus
                style="width:100%;padding:10px 12px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);border-radius:8px;color:white;font-size:14px;box-sizing:border-box;margin-bottom:8px;">
            <div id="create-channel-status" style="font-size:12px;min-height:18px;margin-bottom:8px;"></div>
            <div style="display:flex;gap:8px;justify-content:flex-end;">
                <button onclick="document.getElementById('create-channel-modal').remove()" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 16px;border-radius:8px;cursor:pointer;font-size:13px;">Cancel</button>
                <button onclick="_submitCreateChannel('${serverId}','${type}')" style="background:#23a559;color:white;border:none;padding:8px 16px;border-radius:8px;cursor:pointer;font-size:13px;font-weight:600;">Create</button>
            </div>
        </div>`;
    modal.onclick = (e) => { if (e.target === modal) modal.remove(); };
    document.body.appendChild(modal);
    // Focus the input and handle Enter key
    const inp = document.getElementById('new-channel-name');
    if (inp) {
        setTimeout(() => inp.focus(), 100);
        inp.onkeydown = (e) => { if (e.key === 'Enter') _submitCreateChannel(serverId, type); };
    }
}

async function _submitCreateChannel(serverId, type) {
    const inp = document.getElementById('new-channel-name');
    const status = document.getElementById('create-channel-status');
    const name = inp?.value?.trim();
    if (!name) { if (status) { status.style.color = '#ed4245'; status.textContent = 'Enter a channel name.'; } return; }
    if (status) { status.style.color = 'yellow'; status.textContent = 'Creating...'; }
    const res = await apiRequest('CREATE_CHANNEL', { server_id: serverId, channel_name: name, channel_type: type });
    if (res.status === 'success') {
        document.getElementById('create-channel-modal')?.remove();
        showGlobalNotification('Channel "' + name + '" created!', '#23a559');
        // Refresh server view
        const srvRes = await apiRequest('GET_JOINED_SERVERS');
        if (srvRes.status === 'success') {
            const srv = srvRes.servers.find(s => s.id === serverId);
            if (srv) loadServerView(JSON.stringify(srv));
        }
    } else {
        if (status) { status.style.color = '#ed4245'; status.textContent = res.message || 'Failed to create channel'; }
    }
}

async function viewUserProfile(target) {
    openChat(target);
    _renderDMProfile(target);
}

async function kickUser(target, serverId) {
    if (!confirm('Kick ' + target + ' from this server?')) return;
    const res = await apiRequest('KICK_USER', { target, server_id: serverId });
    alert(res.message || (res.status === 'success' ? 'Kicked!' : 'Failed'));
}

async function muteUserInServer(target, serverId) {
    const duration = prompt('Mute duration in minutes (0 = unmute):', '10');
    if (duration === null) return;
    const res = await apiRequest('MUTE_USER', { target, server_id: serverId, duration: parseInt(duration) || 0 });
    alert(res.message || (res.status === 'success' ? 'Done!' : 'Failed'));
}

async function assignRolePrompt(target, serverId) {
    if (!currentManagingServer) return;
    const roles = Object.entries(currentManagingServer.roles || {}).map(([id, r]) => r.name).join(', ');
    const roleName = prompt('Assign role to ' + target + '.\nAvailable: ' + roles + '\n\nEnter role name:');
    if (!roleName) return;
    const res = await apiRequest('ASSIGN_ROLE', { target, server_id: serverId, role_name: roleName });
    alert(res.message || (res.status === 'success' ? 'Role assigned!' : 'Failed'));
}

// ── Tab Bar Navigation (works on both mobile and desktop) ────
let _navHistory = [];
let _currentTab = 'hub';

function mobileTab(tab) {
    // Save current tab to history for back navigation
    if (_currentTab && _currentTab !== tab) {
        _navHistory.push(_currentTab);
        if (_navHistory.length > 20) _navHistory = _navHistory.slice(-20);
    }
    _currentTab = tab;

    // Update active tab (both mobile tab bar and topbar nav)
    document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
    document.querySelectorAll(`.tab-btn[data-tab="${tab}"]`).forEach(b => b.classList.add('active'));
    closeMobilePanel();

    // Show back button if there's history
    const backBtn = document.getElementById('back-btn');
    if (backBtn) backBtn.style.display = _navHistory.length > 0 ? 'block' : 'none';

    switch(tab) {
        case 'hub': loadMobileHome(); break;
        case 'friends': loadFriendsView(); break;
        case 'notifs': loadNotifications(); break;
        case 'ai': loadAIChat(); break;
        case 'email': loadEmailClient(); break;
        case 'files': loadFileStorage(); break;
        case 'music': _openMusicStudio(); break;
        case 'settings': toggleSettings(); break;
        case 'profile':
            showSettingsTab('profile');
            toggleSettings();
            break;
        case 'admin': loadAdminPanel(); break;
    }
}

function goBack() {
    if (_navHistory.length === 0) { mobileTab('hub'); return; }
    const prevTab = _navHistory.pop();
    _currentTab = prevTab;
    // Update active tab without pushing to history
    document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
    document.querySelectorAll(`.tab-btn[data-tab="${prevTab}"]`).forEach(b => b.classList.add('active'));
    const backBtn = document.getElementById('back-btn');
    if (backBtn) backBtn.style.display = _navHistory.length > 0 ? 'block' : 'none';
    switch(prevTab) {
        case 'hub': loadMobileHome(); break;
        case 'friends': loadFriendsView(); break;
        case 'notifs': loadNotifications(); break;
        case 'ai': loadAIChat(); break;
        case 'email': loadEmailClient(); break;
        default: loadMobileHome();
    }
}

