async function _loadDiscoverHubs() {
    const list = document.getElementById('discover-hubs-list');
    if (!list) return;
    try {
        const pubRes = await apiRequest('GET_PUBLIC_SERVERS');
        if (pubRes.status !== 'success') { list.innerHTML = ''; return; }

        const joinedRes = _cachedJoinedServers || await apiRequest('GET_JOINED_SERVERS');
        const joinedIds = new Set((joinedRes.servers || []).map(s => s.id));
        const hubs = pubRes.servers || [];

        let html = '';
        hubs.forEach(h => {
            const joined = joinedIds.has(h.id);
            const icon = h.icon || h.name[0].toUpperCase();
            const promoted = h.is_promoted;
            html += `<div style="display:flex;flex-direction:column;gap:6px;padding:12px;background:${promoted ? 'rgba(88,101,242,0.08)' : 'rgba(255,255,255,0.03)'};border:1px solid ${promoted ? 'rgba(88,101,242,0.2)' : 'rgba(255,255,255,0.06)'};border-radius:10px;${promoted ? 'order:-1;' : ''}">
                <div style="display:flex;align-items:center;gap:8px;">
                    <span style="width:32px;height:32px;border-radius:50%;background:${promoted ? 'var(--accent-blue)' : 'rgba(255,255,255,0.1)'};display:flex;align-items:center;justify-content:center;font-size:14px;flex-shrink:0;">${icon.length <= 2 ? icon : icon[0]}</span>
                    <div style="flex:1;min-width:0;">
                        <div style="color:white;font-size:13px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${_escAttr(h.name)}${promoted ? ' <span style="font-size:9px;color:#f0b132;background:rgba(240,177,50,0.15);padding:1px 4px;border-radius:3px;vertical-align:middle;">FEATURED</span>' : ''}</div>
                        <div style="color:var(--text-muted);font-size:10px;">${h.member_count} members · ${h.online_count} online</div>
                    </div>
                </div>
                ${h.description ? `<div style="color:var(--text-muted);font-size:11px;line-height:1.3;overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;">${_escAttr(h.description)}</div>` : ''}
                <div style="display:flex;gap:4px;flex-wrap:wrap;">
                    ${h.bully_prevention !== false ? '<span style="font-size:9px;color:#23a559;background:rgba(35,165,89,0.12);padding:2px 5px;border-radius:3px;">🛡️ Bully-Free</span>' : ''}
                    ${h.ai_moderation !== false ? '<span style="font-size:9px;color:#5865f2;background:rgba(88,101,242,0.12);padding:2px 5px;border-radius:3px;">🤖 AI Moderated</span>' : ''}
                    ${h.nsfw_allowed ? '<span style="font-size:9px;color:#ed4245;background:rgba(237,66,69,0.12);padding:2px 5px;border-radius:3px;">🔞 NSFW</span>' : '<span style="font-size:9px;color:#23a559;background:rgba(35,165,89,0.12);padding:2px 5px;border-radius:3px;">SFW</span>'}
                </div>
                <button onclick="_discoverJoinHub('${h.id}')" style="width:100%;padding:6px;background:${joined ? 'rgba(255,255,255,0.06)' : 'var(--accent-blue)'};color:${joined ? 'var(--text-muted)' : 'white'};border:none;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;">${joined ? '✓ Joined' : 'Join'}</button>
            </div>`;
        });

        if (!html) html = '<div style="color:var(--text-muted);font-size:12px;grid-column:1/-1;">No public hubs available.</div>';
        list.innerHTML = html;
    } catch(e) {
        list.innerHTML = '';
    }
}

async function joinByLink() {
    const input = document.getElementById('join-link-input');
    let val = (input?.value || '').trim();
    if (!val) { alert('Paste an invite link or server name.'); return; }

    // Parse link formats:
    // tenshi.lol/hub?joinServer=Name
    // tenshi.lol/invite/Name
    // https://tenshi.lol/hub?joinServer=Name
    // or just a server name
    let serverName = val;
    try {
        if (val.includes('joinServer=')) {
            const url = new URL(val.startsWith('http') ? val : 'https://' + val);
            serverName = url.searchParams.get('joinServer') || val;
        } else if (val.includes('/invite/')) {
            serverName = val.split('/invite/').pop().split('?')[0].split('#')[0];
        }
    } catch(e) {}

    serverName = decodeURIComponent(serverName);

    // First get hub info to show pre-join confirmation
    const info = await apiRequest('GET_HUB_INFO', { server_name: serverName, invite_code: serverName });
    if (info.status === 'success' && info.hub) {
        _showJoinConfirm(info.hub, serverName, input);
    } else {
        // Hub not found or error — try direct join (might be already a member)
        const res = await apiRequest('JOIN_SERVER', { server_name: serverName, invite_code: serverName });
        if (res.status === 'success') {
            if (input) input.value = '';
            _cachedJoinedServers = null;
            fetchServersJoined();
            if (res.server) loadServerView(JSON.stringify(res.server));
            else loadMobileHome();
        } else {
            alert(res.message || 'Could not find or join that server.');
        }
    }
}

// ── Pre-join confirmation modal ──────────────────────────────────
let _pendingJoinData = null;

function _showJoinConfirm(hub, queryStr, inputEl) {
    _pendingJoinData = { query: queryStr, input: inputEl };
    const modal = document.getElementById('join-confirm-modal');
    if (!modal) return;
    document.getElementById('join-confirm-title').textContent = `Join "${hub.name}"?`;
    document.getElementById('join-confirm-desc').textContent = hub.description || 'No description provided.';

    const rules = document.getElementById('join-confirm-rules');
    const badge = (icon, label, color) => `<div style="display:flex;align-items:center;gap:8px;padding:10px;background:rgba(0,0,0,0.2);border-radius:8px;border-left:3px solid ${color};"><span style="font-size:16px;">${icon}</span><span style="color:white;font-size:13px;">${label}</span></div>`;

    let html = '<div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:.5px;color:var(--text-muted);margin-bottom:4px;">Hub Rules</div>';

    if (hub.nsfw_allowed) {
        html += badge('🔞', 'NSFW content IS allowed in this hub', '#ed4245');
    } else {
        html += badge('🚫', 'NSFW content is NOT allowed in this hub', '#23a559');
    }
    if (hub.bully_prevention !== false) {
        html += badge('🛡️', 'Bully prevention is active — harassment will be blocked', '#23a559');
    } else {
        html += badge('⚠️', 'Bully prevention is OFF — no automatic harassment scanning', '#ed4245');
    }
    if (hub.ai_moderation !== false) {
        html += badge('🤖', 'AI moderation is active — all content is scanned', '#5865f2');
    } else {
        html += badge('👁️', 'AI moderation is OFF — only reported content is reviewed', '#f0b132');
    }

    html += `<div style="padding:8px 10px;background:rgba(255,255,255,0.03);border-radius:6px;margin-top:4px;color:var(--text-muted);font-size:11px;">${Object.keys(hub).includes('member_count') ? hub.member_count + ' members' : ''}</div>`;
    rules.innerHTML = html;

    modal.style.display = 'flex';
}

function _closeJoinConfirm() {
    const modal = document.getElementById('join-confirm-modal');
    if (modal) modal.style.display = 'none';
    _pendingJoinData = null;
}

async function _discoverJoinHub(serverId) {
    const info = await apiRequest('GET_HUB_INFO', { server_name: serverId, invite_code: serverId });
    if (info.status === 'success' && info.hub) {
        _showJoinConfirm(info.hub, serverId, null);
    } else {
        // Fallback direct join
        const res = await apiRequest('JOIN_SERVER', { server_id: serverId });
        if (res.status === 'success') { _cachedJoinedServers = null; fetchServersJoined(); loadMobileHome(); }
        else alert(res.message || 'Failed');
    }
}

async function _confirmJoin() {
    if (!_pendingJoinData) return;
    const { query, input } = _pendingJoinData;
    _closeJoinConfirm();
    const res = await apiRequest('JOIN_SERVER', { server_name: query, invite_code: query });
    if (res.status === 'success') {
        if (input) input.value = '';
        _cachedJoinedServers = null;
        fetchServersJoined();
        if (res.server) loadServerView(JSON.stringify(res.server));
        else loadMobileHome();
    } else {
        alert(res.message || 'Could not find or join that server.');
    }
}

