// ── Mobile UX: swipe-open sidebar, resize handler, keyboard adjust ──

(function _initMobile() {
    // Open/close left panel on mobile
    function _openLeftPanel() {
        const lp = document.getElementById('left-panel');
        const ov = document.getElementById('mobile-panel-overlay');
        if (lp) lp.classList.add('mobile-open');
        if (ov) ov.style.display = 'block';
    }
    function _closeLeftPanel() {
        const lp = document.getElementById('left-panel');
        const ov = document.getElementById('mobile-panel-overlay');
        if (lp) lp.classList.remove('mobile-open');
        if (ov) ov.style.display = 'none';
    }

    // Hamburger button wired via attribute
    document.addEventListener('click', e => {
        if (e.target.closest('#mobile-hamburger, [data-action="open-panel"]')) _openLeftPanel();
    });

    // Open/close right (member) panel on mobile
    function _openRightPanel(fromBottom) {
        const mp = document.getElementById('member-panel');
        const ov = document.getElementById('mobile-panel-overlay');
        if (mp) {
            mp.classList.remove('panel-open', 'panel-open-bottom');
            mp.classList.add(fromBottom ? 'panel-open-bottom' : 'panel-open');
        }
        if (ov) ov.style.display = 'block';
    }
    function _closeRightPanel() {
        const mp = document.getElementById('member-panel');
        const ov = document.getElementById('mobile-panel-overlay');
        if (mp) mp.classList.remove('panel-open', 'panel-open-bottom');
        if (ov && !document.getElementById('left-panel')?.classList.contains('mobile-open')) ov.style.display = 'none';
    }

    // Close both panels on overlay tap
    document.addEventListener('click', e => {
        const ov = document.getElementById('mobile-panel-overlay');
        if (ov && e.target === ov) { _closeLeftPanel(); _closeRightPanel(); }
    });

    // Swipe gestures: left/right for panels, up for member panel
    let _touchStartX = 0;
    let _touchStartY = 0;
    document.addEventListener('touchstart', e => {
        _touchStartX = e.touches[0].clientX;
        _touchStartY = e.touches[0].clientY;
    }, { passive: true });
    document.addEventListener('touchend', e => {
        if (window.innerWidth > 600) return;
        const endX = e.changedTouches[0].clientX;
        const endY = e.changedTouches[0].clientY;
        const dx = endX - _touchStartX;
        const dy = endY - _touchStartY;
        const absDx = Math.abs(dx);
        const absDy = Math.abs(dy);

        // Horizontal swipes (must be more horizontal than vertical)
        if (absDx > 50 && absDx > absDy) {
            if (dx > 0 && _touchStartX < 30) {
                // Swipe right from left edge → open left panel
                _closeRightPanel();
                _openLeftPanel();
            } else if (dx < 0 && _touchStartX > window.innerWidth - 30) {
                // Swipe left from right edge → open right panel
                _closeLeftPanel();
                _openRightPanel(false);
            } else if (dx < -50) {
                // Swipe left anywhere → close left panel
                _closeLeftPanel();
            } else if (dx > 50) {
                // Swipe right anywhere → close right panel
                _closeRightPanel();
            }
        }

        // Vertical swipe up from bottom → open member panel as bottom sheet
        if (dy < -80 && absDy > absDx && _touchStartY > window.innerHeight - 60) {
            _closeLeftPanel();
            _openRightPanel(true);
        }
        // Swipe down on bottom-sheet panel → close it
        if (dy > 80 && absDy > absDx) {
            const mp = document.getElementById('member-panel');
            if (mp?.classList.contains('panel-open-bottom')) _closeRightPanel();
        }
    }, { passive: true });

    // Resize: close panel when viewport widens past mobile breakpoint
    let _lastWidth = window.innerWidth;
    window.addEventListener('resize', () => {
        const w = window.innerWidth;
        if (_lastWidth <= 600 && w > 600) _closeLeftPanel();
        _lastWidth = w;
        // On iOS, keyboard resize — adjust message input
        _adjustForKeyboard();
    });

    // iOS keyboard: shrink messages area so input stays visible
    function _adjustForKeyboard() {
        if (!window.visualViewport) return;
        const vv = window.visualViewport;
        const keyboardH = window.innerHeight - vv.height;
        // Tab bar is at the top now, no need to hide on keyboard
        // Scroll input into view
        if (keyboardH > 100) {
            const input = document.getElementById('msg-input');
            if (input && document.activeElement === input) {
                setTimeout(() => input.scrollIntoView({ block: 'nearest', behavior: 'smooth' }), 100);
            }
        }
    }
    if (window.visualViewport) {
        window.visualViewport.addEventListener('resize', _adjustForKeyboard);
    }

    // Auto-scroll messages to bottom after content loads on mobile
    function _scrollMsgsBottom() {
        const mc = document.getElementById('message-container');
        if (mc) mc.scrollTop = mc.scrollHeight;
    }
    document.addEventListener('tenshi:messages-loaded', _scrollMsgsBottom);
})();

async function leaveServer(serverId, serverName) {
    if (!confirm(`Leave ${serverName}? You can rejoin anytime from the public server list.`)) return;
    const res = await apiRequest('LEAVE_SERVER', { server_id: serverId });
    if (res.status === 'success') {
        fetchServersJoined();
        loadFriendsView();
    } else {
        alert(res.message || 'Could not leave server.');
    }
}

// ── Optimize Mode (Gaming/Call Focus) ─────────────────────────
let _optimizeMode = localStorage.getItem('tenshi_optimize') === 'true';
let _optimizeSavedIntervals = [];

function toggleOptimizeMode() {
    if (!_optimizeMode) {
        const msg = "⚡ Optimize Mode — Gaming/Call Focus\n\n" +
            "Disables background features to free up resources:\n\n" +
            "✓ Stops heartbeat polling (friend status, unread counts)\n" +
            "✓ Stops message polling in background chats\n" +
            "✓ Hides member panels and non-essential UI\n" +
            "✓ Reduces animations and effects\n" +
            "✓ Keeps voice/video call fully active\n" +
            "✓ Keeps safety systems running\n\n" +
            "Toggle off when done gaming to restore everything.\n\nEnable?";
        if (!confirm(msg)) return;
    }
    _optimizeMode = !_optimizeMode;
    localStorage.setItem('tenshi_optimize', _optimizeMode);
    applyOptimizeMode();
}

function applyOptimizeMode() {
    const btn = document.getElementById('optimize-btn');
    if (btn) {
        btn.style.color = _optimizeMode ? '#23a559' : '';
        btn.title = _optimizeMode ? '⚡ Optimize ON — click to disable' : '⚡ Optimize Mode';
    }

    if (_optimizeMode) {
        document.body.classList.add('optimize-mode');

        // Stop heartbeat (friend status, unread counts, email badges)
        if (_heartbeatInterval) {
            clearInterval(_heartbeatInterval);
            _heartbeatInterval = null;
        }

        // Stop message polling for background chats
        if (currentChatInterval && !_activeCall && !_voiceChannelName) {
            clearInterval(currentChatInterval);
            currentChatInterval = null;
        }

        // Hide non-essential UI elements
        const mp = document.getElementById('member-list-content');
        if (mp) mp.innerHTML = '<div style="padding:16px;text-align:center;color:var(--text-muted);font-size:12px;">⚡ Optimize Mode<br><span style="font-size:10px;">Members hidden to save resources</span></div>';

        // Reduce Spotify polling
        const spotifyEl = document.getElementById('spotify-player');
        if (spotifyEl) spotifyEl.style.display = 'none';

        // Show indicator
        _showOptimizeIndicator();

        console.log('[Optimize] Mode ON — background tasks paused');
    } else {
        document.body.classList.remove('optimize-mode');

        // Restart heartbeat
        _startHeartbeat();

        // Restart message polling if in a chat
        if (currentTarget && !currentChatInterval) {
            currentChatInterval = setInterval(pollMessages, 3000);
        }

        // Show Spotify player
        const spotifyEl = document.getElementById('spotify-player');
        if (spotifyEl) spotifyEl.style.display = '';

        // Remove indicator
        _hideOptimizeIndicator();

        if (currentManagingServer && currentManagingServer.id) {
            refreshHubMemberPanel(currentManagingServer.id, currentManagingServer.owner || '');
        }

        console.log('[Optimize] Mode OFF — all features restored');
    }
}

function _showOptimizeIndicator() {
    let ind = document.getElementById('optimize-indicator');
    if (ind) return;
    ind = document.createElement('div');
    ind.id = 'optimize-indicator';
    ind.style.cssText = 'position:fixed;bottom:60px;right:12px;z-index:50;background:rgba(35,165,89,0.9);color:white;padding:6px 12px;border-radius:8px;font-size:11px;font-weight:600;cursor:pointer;display:flex;align-items:center;gap:6px;box-shadow:0 2px 12px rgba(0,0,0,0.3);';
    ind.innerHTML = '⚡ Optimize ON';
    ind.title = 'Click to disable Optimize Mode';
    ind.onclick = toggleOptimizeMode;
    document.body.appendChild(ind);
}

function _hideOptimizeIndicator() {
    const ind = document.getElementById('optimize-indicator');
    if (ind) ind.remove();
}

// Apply on load
if (_optimizeMode) setTimeout(applyOptimizeMode, 500);

// ── Image Upload to Chat ──────────────────────────────────────
let _pendingImage = null;

async function uploadImageToChat(input) {
    const file = input.files[0];
    if (!file) return;
    input.value = '';
    if (!file.type.startsWith('image/') && file.type !== 'image/gif') {
        alert('Only images and GIFs are supported.');
        return;
    }
    if (file.size > 5 * 1024 * 1024) {
        alert('Image must be under 5MB.');
        return;
    }
    const reader = new FileReader();
    reader.onload = function(e) {
        _pendingImage = { name: file.name, data: e.target.result, type: file.type };
        const preview = document.getElementById('image-preview-bar');
        const thumb = document.getElementById('image-preview-thumb');
        const name = document.getElementById('image-preview-name');
        if (preview) preview.style.display = 'block';
        if (thumb) thumb.src = e.target.result;
        if (name) name.textContent = file.name + ' (' + (file.size / 1024).toFixed(1) + ' KB)';
    };
    reader.readAsDataURL(file);
}

function cancelImageUpload() {
    _pendingImage = null;
    const preview = document.getElementById('image-preview-bar');
    if (preview) preview.style.display = 'none';
}

// Override sendMessage to include images
const _originalSendMessage = sendMessage;
sendMessage = async function() {
    if (_pendingImage && currentTarget) {
        const content = '[IMG]' + _pendingImage.data;
        const mc = document.getElementById('message-container');
        const empty = mc?.querySelector('.ch-empty');
        if (empty) empty.remove();
        // Resize image before sending to reduce payload
        const _sendImg = async (imgData) => {
            const img = new Image();
            img.src = imgData;
            await new Promise(r => img.onload = r);
            const canvas = document.createElement('canvas');
            const maxW = 600, maxH = 400;
            let w = img.width, h = img.height;
            if (w > maxW) { h = h * maxW / w; w = maxW; }
            if (h > maxH) { w = w * maxH / h; h = maxH; }
            canvas.width = w; canvas.height = h;
            canvas.getContext('2d').drawImage(img, 0, 0, w, h);
            return canvas.toDataURL('image/jpeg', 0.7);
        };
        const resized = await _sendImg(_pendingImage.data);
        const imgContent = `[IMG]${resized}[/IMG]`;

        // Encrypt and send to server FIRST, only show if allowed
        const isDM = !currentTarget.includes('@') && !currentTarget.startsWith('srv:');
        let encContent = imgContent;
        if (isDM) {
            const enc = await fernetEncrypt(imgContent, currentTarget);
            if (enc) encContent = enc;
        }
        const rawB64 = isDM ? resized.replace(/^data:image\/[^;]+;base64,/, '') : '';
        const sendPayload = {
            target_type: isDM ? 'dm' : (currentTarget.includes('@') ? 'email' : 'server'),
            target_id: currentTarget,
            content: encContent,
            timestamp: new Date().toISOString()
        };
        if (rawB64) sendPayload.image_b64 = rawB64;
        const sendRes = await apiRequest('SEND_MESSAGE', sendPayload);
        if (sendRes.status === 'success') {
            const selfm = document.createElement('div');
            selfm.className = 'msg self';
            selfm.innerHTML = `<img src="${resized}" style="max-width:300px;max-height:200px;border-radius:8px;">`;
            if (mc) { mc.appendChild(selfm); mc.scrollTop = mc.scrollHeight; }
        } else if (sendRes.message) {
            alert(sendRes.message);
        }
        cancelImageUpload();
        return;
    }
    return _originalSendMessage();
};

