// ── Sticker Picker (dynamic, works in both DM and server) ────
function toggleStickerPicker() {
    const old = document.getElementById('sticker-popup');
    if (old) { old.remove(); return; }
    const popup = document.createElement('div');
    popup.id = 'sticker-popup';
    popup.style.cssText = 'position:fixed;bottom:70px;left:50%;transform:translateX(-50%);z-index:600;background:var(--bg-secondary,#1e1f22);border:1px solid rgba(255,255,255,0.1);border-radius:12px;padding:10px;width:320px;max-width:90vw;max-height:280px;box-shadow:0 8px 32px rgba(0,0,0,0.6);display:flex;flex-direction:column;';
    popup.innerHTML = `
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;flex-shrink:0;">
            <span style="font-weight:bold;font-size:13px;color:white;">Stickers</span>
            <button onclick="openStickerUpload()" style="background:var(--accent-blue);border:none;color:white;padding:3px 8px;border-radius:6px;cursor:pointer;font-size:10px;">+ Add</button>
        </div>
        <div id="sticker-popup-grid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(60px,1fr));gap:6px;overflow-y:auto;flex:1;"></div>
        <div id="sticker-popup-empty" style="text-align:center;color:var(--text-muted);font-size:12px;padding:16px;display:none;">No stickers yet</div>`;
    document.body.appendChild(popup);
    // Close on outside tap/click (pointerdown works on all mobile browsers)
    setTimeout(() => document.addEventListener('pointerdown', function _cls(e) {
        if (!popup.contains(e.target) && !e.target.closest('[onclick*="toggleStickerPicker"]')) { popup.remove(); document.removeEventListener('pointerdown', _cls); }
    }), 50);
    _loadStickerGrid();
}

async function _loadStickerGrid() {
    const grid = document.getElementById('sticker-popup-grid');
    const empty = document.getElementById('sticker-popup-empty');
    if (!grid) return;
    let serverId = null;
    if (currentTarget && currentTarget.startsWith('srv:')) serverId = currentTarget.split(':')[1];
    else if (currentManagingServer) serverId = currentManagingServer.id;
    const res = await apiRequest('GET_STICKERS', { server_id: serverId });
    if (res.status === 'success' && res.stickers && res.stickers.length > 0) {
        grid.innerHTML = res.stickers.map(s =>
            `<div style="cursor:pointer;border-radius:6px;overflow:hidden;background:rgba(255,255,255,0.05);padding:3px;text-align:center;" title="${_escAttr(s.name)}">
                <img src="${_escAttr(s.data)}" style="max-width:52px;max-height:52px;object-fit:contain;" onclick="sendSticker(this.src)">
            </div>`
        ).join('');
        if (empty) empty.style.display = 'none';
    } else {
        grid.innerHTML = '';
        if (empty) empty.style.display = 'block';
    }
}

async function sendSticker(dataUrl) {
    if (!currentTarget) return;
    const content = '[STICKER]' + dataUrl;
    const isServer = currentTarget.startsWith('srv:');
    // Show preview in correct container
    const mc = document.getElementById(isServer ? 'server-chat-messages' : 'message-container');
    if (mc) {
        const empty = mc.querySelector('.ch-empty');
        if (empty) empty.remove();
        const selfm = document.createElement('div');
        selfm.className = 'msg self';
        selfm.innerHTML = `<img src="${dataUrl}" style="max-width:128px;max-height:128px;">`;
        mc.appendChild(selfm);
        mc.scrollTop = mc.scrollHeight;
    }
    if (isServer) {
        const parts = currentTarget.split(':');
        await apiRequest('SEND_MESSAGE', { target_type: 'server', target_id: parts[1], channel: parts.slice(2).join(':'), content });
    } else {
        await apiRequest('SEND_MESSAGE', {
            target_type: currentTarget.includes('@') ? 'email' : 'dm',
            target_id: currentTarget,
            content, timestamp: new Date().toISOString()
        });
    }
    const popup = document.getElementById('sticker-popup');
    if (popup) popup.remove();
}

function openStickerUpload() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/png,image/gif';
    input.onchange = async function() {
        const file = input.files[0];
        if (!file) return;
        if (file.size > 512 * 1024) { alert('Sticker must be under 512KB'); return; }
        const name = prompt('Sticker name:', file.name.split('.')[0]);
        if (!name) return;
        const reader = new FileReader();
        reader.onload = async function(e) {
            let serverId = null;
            if (currentTarget && currentTarget.startsWith('srv:')) serverId = currentTarget.split(':')[1];
            else if (currentManagingServer) serverId = currentManagingServer.id;
            const res = await apiRequest('ADD_STICKER', { server_id: serverId, name: name, data: e.target.result });
            if (res.status === 'success') _loadStickerGrid();
            else alert(res.message || 'Failed to add sticker');
        };
        reader.readAsDataURL(file);
    };
    input.click();
}

