function _gifSearch(query) {
    clearTimeout(_gifSearchTimer);
    _gifSearchTimer = setTimeout(() => _gifFetch(query), 350);
}

async function _gifFetch(query) {
    const grid = document.getElementById('gif-results');
    if (!grid) return;
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;color:var(--text-muted);font-size:12px;padding:20px;">Loading...</div>';
    try {
        const endpoint = query.trim()
            ? `https://tenor.googleapis.com/v2/search?q=${encodeURIComponent(query)}&key=${_TENOR_KEY}&client_key=tenshi&limit=30&media_filter=tinygif,gif`
            : `https://tenor.googleapis.com/v2/featured?key=${_TENOR_KEY}&client_key=tenshi&limit=30&media_filter=tinygif,gif`;
        const res = await fetch(endpoint);
        const data = await res.json();
        const results = data.results || [];
        if (!results.length) {
            grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;color:var(--text-muted);font-size:12px;padding:20px;">No GIFs found</div>';
            return;
        }
        grid.innerHTML = '<div style="display:grid;grid-template-columns:repeat(2,1fr);gap:6px;">' + results.map(g => {
            const preview = g.media_formats?.tinygif?.url || g.media_formats?.gif?.url || '';
            const full = g.media_formats?.gif?.url || preview;
            return `<div style="cursor:pointer;border-radius:6px;overflow:hidden;background:rgba(255,255,255,0.05);height:120px;" onclick="_sendGif('${_escAttr(full)}')">
                <img src="${_escAttr(preview)}" style="width:100%;height:100%;object-fit:cover;" loading="lazy">
            </div>`;
        }).join('') + '</div>';
    } catch {
        grid.innerHTML = '<div style="text-align:center;color:var(--text-muted);font-size:12px;padding:20px;">Failed to load GIFs</div>';
    }
}

