// ── Reactions System ──────────────────────────────────────────
const QUICK_REACTIONS = ['👍','❤️','😂','😮','😢','🔥','👎','🎉'];

function renderReactions(msgId, reactions) {
    if (!reactions || !Object.keys(reactions).length) return '';
    let html = '<div class="msg-reactions" style="display:flex;gap:4px;flex-wrap:wrap;margin-top:4px;">';
    for (const [emoji, users] of Object.entries(reactions)) {
        const count = users.length;
        const isMine = users.includes(currentUser);
        html += `<button class="reaction-btn${isMine ? ' reacted' : ''}" onclick="toggleReaction('${msgId}','${emoji}')" style="background:${isMine ? 'rgba(88,101,242,0.3)' : 'rgba(255,255,255,0.06)'};border:1px solid ${isMine ? 'var(--accent-blue)' : 'transparent'};color:white;padding:2px 6px;border-radius:10px;font-size:12px;cursor:pointer;display:flex;align-items:center;gap:3px;">${emoji} <span style="font-size:11px;color:var(--text-muted);">${count}</span></button>`;
    }
    html += '</div>';
    return html;
}

function quickReact(msgId) {
    const existing = document.querySelector('.quick-react-popup');
    if (existing) existing.remove();
    const popup = document.createElement('div');
    popup.className = 'quick-react-popup';
    popup.style.cssText = 'position:fixed;z-index:200;background:var(--panel-bg);border:1px solid var(--glass-border);border-radius:8px;padding:6px;display:flex;gap:4px;box-shadow:0 8px 24px rgba(0,0,0,0.5);';
    popup.innerHTML = QUICK_REACTIONS.map(e => `<span style="cursor:pointer;font-size:20px;padding:2px 4px;border-radius:4px;" onmouseover="this.style.background='rgba(255,255,255,0.1)'" onmouseout="this.style.background=''" onclick="toggleReaction('${_escAttr(msgId)}','${e}');this.parentNode.remove();">${e}</span>`).join('');
    // Position near cursor
    const msgEl = document.querySelector(`[data-msg-id="${msgId}"]`);
    if (msgEl) {
        const rect = msgEl.getBoundingClientRect();
        popup.style.top = (rect.top - 40) + 'px';
        popup.style.left = (rect.right - 280) + 'px';
    }
    document.body.appendChild(popup);
    setTimeout(() => { document.addEventListener('click', function rem() { popup.remove(); document.removeEventListener('click', rem); }, { once: true }); }, 100);
}

async function toggleReaction(msgId, emoji) {
    const res = await apiRequest('TOGGLE_REACTION', { msg_id: msgId, emoji: emoji });
    if (res.status !== 'success') console.warn('Reaction failed:', res.message);
}

// ── Custom Emoji per Server ───────────────────────────────────
async function loadServerEmojis(serverId) {
    const res = await apiRequest('GET_SERVER_EMOJIS', { server_id: serverId });
    if (res.status === 'success') return res.emojis || [];
    return [];
}

async function uploadServerEmoji(serverId) {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/png,image/gif';
    input.onchange = async function() {
        const file = input.files[0];
        if (!file) return;
        if (file.size > 256 * 1024) { alert('Emoji must be under 256KB'); return; }
        const name = prompt('Emoji name (letters/numbers only):', file.name.split('.')[0].replace(/[^a-zA-Z0-9_]/g, ''));
        if (!name) return;
        const reader = new FileReader();
        reader.onload = async function(e) {
            const res = await apiRequest('ADD_SERVER_EMOJI', { server_id: serverId, name: name, data: e.target.result });
            if (res.status === 'success') alert('Emoji :' + name + ': added!');
            else alert(res.message || 'Failed');
        };
        reader.readAsDataURL(file);
    };
    input.click();
}

