async function linkFamilyAccount() {
    const teen = prompt('Enter teen username to link:');
    if (!teen) return;
    const res = await apiRequest('LINK_FAMILY_ACCOUNT', { target: teen });
    if (res.status === 'success') { alert('Link request sent to ' + teen); loadFamilyCenter(); }
    else alert(res.message || 'Failed');
}

// ── Spotify Controls ──────────────────────────────────────────
let _spotifyConnected = false;
let _spotifyPlaying = false;

async function connectSpotify() {
    const res = await apiRequest('GET_SPOTIFY_STATUS');
    if (res.status === 'success' && res.connected) {
        _spotifyConnected = true;
        const player = document.getElementById('spotify-player');
        if (player) player.style.display = 'block';
        updateSpotifyUI(res);
    }
}

function updateSpotifyUI(data) {
    if (!data) return;
    const track = document.getElementById('spotify-track');
    const artist = document.getElementById('spotify-artist');
    const art = document.getElementById('spotify-art');
    const btn = document.getElementById('spotify-play-btn');
    if (track) track.textContent = data.track || 'Not Playing';
    if (artist) artist.textContent = data.artist || '';
    if (art && data.album_art) art.src = data.album_art;
    _spotifyPlaying = data.is_playing || false;
    if (btn) btn.textContent = _spotifyPlaying ? '⏸' : '▶';
}

async function spotifyControl(action) {
    const res = await apiRequest('SPOTIFY_CONTROL', { control: action });
    if (res.status === 'success') {
        if (action === 'toggle') {
            _spotifyPlaying = !_spotifyPlaying;
            const btn = document.getElementById('spotify-play-btn');
            if (btn) btn.textContent = _spotifyPlaying ? '⏸' : '▶';
        }
        // Refresh after skip
        if (action === 'prev' || action === 'next') {
            setTimeout(() => connectSpotify(), 500);
        }
    }
}

// Poll Spotify status every 30s if connected
setInterval(() => { if (_spotifyConnected) connectSpotify(); }, 30000);
// Try connecting on load
setTimeout(connectSpotify, 3000);

// ── Auto-DND While Playing ───────────────────────────────────
let _autoDND = localStorage.getItem('tenshi_auto_dnd') === 'true';
let _preDNDStatus = null;

function toggleAutoDND() {
    _autoDND = !_autoDND;
    localStorage.setItem('tenshi_auto_dnd', _autoDND);
    return _autoDND;
}

// Check for game activity and auto-set DND
async function checkGameActivity() {
    if (!_autoDND) return;
    const res = await apiRequest('GET_ACTIVITY');
    if (res.status === 'success' && res.playing) {
        if (_preDNDStatus === null) {
            _preDNDStatus = 'Online';
            await apiRequest('UPDATE_CUSTOM_STATUS', { status_type: 'dnd', status_text: 'Playing ' + (res.game_name || 'a game') });
            const dot = document.getElementById('statusbar-dot');
            if (dot) { dot.className = 'status-dot dnd'; }
            const status = document.getElementById('statusbar-status');
            if (status) status.textContent = 'Do Not Disturb';
        }
    } else if (_preDNDStatus !== null) {
        await apiRequest('UPDATE_CUSTOM_STATUS', { status_type: 'online', status_text: '' });
        _preDNDStatus = null;
        const dot = document.getElementById('statusbar-dot');
        if (dot) { dot.className = 'status-dot online'; }
        const status = document.getElementById('statusbar-status');
        if (status) status.textContent = 'Online';
    }
}
setInterval(checkGameActivity, 15000);

// ── Better Activities (member list shows activities) ──────────
function renderMemberList(members) {
    const container = document.getElementById('member-list-content');
    if (!container || _optimizeMode) return;
    if (!members || !members.length) {
        container.innerHTML = '<div style="padding:16px;color:var(--text-muted);font-size:12px;text-align:center;">No members</div>';
        return;
    }
    // Fetch online status, activities, avatars, colors
    apiRequest('GET_MEMBERS_ACTIVITY', { usernames: members }).then(res => {
        if (res.status !== 'success') {
            container.innerHTML = members.map(m =>
                `<div class="member-item" onclick="_showUserProfileCard('${_escAttr(m)}')" oncontextmenu="event.preventDefault();showUserContextMenu(event,'${_escAttr(m)}')"><div class="member-avatar">${(m[0]||'?').toUpperCase()}</div><span>${_escAttr(m)}</span></div>`
            ).join('');
            return;
        }
        const data = res.members || {};
        let onlineItems = [], offlineItems = [];
        let onlineCount = 0, offlineCount = 0;
        members.forEach(m => {
            const info = data[m] || {};
            const isOnline = info.online;
            const activity = info.activity || '';
            const avatar = info.avatar_full || '';
            const nameColor = info.username_color || '#ffffff';
            const profileColor = info.profile_color || '#0078d4';
            const badges = info.badges || [];
            const displayName = info.display_name || m;

            // Avatar: show image if available, otherwise styled initial
            const avatarHtml = avatar
                ? `<img src="${avatar}" style="width:32px;height:32px;border-radius:50%;object-fit:cover;" onerror="this.outerHTML='<div class=\\'member-avatar\\' style=\\'background:${profileColor};\\'>${(m[0]||'?').toUpperCase()}</div>'">`
                : `<div class="member-avatar" style="background:${_escAttr(profileColor)};">${(m[0]||'?').toUpperCase()}</div>`;

            // Activity line
            const activityHtml = activity ? `<div style="font-size:10px;color:#1DB954;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${_escAttr(activity)}</div>` : '';

            // Badge icons
            const badgeHtml = badges.map(b => {
                if (b === 'verified') return '<span title="Verified" style="font-size:10px;margin-left:3px;">✅</span>';
                if (b === 'beta') return '<span title="Beta Tester" style="font-size:10px;margin-left:3px;">🧪</span>';
                return '';
            }).join('');

            const item = `<div class="member-item" style="opacity:${isOnline ? '1' : '0.5'};cursor:pointer;"
                onclick="_showUserProfileCard('${_escAttr(m)}')"
                oncontextmenu="event.preventDefault();showUserContextMenu(event,'${_escAttr(m)}')">
                <div style="position:relative;flex-shrink:0;">
                    ${avatarHtml}
                    <div class="status-dot ${isOnline ? 'online' : 'offline'}" style="width:8px;height:8px;position:absolute;bottom:-1px;right:-1px;border:2px solid var(--panel-bg);border-radius:50%;"></div>
                </div>
                <div style="flex:1;overflow:hidden;min-width:0;margin-left:8px;">
                    <div style="display:flex;align-items:center;">
                        <span style="font-size:13px;font-weight:500;color:${_escAttr(nameColor)};overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${_escAttr(displayName)}</span>
                        ${badgeHtml}
                    </div>
                    ${activityHtml}
                </div>
            </div>`;
            if (isOnline) { onlineItems.push(item); onlineCount++; }
            else { offlineItems.push(item); offlineCount++; }
        });
        container.innerHTML =
            `<div class="member-panel-header">ONLINE — ${onlineCount}</div>` +
            onlineItems.join('') +
            `<div class="member-panel-header" style="margin-top:12px;">OFFLINE — ${offlineCount}</div>` +
            offlineItems.join('');
    });
}

