async function editServerNickname(serverId) {
    const nick = prompt('Enter your nickname for this server:');
    if (nick === null) return;
    const res = await apiRequest('SET_SERVER_NICKNAME', { server_id: serverId, nickname: nick });
    if (res.status === 'success') alert('Nickname updated!');
    else alert(res.message || 'Failed');
}

async function setCustomStatus() {
    const text = prompt('Custom status text:', '');
    if (text === null) return;
    await apiRequest('UPDATE_CUSTOM_STATUS', { status_text: text });
    const st = document.getElementById('statusbar-status');
    if (st) st.textContent = text || 'Online';
}

async function setStatusType(type) {
    await apiRequest('UPDATE_CUSTOM_STATUS', { status_type: type });
    const dot = document.getElementById('statusbar-dot');
    if (dot) dot.className = 'status-dot ' + type;
    const st = document.getElementById('statusbar-status');
    const labels = { online: 'Online', idle: 'Idle', dnd: 'Do Not Disturb', invisible: 'Invisible' };
    if (st) st.textContent = labels[type] || type;
}

// ── Better Ban Reasons (pre-written templates) ────────────────
const BAN_REASON_TEMPLATES = [
    { label: 'Spam / Flooding', reason: 'Excessive spam or flooding in text channels.' },
    { label: 'Harassment', reason: 'Targeted harassment or bullying of other members.' },
    { label: 'NSFW Content', reason: 'Posting NSFW or explicit content outside of designated channels.' },
    { label: 'Hate Speech', reason: 'Use of hate speech, slurs, or discriminatory language.' },
    { label: 'Scam / Phishing', reason: 'Sharing scam links or attempting phishing.' },
    { label: 'Underage', reason: 'User is under the minimum age requirement.' },
    { label: 'Alt Account', reason: 'Using an alternate account to evade a previous ban.' },
    { label: 'Raid Participation', reason: 'Participating in a coordinated raid against the server.' },
    { label: 'Custom...', reason: '' },
];

function showBanDialog(targetUser, serverId) {
    const existing = document.querySelector('.ban-dialog');
    if (existing) existing.remove();
    const dialog = document.createElement('div');
    dialog.className = 'ban-dialog';
    dialog.style.cssText = 'position:fixed;inset:0;z-index:600;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;';
    dialog.innerHTML = `
        <div style="background:#2b2d31;border-radius:14px;width:420px;max-width:95vw;padding:24px;border:1px solid #404249;">
            <h3 style="color:white;margin:0 0 4px;">Ban ${_escAttr(targetUser)}</h3>
            <p style="color:var(--text-muted);font-size:12px;margin:0 0 16px;">Select a reason or write a custom one.</p>
            <div style="display:flex;flex-direction:column;gap:6px;max-height:240px;overflow-y:auto;margin-bottom:14px;">
                ${BAN_REASON_TEMPLATES.map((t, i) => `
                    <label style="display:flex;align-items:center;gap:8px;padding:8px;background:rgba(255,255,255,0.04);border-radius:6px;cursor:pointer;" onmouseover="this.style.background='rgba(255,255,255,0.08)'" onmouseout="this.style.background='rgba(255,255,255,0.04)'">
                        <input type="radio" name="ban-reason" value="${i}" style="accent-color:var(--accent-blue);" ${i === 0 ? 'checked' : ''} onchange="document.getElementById('ban-custom-reason').style.display=this.value==='${BAN_REASON_TEMPLATES.length - 1}'?'block':'none'">
                        <span style="color:white;font-size:13px;">${t.label}</span>
                    </label>
                `).join('')}
            </div>
            <textarea id="ban-custom-reason" placeholder="Custom reason..." style="display:none;width:100%;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;padding:8px;border-radius:6px;font-size:13px;resize:none;height:60px;box-sizing:border-box;margin-bottom:10px;"></textarea>
            <div style="display:flex;gap:8px;">
                <button onclick="executeBan('${_escAttr(targetUser)}','${_escAttr(serverId)}')" style="flex:1;background:#ed4245;color:white;border:none;padding:10px;border-radius:8px;cursor:pointer;font-weight:600;">Ban User</button>
                <button onclick="this.closest('.ban-dialog').remove()" style="flex:1;background:rgba(255,255,255,0.08);color:white;border:none;padding:10px;border-radius:8px;cursor:pointer;">Cancel</button>
            </div>
        </div>
    `;
    document.body.appendChild(dialog);
    dialog.onclick = e => { if (e.target === dialog) dialog.remove(); };
}

async function executeBan(targetUser, serverId) {
    const selected = document.querySelector('input[name="ban-reason"]:checked');
    let reason;
    if (selected && parseInt(selected.value) === BAN_REASON_TEMPLATES.length - 1) {
        reason = document.getElementById('ban-custom-reason')?.value || 'No reason provided';
    } else if (selected) {
        reason = BAN_REASON_TEMPLATES[parseInt(selected.value)].reason;
    } else {
        reason = 'No reason provided';
    }
    const res = await apiRequest('BAN_USER', { target: targetUser, server_id: serverId, reason: reason });
    document.querySelector('.ban-dialog')?.remove();
    if (res.status === 'success') alert(targetUser + ' has been banned: ' + reason);
    else alert(res.message || 'Ban failed');
}

// ══════════════════════════════════════════════════════════════
// ── ACTIVITIES (Mini-Games in Voice Channels) ─────────────────
// ══════════════════════════════════════════════════════════════

const ACTIVITIES = [
    { id: 'tictactoe', name: 'Tic Tac Toe', icon: '❌', desc: 'Classic 3x3 grid game', players: '1-6' },
    { id: 'rps', name: 'Rock Paper Scissors', icon: '✊', desc: 'Best of 3 rounds', players: '1-6' },
    { id: 'trivia', name: 'Trivia Quiz', icon: '🧠', desc: 'Answer random questions', players: '1-6' },
    { id: 'drawing', name: 'Collaborative Whiteboard', icon: '🎨', desc: 'Draw together in real-time', players: '1-6' },
    { id: 'wordchain', name: 'Word Chain', icon: '🔤', desc: 'Each word starts with the last letter', players: '1-6' },
    { id: 'poker', name: 'Poker (Texas Hold\'em)', icon: '🃏', desc: 'Play with virtual chips', players: '1-6' },
    { id: 'chess', name: 'Chess', icon: '♟️', desc: 'Classic chess game', players: '1-6' },
    { id: '8ball', name: 'Magic 8-Ball', icon: '🎱', desc: 'Ask a question, get an answer', players: '1-6' },
    { id: 'tenshidance', name: 'Tenshi Dance', icon: '💃', desc: 'DDR rhythm game synced to music', players: '1-6' },
];

function showActivities() {
    document.querySelector('.activities-modal')?.remove();
    const modal = document.createElement('div');
    modal.className = 'activities-modal';
    modal.style.cssText = 'position:fixed;inset:0;z-index:600;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;';
    modal.innerHTML = `
        <div style="background:#2b2d31;border-radius:14px;width:480px;max-width:95vw;max-height:85vh;overflow-y:auto;padding:24px;border:1px solid #404249;">
            <h3 style="color:white;margin:0 0 4px;font-size:18px;">🎮 Activities</h3>
            <p style="color:var(--text-muted);font-size:12px;margin:0 0 16px;">Launch a game or activity for everyone in the voice channel.</p>
            <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:10px;">
                ${ACTIVITIES.map(a => `
                    <div onclick="launchActivity('${a.id}')" style="background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.06);border-radius:10px;padding:14px;cursor:pointer;transition:background 0.15s;" onmouseover="this.style.background='rgba(255,255,255,0.08)'" onmouseout="this.style.background='rgba(255,255,255,0.04)'">
                        <div style="font-size:28px;margin-bottom:6px;">${a.icon}</div>
                        <div style="color:white;font-weight:bold;font-size:14px;">${a.name}</div>
                        <div style="color:var(--text-muted);font-size:11px;margin-top:2px;">${a.desc}</div>
                        <div style="display:flex;align-items:center;gap:6px;margin-top:4px;">
                            <span style="color:var(--accent-blue);font-size:10px;">${a.players} players</span>
                            ${_MULTIPLAYER_GAMES.includes(a.id) ? '<span style="background:rgba(88,101,242,0.15);color:#5865F2;font-size:9px;padding:1px 6px;border-radius:4px;">MULTIPLAYER</span>' : ''}
                        </div>
                    </div>
                `).join('')}
            </div>
            <div style="margin-top:12px;display:flex;gap:8px;align-items:center;">
                <input id="activity-join-code" type="text" placeholder="Enter game code to join..." maxlength="6"
                    style="flex:1;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;padding:10px;border-radius:8px;font-size:13px;text-transform:uppercase;text-align:center;letter-spacing:2px;"
                    onkeydown="if(event.key==='Enter'){const c=this.value.trim();if(c){document.querySelector('.activities-modal')?.remove();_joinGameSession(c);}}">
                <button onclick="const c=document.getElementById('activity-join-code')?.value?.trim();if(c){document.querySelector('.activities-modal')?.remove();_joinGameSession(c);}" style="background:#23a559;color:white;border:none;padding:10px 16px;border-radius:8px;cursor:pointer;font-size:13px;font-weight:600;">Join</button>
            </div>
            <button onclick="this.closest('.activities-modal').remove()" style="margin-top:8px;width:100%;background:rgba(255,255,255,0.08);color:white;border:none;padding:10px;border-radius:8px;cursor:pointer;">Close</button>
        </div>
    `;
    document.body.appendChild(modal);
    modal.onclick = e => { if (e.target === modal) modal.remove(); };
}

// ── Multiplayer Session State ─────────────────────────────
let _activeGameSession = null;   // current session ID
let _gameSessionVersion = -1;    // for change detection polling
let _gamePollTimer = null;       // polling interval

const _MULTIPLAYER_GAMES = ['tictactoe', 'rps', 'trivia', 'chess', 'wordchain'];

function launchActivity(id) {
    document.querySelector('.activities-modal')?.remove();
    const activity = ACTIVITIES.find(a => a.id === id);
    if (!activity) return;

    // If multiplayer-capable, show choice
    if (_MULTIPLAYER_GAMES.includes(id)) {
        _showPlayModeChoice(activity);
        return;
    }

    // Solo-only games
    apiRequest('START_ACTIVITY', { activity_id: id, activity_name: activity.name });
    const mc = document.getElementById('message-container');
    if (!mc) return;
    _launchSoloGame(id, mc);
}

function _launchSoloGame(id, mc) {
    switch (id) {
        case 'tictactoe': renderTicTacToe(mc); break;
        case 'rps': renderRPS(mc); break;
        case 'trivia': renderTrivia(mc); break;
        case 'drawing': renderWhiteboard(mc); break;
        case 'wordchain': renderWordChain(mc); break;
        case 'chess': renderChess(mc); break;
        case '8ball': render8Ball(mc); break;
        case 'poker': renderPoker(mc); break;
        case 'tenshidance': renderTenshiDance(mc); break;
        default: mc.innerHTML = `<div style="text-align:center;padding:40px;color:white;">Activity "${activity.name}" coming soon!</div>`;
    }
}

function _showPlayModeChoice(activity) {
    const isMobile = window.innerWidth <= 600;
    document.querySelector('.game-mode-modal')?.remove();
    const modal = document.createElement('div');
    modal.className = 'game-mode-modal';
    modal.style.cssText = 'position:fixed;inset:0;z-index:650;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;';
    modal.innerHTML = `
        <div style="background:#2b2d31;border-radius:14px;width:400px;max-width:92vw;padding:${isMobile?'20px':'28px'};border:1px solid #404249;text-align:center;">
            <div style="font-size:40px;margin-bottom:8px;">${activity.icon}</div>
            <h3 style="color:white;margin:0 0 4px;font-size:${isMobile?'17px':'20px'};">${activity.name}</h3>
            <p style="color:var(--text-muted);font-size:12px;margin:0 0 20px;">${activity.desc}</p>
            <div style="display:flex;flex-direction:column;gap:10px;">
                <button onclick="document.querySelector('.game-mode-modal')?.remove();apiRequest('START_ACTIVITY',{activity_id:'${activity.id}',activity_name:'${activity.name}'});_launchSoloGame('${activity.id}',document.getElementById('message-container'))"
                    style="background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.1);color:white;padding:14px;border-radius:10px;cursor:pointer;font-size:15px;display:flex;align-items:center;gap:10px;justify-content:center;">
                    🎮 <span><b>Play Solo</b><br><span style="font-size:11px;color:var(--text-muted);">Play against the computer</span></span>
                </button>
                <button onclick="document.querySelector('.game-mode-modal')?.remove();_createGameSession('${activity.id}','${activity.name}')"
                    style="background:rgba(88,101,242,0.15);border:1px solid rgba(88,101,242,0.3);color:white;padding:14px;border-radius:10px;cursor:pointer;font-size:15px;display:flex;align-items:center;gap:10px;justify-content:center;">
                    👥 <span><b>Multiplayer</b><br><span style="font-size:11px;color:var(--accent-blue);">Invite friends to play together</span></span>
                </button>
                <div style="display:flex;gap:8px;align-items:center;">
                    <input id="join-game-code-input" type="text" placeholder="Have a code? Enter it here..." maxlength="6"
                        style="flex:1;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;padding:10px;border-radius:8px;font-size:13px;text-transform:uppercase;text-align:center;letter-spacing:2px;"
                        onkeydown="if(event.key==='Enter')_joinGameByCode()">
                    <button onclick="_joinGameByCode()" style="background:#23a559;color:white;border:none;padding:10px 14px;border-radius:8px;cursor:pointer;font-size:13px;font-weight:600;">Join</button>
                </div>
            </div>
            <button onclick="this.closest('.game-mode-modal').remove()" style="margin-top:12px;background:none;color:var(--text-muted);border:none;cursor:pointer;font-size:12px;">Cancel</button>
        </div>`;
    document.body.appendChild(modal);
    modal.onclick = e => { if (e.target === modal) modal.remove(); };
}

function _joinGameByCode() {
    const input = document.getElementById('join-game-code-input');
    if (!input) return;
    const code = input.value.trim().toUpperCase();
    if (!code || code.length < 4) { input.style.borderColor = '#ed4245'; return; }
    document.querySelector('.game-mode-modal')?.remove();
    _joinGameSession(code);
}

async function _createGameSession(gameId, gameName) {
    const maxP = (gameId === 'chess' || gameId === 'tictactoe') ? 2 : (gameId === 'rps' ? 2 : 6);
    const res = await apiRequest('CREATE_GAME', { game_id: gameId, game_name: gameName, max_players: maxP });
    if (res.status === 'success') {
        _activeGameSession = res.session_id;
        _gameSessionVersion = -1;
        _showGameLobby(res.session_id, gameId, gameName);
    } else {
        showGlobalNotification(res.message || 'Failed to create game session.');
    }
}

async function _joinGameSession(sessionId) {
    const res = await apiRequest('JOIN_GAME', { session_id: sessionId });
    if (res.status === 'success') {
        _activeGameSession = sessionId;
        _gameSessionVersion = -1;
        const sess = res.session;
        if (sess.started) {
            _renderMultiplayerGame(sess);
        } else {
            _showGameLobby(sessionId, sess.game, sess.game_name);
        }
    } else {
        showGlobalNotification(res.message || 'Could not join game.');
    }
}

function _showGameLobby(sessionId, gameId, gameName) {
    const mc = document.getElementById('message-container');
    if (!mc) return;
    const activity = ACTIVITIES.find(a => a.id === gameId);
    const icon = activity ? activity.icon : '🎮';

    // Start polling for lobby updates
    _startGamePoll(sessionId);

    _renderLobbyUI(mc, sessionId, gameId, gameName, icon);
}

async function _renderLobbyUI(mc, sessionId, gameId, gameName, icon) {
    const res = await apiRequest('GET_GAME', { session_id: sessionId });
    if (res.status !== 'success') return;
    const sess = res.session;
    if (sess.started) { _renderMultiplayerGame(sess); return; }

    const isMobile = window.innerWidth <= 600;
    const isHost = sess.host === currentUser;
    const players = sess.players || [];
    const pInfo = sess.player_info || {};

    mc.innerHTML = `
        <div style="display:flex;flex-direction:column;align-items:center;padding:${isMobile?'16px':'30px'};gap:16px;max-width:500px;margin:0 auto;">
            <div style="font-size:48px;">${icon}</div>
            <h3 style="color:white;margin:0;font-size:${isMobile?'18px':'22px'};">${gameName}</h3>
            <div style="color:var(--text-muted);font-size:13px;">Waiting for players... (${players.length}/${sess.max_players})</div>

            <div style="background:rgba(0,0,0,0.3);border:1px solid var(--glass-border);border-radius:12px;padding:16px;width:100%;">
                <div style="color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:.5px;margin-bottom:10px;">Players</div>
                ${players.map(p => {
                    const pi = pInfo[p] || {};
                    const dn = pi.display_name || p;
                    const av = pi.avatar ? `<img src="${pi.avatar}" style="width:32px;height:32px;border-radius:50%;object-fit:cover;">` : `<div style="width:32px;height:32px;border-radius:50%;background:var(--accent-blue);display:flex;align-items:center;justify-content:center;color:white;font-weight:bold;">${dn[0].toUpperCase()}</div>`;
                    const hostBadge = p === sess.host ? '<span style="background:rgba(88,101,242,0.2);color:#5865F2;font-size:9px;padding:2px 6px;border-radius:4px;margin-left:6px;">HOST</span>' : '';
                    const youBadge = p === currentUser ? '<span style="background:rgba(35,165,89,0.2);color:#23a559;font-size:9px;padding:2px 6px;border-radius:4px;margin-left:4px;">YOU</span>' : '';
                    return `<div style="display:flex;align-items:center;gap:10px;padding:8px 0;${p !== players[players.length-1] ? 'border-bottom:1px solid rgba(255,255,255,0.05);' : ''}">${av}<div style="color:white;font-size:14px;font-weight:600;">${dn.replace(/</g,'&lt;')}${hostBadge}${youBadge}</div></div>`;
                }).join('')}
            </div>

            <div style="background:rgba(88,101,242,0.08);border:1px dashed rgba(88,101,242,0.3);border-radius:10px;padding:14px;width:100%;text-align:center;">
                <div style="color:var(--text-muted);font-size:11px;margin-bottom:8px;">Share this code to invite friends</div>
                <div style="display:flex;align-items:center;justify-content:center;gap:8px;">
                    <span style="font-size:${isMobile?'22px':'28px'};font-weight:900;letter-spacing:4px;color:white;font-family:monospace;">${sessionId}</span>
                    <button onclick="navigator.clipboard.writeText('${sessionId}');this.textContent='✓ Copied'" style="background:rgba(255,255,255,0.1);color:white;border:none;padding:6px 12px;border-radius:6px;cursor:pointer;font-size:12px;">📋 Copy</button>
                </div>
            </div>

            <div style="display:flex;gap:8px;flex-wrap:wrap;justify-content:center;width:100%;">
                <button onclick="_showInvitePicker('${sessionId}')" style="flex:1;min-width:140px;background:rgba(88,101,242,0.15);border:1px solid rgba(88,101,242,0.3);color:white;padding:10px;border-radius:8px;cursor:pointer;font-size:13px;">👥 Invite Friends</button>
                ${isHost ? `<button id="game-start-btn" onclick="_startGame('${sessionId}')" ${players.length < 2 ? 'disabled style="flex:1;min-width:140px;background:rgba(35,165,89,0.15);border:1px solid rgba(35,165,89,0.2);color:rgba(255,255,255,0.4);padding:10px;border-radius:8px;cursor:not-allowed;font-size:13px;"' : 'style="flex:1;min-width:140px;background:#23a559;border:none;color:white;padding:10px;border-radius:8px;cursor:pointer;font-size:13px;font-weight:600;"'}>▶ Start Game</button>` : '<div style="color:var(--text-muted);font-size:12px;padding:10px;">Waiting for host to start...</div>'}
                <button onclick="_leaveGame('${sessionId}')" style="background:rgba(237,66,69,0.1);border:1px solid rgba(237,66,69,0.2);color:#ed4245;padding:10px 16px;border-radius:8px;cursor:pointer;font-size:13px;">Leave</button>
            </div>
        </div>`;
}

async function _showInvitePicker(sessionId) {
    document.querySelector('.invite-picker-modal')?.remove();
    const isMobile = window.innerWidth <= 600;
    // Fetch friends list
    const res = await apiRequest('GET_FRIENDS');
    const friends = res.status === 'success' ? (res.friends || []) : [];

    const modal = document.createElement('div');
    modal.className = 'invite-picker-modal';
    modal.style.cssText = 'position:fixed;inset:0;z-index:700;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;';
    modal.innerHTML = `
        <div style="background:#2b2d31;border-radius:14px;width:380px;max-width:92vw;max-height:70vh;display:flex;flex-direction:column;border:1px solid #404249;">
            <div style="padding:16px 20px;border-bottom:1px solid rgba(255,255,255,0.06);">
                <h3 style="color:white;margin:0;font-size:16px;">👥 Invite to Game</h3>
                <p style="color:var(--text-muted);font-size:11px;margin:4px 0 0;">Select friends to invite</p>
            </div>
            <div style="flex:1;overflow-y:auto;padding:8px 12px;">
                ${friends.length === 0 ? '<div style="color:var(--text-muted);text-align:center;padding:20px;font-size:13px;">No friends to invite.</div>' :
                friends.map(f => {
                    const name = typeof f === 'string' ? f : (f.username || f);
                    return `<div style="display:flex;align-items:center;gap:10px;padding:10px 8px;border-radius:8px;cursor:pointer;transition:background .15s;" onmouseover="this.style.background='rgba(255,255,255,0.06)'" onmouseout="this.style.background='transparent'" onclick="_sendGameInvite('${sessionId}','${name}',this)">
                        <div style="width:36px;height:36px;border-radius:50%;background:var(--accent-blue);display:flex;align-items:center;justify-content:center;color:white;font-weight:bold;font-size:14px;">${name[0].toUpperCase()}</div>
                        <div style="flex:1;color:white;font-size:14px;">${name}</div>
                        <button class="invite-btn" style="background:var(--accent-blue);color:white;border:none;padding:6px 14px;border-radius:6px;cursor:pointer;font-size:12px;">Invite</button>
                    </div>`;
                }).join('')}
            </div>
            <div style="padding:12px 16px;border-top:1px solid rgba(255,255,255,0.06);text-align:center;">
                <button onclick="this.closest('.invite-picker-modal').remove()" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 20px;border-radius:8px;cursor:pointer;font-size:13px;">Done</button>
            </div>
        </div>`;
    document.body.appendChild(modal);
    modal.onclick = e => { if (e.target === modal) modal.remove(); };
}

async function _sendGameInvite(sessionId, target, el) {
    const btn = el.querySelector('.invite-btn');
    if (btn) { btn.textContent = '...'; btn.disabled = true; }
    const res = await apiRequest('INVITE_TO_GAME', { session_id: sessionId, target: target });
    if (btn) {
        if (res.status === 'success') {
            btn.textContent = '✓ Sent';
            btn.style.background = '#23a559';
        } else {
            btn.textContent = res.message || 'Failed';
            btn.style.background = '#ed4245';
        }
    }
}

async function _startGame(sessionId) {
    const btn = document.getElementById('game-start-btn');
    if (btn) { btn.textContent = 'Starting...'; btn.disabled = true; }
    const res = await apiRequest('START_GAME', { session_id: sessionId });
    if (res.status === 'success') {
        _renderMultiplayerGame(res.session);
    } else {
        showGlobalNotification(res.message || 'Could not start game.');
        if (btn) { btn.textContent = '▶ Start Game'; btn.disabled = false; }
    }
}

async function _leaveGame(sessionId) {
    _stopGamePoll();
    await apiRequest('LEAVE_GAME', { session_id: sessionId });
    _activeGameSession = null;
    _gameSessionVersion = -1;
    const mc = document.getElementById('message-container');
    if (mc) mc.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted);">You left the game.</div>';
}

function _startGamePoll(sessionId) {
    _stopGamePoll();
    _gamePollTimer = setInterval(() => _pollGameState(sessionId), 1500);
}

function _stopGamePoll() {
    if (_gamePollTimer) { clearInterval(_gamePollTimer); _gamePollTimer = null; }
}

async function _pollGameState(sessionId) {
    if (_activeGameSession !== sessionId) { _stopGamePoll(); return; }
    const res = await apiRequest('GET_GAME', { session_id: sessionId, version: _gameSessionVersion });
    if (res.status === 'no_change') return;
    if (res.status !== 'success') { _stopGamePoll(); return; }
    const sess = res.session;
    _gameSessionVersion = sess.version;
    if (sess.started) {
        _renderMultiplayerGame(sess);
    } else {
        // Re-render lobby
        const mc = document.getElementById('message-container');
        const activity = ACTIVITIES.find(a => a.id === sess.game);
        if (mc) _renderLobbyUI(mc, sessionId, sess.game, sess.game_name, activity ? activity.icon : '🎮');
    }
}

// ── Multiplayer Game Renderers ───────────────────────────
function _renderMultiplayerGame(sess) {
    const mc = document.getElementById('message-container');
    if (!mc) return;
    _startGamePoll(sess.id);

    switch (sess.game) {
        case 'tictactoe': _renderMP_TicTacToe(mc, sess); break;
        case 'rps': _renderMP_RPS(mc, sess); break;
        case 'trivia': _renderMP_Trivia(mc, sess); break;
        case 'chess': _renderMP_Chess(mc, sess); break;
        case 'wordchain': _renderMP_WordChain(mc, sess); break;
        default: mc.innerHTML = '<div style="text-align:center;padding:40px;color:white;">Multiplayer not available for this game.</div>';
    }
}

function _mpHeader(sess, subtitle) {
    const pInfo = sess.player_info || {};
    const scores = sess.scores || {};
    return `<div style="display:flex;align-items:center;justify-content:center;gap:16px;flex-wrap:wrap;margin-bottom:12px;">
        ${sess.players.map(p => {
            const pi = pInfo[p] || {};
            const dn = pi.display_name || p;
            const isMe = p === currentUser;
            const isTurn = p === sess.turn;
            return `<div style="display:flex;align-items:center;gap:6px;padding:6px 12px;border-radius:8px;background:${isTurn ? 'rgba(88,101,242,0.15)' : 'rgba(255,255,255,0.04)'};border:1px solid ${isTurn ? 'rgba(88,101,242,0.4)' : 'transparent'};">
                <div style="width:24px;height:24px;border-radius:50%;background:${isMe ? '#23a559' : 'var(--accent-blue)'};display:flex;align-items:center;justify-content:center;color:white;font-size:11px;font-weight:bold;">${dn[0].toUpperCase()}</div>
                <span style="color:white;font-size:13px;font-weight:${isMe?'700':'500'};">${dn.replace(/</g,'&lt;')}</span>
                <span style="color:var(--accent-blue);font-size:12px;font-weight:600;">${scores[p] || 0}</span>
                ${isTurn ? '<span style="font-size:10px;">◀</span>' : ''}
            </div>`;
        }).join('')}
    </div>${subtitle ? `<div style="color:var(--accent-blue);font-size:13px;text-align:center;margin-bottom:8px;">${subtitle}</div>` : ''}`;
}

// ── MP Tic Tac Toe ──
function _renderMP_TicTacToe(mc, sess) {
    const board = sess.state.board || [];
    const symbols = sess.state.symbols || {};
    const mySym = symbols[currentUser] || '?';
    const isMyTurn = sess.turn === currentUser;
    const ended = sess.ended;
    const winner = sess.state.winner;

    let subtitle = '';
    if (ended) {
        subtitle = winner === 'draw' ? "It's a draw!" : (winner === currentUser ? '🎉 You win!' : `${(sess.player_info[winner]||{}).display_name || winner} wins!`);
    } else {
        subtitle = isMyTurn ? `Your turn (${mySym})` : `Waiting for opponent...`;
    }

    mc.innerHTML = `
        <div style="display:flex;flex-direction:column;align-items:center;padding:20px;gap:8px;">
            <h3 style="color:white;margin:0;">❌ Tic Tac Toe — Multiplayer</h3>
            ${_mpHeader(sess, subtitle)}
            <div style="display:grid;grid-template-columns:repeat(3,80px);gap:4px;">
                ${board.map((cell, i) => `<div class="mp-ttt-cell" data-idx="${i}" style="width:80px;height:80px;background:${cell ? 'rgba(255,255,255,0.03)' : 'rgba(255,255,255,0.06)'};border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:32px;font-weight:bold;cursor:${!cell && isMyTurn && !ended ? 'pointer' : 'default'};user-select:none;color:${cell === 'X' ? '#5865F2' : '#ed4245'};transition:background 0.15s;">${cell}</div>`).join('')}
            </div>
            ${ended ? `<div style="display:flex;gap:8px;margin-top:8px;"><button onclick="_leaveGame('${sess.id}')" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 20px;border-radius:8px;cursor:pointer;font-size:13px;">Leave</button></div>` : ''}
        </div>`;

    if (!ended && isMyTurn) {
        mc.querySelectorAll('.mp-ttt-cell').forEach(cell => {
            cell.onclick = async () => {
                const idx = parseInt(cell.dataset.idx);
                if (board[idx]) return;
                cell.textContent = mySym;
                cell.style.cursor = 'default';
                await apiRequest('GAME_MOVE', { session_id: sess.id, move: { cell: idx } });
            };
            cell.onmouseover = () => { if (!board[parseInt(cell.dataset.idx)]) cell.style.background = 'rgba(255,255,255,0.12)'; };
            cell.onmouseout = () => cell.style.background = board[parseInt(cell.dataset.idx)] ? 'rgba(255,255,255,0.03)' : 'rgba(255,255,255,0.06)';
        });
    }
}

// ── MP Rock Paper Scissors ──
function _renderMP_RPS(mc, sess) {
    const state = sess.state;
    const ended = sess.ended;
    const myChoice = state.choices?.[currentUser];
    const results = state.results || [];
    const lastResult = results.length ? results[results.length - 1] : null;

    let subtitle = '';
    if (ended) {
        subtitle = state.match_winner === currentUser ? '🎉 You win the match!' : `${(sess.player_info[state.match_winner]||{}).display_name || state.match_winner} wins!`;
    } else if (myChoice) {
        subtitle = 'Waiting for opponent to choose...';
    } else {
        subtitle = `Round ${state.round} — Pick your move!`;
    }

    mc.innerHTML = `
        <div style="display:flex;flex-direction:column;align-items:center;padding:20px;gap:12px;">
            <h3 style="color:white;margin:0;">✊ Rock Paper Scissors — Multiplayer</h3>
            ${_mpHeader(sess, subtitle)}
            ${lastResult ? `<div style="background:rgba(255,255,255,0.04);border-radius:8px;padding:10px 16px;color:var(--text-muted);font-size:12px;">
                Last round: ${Object.entries(lastResult.choices).map(([p, c]) => `${(sess.player_info[p]||{}).display_name || p}: ${c}`).join(' vs ')}
                ${lastResult.winner === 'draw' ? '— Draw!' : `— ${(sess.player_info[lastResult.winner]||{}).display_name || lastResult.winner} wins!`}
            </div>` : ''}
            ${!ended && !myChoice ? `<div style="display:flex;gap:12px;">
                ${['✊ Rock','✋ Paper','✌️ Scissors'].map(c => {
                    const choice = c.split(' ')[1].toLowerCase();
                    return `<button onclick="_mpRPSChoice('${sess.id}','${choice}',this)" style="background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.1);color:white;padding:16px 24px;border-radius:12px;cursor:pointer;font-size:18px;transition:transform 0.15s;" onmouseover="this.style.transform='scale(1.1)'" onmouseout="this.style.transform='scale(1)'">${c}</button>`;
                }).join('')}
            </div>` : (!ended && myChoice ? `<div style="color:#23a559;font-size:16px;">You chose: ${myChoice} ✓</div>` : '')}
            ${ended ? `<button onclick="_leaveGame('${sess.id}')" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 20px;border-radius:8px;cursor:pointer;font-size:13px;">Leave</button>` : ''}
        </div>`;
}

async function _mpRPSChoice(sessionId, choice, btn) {
    btn.parentElement.querySelectorAll('button').forEach(b => { b.disabled = true; b.style.opacity = '0.5'; });
    btn.style.opacity = '1';
    btn.style.border = '2px solid #23a559';
    await apiRequest('GAME_MOVE', { session_id: sessionId, move: { choice } });
}

// ── MP Trivia ──
function _renderMP_Trivia(mc, sess) {
    const state = sess.state;
    const ended = sess.ended;
    const questions = state.questions || [];
    const cur = state.current || 0;
    const answered = state.answered || {};
    const curAnswers = answered[String(cur)] || {};
    const myAnswer = curAnswers[currentUser];
    const allAnswered = Object.keys(curAnswers).length >= sess.players.length;
    const reveal = state.reveal || allAnswered;

    if (ended) {
        // Final scores
        const scores = state.scores || {};
        const sorted = Object.entries(scores).sort((a, b) => b[1] - a[1]);
        mc.innerHTML = `
            <div style="display:flex;flex-direction:column;align-items:center;padding:30px;gap:16px;">
                <h3 style="color:white;margin:0;">🧠 Trivia — Final Results</h3>
                ${sorted.map(([p, s], i) => `<div style="display:flex;align-items:center;gap:12px;padding:12px 20px;background:rgba(255,255,255,0.04);border-radius:10px;width:100%;max-width:300px;${i === 0 ? 'border:1px solid #23a559;' : ''}">
                    <span style="font-size:24px;">${i === 0 ? '🥇' : i === 1 ? '🥈' : '🥉'}</span>
                    <span style="color:white;font-size:15px;flex:1;">${(sess.player_info[p]||{}).display_name || p}</span>
                    <span style="color:var(--accent-blue);font-size:18px;font-weight:bold;">${s}/${questions.length}</span>
                </div>`).join('')}
                <button onclick="_leaveGame('${sess.id}')" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 20px;border-radius:8px;cursor:pointer;font-size:13px;">Leave</button>
            </div>`;
        return;
    }

    const q = questions[cur];
    if (!q) return;

    mc.innerHTML = `
        <div style="display:flex;flex-direction:column;align-items:center;padding:20px;gap:12px;">
            <h3 style="color:white;margin:0;">🧠 Trivia — Multiplayer</h3>
            ${_mpHeader(sess, `Question ${cur + 1}/${questions.length}`)}
            <h3 style="color:white;margin:0;text-align:center;max-width:450px;font-size:16px;">${q.q}</h3>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;width:100%;max-width:400px;">
                ${q.a.map((a, i) => {
                    const isCorrect = i === q.c;
                    let bg = 'rgba(255,255,255,0.06)';
                    let border = 'rgba(255,255,255,0.1)';
                    if (reveal) {
                        if (isCorrect) { bg = 'rgba(35,165,89,0.3)'; border = '#23a559'; }
                        else if (myAnswer !== undefined && myAnswer.answer === i && !isCorrect) { bg = 'rgba(237,66,69,0.3)'; border = '#ed4245'; }
                    } else if (myAnswer !== undefined && myAnswer.answer === i) {
                        bg = 'rgba(88,101,242,0.2)'; border = '#5865F2';
                    }
                    return `<button onclick="${myAnswer === undefined && !reveal ? `_mpTriviaAnswer('${sess.id}',${i},this)` : ''}" style="background:${bg};border:1px solid ${border};color:white;padding:12px;border-radius:8px;cursor:${myAnswer === undefined && !reveal ? 'pointer' : 'default'};font-size:14px;transition:background .2s;">${a}</button>`;
                }).join('')}
            </div>
            <div style="color:var(--text-muted);font-size:12px;">
                ${myAnswer !== undefined ? '✓ You answered' : 'Pick an answer'}
                ${reveal ? ` — ${Object.entries(curAnswers).filter(([,v]) => v.correct).length}/${Object.keys(curAnswers).length} correct` : ` — ${Object.keys(curAnswers).length}/${sess.players.length} answered`}
            </div>
            ${reveal && sess.host === currentUser ? `<button onclick="_mpTriviaNext('${sess.id}')" style="background:var(--accent-blue);color:white;border:none;padding:8px 20px;border-radius:8px;cursor:pointer;font-size:13px;">Next Question →</button>` : ''}
            ${reveal && sess.host !== currentUser ? `<div style="color:var(--text-muted);font-size:12px;">Waiting for host to continue...</div>` : ''}
        </div>`;
}

async function _mpTriviaAnswer(sessionId, answer, btn) {
    btn.parentElement.querySelectorAll('button').forEach(b => b.style.cursor = 'default');
    btn.style.background = 'rgba(88,101,242,0.2)';
    btn.style.border = '1px solid #5865F2';
    await apiRequest('GAME_MOVE', { session_id: sessionId, move: { answer } });
}

async function _mpTriviaNext(sessionId) {
    await apiRequest('TRIVIA_NEXT', { session_id: sessionId });
}

// ── MP Chess ──
function _renderMP_Chess(mc, sess) {
    const pieces = { K:'♔', Q:'♕', R:'♖', B:'♗', N:'♘', P:'♙', k:'♚', q:'♛', r:'♜', b:'♝', n:'♞', p:'♟' };
    const board = sess.state.board || [];
    const colors = sess.state.colors || {};
    const myColor = colors[currentUser] || 'white';
    const isMyTurn = sess.turn === currentUser;
    const ended = sess.ended;
    const winner = sess.state.winner;

    let subtitle = '';
    if (ended) subtitle = winner === currentUser ? '🎉 You win!' : `${(sess.player_info[winner]||{}).display_name || winner} wins!`;
    else subtitle = isMyTurn ? `Your turn (${myColor})` : 'Opponent\'s turn...';

    const isWhite = (p) => p === p.toUpperCase() && p !== '';

    mc.innerHTML = `
        <div style="display:flex;flex-direction:column;align-items:center;padding:10px;gap:8px;">
            <h3 style="color:white;margin:0;">♟️ Chess — Multiplayer</h3>
            ${_mpHeader(sess, subtitle)}
            <div id="mp-chess-board" style="display:grid;grid-template-columns:repeat(8,1fr);width:min(400px,90vw);aspect-ratio:1;">
                ${(() => {
                    let html = '';
                    for (let r = 0; r < 8; r++) {
                        for (let c = 0; c < 8; c++) {
                            const isDark = (r + c) % 2 === 1;
                            const bg = isDark ? '#779556' : '#ebecd0';
                            const piece = board[r]?.[c] || '';
                            html += `<div class="mp-chess-sq" data-r="${r}" data-c="${c}" style="background:${bg};display:flex;align-items:center;justify-content:center;font-size:min(5vw,32px);cursor:${isMyTurn && !ended ? 'pointer' : 'default'};user-select:none;aspect-ratio:1;">${piece ? pieces[piece] || '' : ''}</div>`;
                        }
                    }
                    return html;
                })()}
            </div>
            ${ended ? `<button onclick="_leaveGame('${sess.id}')" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 20px;border-radius:8px;cursor:pointer;font-size:13px;">Leave</button>` : ''}
        </div>`;

    if (!ended && isMyTurn) {
        let selected = null;
        mc.querySelectorAll('.mp-chess-sq').forEach(sq => {
            sq.onclick = async () => {
                const r = parseInt(sq.dataset.r), c = parseInt(sq.dataset.c);
                const piece = board[r]?.[c] || '';
                if (selected) {
                    const [sr, sc] = selected;
                    const movingPiece = board[sr][sc];
                    const canMove = (myColor === 'white' && isWhite(movingPiece)) || (myColor === 'black' && !isWhite(movingPiece));
                    if (canMove) {
                        if (piece && isWhite(piece) === isWhite(movingPiece)) {
                            // Select new piece
                            mc.querySelectorAll('.mp-chess-sq').forEach(s => { const rr = parseInt(s.dataset.r), cc = parseInt(s.dataset.c); s.style.background = (rr+cc)%2===1?'#779556':'#ebecd0'; });
                            sq.style.background = 'rgba(88,101,242,0.5)';
                            selected = [r, c];
                            return;
                        }
                        await apiRequest('GAME_MOVE', { session_id: sess.id, move: { from_r: sr, from_c: sc, to_r: r, to_c: c } });
                        selected = null;
                        return;
                    }
                    // Deselect
                    mc.querySelectorAll('.mp-chess-sq').forEach(s => { const rr = parseInt(s.dataset.r), cc = parseInt(s.dataset.c); s.style.background = (rr+cc)%2===1?'#779556':'#ebecd0'; });
                    selected = null;
                } else if (piece) {
                    const canSelect = (myColor === 'white' && isWhite(piece)) || (myColor === 'black' && !isWhite(piece));
                    if (canSelect) {
                        sq.style.background = 'rgba(88,101,242,0.5)';
                        selected = [r, c];
                    }
                }
            };
        });
    }
}

// ── MP Word Chain ──
function _renderMP_WordChain(mc, sess) {
    const state = sess.state;
    const words = state.words || [];
    const usedBy = state.used_by || [];
    const lastLetter = state.last_letter || '';
    const isMyTurn = sess.turn === currentUser;
    const ended = sess.ended;

    mc.innerHTML = `
        <div style="display:flex;flex-direction:column;align-items:center;padding:20px;gap:12px;">
            <h3 style="color:white;margin:0;">🔤 Word Chain — Multiplayer</h3>
            ${_mpHeader(sess, isMyTurn ? 'Your turn!' : `Waiting for ${(sess.player_info[sess.turn]||{}).display_name || sess.turn}...`)}
            <div style="max-height:200px;overflow-y:auto;width:100%;max-width:400px;padding:8px;background:rgba(0,0,0,0.2);border-radius:8px;">
                ${words.length === 0 ? '<div style="color:var(--text-muted);font-size:12px;text-align:center;">Waiting for first word...</div>' :
                words.map((w, i) => `<span style="color:${usedBy[i] === currentUser ? '#23a559' : '#5865F2'};font-weight:bold;" title="${usedBy[i]}">${w}</span>`).join(' → ')}
            </div>
            ${isMyTurn && !ended ? `<div style="display:flex;gap:8px;width:100%;max-width:400px;">
                <input id="mp-wc-input" type="text" placeholder="${lastLetter ? 'Start with ' + lastLetter.toUpperCase() + '...' : 'Type a word...'}" style="flex:1;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;padding:10px;border-radius:8px;font-size:14px;" onkeydown="if(event.key==='Enter')_mpWordChainSubmit('${sess.id}')">
                <button onclick="_mpWordChainSubmit('${sess.id}')" style="background:var(--accent-blue);color:white;border:none;padding:10px 16px;border-radius:8px;cursor:pointer;">Go</button>
            </div>
            <div id="mp-wc-error" style="color:#ed4245;font-size:12px;min-height:16px;"></div>` : ''}
            ${ended ? `<button onclick="_leaveGame('${sess.id}')" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:8px 20px;border-radius:8px;cursor:pointer;font-size:13px;">Leave</button>` : ''}
        </div>`;
}

async function _mpWordChainSubmit(sessionId) {
    const input = document.getElementById('mp-wc-input');
    const errorEl = document.getElementById('mp-wc-error');
    if (!input) return;
    const word = input.value.trim().toLowerCase();
    if (!word) return;
    const res = await apiRequest('GAME_MOVE', { session_id: sessionId, move: { word } });
    if (res.status === 'fail' && errorEl) {
        errorEl.textContent = res.message || 'Invalid word.';
    } else {
        input.value = '';
    }
}

