let _notifications = JSON.parse(localStorage.getItem('tenshi_notifs') || '[]');

function addNotification(type, title, detail, icon, target, actionable) {
    const notif = { id: Date.now(), type, title, detail, icon: icon || '🔔', time: new Date().toISOString(), read: false, target: target || '', actionable: actionable || false };
    _notifications.unshift(notif);
    if (_notifications.length > 50) _notifications = _notifications.slice(0, 50);
    localStorage.setItem('tenshi_notifs', JSON.stringify(_notifications));
    updateNotifBadge();
}

function updateNotifBadge() {
    const unread = _notifications.filter(n => !n.read).length;
    const countText = unread > 99 ? '99+' : unread > 0 ? String(unread) : '';
    // Update all alert badges (topbar, mobile tab bar, sidebar)
    ['notif-badge', 'topbar-notif-badge', 'mobile-notif-badge'].forEach(id => {
        const el = document.getElementById(id);
        if (el) {
            el.style.display = unread > 0 ? 'flex' : 'none';
            el.textContent = countText;
        }
    });
}

function loadNotifications() {
    stopMedia();
    if (currentChatInterval) clearInterval(currentChatInterval);
    currentTarget = null;
    localStorage.setItem('tenshi_last_view', 'notifs');
    const ca = document.getElementById('chat-header-actions'); if (ca) ca.style.display = 'none';
    const gi = document.getElementById('message-input-bar'); if (gi) gi.style.display = 'none';
    const tc = document.getElementById('topbar-channel-name'); if (tc) tc.style.display = 'none';

    document.getElementById('current-chat').innerText = '🔔 Notifications';
    document.getElementById('sidebar-header').innerText = 'NOTIFICATIONS';
    document.getElementById('dynamic-list').innerHTML = `
        <div class="channel-item" onclick="filterNotifs('all')" style="font-weight:bold;">📋 All</div>
        <div class="channel-item" onclick="filterNotifs('friend')">👥 Friend Requests</div>
        <div class="channel-item" onclick="filterNotifs('message')">💬 Messages</div>
        <div class="channel-item" onclick="filterNotifs('server')">🏠 Server</div>
        <div class="channel-item" onclick="filterNotifs('system')">⚙️ System</div>
        <hr style="border:0;border-top:1px solid rgba(255,255,255,0.06);margin:8px 16px;">
        <div class="channel-item" onclick="clearNotifications()" style="color:#ed4245;">🗑️ Clear All</div>
    `;

    // Mark all as read
    _notifications.forEach(n => n.read = true);
    localStorage.setItem('tenshi_notifs', JSON.stringify(_notifications));
    updateNotifBadge();

    renderNotifList('all');
}

function filterNotifs(type) {
    renderNotifList(type);
}

function renderNotifList(filter) {
    const mc = document.getElementById('message-container');
    if (!mc) return;
    const filtered = filter === 'all' ? _notifications : _notifications.filter(n => n.type === filter);

    if (!filtered.length) {
        mc.innerHTML = `<div style="text-align:center;padding:60px 20px;">
            <div style="font-size:48px;margin-bottom:16px;">🔔</div>
            <h3 style="color:white;margin:0 0 8px;">No notifications</h3>
            <p style="color:var(--text-muted);font-size:13px;">You're all caught up!</p>
        </div>`;
        return;
    }

    mc.innerHTML = filtered.map(n => {
        const timeAgo = _timeAgo(n.time);
        // Determine click action based on notification type
        let clickAction = '';
        if (n.type === 'friend') clickAction = `onclick="loadFriendsView()"`;
        else if (n.type === 'message' && n.target) clickAction = `onclick="openChat('${_escAttr(n.target)}')"`;
        else if (n.type === 'message') clickAction = `onclick="loadFriendsView()"`;
        else if (n.type === 'server') clickAction = `onclick="loadFriendsView()"`;
        const cursor = clickAction ? 'cursor:pointer;' : '';
        return `<div ${clickAction} style="display:flex;gap:12px;padding:12px 16px;border-bottom:1px solid rgba(255,255,255,0.04);${n.read ? '' : 'background:rgba(88,101,242,0.05);'}${cursor}transition:background 0.15s;" onmouseover="this.style.background='rgba(255,255,255,0.04)'" onmouseout="this.style.background='${n.read ? '' : 'rgba(88,101,242,0.05)'}'">
            <div style="font-size:24px;flex-shrink:0;">${n.icon}</div>
            <div style="flex:1;min-width:0;">
                <div style="color:white;font-size:14px;font-weight:600;">${_escAttr(n.title)}</div>
                <div style="color:var(--text-muted);font-size:12px;margin-top:2px;">${_escAttr(n.detail)}</div>
                <div style="color:var(--text-muted);font-size:10px;margin-top:4px;">${timeAgo}</div>
            </div>
            ${n.type === 'friend' && n.actionable ? `<div style="display:flex;gap:6px;flex-shrink:0;align-items:center;">
                <button onclick="event.stopPropagation();acceptFriend('${_escAttr(n.target || '')}');this.closest('div[style]').remove();" style="background:#23a559;color:white;border:none;padding:6px 12px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:bold;">Accept</button>
                <button onclick="event.stopPropagation();declineFriend('${_escAttr(n.target || '')}');this.closest('div[style]').remove();" style="background:#ed4245;color:white;border:none;padding:6px 12px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:bold;">Decline</button>
            </div>` : ''}
        </div>`;
    }).join('');
}

function clearNotifications() {
    _notifications = [];
    localStorage.setItem('tenshi_notifs', JSON.stringify(_notifications));
    updateNotifBadge();
    renderNotifList('all');
}

function _parseTs(val) {
    if (!val) return 0;
    if (typeof val === 'number') return val < 1e12 ? val * 1000 : val;
    const t = new Date(val).getTime();
    return isNaN(t) ? 0 : t;
}

function _timeAgo(val) {
    const ts = _parseTs(val);
    if (!ts) return '';
    const diff = Date.now() - ts;
    if (diff < 0) return 'Just now';
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'Just now';
    if (mins < 60) return mins + 'm ago';
    const hours = Math.floor(mins / 60);
    if (hours < 24) return hours + 'h ago';
    const days = Math.floor(hours / 24);
    if (days < 30) return days + 'd ago';
    const months = Math.floor(days / 30);
    if (months < 12) return months + 'mo ago';
    return Math.floor(days / 365) + 'y ago';
}

function _fullTime(val) {
    const ts = _parseTs(val);
    if (!ts) return '';
    const d = new Date(ts);
    const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const month = months[d.getMonth()];
    const day = d.getDate();
    const year = d.getFullYear();
    const h = d.getHours();
    const m = String(d.getMinutes()).padStart(2, '0');
    const ampm = h >= 12 ? 'PM' : 'AM';
    const h12 = h % 12 || 12;
    const tz = Intl.DateTimeFormat().resolvedOptions().timeZone || '';
    const tzShort = new Date().toLocaleTimeString('en-US', { timeZoneName: 'short' }).split(' ').pop();
    return `${month} ${day}, ${year} ${h12}:${m} ${ampm} ${tzShort}`;
}

function _timeStamp(val) {
    const ts = _parseTs(val);
    if (!ts) return '';
    const d = new Date(ts);
    const now = new Date();
    const diff = Date.now() - ts;
    const h = d.getHours();
    const m = String(d.getMinutes()).padStart(2, '0');
    const ampm = h >= 12 ? 'PM' : 'AM';
    const h12 = h % 12 || 12;
    const time = `${h12}:${m} ${ampm}`;
    // Today
    if (d.toDateString() === now.toDateString()) return `Today at ${time}`;
    // Yesterday
    const yesterday = new Date(now); yesterday.setDate(now.getDate() - 1);
    if (d.toDateString() === yesterday.toDateString()) return `Yesterday at ${time}`;
    // This week
    if (diff < 7 * 86400000) {
        const days = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
        return `${days[d.getDay()]} at ${time}`;
    }
    // Older
    return `${d.getMonth()+1}/${d.getDate()}/${d.getFullYear()} ${time}`;
}

function _lastSeen(val) {
    const ts = _parseTs(val);
    if (!ts) return 'Unknown';
    const diff = Date.now() - ts;
    if (diff < 90000) return 'Online now';
    if (diff < 300000) return 'Active ' + _timeAgo(val);
    return 'Last seen ' + _timeStamp(val);
}

// Hook into existing events to generate notifications
const _origIncrUnread = typeof _incrUnread === 'function' ? _incrUnread : null;
if (_origIncrUnread) {
    const _wrappedIncrUnread = _incrUnread;
    _incrUnread = function(sender) {
        _wrappedIncrUnread(sender);
        addNotification('message', 'New message from ' + sender, 'You have an unread message.', '💬', sender);
        // Play DM notification sound
        if (window.notifSettings?.dm !== false) tenshiAudio.dm();
    };
}

