// ── Handle return from Stripe username-change payment ──
async function _handleUsernameChangeReturn() {
    const pending = localStorage.getItem('tenshi_pending_username_change');
    if (!pending) return false;
    try {
        const { username: oldUser, new_username } = JSON.parse(pending);
        localStorage.removeItem('tenshi_pending_username_change');
        if (!oldUser || !new_username) return false;
        // Mark payment as complete on server
        const markRes = await apiRequest('MARK_USERNAME_CHANGE_PAID', {});
        if (markRes.status !== 'success') return false;
        // Now execute the change
        const res = await apiRequest('CHANGE_USERNAME', { new_username });
        if (res.status === 'success') {
            currentUser = res.new_username;
            localStorage.setItem('tenshi_user', res.new_username);
            const session = JSON.parse(localStorage.getItem('tenshi_session') || '{}');
            session.username = res.new_username;
            localStorage.setItem('tenshi_session', JSON.stringify(session));
            alert(`Username changed to ${res.new_username}!`);
            loadHub();
            return true;
        } else {
            alert(res.message || 'Username change failed after payment. Contact support.');
            return false;
        }
    } catch { return false; }
}

// ══════════════════════════════════════════════════════════════
// ── DM VOICE/VIDEO CALLING ────────────────────────────────────
// ══════════════════════════════════════════════════════════════

let _activeCall = null;  // { target, type, status, startTime }
let _savedChatHTML = '';  // saved chat content before call starts
let _callDeafened = false;
let _callCheckInterval = null;
let _callRingtone = null;

async function _setupCallUI(targetUser, initialStatus) {
    // Don't touch message-container — keep chat visible during calls
    _hideReturnToCallBar();

    // Fetch profile colors for both users
    let myColor = '#5865F2', theirColor = '#23a559';
    try {
        const [myProf, theirProf] = await Promise.all([
            apiRequest('GET_PROFILE', { target: currentUser }),
            apiRequest('GET_PROFILE', { target: targetUser }),
        ]);
        if (myProf.status === 'success') myColor = myProf.profile_color || '#5865F2';
        if (theirProf.status === 'success') {
            theirColor = theirProf.profile_color || '#23a559';
            _theirMinThreshold = parseInt(theirProf.voice_threshold || '15');
        }
    } catch {}

    // Build call participant display in video container
    const vc = document.getElementById('video-container');
    if (vc) {
        vc.style.display = 'block';
        // Add call status/timer to video container
        let callStatusBar = document.getElementById('call-status-bar');
        if (!callStatusBar) {
            callStatusBar = document.createElement('div');
            callStatusBar.id = 'call-status-bar';
            callStatusBar.style.cssText = 'text-align:center;padding:8px;font-size:13px;';
            vc.appendChild(callStatusBar);
        }
        const statusColor = initialStatus === 'connected' ? '#23a559' : 'var(--text-muted)';
        const statusIcon = initialStatus === 'connected' ? '●' : '📞';
        const statusText = initialStatus === 'connected' ? 'Connected' : `Calling ${_escAttr(targetUser)}...`;
        callStatusBar.innerHTML = `<div id="call-status-text" style="color:${statusColor};">${statusIcon} ${statusText}</div><div id="call-timer" style="color:white;font-size:16px;font-weight:bold;${initialStatus === 'connected' ? '' : 'display:none;'}margin-top:4px;">00:00</div>`;
        const remoteDiv = document.getElementById('remote-videos');
        if (remoteDiv) {
            const myInitial = (currentUser || 'U')[0].toUpperCase();
            const theirInitial = (targetUser || '?')[0].toUpperCase();
            remoteDiv.innerHTML = `
                <div id="call-participant-me" style="display:flex;flex-direction:column;align-items:center;gap:6px;">
                    <div style="color:${myColor};font-size:13px;font-weight:600;">${_escAttr(currentUser)}</div>
                    <div id="call-box-me" style="position:relative;width:180px;height:180px;border-radius:16px;transition:box-shadow 0.15s;">
                        <video id="local-video" autoplay muted playsinline style="width:180px;height:180px;border-radius:16px;border:3px solid ${myColor};background:black;object-fit:cover;"></video>
                        <div id="call-avatar-me" style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(30,31,35,0.95);border-radius:16px;border:3px solid ${myColor};">
                            <div style="width:80px;height:80px;border-radius:50%;background:${myColor};display:flex;align-items:center;justify-content:center;font-size:36px;font-weight:bold;color:white;">${myInitial}</div>
                        </div>
                    </div>
                    <div id="call-mic-me" style="font-size:11px;color:#23a559;">🎤 Unmuted</div>
                    <div style="width:180px;margin-top:4px;">
                        <div style="background:rgba(255,255,255,0.1);border-radius:4px;height:4px;overflow:hidden;">
                            <div id="call-mic-level" style="height:100%;width:0%;background:${myColor};transition:width 0.1s;border-radius:4px;"></div>
                        </div>
                        ${_vqSettings.manualNoiseSuppression ? `<div style="display:flex;align-items:center;gap:4px;margin-top:4px;">
                            <span style="font-size:10px;color:var(--text-muted);white-space:nowrap;">Suppression:</span>
                            <input type="range" min="5" max="60" value="${_myVoiceThreshold}" style="flex:1;accent-color:${myColor};height:12px;" oninput="_setMyThreshold(this.value)">
                            <span id="call-threshold-label" style="font-size:10px;color:var(--text-muted);min-width:16px;">${_myVoiceThreshold}</span>
                        </div>` : ''}
                    </div>
                </div>
                <div id="call-participant-them" style="display:flex;flex-direction:column;align-items:center;gap:6px;">
                    <div style="color:${theirColor};font-size:13px;font-weight:600;">${_escAttr(targetUser)}</div>
                    <div id="remote-call-box" style="position:relative;width:180px;height:180px;border-radius:16px;transition:box-shadow 0.15s;cursor:pointer;" onclick="_vcToggleFullscreen(this)">
                        <video id="remote-call-video" autoplay playsinline style="width:180px;height:180px;border-radius:16px;border:3px solid ${theirColor};background:black;object-fit:cover;display:none;"></video>
                        <div id="remote-call-avatar" style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(30,31,35,0.95);border-radius:16px;border:3px solid ${theirColor};">
                            <div style="width:80px;height:80px;border-radius:50%;background:${theirColor};display:flex;align-items:center;justify-content:center;font-size:36px;font-weight:bold;color:white;">${theirInitial}</div>
                        </div>
                    </div>
                    <div id="call-status-them" style="font-size:11px;color:var(--text-muted);">In call</div>
                    <div style="display:flex;align-items:center;gap:6px;margin-top:4px;">
                        <span id="call-vol-icon" style="font-size:14px;cursor:pointer;" onclick="_toggleUserMute()">🔊</span>
                        <input id="call-vol-slider" type="range" min="0" max="200" value="30" style="width:120px;accent-color:${theirColor};cursor:pointer;" oninput="_setUserVolume(this.value)" title="User volume">
                        <span id="call-vol-label" style="font-size:11px;color:var(--text-muted);min-width:30px;">30%</span>
                    </div>
                </div>`;
        }
        // Store colors for speaking glow
        vc.dataset.myColor = myColor;
        vc.dataset.theirColor = theirColor;
    }

    // Wire disconnect button
    const dcBtn = document.querySelector('[onclick*="leaveVoiceWithPresence"]');
    if (dcBtn) dcBtn.setAttribute('onclick', 'endDMCall()');

    // Get media — audio + video, camera OFF by default
    try {
        localMediaStream = await navigator.mediaDevices.getUserMedia(_getMediaConstraints(true));
        localMediaStream.getVideoTracks().forEach(t => t.enabled = false);
        localMediaStream.getAudioTracks().forEach(t => t.enabled = true);
        // Apply noise suppression filter
        if (localMediaStream) _applyNoiseFilter(localMediaStream, _vqSettings.noiseMode || 'rnnoise');
        document.getElementById('local-video').srcObject = localMediaStream;
        const camBtn = document.getElementById('voice-cam-btn');
        if (camBtn) camBtn.textContent = '📵 Camera Off';
    } catch(e) {
        try {
            localMediaStream = await navigator.mediaDevices.getUserMedia(_getMediaConstraints(false));
            localMediaStream.getAudioTracks().forEach(t => t.enabled = true);
            if (localMediaStream) _applyNoiseFilter(localMediaStream, _vqSettings.noiseMode || 'rnnoise');
        } catch(e2) { console.warn('Media denied:', e2); }
    }

    // Reset mute/deafen state for new call
    _isMuted = false;
    _isDeafened = false;
    const muteBtn = document.getElementById('voice-mute-btn');
    if (muteBtn) muteBtn.textContent = '🎤 Mute';
    const deafenBtn = document.getElementById('voice-deafen-btn');
    if (deafenBtn) deafenBtn.textContent = '🎧 Deafen';
    const sidebarMuteBtn = document.getElementById('mute-btn');
    if (sidebarMuteBtn) sidebarMuteBtn.textContent = '🎤';

    // Speaking detection — glow border when mic picks up audio
    _startSpeakingDetection();
}

let _speakingDetectionInterval = null;
function _startSpeakingDetection() {
    if (_speakingDetectionInterval) clearInterval(_speakingDetectionInterval);
    if (!localMediaStream) return;
    try {
        const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        if (audioCtx.state === 'suspended') audioCtx.resume();
        const source = audioCtx.createMediaStreamSource(localMediaStream);
        const analyser = audioCtx.createAnalyser();
        analyser.fftSize = 256;
        analyser.smoothingTimeConstant = 0.5;
        source.connect(analyser);
        const data = new Uint8Array(analyser.frequencyBinCount);

        let _lastSpeakingState = false;
        _speakingDetectionInterval = setInterval(() => {
            if (!_activeCall) { clearInterval(_speakingDetectionInterval); _speakingDetectionInterval = null; audioCtx.close(); return; }
            analyser.getByteFrequencyData(data);
            const avg = data.reduce((a, b) => a + b, 0) / data.length;
            // Update live mic level indicator
            const levelBar = document.getElementById('call-mic-level');
            if (levelBar) levelBar.style.width = Math.min(avg / 60 * 100, 100) + '%';
            const speaking = avg > _myVoiceThreshold && !_isMuted;
            const box = document.getElementById('call-box-me');
            const vc = document.getElementById('video-container');
            const myColor = vc?.dataset.myColor || '#5865F2';
            if (box) {
                box.style.boxShadow = speaking ? `0 0 20px ${myColor}, 0 0 40px ${myColor}44` : 'none';
            }
            // Report speaking state to server when it changes
            if (speaking !== _lastSpeakingState) {
                _lastSpeakingState = speaking;
                apiRequest('CALL_SPEAKING', { speaking, target: _activeCall?.target });
            }
        }, 100);

        // Remote speaking detection is now handled by _setupRemoteSpeakingDetection (Web Audio API)
    } catch(e) { console.warn('Speaking detection failed:', e); }
}
let _remoteSpeakingInterval = null;

// Ensure AudioContext is resumed (browsers require user gesture)
function _ensureCallAudio() {
    try {
        if (typeof tenshiAudio !== 'undefined' && tenshiAudio.ctx && tenshiAudio.ctx.state === 'suspended') {
            tenshiAudio.ctx.resume();
        }
    } catch(e) {}
}

async function startDMCall(withVideo) {
    if (!currentTarget || currentTarget === 'AI') return;
    if (_activeCall) {
        // Already in a DM call — just return to call UI
        _returnToCall();
        return;
    }
    // Auto-disconnect from voice channel before starting DM call
    if (_voiceChannelName) {
        await _leaveVoiceChannelAsync();
        await new Promise(r => setTimeout(r, 500));
    }

    // Unlock audio playback on user gesture
    _ensureCallAudio();

    const type = withVideo ? 'video' : 'voice';
    _activeCall = { target: currentTarget, type, status: 'ringing', startTime: null, _isCaller: true };
    _saveCallState({ type: 'dm_call', target: currentTarget, callType: type });
    tenshiAudio.startDial();

    // Send call request to target
    const res = await apiRequest('START_CALL', { target: currentTarget, call_type: type });
    if (res.status !== 'success') {
        tenshiAudio.stopDial();
        alert(res.message || 'Could not start call.');
        _activeCall = null;
        return;
    }

    // Use shared call UI setup (MUST await for getUserMedia)
    await _setupCallUI(currentTarget, 'ringing');

    // Poll for call status (accepted/declined) — stops once connected
    _callCheckInterval = setInterval(async () => {
        if (!_activeCall) {
            clearInterval(_callCheckInterval); _callCheckInterval = null;
            return;
        }
        const callTarget = _activeCall.target || currentTarget;
        const status = await apiRequest('CHECK_CALL_STATUS', { target: callTarget });
        if (status.status === 'success') {
            if (status.call_status === 'accepted' && _activeCall.status !== 'connected') {
                tenshiAudio.stopDial();
                tenshiAudio.join();
                _activeCall.status = 'connected';
                _activeCall.startTime = Date.now();
                _startCallEndChecker();
                const statusText = document.getElementById('call-status-text');
                if (statusText) statusText.innerHTML = '<span style="color:#23a559;">● Connected</span>';
                const timer = document.getElementById('call-timer');
                if (timer) timer.style.display = 'block';
                _startCallTimer();
                _startCallMedia(callTarget);
                // Stop this ringing check — switch to end-detection only
                clearInterval(_callCheckInterval);
                _callCheckInterval = setInterval(async () => {
                    if (!_activeCall) { clearInterval(_callCheckInterval); _callCheckInterval = null; return; }
                    const s2 = await apiRequest('CHECK_CALL_STATUS', { target: _activeCall.target });
                    if (s2.status === 'success' && (s2.call_status === 'ended' || s2.call_status === 'declined')) {
                        clearInterval(_callCheckInterval); _callCheckInterval = null;
                        endDMCall(true);
                        const mc2 = document.getElementById('message-container');
                        if (mc2) mc2.innerHTML += `<div style="text-align:center;color:var(--text-muted);font-size:13px;padding:8px;">📵 ${_activeCall?.target || 'Other user'} ended the call</div>`;
                    }
                }, 3000);
                return; // Don't check declined/ended below
            } else if (status.call_status === 'declined' || status.call_status === 'ended') {
                clearInterval(_callCheckInterval); _callCheckInterval = null;
                const who = status.call_status === 'declined' ? 'declined' : 'ended by ' + callTarget;
                endDMCall(true);
                const mc2 = document.getElementById('message-container');
                if (mc2) mc2.innerHTML += `<div style="text-align:center;color:var(--text-muted);font-size:13px;padding:8px;">📵 ${callTarget} ended the call</div>`;
            }
        }
    }, 2000);
}

let _callTimerInterval = null;
function _startCallTimer() {
    if (_callTimerInterval) clearInterval(_callTimerInterval);
    const timerEl = document.getElementById('call-timer');
    if (!timerEl) return;
    _callTimerInterval = setInterval(() => {
        if (!_activeCall || !_activeCall.startTime) {
            clearInterval(_callTimerInterval); _callTimerInterval = null;
            return;
        }
        const elapsed = Math.floor((Date.now() - _activeCall.startTime) / 1000);
        const mins = String(Math.floor(elapsed / 60)).padStart(2, '0');
        const secs = String(elapsed % 60).padStart(2, '0');
        timerEl.textContent = `${mins}:${secs}`;
    }, 1000);
}

function _startCallMedia(target) {
    // WebRTC: create peer connection for audio/video
    const isCaller = !!(_activeCall && _activeCall._isCaller);
    _createPeerConnection(target, isCaller);
}

function endDMCall(silent) {
    if (_callCheckInterval) { clearInterval(_callCheckInterval); _callCheckInterval = null; }
    if (_callTimerInterval) { clearInterval(_callTimerInterval); _callTimerInterval = null; }
    if (_speakingDetectionInterval) { clearInterval(_speakingDetectionInterval); _speakingDetectionInterval = null; }
    if (_remoteSpeakingInterval) { clearInterval(_remoteSpeakingInterval); _remoteSpeakingInterval = null; }
    // Stop screen share if active
    if (_screenStream) {
        _screenStream.getTracks().forEach(t => t.stop());
        _screenStream = null;
    }
    _screenShareSender = null;
    _remoteScreenSharing = false;
    _remoteScreenSharer = '';
    const localSS = document.getElementById('screen-share-participant-local');
    if (localSS) localSS.remove();
    const remoteSS = document.getElementById('screen-share-participant-remote');
    if (remoteSS) remoteSS.remove();
    tenshiAudio.stopDial();
    tenshiAudio.stopRing();
    tenshiAudio.callEnd();
    const wasTarget = _activeCall?.target;
    if (_activeCall && !silent) {
        apiRequest('END_CALL', { target: _activeCall.target });
    }
    _activeCall = null;
    _callDeafened = false;
    _saveCallState(null);
    stopMedia(true); // Force-stop — actually kill media and WebRTC

    // Clean up WebRTC
    _stopWebRTC();
    _callSpeakerId = '';

    // Hide call UI — chat stays in message-container
    _hideReturnToCallBar();
    const vc = document.getElementById('video-container');
    if (vc) vc.style.display = 'none';
    const callStatusBar = document.getElementById('call-status-bar');
    if (callStatusBar) callStatusBar.remove();
    const mc = document.getElementById('message-container');
    if (mc) {
        mc.style.display = 'block';
        // Add call ended notice to chat
        const notice = document.createElement('div');
        notice.style.cssText = 'text-align:center;color:var(--text-muted);font-size:12px;padding:8px;border-top:1px solid rgba(255,255,255,0.06);margin-top:8px;';
        notice.textContent = '📞 Call ended';
        mc.appendChild(notice);
        mc.scrollTop = mc.scrollHeight;
    }
}

function toggleCallMute() {
    if (!localMediaStream) return;
    const tracks = localMediaStream.getAudioTracks();
    tracks.forEach(t => t.enabled = !t.enabled);
    const btn = document.getElementById('call-mute-btn');
    if (btn) btn.textContent = tracks[0]?.enabled ? '🎤' : '🔇';
}

function toggleCallDeafen() {
    // Redirect to main toggleDeafen — both DM and VC calls use the same deafen logic
    toggleDeafen();
}

// ── Voice threshold control ──
let _myVoiceThreshold = parseInt(localStorage.getItem('tenshi_voice_threshold') || '15');
let _theirMinThreshold = 15; // fetched from other user's profile

function _setMyThreshold(val) {
    _myVoiceThreshold = parseInt(val);
    localStorage.setItem('tenshi_voice_threshold', _myVoiceThreshold);
    const label = document.getElementById('call-threshold-label');
    if (label) label.textContent = _myVoiceThreshold;
    // Update the noise filter gate threshold in real-time
    // _myVoiceThreshold 0-80 maps to gate sensitivity: 0 = no gate, 80 = very aggressive
    if (window._noiseGateThreshRef) {
        if (_myVoiceThreshold === 0) {
            window._noiseGateThreshRef.value = 0; // Disable gate
        } else {
            // Scale: user threshold 1-80 → linear threshold multiplier
            // Higher user value = higher gate threshold = more noise cut
            const baseFloor = window._noiseGateNoiseFloor || 0.002;
            window._noiseGateThreshRef.value = baseFloor * (1 + _myVoiceThreshold / 10);
        }
    }
    // Save to profile so other users can see our minimum
    apiRequest('UPDATE_PROFILE', { voice_threshold: _myVoiceThreshold }).catch(() => {});
}

function _setTheirThreshold(val) {
    const v = parseInt(val);
    // Cannot go below their set minimum
    const effective = Math.max(v, _theirMinThreshold);
    const slider = document.getElementById('call-their-threshold');
    if (slider) slider.value = effective;
    const label = document.getElementById('call-their-threshold-label');
    if (label) label.textContent = effective;
    // Store locally for this call session — affects what we consider "speaking" for display
    if (_activeCall) _activeCall._theirThresholdOverride = effective;
}

// ── Per-user volume control ──
// _userVolume already declared in WebRTC section
let _userMuted = false;

function _setUserVolume(val) {
    _userVolume = parseInt(val);
    _userMuted = _userVolume === 0;
    // Apply volume through WebAudio gain node
    _updateCallVolume(_userVolume);
    // Update label + icon
    const label = document.getElementById('call-vol-label');
    if (label) label.textContent = _userVolume + '%';
    const icon = document.getElementById('call-vol-icon');
    if (icon) {
        if (_userVolume === 0) icon.textContent = '🔇';
        else if (_userVolume < 50) icon.textContent = '🔉';
        else icon.textContent = '🔊';
    }
    // Save preference
    localStorage.setItem('tenshi_call_volume', _userVolume);
}

function _toggleUserMute() {
    const slider = document.getElementById('call-vol-slider');
    if (!slider) return;
    if (_userMuted) {
        // Unmute — restore to saved or 100
        const saved = parseInt(localStorage.getItem('tenshi_call_volume') || '100');
        slider.value = saved > 0 ? saved : 100;
        _setUserVolume(slider.value);
    } else {
        // Mute
        slider.value = 0;
        _setUserVolume(0);
    }
}

function toggleCallCamera() {
    if (!localMediaStream) return;
    const tracks = localMediaStream.getVideoTracks();
    tracks.forEach(t => t.enabled = !t.enabled);
    const btn = document.getElementById('call-cam-toggle');
    if (btn) btn.textContent = tracks[0]?.enabled ? '📷' : '📵';
}

// ── Incoming call handling ────────────────────────────────────
let _incomingCall = null;

function showIncomingCall(caller, callType) {
    // Auto-decline if already in any call
    if (_activeCall || _voiceChannelName) {
        apiRequest('ANSWER_CALL', { caller, accepted: false }).catch(() => {});
        return;
    }
    _incomingCall = { caller, type: callType };
    const overlay = document.getElementById('incoming-call-overlay');
    if (!overlay) return;
    overlay.style.display = 'flex';
    document.getElementById('call-caller-avatar').textContent = caller[0].toUpperCase();
    document.getElementById('call-caller-name').textContent = caller;
    document.getElementById('call-type-label').textContent = `Incoming ${callType === 'video' ? 'Video' : 'Voice'} Call...`;

    // Play ringtone
    tenshiAudio.startRing();

    // TTS notification
    _ttsReadNotification(`Incoming ${callType === 'video' ? 'video' : 'voice'} call from ${caller}`);

    // Browser notification (works even when tab is in background)
    try {
        if ('Notification' in window && Notification.permission === 'granted') {
            const notif = new Notification('Incoming call from ' + caller, {
                body: (callType === 'video' ? 'Video' : 'Voice') + ' call on Tenshi',
                icon: 'tenshi_logo.png',
                tag: 'tenshi-call',
                requireInteraction: true,
                silent: false,
            });
            notif.onclick = () => { window.focus(); notif.close(); };
            // Auto-close after 30s
            setTimeout(() => notif.close(), 30000);
        }
    } catch {}

    // Flash the page title
    let _titleFlash = setInterval(() => {
        if (!_incomingCall) { clearInterval(_titleFlash); document.title = 'Tenshi Web Hub'; return; }
        document.title = document.title.includes('📞') ? 'Tenshi Web Hub' : `📞 ${caller} is calling...`;
    }, 1000);
}

// Request notification permission on load
if ('Notification' in window && Notification.permission === 'default') {
    // Delay to avoid blocking — will prompt on first user interaction
    document.addEventListener('click', function _reqNotif() {
        Notification.requestPermission();
        document.removeEventListener('click', _reqNotif);
    }, { once: true });
}

async function answerCall() {
    if (!_incomingCall) return;
    // Enforce single call — block if already in any call
    if (_voiceChannelName) { alert('You must leave your current voice channel before answering.'); declineCall(); return; }
    if (_activeCall) { alert('You are already in a call.'); declineCall(); return; }
    // Unlock audio playback on user gesture
    _ensureCallAudio();
    tenshiAudio.stopRing();
    tenshiAudio.join();
    const overlay = document.getElementById('incoming-call-overlay');
    if (overlay) overlay.style.display = 'none';

    await apiRequest('ANSWER_CALL', { caller: _incomingCall.caller, accepted: true });

    // Open chat with caller and start call
    currentTarget = _incomingCall.caller;
    _activeCall = { target: _incomingCall.caller, type: _incomingCall.type, status: 'connected', startTime: Date.now() };
    _saveCallState({ type: 'dm_call', target: _incomingCall.caller, callType: _incomingCall.type });
    _startCallEndChecker();

    // Use shared call UI setup — same as caller (MUST await for getUserMedia)
    await _setupCallUI(_incomingCall.caller, 'connected');

    // Start audio + video relay immediately (already connected)
    _startCallMedia(_incomingCall.caller);
    _startCallTimer();

    // Start polling for call end from other side
    if (_callCheckInterval) clearInterval(_callCheckInterval);
    _callCheckInterval = setInterval(async () => {
        if (!_activeCall) { clearInterval(_callCheckInterval); _callCheckInterval = null; return; }
        const status = await apiRequest('CHECK_CALL_STATUS', { target: _activeCall.target });
        if (status.status === 'success' && (status.call_status === 'ended' || status.call_status === 'declined')) {
            clearInterval(_callCheckInterval); _callCheckInterval = null;
            endDMCall(true);
            const mc2 = document.getElementById('message-container');
            if (mc2) mc2.innerHTML += `<div style="text-align:center;color:var(--text-muted);font-size:13px;padding:8px;">📵 ${_activeCall?.target || 'Other user'} ended the call</div>`;
        }
    }, 2000);

    _incomingCall = null;
}

async function declineCall() {
    if (!_incomingCall) return;
    tenshiAudio.stopRing();
    tenshiAudio.callEnd();
    await apiRequest('ANSWER_CALL', { caller: _incomingCall.caller, accepted: false });
    const overlay = document.getElementById('incoming-call-overlay');
    if (overlay) overlay.style.display = 'none';
    _incomingCall = null;
}

// Poll for incoming calls during message polling
const _origPollMessages = pollMessages;
pollMessages = async function() {
    await _origPollMessages();
};

// ── Active call end checker (only runs during calls) ──
let _callEndCheckInterval = null;
function _startCallEndChecker() {
    if (_callEndCheckInterval) return;
    _callEndCheckInterval = setInterval(async () => {
        if (!_activeCall || _activeCall.status !== 'connected') {
            clearInterval(_callEndCheckInterval);
            _callEndCheckInterval = null;
            return;
        }
        try {
            const res = await apiRequest('CHECK_CALL_STATUS', { target: _activeCall.target });
            if (res.status === 'success' && res.call_status === 'ended') {
                const who = _activeCall.target;
                endDMCall(true);
                const mc = document.getElementById('message-container');
                if (mc) mc.innerHTML += `<div style="text-align:center;color:var(--text-muted);font-size:13px;padding:12px;">📵 ${_escAttr(who)} ended the call</div>`;
                tenshiAudio.callEnd();
            }
        } catch {}
    }, 3000);
}

// Start heartbeat when hub loads (handles: unread DMs, unread emails, incoming calls)
(function() {
    const _prevLoadHub = loadHub;
    loadHub = function() {
        _prevLoadHub();
        _startHeartbeat();
        _checkAppVersion();
    };
})();

