// ── Report Modal System ─────────────────────────────────────
let _reportModalPayload = null; // pending report payload to send on submit

function _openReportModal(targetLabel, payloadBuilder) {
    _reportModalPayload = payloadBuilder;
    const modal = document.getElementById('report-modal');
    if (!modal) return;
    document.getElementById('report-modal-target').textContent = targetLabel;
    document.getElementById('report-modal-details').value = '';
    document.getElementById('report-modal-status').textContent = '';
    document.querySelectorAll('input[name="report-category"]').forEach(r => r.checked = false);
    modal.style.display = 'flex';
}

function _closeReportModal() {
    const modal = document.getElementById('report-modal');
    if (modal) modal.style.display = 'none';
    _reportModalPayload = null;
}

async function _submitReport() {
    const category = document.querySelector('input[name="report-category"]:checked')?.value;
    if (!category) {
        document.getElementById('report-modal-status').textContent = 'Please select a report category.';
        document.getElementById('report-modal-status').style.color = '#ed4245';
        return;
    }
    const details = document.getElementById('report-modal-details')?.value || '';
    const btn = document.getElementById('report-modal-submit');
    if (btn) { btn.disabled = true; btn.textContent = 'Submitting...'; }
    try {
        const payload = typeof _reportModalPayload === 'function' ? _reportModalPayload(category, details) : {};
        payload.reason_category = category;
        if (details) payload.reason = (payload.reason ? payload.reason + ' — ' : '') + details;
        const r = await apiRequest('FLAG_CONTENT', payload);
        const status = document.getElementById('report-modal-status');
        if (status) { status.style.color = '#23a559'; status.textContent = r.message || 'Report submitted. Our team will review it.'; }
        setTimeout(_closeReportModal, 2000);
    } catch (e) {
        const status = document.getElementById('report-modal-status');
        if (status) { status.style.color = '#ed4245'; status.textContent = 'Failed to submit report.'; }
    } finally {
        if (btn) { btn.disabled = false; btn.textContent = 'Submit Report'; }
    }
}

async function flagContent(target) {
    _openReportModal(`Reporting user: ${target}`, (category, details) => ({
        target_user: target,
        reason: details || category,
        context: ''
    }));
}

// ── Report a specific message ────────────────────────────────
async function _reportMessage(msgId, sender, el) {
    // Pre-extract message content and image before opening modal
    const msgEl = el?.closest('.msg') || el?.closest('[style*="display:flex"]');
    const content = msgEl?.querySelector('[style*="word-break"]')?.textContent || msgEl?.querySelector('.msg')?.textContent || '[content not available]';
    const imgEl = msgEl?.querySelector('img[src*="data:image"], img[src*="base64"]');
    let image_b64 = '';
    let cType = 'message';
    if (imgEl && imgEl.src) {
        const b64Match = imgEl.src.match(/base64,(.+)/);
        if (b64Match) { image_b64 = b64Match[1]; cType = 'image'; }
    }

    _openReportModal(`Reporting message from ${sender}`, (category, details) => {
        const payload = {
            target_user: sender,
            content_type: cType,
            reason: details || category,
            context: `Message ID: ${msgId}\nContent: ${content.substring(0, 500)}`,
            msg_id: msgId,
            report_type: 'message'
        };
        if (image_b64) payload.image_b64 = image_b64;
        return payload;
    });
}

// ── Report entire chat log (DM conversation) ─────────────────
async function _reportChatLog() {
    if (!currentTarget || currentTarget.startsWith('srv:')) { alert('Open a DM conversation first.'); return; }
    // Gather visible messages as context
    const msgs = [];
    document.querySelectorAll('#message-container .msg').forEach(m => {
        const sender = m.dataset.sender || '';
        const text = m.textContent?.substring(0, 200) || '';
        if (text.trim()) msgs.push(`${sender}: ${text.trim()}`);
    });
    const chatSnippet = msgs.slice(-30).join('\n').substring(0, 3000);
    const target = currentTarget;

    _openReportModal(`Reporting entire conversation with ${target}`, (category, details) => ({
        target_user: target,
        content_type: 'chat_log',
        reason: details || category,
        context: `Full DM conversation report\nTarget: ${target}\nLast ${Math.min(msgs.length, 30)} messages:\n${chatSnippet}`,
        report_type: 'chat_log'
    }));
}

// ── Report an entire hub/server ──────────────────────────────
async function _reportHub(serverId, serverName) {
    serverId = serverId || currentManagingServer?.id;
    serverName = serverName || currentManagingServer?.name || serverId;
    if (!serverId) { alert('No hub selected.'); return; }
    const members = currentManagingServer?.members ? Object.keys(currentManagingServer.members).length : '?';
    const owner = currentManagingServer?.owner || '?';
    const channels = currentManagingServer?.channels ? Object.keys(currentManagingServer.channels).length : '?';

    _openReportModal(`Reporting hub "${serverName}"`, (category, details) => ({
        target_user: owner,
        content_type: 'hub',
        reason: details || category,
        context: `Hub Report\nHub: ${serverName} (${serverId})\nOwner: ${owner}\nMembers: ${members}\nChannels: ${channels}`,
        report_type: 'hub',
        hub_id: serverId
    }));
}
