// STORIES & TEMPS — Temp-style system
// ══════════════════════════════════════════════════════════════
let _storyViewerData = { stories: [], storyOwnerUsername: '', currentIndex: 0, timer: null, progressTimer: null };
let _tempStreaksCache = {};

/** https: or data: URLs for inline story / temp media. */
function _safeSrc(url) {
    if (!url || typeof url !== 'string') return '';
    const t = url.trim().replace(/[\r\n\0]/g, '');
    if (t.startsWith('data:image/') || t.startsWith('data:video/')) return t;
    if (/^https:\/\//i.test(t)) return t;
    return '';
}

/** Only image avatar URLs for story rail backgrounds. */
function _sanitizedAvatarUrl(url) {
    const t = _safeSrc(url);
    if (!t || t.startsWith('data:video/')) return '';
    return t;
}

async function viewUserStory(target) {
    const r = await apiRequest('GET_STORY', { target });
    if (!r.stories || r.stories.length === 0) {
        alert(`${target} has no active story.`);
        return;
    }
    _openStoryViewer(target, r.stories);
}

function _openStoryViewer(username, stories) {
    _storyViewerData = { stories, storyOwnerUsername: username, currentIndex: 0, timer: null, progressTimer: null };
    const overlay = document.createElement('div');
    overlay.id = 'story-viewer-overlay';
    overlay.className = 'story-viewer-overlay';
    overlay.innerHTML = `
        <div class="story-viewer-container">
            <div class="story-progress-bar" id="story-progress-bar"></div>
            <div class="story-header">
                <div style="display:flex;align-items:center;gap:10px;">
                    <div class="story-avatar">${username[0].toUpperCase()}</div>
                    <div>
                        <div class="story-username">${username}</div>
                        <div class="story-time" id="story-time-label"></div>
                    </div>
                </div>
                <button class="story-close-btn" onclick="_closeStoryViewer()">✕</button>
            </div>
            <div class="story-content" id="story-content-display"></div>
            <div class="story-nav-left" onclick="_storyPrev()"></div>
            <div class="story-nav-right" onclick="_storyNext()"></div>
            <div class="story-footer" id="story-footer"></div>
        </div>`;
    document.body.appendChild(overlay);
    // Keyboard navigation
    overlay._keyHandler = (e) => {
        if (e.key === 'Escape') _closeStoryViewer();
        else if (e.key === 'ArrowLeft') _storyPrev();
        else if (e.key === 'ArrowRight') _storyNext();
    };
    document.addEventListener('keydown', overlay._keyHandler);
    _showStoryAtIndex(0);
}

function _showStoryAtIndex(idx) {
    const { stories, storyOwnerUsername } = _storyViewerData;
    if (idx < 0 || idx >= stories.length) { _closeStoryViewer(); return; }
    _storyViewerData.currentIndex = idx;
    const s = stories[idx];
    // Mark as viewed
    apiRequest('VIEW_STORY', { target: storyOwnerUsername, story_id: s.id });
    // Progress bars
    const bar = document.getElementById('story-progress-bar');
    if (bar) {
        bar.innerHTML = stories.map((_, i) =>
            `<div class="story-progress-segment"><div class="story-progress-fill" id="story-prog-${i}" style="width:${i < idx ? '100' : '0'}%"></div></div>`
        ).join('');
    }
    // Time
    const timeEl = document.getElementById('story-time-label');
    if (timeEl) {
        const ago = Math.floor((Date.now() / 1000 - s.posted_at) / 60);
        timeEl.textContent = ago < 60 ? `${ago}m ago` : `${Math.floor(ago / 60)}h ago`;
    }
    // Content
    const display = document.getElementById('story-content-display');
    if (display) {
        if (s.media && s.media_type === 'image') {
            // SECURITY: validate media URL via shared _safeSrc allowlist (https:/data:image/etc.)
            const safeMediaUrl = _safeSrc(s.media);
            display.innerHTML = safeMediaUrl ? `<img src="${safeMediaUrl}" style="max-width:100%;max-height:100%;object-fit:contain;border-radius:12px;">` : '';
            if (s.content) display.innerHTML += `<div class="story-text-overlay">${_escHtml(s.content)}</div>`;
        } else if (s.media && s.media_type === 'video') {
            const safeVideoUrl = _safeSrc(s.media);
            display.innerHTML = safeVideoUrl ? `<video src="${safeVideoUrl}" autoplay muted playsinline style="max-width:100%;max-height:100%;border-radius:12px;"></video>` : '';
            if (s.content) display.innerHTML += `<div class="story-text-overlay">${_escHtml(s.content)}</div>`;
        } else {
            display.innerHTML = `<div class="story-text-only">${_escHtml(s.content || '')}</div>`;
        }
    }
    // Footer (viewer count for own stories)
    const footer = document.getElementById('story-footer');
    if (footer) {
        if (storyOwnerUsername === currentUser) {
            const viewers = s.viewers || [];
            footer.innerHTML = viewers.length > 0
                ? `<span style="color:rgba(255,255,255,0.7);font-size:12px;">👁 ${viewers.length} view${viewers.length !== 1 ? 's' : ''}</span>`
                : '';
        } else {
            footer.innerHTML = '';
        }
    }
    // Auto-advance timer (5 seconds for text, 7 for media)
    if (_storyViewerData.timer) clearTimeout(_storyViewerData.timer);
    if (_storyViewerData.progressTimer) clearInterval(_storyViewerData.progressTimer);
    const duration = s.media ? 7000 : 5000;
    const progFill = document.getElementById(`story-prog-${idx}`);
    if (progFill) {
        progFill.style.width = '0%';
        progFill.style.transition = `width ${duration}ms linear`;
        requestAnimationFrame(() => { progFill.style.width = '100%'; });
    }
    _storyViewerData.timer = setTimeout(() => _storyNext(), duration);
}

function _storyNext() {
    if (_storyViewerData.timer) clearTimeout(_storyViewerData.timer);
    const next = _storyViewerData.currentIndex + 1;
    if (next >= _storyViewerData.stories.length) {
        _closeStoryViewer();
    } else {
        _showStoryAtIndex(next);
    }
}

function _storyPrev() {
    if (_storyViewerData.timer) clearTimeout(_storyViewerData.timer);
    const prev = _storyViewerData.currentIndex - 1;
    if (prev < 0) return;
    _showStoryAtIndex(prev);
}

function _closeStoryViewer() {
    if (_storyViewerData.timer) clearTimeout(_storyViewerData.timer);
    if (_storyViewerData.progressTimer) clearInterval(_storyViewerData.progressTimer);
    const overlay = document.getElementById('story-viewer-overlay');
    if (overlay) {
        document.removeEventListener('keydown', overlay._keyHandler);
        overlay.remove();
    }
    setTimeout(() => _refreshStoryFeed(), 0);
}

// ══════════════════════════════════════════════════════════════
// GROUP 4: Profile Settings — Activity, Platforms, Stories
// ══════════════════════════════════════════════════════════════
async function _saveActivity() { const activity=document.getElementById('pf-activity')?.value||''; const game=document.getElementById('pf-game')?.value||''; const r=await apiRequest('SET_ACTIVITY',{activity,game_name:game}); const s=document.getElementById('activity-save-status'); if(s){s.style.color=r.status==='success'?'#23a559':'#ed4245';s.textContent=r.status==='success'?'Saved!':'Failed';} }

// ── Phase 4: Auto Game Detection (Desktop App Only) ─────────────
let _gameDetectionInterval = null;
let _lastDetectedGame = null;

function _startGameDetection() {
    if (_gameDetectionInterval) return; // already running
    if (!window.tenshiApp?.getRunningGames) return; // not in desktop app

    async function _pollAndSync() {
        try {
            const games = await window.tenshiApp.getRunningGames();
            // Pick the first detected game (priority = first match)
            // Filter out non-game entries like Spotify for the game field
            // Handle both old format (string[]) and new format ({name,exe,known}[])
            const topGame = games && games.length > 0 ? (typeof games[0] === 'string' ? games[0] : games[0].name) : '';
            const game = topGame && topGame !== 'Spotify' ? topGame :
                (games || []).map(g => typeof g === 'string' ? g : g.name).find(n => n && n !== 'Spotify') || '';
            if (game !== _lastDetectedGame) {
                _lastDetectedGame = game;
                // Preserve the user's custom activity text, only update game_name
                await apiRequest('SET_ACTIVITY', { activity: '', game_name: game });
                // Update the profile game input if it's currently visible
                const pfGame = document.getElementById('pf-game');
                if (pfGame) pfGame.value = game;
            }
        } catch (e) {
            // Silently ignore — game detection is non-critical
        }
    }

    _pollAndSync(); // initial sync
    _gameDetectionInterval = setInterval(_pollAndSync, 15000);
}

async function _linkPlatform(platform) { const username=document.getElementById('platform-'+platform)?.value?.trim(); if(!username){alert('Enter a username');return;} const r=await apiRequest('LINK_PLATFORM',{platform,platform_username:username}); alert(r.message||'Done'); }
async function _postStory() {
    const content = document.getElementById('story-content')?.value?.trim();
    const mediaInput = document.getElementById('story-media-input');
    let media_b64 = '';
    let media_type = 'text';
    if (mediaInput && mediaInput.files && mediaInput.files[0]) {
        const file = mediaInput.files[0];
        if (file.size > 5 * 1024 * 1024) { alert('Media must be under 5MB'); return; }
        media_type = file.type.startsWith('video') ? 'video' : 'image';
        media_b64 = await new Promise((resolve) => {
            const reader = new FileReader();
            reader.onload = () => resolve(reader.result);
            reader.readAsDataURL(file);
        });
    }
    if (!content && !media_b64) { showGlobalNotification('Add text or media to your story', '#f0b132'); return; }
    const r = await apiRequest('POST_STORY', { content, media: media_b64, media_type });
    if (r.status === 'success') {
        const sc = document.getElementById('story-content');
        if (sc) sc.value = '';
        if (mediaInput) mediaInput.value = '';
        showGlobalNotification('Story posted!', '#23a559');
        _refreshStoryFeed();
    } else {
        showGlobalNotification(r.message || 'Failed to post story', '#ed4245');
    }
}

async function _openStoryComposer() {
    const overlay = document.createElement('div');
    overlay.id = 'story-composer-overlay';
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.95);z-index:10000;display:flex;flex-direction:column;align-items:center;justify-content:center;overflow-y:auto;';
    overlay.innerHTML = `
        <div style="width:100%;max-width:420px;padding:20px;display:flex;flex-direction:column;gap:14px;">
            <div style="display:flex;justify-content:space-between;align-items:center;">
                <h3 style="color:white;margin:0;font-size:18px;">Create Story</h3>
                <button onclick="document.getElementById('story-composer-overlay')?.remove();if(_storyCameraStream){_storyCameraStream.getTracks().forEach(t=>t.stop());_storyCameraStream=null;}" style="background:none;border:none;color:white;font-size:22px;cursor:pointer;">&#x2715;</button>
            </div>
            <div id="story-composer-preview" style="width:100%;aspect-ratio:9/16;max-height:55vh;background:rgba(255,255,255,0.05);border-radius:16px;overflow:hidden;display:flex;align-items:center;justify-content:center;border:2px dashed rgba(255,255,255,0.15);position:relative;">
                <div id="story-composer-placeholder" style="color:var(--text-muted);font-size:14px;text-align:center;padding:20px;">
                    <div style="font-size:40px;margin-bottom:8px;">&#x1F4F7;</div>
                    Upload photos, videos, gaming clips<br>or capture from camera
                </div>
                <video id="story-camera-feed" autoplay playsinline muted style="display:none;width:100%;height:100%;object-fit:cover;"></video>
                <img id="story-img-preview" style="display:none;width:100%;height:100%;object-fit:contain;">
                <div id="story-text-overlay" style="display:none;position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);color:white;font-size:24px;font-weight:bold;text-shadow:0 2px 8px rgba(0,0,0,0.8);pointer-events:none;text-align:center;max-width:90%;word-break:break-word;"></div>
            </div>
            <div id="story-file-size-info" style="display:none;font-size:11px;color:var(--text-muted);text-align:center;"></div>
            <textarea id="story-composer-text" placeholder="Add text overlay to your story..." maxlength="280" oninput="_storyUpdateTextOverlay()" style="width:100%;padding:10px 14px;background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.12);border-radius:10px;color:white;font-size:14px;resize:none;min-height:50px;box-sizing:border-box;"></textarea>
            <div style="display:flex;gap:8px;flex-wrap:wrap;">
                <button onclick="_storyUseCamera()" style="flex:1;padding:10px;background:rgba(255,255,255,0.1);color:white;border:none;border-radius:10px;cursor:pointer;font-size:13px;font-weight:600;min-width:80px;">&#x1F4F7; Camera</button>
                <label style="flex:1;padding:10px;background:rgba(255,255,255,0.1);color:white;border:none;border-radius:10px;cursor:pointer;font-size:13px;font-weight:600;text-align:center;min-width:80px;">
                    &#x1F4C1; Upload
                    <input type="file" id="story-composer-file" accept="image/*,video/*,.mp4,.webm,.mov,.avi,.mkv,.gif" style="display:none;" onchange="_storyFileSelected(this)">
                </label>
                <button onclick="_storyToggleDraw()" id="story-draw-btn" style="flex:1;padding:10px;background:rgba(255,255,255,0.1);color:white;border:none;border-radius:10px;cursor:pointer;font-size:13px;font-weight:600;min-width:80px;">&#x270F;&#xFE0F; Draw</button>
            </div>
            <div id="story-draw-tools" style="display:none;padding:8px;background:rgba(255,255,255,0.05);border-radius:10px;">
                <div style="display:flex;gap:6px;align-items:center;justify-content:center;">
                    <span style="color:var(--text-muted);font-size:11px;">Color:</span>
                    <input type="color" id="story-draw-color" value="#ffffff" style="width:28px;height:28px;border:none;border-radius:4px;cursor:pointer;">
                    <span style="color:var(--text-muted);font-size:11px;margin-left:8px;">Size:</span>
                    <input type="range" id="story-draw-size" min="2" max="12" value="4" style="width:80px;">
                    <button onclick="_storyClearDraw()" style="background:rgba(237,66,69,0.2);color:#ed4245;border:none;padding:4px 10px;border-radius:6px;cursor:pointer;font-size:11px;">Clear</button>
                </div>
            </div>
            <div style="font-size:11px;color:var(--text-muted);text-align:center;">Max 5MB per story. Stories are visible for 24 hours and count toward storage.</div>
            <div id="story-composer-status" style="text-align:center;font-size:13px;min-height:18px;"></div>
            <button onclick="_postStoryFromComposer()" style="padding:12px;background:linear-gradient(135deg,#FFFC00,#FF6600);color:#000;border:none;border-radius:10px;cursor:pointer;font-size:15px;font-weight:700;">Post Story</button>
        </div>`;
    document.body.appendChild(overlay);
    // Set up draw canvas if media is present
    _storyDrawCanvas = null;
}

function _storyUpdateTextOverlay() {
    const text = document.getElementById('story-composer-text')?.value || '';
    const overlay = document.getElementById('story-text-overlay');
    if (!overlay) return;
    if (text.trim()) {
        overlay.style.display = 'block';
        overlay.textContent = text;
    } else {
        overlay.style.display = 'none';
    }
}

let _storyDrawCanvas = null;
function _storyToggleDraw() {
    const tools = document.getElementById('story-draw-tools');
    const preview = document.getElementById('story-composer-preview');
    if (!tools || !preview) return;
    const visible = tools.style.display !== 'none';
    tools.style.display = visible ? 'none' : 'block';
    if (!visible && !_storyDrawCanvas) {
        // Create canvas overlay for drawing
        const canvas = document.createElement('canvas');
        canvas.id = 'story-draw-canvas';
        canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;cursor:crosshair;z-index:5;';
        canvas.width = preview.offsetWidth;
        canvas.height = preview.offsetHeight;
        preview.appendChild(canvas);
        _storyDrawCanvas = canvas;
        const ctx = canvas.getContext('2d');
        let drawing = false;
        canvas.onpointerdown = e => { drawing = true; ctx.beginPath(); ctx.moveTo(e.offsetX, e.offsetY); };
        canvas.onpointermove = e => {
            if (!drawing) return;
            ctx.strokeStyle = document.getElementById('story-draw-color')?.value || '#fff';
            ctx.lineWidth = parseInt(document.getElementById('story-draw-size')?.value || '4');
            ctx.lineCap = 'round'; ctx.lineJoin = 'round';
            ctx.lineTo(e.offsetX, e.offsetY); ctx.stroke();
        };
        canvas.onpointerup = () => { drawing = false; };
        canvas.onpointerleave = () => { drawing = false; };
    } else if (visible && _storyDrawCanvas) {
        _storyDrawCanvas.remove();
        _storyDrawCanvas = null;
    }
}

function _storyClearDraw() {
    if (!_storyDrawCanvas) return;
    const ctx = _storyDrawCanvas.getContext('2d');
    ctx.clearRect(0, 0, _storyDrawCanvas.width, _storyDrawCanvas.height);
}

let _storyCameraStream = null;
async function _storyUseCamera() {
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user', width: 720, height: 1280 }, audio: false });
        _storyCameraStream = stream;
        const video = document.getElementById('story-camera-feed');
        const placeholder = document.getElementById('story-composer-placeholder');
        const imgPreview = document.getElementById('story-img-preview');
        if (video) { video.style.display = 'block'; video.srcObject = stream; }
        if (placeholder) placeholder.style.display = 'none';
        if (imgPreview) imgPreview.style.display = 'none';
        // Add capture button
        const preview = document.getElementById('story-composer-preview');
        if (preview && !document.getElementById('story-capture-btn')) {
            const btn = document.createElement('button');
            btn.id = 'story-capture-btn';
            btn.style.cssText = 'position:absolute;bottom:16px;left:50%;transform:translateX(-50%);width:60px;height:60px;border-radius:50%;background:white;border:4px solid rgba(255,255,255,0.5);cursor:pointer;z-index:2;';
            btn.onclick = _storyCapturePhoto;
            preview.appendChild(btn);
        }
    } catch (e) {
        alert('Camera access denied. You can upload a file instead.');
    }
}

function _storyCapturePhoto() {
    const video = document.getElementById('story-camera-feed');
    if (!video) return;
    const canvas = document.createElement('canvas');
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    canvas.getContext('2d').drawImage(video, 0, 0);
    const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
    // Stop camera
    if (_storyCameraStream) { _storyCameraStream.getTracks().forEach(t => t.stop()); _storyCameraStream = null; }
    video.style.display = 'none';
    const imgPreview = document.getElementById('story-img-preview');
    if (imgPreview) { imgPreview.src = dataUrl; imgPreview.style.display = 'block'; }
    document.getElementById('story-capture-btn')?.remove();
    // Store data for posting
    document.getElementById('story-composer-preview').dataset.mediaData = dataUrl;
    document.getElementById('story-composer-preview').dataset.mediaType = 'image';
}

function _storyFileSelected(input) {
    if (!input.files || !input.files[0]) return;
    const file = input.files[0];
    if (file.size > 5 * 1024 * 1024) { alert('File must be under 5MB. Upgrade your plan for larger uploads.'); return; }
    // Show file size info
    const sizeInfo = document.getElementById('story-file-size-info');
    if (sizeInfo) {
        const sizeMB = (file.size / (1024 * 1024)).toFixed(2);
        sizeInfo.style.display = 'block';
        sizeInfo.innerHTML = `${file.name} &mdash; ${sizeMB} MB / 5 MB${file.size > 4 * 1024 * 1024 ? ' <span style="color:#f0b132;">(close to limit!)</span>' : ''}`;
    }
    const reader = new FileReader();
    reader.onload = () => {
        const preview = document.getElementById('story-composer-preview');
        const placeholder = document.getElementById('story-composer-placeholder');
        const video = document.getElementById('story-camera-feed');
        const imgPreview = document.getElementById('story-img-preview');
        if (placeholder) placeholder.style.display = 'none';
        if (video) video.style.display = 'none';
        if (_storyCameraStream) { _storyCameraStream.getTracks().forEach(t => t.stop()); _storyCameraStream = null; }
        document.getElementById('story-capture-btn')?.remove();
        if (file.type.startsWith('video')) {
            if (imgPreview) imgPreview.style.display = 'none';
            const vid = document.createElement('video');
            vid.src = reader.result;
            vid.autoplay = true; vid.muted = true; vid.loop = true; vid.playsinline = true;
            vid.style.cssText = 'width:100%;height:100%;object-fit:contain;';
            preview.querySelector('video:not(#story-camera-feed)')?.remove();
            preview.appendChild(vid);
            preview.dataset.mediaType = 'video';
        } else {
            if (imgPreview) { imgPreview.src = reader.result; imgPreview.style.display = 'block'; }
            preview.dataset.mediaType = 'image';
        }
        preview.dataset.mediaData = reader.result;
    };
    reader.readAsDataURL(file);
}

async function _postStoryFromComposer() {
    const text = document.getElementById('story-composer-text')?.value?.trim() || '';
    const preview = document.getElementById('story-composer-preview');
    let media = preview?.dataset?.mediaData || '';
    let media_type = preview?.dataset?.mediaType || 'text';

    // Capture draw canvas content as media if user drew something
    if (!media && _storyDrawCanvas) {
        const ctx = _storyDrawCanvas.getContext('2d');
        const px = ctx.getImageData(0, 0, _storyDrawCanvas.width, _storyDrawCanvas.height).data;
        const hasDrawing = px.some((v, i) => i % 4 === 3 && v > 0); // check alpha channel
        if (hasDrawing) {
            media = _storyDrawCanvas.toDataURL('image/png', 0.9);
            media_type = 'image';
        }
    }

    if (!text && !media) {
        // Show inline warning instead of alert
        const statusEl = document.getElementById('story-composer-status');
        if (statusEl) {
            statusEl.textContent = 'Add text, upload media, or draw something first.';
            statusEl.style.color = '#f0b132';
            setTimeout(() => { statusEl.textContent = ''; }, 3000);
        } else {
            showGlobalNotification('Add text or media to your story', '#f0b132');
        }
        return;
    }
    if (_storyCameraStream) { _storyCameraStream.getTracks().forEach(t => t.stop()); _storyCameraStream = null; }

    // Show posting state
    const postBtn = document.querySelector('#story-composer-overlay .story-post-btn, #story-composer-overlay button[style*="gradient"]');
    if (postBtn) { postBtn.disabled = true; postBtn.textContent = 'Posting...'; }

    const r = await apiRequest('POST_STORY', { content: text, media, media_type });
    if (r.status === 'success') {
        document.getElementById('story-composer-overlay')?.remove();
        _refreshStoryFeed();
        showGlobalNotification('Story posted!', '#23a559');
    } else {
        if (postBtn) { postBtn.disabled = false; postBtn.textContent = 'Post Story'; }
        const statusEl = document.getElementById('story-composer-status');
        if (statusEl) {
            statusEl.textContent = r.message || 'Failed to post';
            statusEl.style.color = '#ed4245';
        } else {
            showGlobalNotification(r.message || 'Failed to post story', '#ed4245');
        }
    }
}

async function _refreshStoryFeed() {
    const bar = document.getElementById('story-feed-bar');
    if (!bar) return;
    const r = await apiRequest('GET_STORIES_FEED', {});
    if (r.status !== 'success') return;
    _renderStoryFeedBar(bar, r.feed || [], r.own_count || 0);
}

function _renderStoryFeedBar(container, feed, ownCount) {
    const myName = currentUser || '';
    const myEscaped = _escAttr(myName);
    const myPic = _sanitizedAvatarUrl(localStorage.getItem('tenshi_avatar') || '');
    let myStyle = '';
    if (myPic) myStyle = `background-image:url(${JSON.stringify(myPic)});`;
    else if (ownCount > 0) myStyle = 'background:var(--accent-blue);';
    else myStyle = 'background:var(--accent-blue);font-size:20px;';
    const myGlyph = !myPic && myName ? myName[0].toUpperCase() : (!myPic && !myName ? '+' : '');
    const myOnclick = ownCount > 0 ? `viewUserStory('${myEscaped}')` : '_openStoryComposer()';
    const myRingOuter = ownCount > 0
        ? `<div class="story-ring-live" aria-hidden="true"></div>`
        : `<div class="story-ring-addring" aria-hidden="true"></div>`;
    const myBadge = ownCount > 0
        ? `<span style="position:absolute;top:0;right:0;z-index:3;background:#ed4245;color:white;font-size:10px;font-weight:700;min-width:16px;height:16px;border-radius:8px;display:flex;align-items:center;justify-content:center;border:2px solid var(--bg-primary,#1a1b1e);">${ownCount}</span>`
        : '';
    let html = `<div class="story-feed-item" onclick="${myOnclick}">
        <div class="story-ring-slot">${myRingOuter}
            <div class="story-feed-avatar" style="${myStyle}">${myGlyph}</div>${myBadge}
        </div>
        <span class="story-feed-name">${ownCount > 0 ? 'My Story' : 'Add Story'}</span>
    </div>`;
    if (ownCount > 0) {
        html += `<div class="story-feed-item" onclick="_openStoryComposer()">
            <div class="story-ring-slot">
                <div class="story-ring-addring" aria-hidden="true"></div>
                <div class="story-feed-avatar" style="background:rgba(255,255,255,0.1);font-size:20px;">+</div>
            </div>
            <span class="story-feed-name">Add</span>
        </div>`;
    }
    feed.forEach((f) => {
        const u = _escAttr(f.username);
        const unseen = (f.unseen || 0) > 0;
        const avatarUrl = _sanitizedAvatarUrl(f.avatar || '');
        const avatarStyle = avatarUrl
            ? `background-image:url(${JSON.stringify(avatarUrl)});`
            : `background:${f.username_color || '#5865F2'};`;
        const initials = avatarUrl ? '' : (f.username[0] || '?').toUpperCase();
        const seenCls = unseen ? '' : ' seen';
        html += `<div class="story-feed-item" onclick="viewUserStory('${u}')">
            <div class="story-ring-slot${seenCls}">
                <div class="story-ring-live" aria-hidden="true"></div>
                <div class="story-feed-avatar" style="${avatarStyle}">${initials}</div>
            </div>
            <span class="story-feed-name">${u}</span>
        </div>`;
    });
    container.innerHTML = html;
}

// ── Snap System ──────────────────────────────────────────────
async function _openTempCapture(target) {
    // If no target, show friend picker first
    if (!target) {
        const res = await apiRequest('GET_RELATIONSHIPS', {});
        const friends = (res.friends || []).sort();
        if (friends.length === 0) { alert('Add friends first to send temps!'); return; }
        const picker = document.createElement('div');
        picker.id = 'temp-friend-picker';
        picker.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.95);z-index:10000;display:flex;flex-direction:column;align-items:center;justify-content:center;';
        let pickerHtml = '<div style="width:100%;max-width:360px;padding:20px;"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;"><h3 style="color:white;margin:0;">Send Temp to...</h3><button onclick="document.getElementById(\'temp-friend-picker\')?.remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer;">\u2715</button></div>';
        pickerHtml += '<div style="max-height:60vh;overflow-y:auto;">';
        friends.forEach(f => {
            const safe = _escAttr(f);
            pickerHtml += `<div onclick="document.getElementById('temp-friend-picker')?.remove();_openTempCapture('${safe}')" style="display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:10px;cursor:pointer;transition:background 0.15s;" onmouseenter="this.style.background='rgba(255,255,255,0.06)'" onmouseleave="this.style.background='transparent'"><div style="width:36px;height:36px;border-radius:50%;background:var(--accent-blue);display:flex;align-items:center;justify-content:center;font-weight:bold;color:white;">${f[0].toUpperCase()}</div><span style="color:white;font-size:14px;">${safe}</span></div>`;
        });
        pickerHtml += '</div></div>';
        picker.innerHTML = pickerHtml;
        document.body.appendChild(picker);
        return;
    }
    const overlay = document.createElement('div');
    overlay.id = 'temp-capture-overlay';
    overlay.className = 'temp-capture-shell';
    overlay.style.cssText = 'position:fixed;inset:0;background:#000;z-index:10000;display:flex;flex-direction:column;';
    overlay.innerHTML = `
        <div style="display:flex;justify-content:space-between;align-items:center;padding:12px 16px;position:absolute;top:0;left:0;right:0;z-index:2;">
            <button onclick="_closeTempCapture()" style="background:rgba(0,0,0,0.4);border:none;color:white;width:36px;height:36px;border-radius:50%;font-size:18px;cursor:pointer;">✕</button>
            <span style="color:white;font-size:14px;font-weight:600;">Temp to ${_escHtml(target)}</span>
            <div style="width:36px;"></div>
        </div>
        <div style="flex:1;display:flex;align-items:center;justify-content:center;position:relative;">
            <video id="temp-camera-feed" autoplay playsinline muted style="width:100%;height:100%;object-fit:cover;"></video>
            <img id="temp-img-preview" style="display:none;width:100%;height:100%;object-fit:contain;">
            <div id="temp-text-area" style="display:none;position:absolute;bottom:80px;left:16px;right:16px;">
                <input type="text" id="temp-text-input" placeholder="Add a caption..." style="width:100%;padding:10px 14px;background:rgba(0,0,0,0.6);border:1px solid rgba(255,255,255,0.2);border-radius:20px;color:white;font-size:14px;text-align:center;box-sizing:border-box;">
            </div>
        </div>
        <div style="padding:16px;display:flex;align-items:center;justify-content:center;gap:20px;background:rgba(0,0,0,0.6);">
            <div id="temp-pre-capture" style="display:flex;align-items:center;gap:20px;">
                <label style="width:40px;height:40px;border-radius:50%;background:rgba(255,255,255,0.15);display:flex;align-items:center;justify-content:center;cursor:pointer;">
                    📁<input type="file" accept="image/*" style="display:none;" onchange="_tempFileSelected(this,'${_escAttr(target)}')">
                </label>
                <button id="temp-shutter" onclick="_tempCapture('${_escAttr(target)}')" style="width:68px;height:68px;border-radius:50%;background:white;border:4px solid rgba(255,252,0,0.65);cursor:pointer;box-shadow:0 0 0 2px rgba(255,252,0,0.25);"></button>
                <div style="width:40px;"></div>
            </div>
            <div id="temp-post-capture" style="display:none;align-items:center;gap:16px;width:100%;justify-content:space-between;">
                <button onclick="_tempRetake('${_escAttr(target)}')" style="background:rgba(255,255,255,0.15);border:none;color:white;padding:10px 20px;border-radius:20px;cursor:pointer;font-size:13px;">Retake</button>
                <div style="display:flex;align-items:center;gap:8px;">
                    <span style="color:white;font-size:12px;">Timer:</span>
                    <select id="temp-timer-select" style="background:rgba(255,255,255,0.15);color:white;border:none;padding:6px 10px;border-radius:8px;font-size:13px;">
                        <option value="3">3s</option><option value="5" selected>5s</option><option value="7">7s</option><option value="10">10s</option>
                    </select>
                </div>
                <button onclick="_tempSend('${_escAttr(target)}')" style="background:linear-gradient(180deg,#fffc4a,#fbc02d);border:none;color:#111;padding:10px 24px;border-radius:20px;cursor:pointer;font-size:14px;font-weight:700;">Send ➤</button>
            </div>
        </div>`;
    document.body.appendChild(overlay);
    // Start camera
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user', width: 720, height: 1280 }, audio: false });
        window._tempCameraStream = stream;
        const vid = document.getElementById('temp-camera-feed');
        if (vid) vid.srcObject = stream;
    } catch (e) {
        // No camera — just show upload option
        const vid = document.getElementById('temp-camera-feed');
        if (vid) vid.style.display = 'none';
    }
}

function _tempCapture(target) {
    const video = document.getElementById('temp-camera-feed');
    if (!video || !video.srcObject) return;
    // Resize to max 800x600 and compress like chat images
    const canvas = document.createElement('canvas');
    const maxW = 800, maxH = 600;
    let w = video.videoWidth, h = video.videoHeight;
    if (w > maxW) { h = h * maxW / w; w = maxW; }
    if (h > maxH) { w = w * maxH / h; h = maxH; }
    canvas.width = w;
    canvas.height = h;
    canvas.getContext('2d').drawImage(video, 0, 0, w, h);
    const dataUrl = canvas.toDataURL('image/jpeg', 0.75);
    // Stop camera
    if (window._tempCameraStream) { window._tempCameraStream.getTracks().forEach(t => t.stop()); window._tempCameraStream = null; }
    video.style.display = 'none';
    const img = document.getElementById('temp-img-preview');
    if (img) { img.src = dataUrl; img.style.display = 'block'; }
    // Show post-capture UI
    document.getElementById('temp-pre-capture').style.display = 'none';
    document.getElementById('temp-post-capture').style.display = 'flex';
    document.getElementById('temp-text-area').style.display = 'block';
    window._tempCapturedData = dataUrl;
    window._tempMediaType = 'image';
}

function _tempFileSelected(input, target) {
    if (!input.files || !input.files[0]) return;
    const file = input.files[0];
    if (file.size > 12 * 1024 * 1024) { alert('File must be under 12MB'); return; }
    // Resize and compress like chat images (800x600 max, JPEG 0.75)
    const img = new Image();
    img.onload = () => {
        const canvas = document.createElement('canvas');
        const maxW = 800, maxH = 600;
        let w = img.width, h = img.height;
        if (w > maxW) { h = h * maxW / w; w = maxW; }
        if (h > maxH) { w = w * maxH / h; h = maxH; }
        canvas.width = w;
        canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.75);

        if (window._tempCameraStream) { window._tempCameraStream.getTracks().forEach(t => t.stop()); window._tempCameraStream = null; }
        const video = document.getElementById('temp-camera-feed');
        if (video) video.style.display = 'none';
        const preview = document.getElementById('temp-img-preview');
        if (preview) { preview.src = dataUrl; preview.style.display = 'block'; }
        document.getElementById('temp-pre-capture').style.display = 'none';
        document.getElementById('temp-post-capture').style.display = 'flex';
        document.getElementById('temp-text-area').style.display = 'block';
        window._tempCapturedData = dataUrl;
        window._tempMediaType = 'image';
    };
    img.src = URL.createObjectURL(file);
}

function _tempRetake(target) {
    document.getElementById('temp-capture-overlay')?.remove();
    window._tempCapturedData = null;
    _openTempCapture(target);
}

async function _tempSend(target) {
    const media = window._tempCapturedData || '';
    const content = document.getElementById('temp-text-input')?.value?.trim() || '';
    const timer = parseInt(document.getElementById('temp-timer-select')?.value || '5');
    if (!media && !content) { alert('Capture a photo first'); return; }
    // Extract raw base64 for server-side content scanning (same as chat images)
    const rawB64 = media ? media.replace(/^data:image\/[^;]+;base64,/, '') : '';
    const payload = { target, content, media, media_type: window._tempMediaType || 'image', timer };
    if (rawB64) payload.image_b64 = rawB64;
    const r = await apiRequest('SEND_TEMP', payload);
    if (r.status === 'success') {
        _closeTempCapture();
        // Brief confirmation
        const toast = document.createElement('div');
        toast.style.cssText = 'position:fixed;bottom:80px;left:50%;transform:translateX(-50%);background:var(--accent-blue);color:white;padding:10px 20px;border-radius:20px;font-size:14px;font-weight:600;z-index:10001;animation:fadeInUp .3s;';
        toast.textContent = `Temp sent to ${target}!`;
        document.body.appendChild(toast);
        setTimeout(() => toast.remove(), 2000);
    } else {
        alert(r.message || 'Failed to send temp');
    }
}

function _closeTempCapture() {
    if (window._tempCameraStream) { window._tempCameraStream.getTracks().forEach(t => t.stop()); window._tempCameraStream = null; }
    window._tempCapturedData = null;
    document.getElementById('temp-capture-overlay')?.remove();
}

async function _openTempViewer(tempMsg, target) {
    // Mark temp as opened
    await apiRequest('OPEN_TEMP', { temp_id: tempMsg.msg_id, target });
    const timer = tempMsg.temp_timer || 5;
    const safeMedia = _safeSrc(tempMsg.media || '');
    const overlay = document.createElement('div');
    overlay.id = 'temp-viewer-overlay';
    overlay.className = 'temp-capture-shell';
    overlay.style.cssText = 'position:fixed;inset:0;background:#000;z-index:10000;display:flex;flex-direction:column;align-items:center;justify-content:center;';
    overlay.innerHTML = `
        <div style="position:absolute;top:0;left:0;right:0;padding:12px 16px;display:flex;justify-content:space-between;align-items:center;z-index:2;">
            <div style="display:flex;align-items:center;gap:8px;">
                <div style="width:32px;height:32px;border-radius:50%;background:var(--accent-blue);display:flex;align-items:center;justify-content:center;color:white;font-weight:bold;">${tempMsg.sender[0].toUpperCase()}</div>
                <span style="color:white;font-weight:600;">${_escHtml(tempMsg.sender)}</span>
            </div>
            <div id="temp-countdown" style="color:white;font-size:24px;font-weight:bold;background:rgba(0,0,0,0.4);width:40px;height:40px;border-radius:50%;display:flex;align-items:center;justify-content:center;">${timer}</div>
        </div>
        <div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;">
            ${safeMedia ? `<img src=${JSON.stringify(safeMedia)} style="max-width:100%;max-height:100%;object-fit:contain;">` : ''}
        </div>
        ${tempMsg.content ? `<div style="position:absolute;bottom:60px;left:16px;right:16px;text-align:center;color:white;font-size:16px;background:rgba(0,0,0,0.5);padding:12px;border-radius:12px;">${_escHtml(tempMsg.content)}</div>` : ''}
        <div style="position:absolute;top:0;left:0;right:0;height:3px;background:rgba(255,255,255,0.15);">
            <div id="temp-timer-bar" style="height:100%;background:linear-gradient(90deg,#fbc02d,#fffc4a);width:100%;transition:width ${timer}s linear;"></div>
        </div>`;
    document.body.appendChild(overlay);
    // Start countdown
    let remaining = timer;
    const countdownEl = document.getElementById('temp-countdown');
    requestAnimationFrame(() => {
        const bar = document.getElementById('temp-timer-bar');
        if (bar) bar.style.width = '0%';
    });
    const interval = setInterval(() => {
        remaining--;
        if (countdownEl) countdownEl.textContent = remaining;
        if (remaining <= 0) {
            clearInterval(interval);
            overlay.remove();
        }
    }, 1000);
    overlay.onclick = () => { clearInterval(interval); overlay.remove(); };
}

async function _loadTempStreaks() {
    const r = await apiRequest('GET_TEMP_STREAKS', {});
    if (r.status === 'success') _tempStreaksCache = r.streaks || {};
}

function _getStreakDisplay(friend) {
    const streak = _tempStreaksCache[friend];
    if (!streak || streak.count < 1) return '';
    let emoji = '🔥';
    if (streak.count >= 100) emoji = '💯';
    else if (streak.count >= 50) emoji = '⭐';
    return `<span class="temp-streak" title="${streak.count} day streak">  ${emoji} ${streak.count}</span>`;
}

// ── Snap Recents Cache & Conversation View ──
let _tempRecentsCache = {};
async function _loadTempRecents(friends) {
    try {
        const r = await apiRequest('GET_TEMP_RECENTS', {});
        if (r.status === 'success' && r.recents) _tempRecentsCache = r.recents;
    } catch(e) { /* optional */ }
}

async function _openTempConversation(target) {
    // Unified inbox: temps live in the DM thread alongside regular messages.
    // The old slide-up "temp history" panel duplicated the conversation surface;
    // clicking now opens the DM directly so users see messages and temps together.
    if (typeof openChat === 'function' && target) {
        return openChat(target);
    }
    const mc = document.getElementById('message-container');
    if (!mc) return;
    const globalInput = document.getElementById('message-input-bar');
    if (globalInput) globalInput.style.display = 'none';
    document.getElementById('current-chat').innerText = '\u{1F4F7} ' + target;
    mc.innerHTML = '<div style="padding:20px;color:var(--text-muted);font-size:13px;">Loading temp history...</div>';
    const streak = _tempStreaksCache[target] || {};
    const streakCount = streak.count || 0;
    let temps = [];
    try { const r = await apiRequest('GET_TEMP_HISTORY', { target }); if (r.status === 'success') temps = r.temps || []; } catch(e) {}
    let html = '<div style="padding:16px 20px;max-width:600px;margin:0 auto;">';
    html += `<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;padding-bottom:12px;border-bottom:1px solid rgba(255,255,255,0.06);">
        <div style="display:flex;align-items:center;gap:10px;">
            <button onclick="renderFriendsMainView()" style="background:rgba(255,255,255,0.08);border:none;color:white;width:32px;height:32px;border-radius:50%;cursor:pointer;font-size:16px;">\u2190</button>
            <div style="width:40px;height:40px;border-radius:50%;background:var(--accent-blue);display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:bold;color:white;">${target[0].toUpperCase()}</div>
            <div>
                <div style="color:white;font-size:16px;font-weight:600;">${_escAttr(target)}</div>
                ${streakCount > 0 ? `<div class="temp-streak-badge" style="font-size:13px;">${streakCount >= 100 ? '\u{1F4AF}' : streakCount >= 50 ? '\u2B50' : '\u{1F525}'} ${streakCount} day streak</div>` : '<div style="color:var(--text-muted);font-size:12px;">No streak yet</div>'}
            </div>
        </div>
        <button onclick="_openTempCapture('${_escAttr(target)}')" style="background:linear-gradient(135deg,#FFFC00,#FF6600);border:none;color:#000;padding:8px 16px;border-radius:20px;cursor:pointer;font-size:13px;font-weight:600;">\u{1F4F7} Send Temp</button>
    </div>`;
    if (temps.length === 0) {
        html += '<div style="text-align:center;padding:40px 20px;color:var(--text-muted);font-size:14px;">No temps yet. Send the first temp!</div>';
    } else {
        temps.forEach(s => {
            const isSent = s.sender === currentUser;
            const timeStr = s.time ? _tempTimeAgo(s.time) : '';
            let statusText = '', indicatorClass = '';
            if (isSent) { indicatorClass = s.opened ? 'opened' : 'sent'; statusText = s.opened ? 'Opened' : 'Sent'; if (s.media_type === 'video') statusText += ' (video)'; }
            else { if (s.opened) { indicatorClass = 'opened'; statusText = 'Opened'; } else { indicatorClass = s.media_type === 'video' ? 'received-video' : 'received-photo'; statusText = 'Tap to view'; } }
            const tempPayload = JSON.stringify({msg_id:s.msg_id||s.id,sender:s.sender,media:s.media||'',content:s.content||'',temp_timer:s.timer||5}).replace(/'/g,"\\'").replace(/"/g,'&quot;');
            html += `<div class="temp-recent-item" style="border-radius:10px;${!isSent && !s.opened ? 'cursor:pointer;' : ''}" ${!isSent && !s.opened ? `onclick="_openTempViewer(JSON.parse(this.dataset.temp),'${_escAttr(target)}')" data-temp="${tempPayload}"` : ''}>
                <div style="display:flex;align-items:center;gap:4px;width:24px;justify-content:center;flex-shrink:0;"><div class="temp-indicator ${indicatorClass}"></div></div>
                <div style="flex:1;min-width:0;">
                    <div style="color:white;font-size:13px;font-weight:500;">${isSent ? 'You' : _escAttr(s.sender)}</div>
                    <div class="temp-status-text">${statusText}${s.content ? ' - ' + _escAttr(s.content.substring(0, 40)) : ''}</div>
                </div>
                <span style="color:var(--text-muted);font-size:11px;flex-shrink:0;">${timeStr}</span>
            </div>`;
        });
    }
    html += '</div>';
    mc.innerHTML = html;
}

function _tempTimeAgo(ts) {
    const d = Date.now() - ts * 1000;
    if (d < 60000) return 'now';
    if (d < 3600000) return Math.floor(d / 60000) + 'm';
    if (d < 86400000) return Math.floor(d / 3600000) + 'h';
    return Math.floor(d / 86400000) + 'd';
}

