async function renameChannel(serverId, oldName) { const newName=prompt(`Rename #${oldName} to:`,oldName); if(!newName||newName===oldName)return; const r=await apiRequest('RENAME_CHANNEL',{server_id:serverId,channel_name:oldName,new_name:newName}); if(r.status==='success'){alert('Renamed!');showSrvTab('channels');}else alert(r.message||'Failed'); }
async function lockChannel(serverId, chName) { const rolesStr=prompt('Allowed roles (comma-separated, or leave blank for admin only):',''); const roles=rolesStr?rolesStr.split(',').map(r=>r.trim()):['role_admin']; const r=await apiRequest('LOCK_CHANNEL',{server_id:serverId,channel_name:chName,allowed_roles:roles}); alert(r.message||'Done'); showSrvTab('channels'); }
async function unlockChannel(serverId, chName) { const r=await apiRequest('UNLOCK_CHANNEL',{server_id:serverId,channel_name:chName}); alert(r.message||'Done'); showSrvTab('channels'); }
async function warnUser(serverId, target) { const reason=prompt(`Warn ${target} — reason:`); if(!reason)return; const r=await apiRequest('WARN_USER',{server_id:serverId,target,reason}); alert(r.message||(r.status==='success'?`Warned (${r.total_warnings} total)`:'Failed')); }
async function timeoutUser(serverId, target) { const mins=prompt(`Timeout ${target} — minutes (max 1440):`,5); if(!mins)return; const reason=prompt('Reason (optional):',''); const r=await apiRequest('TIMEOUT_USER',{server_id:serverId,target,duration:parseInt(mins)*60,reason:reason||''}); alert(r.status==='success'?`${target} timed out for ${mins}m`:(r.message||'Failed')); }
async function viewWarnings(target) { const r=await apiRequest('GET_WARNINGS',{target}); const w=r.warnings||[]; if(!w.length){alert(`${target} has no warnings.`);return;} const list=w.map(x=>`• ${x.reason} (by ${x.by}, ${new Date(x.time*1000).toLocaleDateString()})`).join('\n'); alert(`Warnings for ${target} (${w.length}):\n\n${list}`); }
async function suppressUser(serverId, target) { const enable=confirm(`Enable noise suppression for ${target}?`); const r=await apiRequest('SERVER_SUPPRESS_USER',{server_id:serverId,target,enable}); alert(r.status==='success'?'Done':(r.message||'Failed')); }
async function boostServer(serverId) { if(!confirm('Boost this server to the top of public listings?'))return; const r=await apiRequest('BOOST_SERVER',{server_id:serverId}); alert(r.message||'Done'); }
async function configureOnboarding(serverId) { const questions=prompt('Onboarding questions (comma-separated):','What brings you here?'); if(!questions)return; const roles=prompt('Roles for new members to pick (comma-separated):','Member'); const r=await apiRequest('SET_ONBOARDING',{server_id:serverId,questions:questions.split(',').map(q=>q.trim()),selectable_roles:roles?roles.split(',').map(r=>r.trim()):[]}); alert(r.status==='success'?'Onboarding configured!':'Failed'); }
async function listVoiceRooms(serverId) { const r=await apiRequest('LIST_VOICE_ROOMS',{server_id:serverId}); const rooms=r.rooms||[]; if(!rooms.length){alert('No active voice rooms.');return;} const list=rooms.map(rm=>`• ${rm.name||'Room'} (${(rm.members||[]).length} users) by ${rm.creator||'?'}`).join('\n'); alert(`Voice Rooms:\n\n${list}`); }

