async function _adminLinkSSO() { const t=document.getElementById('admin-sso-target')?.value; const p=document.getElementById('admin-sso-provider')?.value; const e=document.getElementById('admin-sso-email')?.value; const r=await apiRequest('ADMIN_LINK_SSO',{target:t,provider:p,email:e}); const s=document.getElementById('admin-sso-status'); if(s){s.style.color=r.status==='success'?'#23a559':'#ed4245';s.textContent=r.message||'';} }
async function _adminUnlinkSSO() { const t=document.getElementById('admin-sso-target')?.value; const p=document.getElementById('admin-sso-provider')?.value; const r=await apiRequest('ADMIN_UNLINK_SSO',{target:t,provider:p}); const s=document.getElementById('admin-sso-status'); if(s){s.style.color=r.status==='success'?'#23a559':'#ed4245';s.textContent=r.message||'';} }

function _adminRenderReportedMessages() {
    const c=document.getElementById('admin-content'); if(!c)return;
    c.innerHTML=`<h3 style="color:white;margin-bottom:16px;">📋 Reported Messages</h3>
    <div style="display:flex;gap:6px;margin-bottom:12px;">
        <input id="admin-report-target" placeholder="Username to check" style="flex:1;padding:8px 12px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;border-radius:6px;font-size:13px;">
        <button onclick="_adminLoadReports()" style="background:var(--accent-blue);color:white;border:none;padding:8px 14px;border-radius:6px;cursor:pointer;font-weight:600;">Check</button>
    </div>
    <div id="admin-reports-list" style="color:var(--text-muted);font-size:13px;">Enter a username to view reports.</div>`;
}
async function _adminLoadReports() {
    const target=document.getElementById('admin-report-target')?.value?.trim(); if(!target)return;
    const r=await apiRequest('GET_REPORTED_MESSAGES',{target}); const c=document.getElementById('admin-reports-list'); if(!c)return;
    if(r.status!=='success'){c.innerHTML=`<div style="color:#ed4245;">${r.message||'Failed'}</div>`;return;}
    let html=`<div style="margin-bottom:8px;color:white;font-weight:600;">${target} — ${r.under_review?'🔴 Under Review':'🟢 Clear'}</div>`;
    const tickets=r.report_tickets||[]; const flagged=r.flagged_messages||[];
    if(tickets.length) { html+=`<div style="font-size:11px;font-weight:600;color:var(--text-muted);margin:8px 0 4px;">Report Tickets (${tickets.length})</div>`; tickets.forEach(t=>{html+=`<div style="padding:6px 10px;background:rgba(255,255,255,0.04);border-radius:6px;margin-bottom:4px;font-size:12px;color:white;">${_escAttr(JSON.stringify(t))}</div>`;}); }
    if(flagged.length) { html+=`<div style="font-size:11px;font-weight:600;color:var(--text-muted);margin:8px 0 4px;">Flagged Messages (${flagged.length})</div>`; flagged.forEach(m=>{html+=`<div style="padding:6px 10px;background:rgba(237,66,69,0.06);border-radius:6px;margin-bottom:4px;font-size:12px;color:white;">${_escAttr(JSON.stringify(m))}</div>`;}); }
    if(!tickets.length && !flagged.length) html+='<div style="color:var(--text-muted);">No reports found.</div>';
    if(r.under_review) html+=`<button onclick="_adminClearReview('${_escAttr(target)}')" style="margin-top:8px;background:#23a559;color:white;border:none;padding:8px 14px;border-radius:6px;cursor:pointer;font-weight:600;">✓ Clear Review Flag</button>`;
    c.innerHTML=html;
}
async function _adminClearReview(target) { const r=await apiRequest('CLEAR_REVIEW_FLAG',{target}); alert(r.message||'Done'); _adminLoadReports(); }

async function _adminRenderModerationFlags() {
    const c = document.getElementById('admin-content'); if (!c) return;
    c.innerHTML = '<div style="color:var(--text-muted);padding:20px;">Loading moderation flags...</div>';
    const res = await apiRequest('GET_MODERATION_FLAGS', { filter_status: '' });
    if (res.status !== 'success') { c.innerHTML = '<div style="color:#ed4245;padding:20px;">Failed to load flags.</div>'; return; }
    const flags = (res.flags || []).reverse();
    const pending = flags.filter(f => f.status === 'pending');
    const resolved = flags.filter(f => f.status !== 'pending');
    c.innerHTML = `
        <h3 style="color:white;margin:0 0 12px;font-size:16px;">🚩 AI Moderation Flags <span style="color:var(--text-muted);font-size:13px;">(${pending.length} pending)</span></h3>
        <div style="display:flex;flex-direction:column;gap:8px;max-height:60vh;overflow-y:auto;">
            ${pending.length === 0 ? '<div style="color:var(--text-muted);padding:12px;">No pending flags.</div>' : ''}
            ${pending.map(f => {
                const catColors = {csam:'#ed4245',ncii:'#e67e22',nsfw_unverified:'#e91e63',harassment:'#f0b132',other:'#949ba4'};
                const catLabel = f.reason_category ? f.reason_category.replace(/_/g,' ').toUpperCase() : '';
                const catColor = catColors[f.reason_category] || '#949ba4';
                const deadlineStr = f.ncii_deadline ? `<div style="color:#e67e22;font-size:11px;font-weight:600;margin-bottom:6px;">TAKE IT DOWN deadline: ${new Date(f.ncii_deadline*1000).toLocaleString()}</div>` : '';
                // SECURITY FIX: escape all server-supplied fields before injecting into innerHTML.
                // A malicious report payload with XSS in content_type/reason/etc. would fire
                // for any admin viewing this panel (stored XSS escalation to admin session).
                const esc = _escAttr;
                const safeFlagId = esc(f.flag_id || '');
                return `
                <div style="padding:12px;background:rgba(237,66,69,0.08);border:1px solid rgba(237,66,69,0.2);border-radius:10px;">
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;flex-wrap:wrap;gap:4px;">
                        <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
                            <span style="color:white;font-weight:600;">${esc(f.user_id || '?')}</span>
                            <span style="color:var(--text-muted);font-size:11px;">${esc(f.content_type || '')} — ${esc(f.ai_classification || '')}</span>
                            ${catLabel ? `<span style="font-size:10px;color:${catColor};background:${catColor}22;padding:2px 8px;border-radius:4px;font-weight:600;">${esc(catLabel)}</span>` : ''}
                            ${safeFlagId ? `<span style="font-size:9px;color:var(--text-muted);font-family:monospace;">#${safeFlagId}</span>` : ''}
                        </div>
                        <span style="font-size:11px;color:var(--text-muted);">${new Date(f.timestamp*1000).toLocaleString()}</span>
                    </div>
                    <div style="color:var(--text-muted);font-size:12px;margin-bottom:6px;">${esc(f.reason || 'No reason')} — <span style="color:#aaa;">${esc(f.conversation_id || '')}</span></div>
                    ${f.auto_action ? `<div style="color:#ed4245;font-size:11px;font-weight:600;margin-bottom:6px;">Auto-action: ${esc(f.auto_action)}</div>` : ''}
                    ${f.csam_report ? `<div style="color:#ed4245;font-size:11px;font-weight:700;margin-bottom:6px;background:rgba(237,66,69,0.15);padding:4px 8px;border-radius:4px;">CSAM — NCMEC notified, account terminated</div>` : ''}
                    ${deadlineStr}
                    ${f.content_hidden ? `<div style="color:#e67e22;font-size:11px;margin-bottom:6px;">Content hidden from users</div>` : ''}
                    <div style="display:flex;gap:6px;">
                        <button data-flag-id="${safeFlagId}" data-action="dismissed" onclick="_resolveModFlag(this.dataset.flagId,this.dataset.action)" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:6px 12px;border-radius:6px;cursor:pointer;font-size:11px;">Dismiss</button>
                        <button data-flag-id="${safeFlagId}" data-action="actioned" data-taken="warn" onclick="_resolveModFlag(this.dataset.flagId,this.dataset.action,this.dataset.taken)" style="background:#f0b132;color:white;border:none;padding:6px 12px;border-radius:6px;cursor:pointer;font-size:11px;">Warn</button>
                        <button data-flag-id="${safeFlagId}" data-action="actioned" data-taken="ban" onclick="_resolveModFlag(this.dataset.flagId,this.dataset.action,this.dataset.taken)" style="background:#ed4245;color:white;border:none;padding:6px 12px;border-radius:6px;cursor:pointer;font-size:11px;">Ban</button>
                    </div>
                </div>`;
            }).join('')}
        </div>
        ${resolved.length > 0 ? `
        <details style="margin-top:16px;">
            <summary style="color:var(--text-muted);font-size:13px;cursor:pointer;">Resolved (${resolved.length})</summary>
            <div style="display:flex;flex-direction:column;gap:6px;margin-top:8px;max-height:30vh;overflow-y:auto;">
                ${resolved.map(f => {
                    const esc = _escAttr;
                    return `
                    <div style="padding:10px;background:rgba(0,0,0,0.2);border-radius:8px;opacity:0.6;">
                        <span style="color:white;font-size:12px;">${esc(f.user_id || '?')}</span>
                        <span style="color:var(--text-muted);font-size:11px;margin-left:6px;">${esc(f.ai_classification || '')} — ${esc(f.status || '')}${f.action_taken ? ' (' + esc(f.action_taken) + ')' : ''}</span>
                        <span style="float:right;font-size:10px;color:var(--text-muted);">${new Date(f.timestamp*1000).toLocaleDateString()}</span>
                    </div>`;
                }).join('')}
            </div>
        </details>` : ''}`;
}
async function _resolveModFlag(flagId, resolution, actionTaken) {
    const payload = { flag_id: flagId, resolution };
    if (actionTaken) payload.action_taken = actionTaken;
    const r = await apiRequest('RESOLVE_MODERATION_FLAG', payload);
    if (r.status === 'success') _adminRenderModerationFlags();
    else alert(r.message || 'Failed');
}

function _adminRenderMediaScanner() {
    const c=document.getElementById('admin-content'); if(!c)return;
    c.innerHTML=`<h3 style="color:white;margin-bottom:16px;">🔍 AI Media Scanner</h3>
    <div style="max-width:500px;">
        <div style="color:var(--text-muted);font-size:12px;margin-bottom:8px;">Upload an image to scan via Groq Vision AI. Only triggers on reports or minor-flagged accounts in production.</div>
        <input type="file" id="scan-media-file" accept="image/*" style="margin-bottom:8px;">
        <input type="text" id="scan-media-user" placeholder="Target username (optional)" style="margin-bottom:8px;padding:6px 10px;background:rgba(0,0,0,0.3);border:1px solid var(--glass-border);color:white;border-radius:6px;font-size:12px;width:200px;display:block;">
        <button onclick="_adminScanMedia()" style="background:var(--accent-blue);color:white;border:none;padding:8px 14px;border-radius:6px;cursor:pointer;font-weight:600;">Scan Image</button>
        <div id="scan-result" style="margin-top:12px;font-size:13px;color:var(--text-muted);"></div>
    </div>`;
}
async function _adminScanMedia() {
    const file=document.getElementById('scan-media-file')?.files?.[0]; if(!file){alert('Select an image');return;}
    const targetUser=document.getElementById('scan-media-user')?.value?.trim()||'';
    const s=document.getElementById('scan-result'); if(s)s.textContent='Scanning with Groq Vision...';
    const reader=new FileReader(); reader.onload=async(e)=>{
        const b64=e.target.result.split(',')[1];
        const r=await apiRequest('SCAN_MEDIA',{image_b64:b64, scan_reason:'admin', reported_user:targetUser});
        if(s){
            if(r.safe===false){
                const typeBadge=r.type?` [${r.type.toUpperCase()}]`:'';
                s.innerHTML=`<span style="color:#ed4245;">⚠️ UNSAFE${typeBadge} — ${_escAttr(r.reason||'flagged')}</span>`;
            } else {
                s.innerHTML=`<span style="color:#23a559;">✅ Safe</span>${r.message?' — '+_escAttr(r.message):''}`;
            }
        }
    }; reader.readAsDataURL(file);
}

