// GROUP 8: Version Check + Onboarding Flow
// ══════════════════════════════════════════════════════════════
// Show the update button in topbar on desktop app
function _initUpdateButton() {
    const btn = document.getElementById('topbar-update-btn');
    if (!btn) return;
    // Show on desktop app or always (users can manually check)
    btn.style.display = 'inline-flex';
    btn.title = window.tenshiApp?.isApp
        ? `Tenshi v${localStorage.getItem('tenshi_app_version') || '?'} — Click to check for updates`
        : 'Check for updates';
}

async function _checkAppUpdate() {
    // Topbar 🔄 button — uses Electron IPC if available, falls back to GET_VERSION API.
    // Wrapped in a top-level try/catch so any exception (including from _showUpdateBanner
    // misbehaving on a malformed server response) can't crash the topbar.
    const btn = document.getElementById('topbar-update-btn');
    if (btn) { btn.style.animation = 'spin 1s linear infinite'; btn.title = 'Checking...'; }

    let found = false;
    try {
        // Method 1: Desktop app IPC
        if (window.tenshiApp?.checkForUpdate) {
            try {
                const data = await window.tenshiApp.checkForUpdate();
                if (data && data.needs_update) {
                    _showUpdateBanner(data.version, data.changelog || '', data.download_url || '');
                    found = true;
                }
            } catch (e) { console.warn('IPC update check failed:', e); }
        }
        // Method 2: Web API check
        if (!found) {
            try {
                const r = await apiRequest('GET_VERSION', { version: localStorage.getItem('tenshi_app_version') || 'web' });
                if (r && r.needs_update) {
                    _showUpdateBanner(r.version || 'new', r.changelog || '', r.download_url || '');
                    found = true;
                }
            } catch (e) { console.warn('API update check failed:', e); }
        }
    } catch (e) {
        console.error('[_checkAppUpdate] unexpected error:', e);
        try { showGlobalNotification('Update check failed. Please try again later.', '#ed4245'); } catch {}
    }

    if (btn) {
        btn.style.animation = '';
        if (!found) {
            btn.title = 'Up to date!';
            try { showGlobalNotification('You\'re on the latest version!', '#23a559'); } catch {}
            setTimeout(() => { btn.title = 'Check for updates'; }, 3000);
        }
    }
}

function _showUpdateBanner(version, changelog, downloadUrl) {
    // Remove existing banner if any
    document.getElementById('app-update-banner')?.remove();

    const banner = document.createElement('div');
    banner.id = 'app-update-banner';
    banner.style.cssText = 'position:fixed;top:0;left:0;right:0;background:linear-gradient(135deg,#5865F2,#7289da);color:white;padding:10px 20px;display:flex;align-items:center;justify-content:space-between;z-index:99999;font-size:14px;box-shadow:0 2px 12px rgba(0,0,0,0.3);';

    const isDesktop = window.tenshiApp?.isApp;
    // SECURITY FIX: escape server-supplied version and changelog before injecting into innerHTML.
    // A malicious server push with XSS in these fields would execute in the page context.
    const safeVersion = _escAttr(version || '');
    const safeChangelog = _escAttr(changelog || '');
    // Validate downloadUrl to https:// only (prevent javascript: protocol injection)
    const safeDownloadUrl = (downloadUrl && /^https:\/\//.test(downloadUrl))
        ? _escAttr(downloadUrl)
        : _escAttr('https://api.tenshi.lol/download/windows');
    banner.innerHTML = `
        <div style="display:flex;align-items:center;gap:10px;">
            <span style="font-size:18px;">🆕</span>
            <div>
                <strong>Tenshi v${safeVersion} is available!</strong>
                ${safeChangelog ? `<span style="opacity:0.9;margin-left:8px;">${safeChangelog}</span>` : ''}
            </div>
        </div>
        <div style="display:flex;align-items:center;gap:8px;">
            ${isDesktop ?
                `<button onclick="_downloadAppUpdate()" style="background:white;color:#5865F2;border:none;padding:8px 16px;border-radius:6px;cursor:pointer;font-weight:700;font-size:13px;">⬇ Download Update</button>` :
                `<a href="${safeDownloadUrl}" target="_blank" style="background:white;color:#5865F2;text-decoration:none;padding:8px 16px;border-radius:6px;font-weight:700;font-size:13px;">⬇ Download</a>`
            }
            <button onclick="this.closest('#app-update-banner').remove()" style="background:rgba(255,255,255,0.2);border:none;color:white;width:28px;height:28px;border-radius:50%;cursor:pointer;font-size:14px;">✕</button>
        </div>
    `;
    document.body.prepend(banner);
}

async function _downloadAppUpdate() {
    if (window.tenshiApp?.downloadUpdate) {
        await window.tenshiApp.downloadUpdate();
    } else {
        window.open('https://api.tenshi.lol/download/windows', '_blank');
    }
}

async function _checkAppVersion() {
    try {
        const r=await apiRequest('GET_VERSION',{version:'web'});
        if(r.needs_update && r.download_url) {
            const bar=document.createElement('div');
            bar.style.cssText='padding:8px 16px;background:linear-gradient(90deg,#f0b132,#e67e22);color:white;font-size:13px;font-weight:600;text-align:center;cursor:pointer;';
            bar.innerHTML=`🔄 A new version (${_escAttr(r.version)}) is available! <a href="${_escAttr(r.download_url)}" style="color:white;text-decoration:underline;">Download</a>`;
            const topbar=document.getElementById('app-topbar');
            if(topbar)topbar.insertAdjacentElement('afterend',bar);
        }
    } catch {}
}

async function _showOnboardingIfNeeded(serverId) {
    try {
        const r=await apiRequest('GET_ONBOARDING',{server_id:serverId});
        if(r.status!=='success'||!r.questions||!r.questions.length) return;
        const questions=r.questions||[];
        const roles=r.selectable_roles||[];
        let html=`<div style="position:fixed;inset:0;background:rgba(0,0,0,0.85);z-index:300;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(6px);" id="onboarding-overlay">
            <div style="background:rgba(22,23,26,0.98);border:1px solid var(--glass-border);border-radius:16px;padding:24px;max-width:450px;width:90%;">
                <h3 style="color:white;margin:0 0 16px;">👋 Welcome! Answer a few questions</h3>`;
        questions.forEach((q,i)=>{html+=`<div style="margin-bottom:12px;"><label style="color:var(--text-muted);font-size:12px;">${_escAttr(q)}</label><input class="onboarding-answer" data-q="${i}" style="width:100%;margin-top:4px;padding:8px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;border-radius:6px;font-size:13px;box-sizing:border-box;"></div>`;});
        if(roles.length) { html+=`<div style="margin-bottom:12px;"><div style="color:var(--text-muted);font-size:12px;margin-bottom:4px;">Select your roles:</div>`; roles.forEach(r=>{html+=`<label style="display:flex;align-items:center;gap:6px;padding:4px 0;color:white;font-size:13px;cursor:pointer;"><input type="checkbox" class="onboarding-role" value="${_escAttr(r)}" style="accent-color:var(--accent-blue);"> ${_escAttr(r)}</label>`;}); html+=`</div>`; }
        html+=`<button onclick="_submitOnboarding('${_escAttr(serverId)}')" style="width:100%;background:#23a559;color:white;border:none;padding:10px;border-radius:8px;cursor:pointer;font-weight:600;">Submit</button></div></div>`;
        document.body.insertAdjacentHTML('beforeend',html);
    } catch {}
}

async function _submitOnboarding(serverId) {
    const answers={}; document.querySelectorAll('.onboarding-answer').forEach(el=>{answers[el.dataset.q]=el.value;});
    const roles=[]; document.querySelectorAll('.onboarding-role:checked').forEach(el=>roles.push(el.value));
    await apiRequest('SUBMIT_ONBOARDING',{server_id:serverId,answers,selected_roles:roles});
    const overlay=document.getElementById('onboarding-overlay'); if(overlay)overlay.remove();
}

// ══════════════════════════════════════════════════════════════
// CURSOR BUDDY — a small character that follows your mouse
// ══════════════════════════════════════════════════════════════
const _BUDDY_CHARS = ['🐱','🐶','🐰','🦊','🐼','🐸','🦉','🐧','🐝','👻','🐉','🦋','🐙','🦎'];
let _buddyEl = null;
let _buddyX = 0, _buddyY = 0, _mouseX = 0, _mouseY = 0;
let _buddyRafId = null;

function _initCursorBuddy() {
    const saved = localStorage.getItem('tenshi_cursor_buddy');
    if (!saved) return;
    _spawnBuddy(saved);
}

function _spawnBuddy(emoji) {
    if (_buddyEl) _buddyEl.remove();
    if (_buddyRafId) cancelAnimationFrame(_buddyRafId);
    if (!emoji) { _buddyEl = null; return; }

    const el = document.createElement('div');
    el.id = 'cursor-buddy';
    el.style.cssText = 'position:fixed;pointer-events:none;z-index:9999;font-size:28px;transition:transform 0.1s;filter:drop-shadow(0 2px 4px rgba(0,0,0,0.4));';
    el.textContent = emoji;
    document.body.appendChild(el);
    _buddyEl = el;
    _buddyX = window.innerWidth / 2;
    _buddyY = window.innerHeight / 2;

    // Inject bounce animation
    let styleEl = document.getElementById('buddy-style');
    if (!styleEl) {
        styleEl = document.createElement('style');
        styleEl.id = 'buddy-style';
        styleEl.textContent = `@keyframes buddy-bounce { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-4px)} } #cursor-buddy{animation:buddy-bounce 1.2s ease-in-out infinite;}`;
        document.head.appendChild(styleEl);
    }

    document.addEventListener('mousemove', _buddyMouseMove);
    _buddyAnimate();
}

function _buddyMouseMove(e) { _mouseX = e.clientX + 16; _mouseY = e.clientY + 16; }

function _buddyAnimate() {
    if (!_buddyEl) return;
    _buddyX += (_mouseX - _buddyX) * 0.12;
    _buddyY += (_mouseY - _buddyY) * 0.12;
    _buddyEl.style.left = _buddyX + 'px';
    _buddyEl.style.top = _buddyY + 'px';
    _buddyRafId = requestAnimationFrame(_buddyAnimate);
}

function _setBuddy(emoji) {
    if (emoji) { localStorage.setItem('tenshi_cursor_buddy', emoji); _spawnBuddy(emoji); }
    else { localStorage.removeItem('tenshi_cursor_buddy'); _spawnBuddy(null); }
}

function _removeBuddy() {
    localStorage.removeItem('tenshi_cursor_buddy');
    if (_buddyEl) { _buddyEl.remove(); _buddyEl = null; }
    if (_buddyRafId) { cancelAnimationFrame(_buddyRafId); _buddyRafId = null; }
    document.removeEventListener('mousemove', _buddyMouseMove);
}

// Init buddy on load
setTimeout(_initCursorBuddy, 1000);

