// MINI PET GAME — tamagotchi-style virtual pet
// ══════════════════════════════════════════════════════════════
const _PET_SPECIES = [
    { emoji: '🐱', name: 'Cat' },
    { emoji: '🐶', name: 'Dog' },
    { emoji: '🐰', name: 'Bunny' },
    { emoji: '🐼', name: 'Panda' },
    { emoji: '🐸', name: 'Frog' },
    { emoji: '🦊', name: 'Fox' },
    { emoji: '🐧', name: 'Penguin' },
    { emoji: '🐉', name: 'Dragon' },
    { emoji: '🦋', name: 'Butterfly' },
    { emoji: '🐙', name: 'Octopus' },
];

function _getPetState() {
    try { return JSON.parse(localStorage.getItem('tenshi_pet') || 'null'); } catch { return null; }
}

function _savePetState(pet) {
    if (pet) { pet.lastUpdated = Date.now(); localStorage.setItem('tenshi_pet', JSON.stringify(pet)); }
    else localStorage.removeItem('tenshi_pet');
}

function _updatePetDecay(pet) {
    if (!pet || !pet.alive) return pet;
    const hours = (Date.now() - (pet.lastUpdated || Date.now())) / 3600000;
    if (hours < 0.05) return pet; // Less than 3 min — no decay
    const decay = Math.floor(hours * 5); // Lose ~5 per hour
    pet.hunger = Math.max(0, (pet.hunger || 100) - decay);
    pet.happiness = Math.max(0, (pet.happiness || 100) - decay);
    pet.energy = Math.max(0, (pet.energy || 100) - Math.floor(hours * 3));
    // Pet runs away if all stats hit 0
    if (pet.hunger <= 0 && pet.happiness <= 0 && pet.energy <= 0) {
        pet.alive = false;
    }
    pet.lastUpdated = Date.now();
    return pet;
}

function _petMood(pet) {
    if (!pet.alive) return '💀 Ran away...';
    const avg = (pet.hunger + pet.happiness + pet.energy) / 3;
    if (avg > 80) return '😄 Ecstatic!';
    if (avg > 60) return '😊 Happy';
    if (avg > 40) return '😐 Okay';
    if (avg > 20) return '😢 Sad';
    return '😰 Critical!';
}

function _statBar(label, value, color) {
    return `<div style="margin-bottom:6px;">
        <div style="display:flex;justify-content:space-between;font-size:11px;color:var(--text-muted);margin-bottom:2px;"><span>${label}</span><span>${value}/100</span></div>
        <div style="height:8px;background:rgba(255,255,255,0.08);border-radius:4px;overflow:hidden;">
            <div style="height:100%;width:${value}%;background:${color};border-radius:4px;transition:width 0.5s;"></div>
        </div>
    </div>`;
}

function _openPetPanel() {
    let overlay = document.getElementById('pet-panel-overlay');
    if (overlay) { overlay.remove(); return; }
    overlay = document.createElement('div');
    overlay.id = 'pet-panel-overlay';
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:300;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px);padding:16px;';
    const panel = document.createElement('div');
    panel.style.cssText = 'background:rgba(22,23,26,0.98);border:1px solid var(--glass-border);border-radius:16px;padding:24px;max-width:450px;width:100%;max-height:90vh;overflow-y:auto;position:relative;';
    panel.innerHTML = '<button onclick="document.getElementById(\'pet-panel-overlay\').remove()" style="position:absolute;top:12px;right:12px;background:none;border:none;color:var(--text-muted);font-size:18px;cursor:pointer;">✕</button><div id="pet-panel-body"></div>';
    overlay.appendChild(panel);
    overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };
    document.body.appendChild(overlay);
    _renderPetGame(document.getElementById('pet-panel-body'));
}

function _renderPetGame(body) {
    let pet = _getPetState();
    if (pet) pet = _updatePetDecay(pet);
    if (pet) _savePetState(pet);

    if (!pet) {
        // Adoption screen
        body.innerHTML = `
            <div style="display:flex;flex-direction:column;gap:16px;max-width:400px;text-align:center;">
                <h2 style="color:white;margin:0;font-size:18px;font-weight:700;">🐾 Adopt a Pet!</h2>
                <p style="color:var(--text-muted);font-size:13px;margin:0;">Choose a companion to take care of. Feed them, play with them, and keep them happy!</p>
                <div style="display:grid;grid-template-columns:repeat(5,1fr);gap:8px;">
                    ${_PET_SPECIES.map(s => `
                        <button onclick="_adoptPet('${s.emoji}','${s.name}')" style="background:rgba(255,255,255,0.06);border:1px solid var(--glass-border);border-radius:12px;padding:12px 4px;cursor:pointer;text-align:center;" onmouseover="this.style.background='rgba(255,255,255,0.12)'" onmouseout="this.style.background='rgba(255,255,255,0.06)'">
                            <div style="font-size:32px;">${s.emoji}</div>
                            <div style="font-size:10px;color:var(--text-muted);margin-top:4px;">${s.name}</div>
                        </button>
                    `).join('')}
                </div>
            </div>`;
        return;
    }

    if (!pet.alive) {
        body.innerHTML = `
            <div style="display:flex;flex-direction:column;gap:16px;max-width:400px;text-align:center;">
                <h2 style="color:white;margin:0;font-size:18px;">😢 Your pet ran away...</h2>
                <p style="color:var(--text-muted);font-size:13px;">${pet.name} the ${pet.speciesName} was too neglected and left. All stats reached zero.</p>
                <div style="font-size:48px;opacity:0.3;">${pet.species}</div>
                <p style="color:var(--text-muted);font-size:12px;">Level ${pet.level} • ${pet.xp} XP earned</p>
                <button onclick="_savePetState(null);_renderPetGame(document.getElementById('pet-panel-body')||document.getElementById('settings-body'))" style="background:var(--accent-blue);color:white;border:none;padding:10px 20px;border-radius:8px;cursor:pointer;font-weight:600;">Adopt a New Pet</button>
            </div>`;
        return;
    }

    const cooldowns = pet.cooldowns || {};
    const now = Date.now();
    const canFeed = !cooldowns.feed || now > cooldowns.feed;
    const canPlay = !cooldowns.play || now > cooldowns.play;
    const canSleep = !cooldowns.sleep || now > cooldowns.sleep;

    const cdText = (key, mins) => {
        if (!cooldowns[key] || now > cooldowns[key]) return '';
        const left = Math.ceil((cooldowns[key] - now) / 60000);
        return `<span style="font-size:10px;color:var(--text-muted);">(${left}m)</span>`;
    };

    body.innerHTML = `
        <div style="display:flex;flex-direction:column;gap:16px;max-width:400px;">
            <h2 style="color:white;margin:0;font-size:18px;font-weight:700;">🐾 Your Pet</h2>
            <div style="text-align:center;padding:20px;background:rgba(0,0,0,0.2);border-radius:16px;border:1px solid var(--glass-border);">
                <div style="font-size:64px;animation:buddy-bounce 1.5s ease-in-out infinite;">${pet.species}</div>
                <div style="color:white;font-size:18px;font-weight:700;margin-top:8px;">${_escAttr(pet.name)}</div>
                <div style="color:var(--text-muted);font-size:12px;">Level ${pet.level} ${pet.speciesName} • ${pet.xp} XP</div>
                <div style="color:var(--accent-blue);font-size:13px;margin-top:4px;">${_petMood(pet)}</div>
            </div>
            <div>
                ${_statBar('🍖 Hunger', pet.hunger, pet.hunger > 30 ? '#23a559' : pet.hunger > 15 ? '#f0b132' : '#ed4245')}
                ${_statBar('💛 Happiness', pet.happiness, pet.happiness > 30 ? '#5865F2' : pet.happiness > 15 ? '#f0b132' : '#ed4245')}
                ${_statBar('⚡ Energy', pet.energy, pet.energy > 30 ? '#00b0f4' : pet.energy > 15 ? '#f0b132' : '#ed4245')}
            </div>
            <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:8px;">
                <button onclick="_petAction('feed')" ${canFeed?'':'disabled'} style="padding:10px;border-radius:8px;border:none;cursor:${canFeed?'pointer':'not-allowed'};font-size:13px;font-weight:600;background:${canFeed?'rgba(35,165,89,0.15)':'rgba(255,255,255,0.04)'};color:${canFeed?'#23a559':'var(--text-muted)'};">🍖 Feed ${cdText('feed')}</button>
                <button onclick="_petAction('play')" ${canPlay?'':'disabled'} style="padding:10px;border-radius:8px;border:none;cursor:${canPlay?'pointer':'not-allowed'};font-size:13px;font-weight:600;background:${canPlay?'rgba(88,101,242,0.15)':'rgba(255,255,255,0.04)'};color:${canPlay?'#5865F2':'var(--text-muted)'};">🎾 Play ${cdText('play')}</button>
                <button onclick="_petAction('sleep')" ${canSleep?'':'disabled'} style="padding:10px;border-radius:8px;border:none;cursor:${canSleep?'pointer':'not-allowed'};font-size:13px;font-weight:600;background:${canSleep?'rgba(0,176,244,0.15)':'rgba(255,255,255,0.04)'};color:${canSleep?'#00b0f4':'var(--text-muted)'};">😴 Sleep ${cdText('sleep')}</button>
                <button onclick="_petAction('medicine')" style="padding:10px;border-radius:8px;border:none;cursor:pointer;font-size:13px;font-weight:600;background:rgba(240,177,50,0.15);color:#f0b132;">💊 Medicine</button>
            </div>
            <div style="display:flex;gap:8px;">
                <button onclick="let n=prompt('Rename your pet:',_getPetState()?.name||'');if(n){let p=_getPetState();p.name=n;_savePetState(p);_renderPetGame(document.getElementById('pet-panel-body')||document.getElementById('settings-body'));}" style="flex:1;padding:8px;border-radius:8px;border:1px solid var(--glass-border);background:rgba(255,255,255,0.04);color:white;cursor:pointer;font-size:12px;">✏️ Rename</button>
                <button onclick="if(confirm('Release your pet? This cannot be undone.')){_savePetState(null);_renderPetGame(document.getElementById('pet-panel-body')||document.getElementById('settings-body'));}" style="flex:1;padding:8px;border-radius:8px;border:1px solid rgba(237,66,69,0.3);background:rgba(237,66,69,0.06);color:#ed4245;cursor:pointer;font-size:12px;">🏃 Release</button>
            </div>
            <div style="border-top:1px solid rgba(255,255,255,0.06);padding-top:12px;">
                <div style="font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:.5px;color:var(--text-muted);margin-bottom:8px;">Cursor Buddy</div>
                <div style="display:flex;flex-wrap:wrap;gap:4px;">
                    <button onclick="_removeBuddy();this.parentElement.querySelector('.buddy-active')?.classList.remove('buddy-active')" style="padding:6px 10px;border-radius:6px;border:1px solid var(--glass-border);background:rgba(255,255,255,0.04);color:var(--text-muted);cursor:pointer;font-size:12px;">Off</button>
                    ${_BUDDY_CHARS.map(c => `<button onclick="_setBuddy('${c}')" style="font-size:20px;padding:4px 6px;border-radius:6px;border:1px solid ${localStorage.getItem('tenshi_cursor_buddy')===c?'var(--accent-blue)':'var(--glass-border)'};background:${localStorage.getItem('tenshi_cursor_buddy')===c?'rgba(88,101,242,0.2)':'rgba(255,255,255,0.04)'};cursor:pointer;">${c}</button>`).join('')}
                </div>
            </div>
        </div>`;

    // Inject bounce animation if not already present
    if (!document.getElementById('buddy-style')) {
        const s = document.createElement('style');
        s.id = 'buddy-style';
        s.textContent = '@keyframes buddy-bounce { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-6px)} }';
        document.head.appendChild(s);
    }
}

function _adoptPet(emoji, speciesName) {
    const name = prompt(`Name your ${speciesName}:`, speciesName);
    if (!name) return;
    const pet = {
        name, species: emoji, speciesName,
        hunger: 100, happiness: 100, energy: 100,
        level: 1, xp: 0, alive: true,
        cooldowns: {}, lastUpdated: Date.now()
    };
    _savePetState(pet);
    _renderPetGame(document.getElementById('pet-panel-body')||document.getElementById('settings-body'));
    tenshiAudio.join();
}

function _petAction(action) {
    let pet = _getPetState();
    if (!pet || !pet.alive) return;
    pet = _updatePetDecay(pet);
    const now = Date.now();
    pet.cooldowns = pet.cooldowns || {};

    switch (action) {
        case 'feed':
            if (pet.cooldowns.feed && now < pet.cooldowns.feed) return;
            pet.hunger = Math.min(100, pet.hunger + 30);
            pet.xp += 10;
            pet.cooldowns.feed = now + 1800000; // 30 min
            tenshiAudio.message();
            break;
        case 'play':
            if (pet.cooldowns.play && now < pet.cooldowns.play) return;
            pet.happiness = Math.min(100, pet.happiness + 25);
            pet.energy = Math.max(0, pet.energy - 10);
            pet.xp += 15;
            pet.cooldowns.play = now + 900000; // 15 min
            tenshiAudio.dm();
            break;
        case 'sleep':
            if (pet.cooldowns.sleep && now < pet.cooldowns.sleep) return;
            pet.energy = Math.min(100, pet.energy + 40);
            pet.xp += 10;
            pet.cooldowns.sleep = now + 3600000; // 1 hr
            tenshiAudio.notify();
            break;
        case 'medicine':
            pet.hunger = Math.min(100, pet.hunger + 15);
            pet.happiness = Math.min(100, pet.happiness + 15);
            pet.energy = Math.min(100, pet.energy + 15);
            pet.xp += 5;
            tenshiAudio.friendReq();
            break;
    }

    // Level up every 100 XP
    const newLevel = Math.floor(pet.xp / 100) + 1;
    if (newLevel > pet.level) {
        pet.level = newLevel;
        alert(`🎉 ${pet.name} leveled up to Level ${pet.level}!`);
    }

    _savePetState(pet);
    _renderPetGame(document.getElementById('pet-panel-body')||document.getElementById('settings-body'));
}

// ══════════════════════════════════════════════════════════════
// ══════════════════════════════════════════════════════════════
// API TRACKER — monitor any external API endpoint
// ══════════════════════════════════════════════════════════════
let _trackerTemplates = [];
let _trackerTemplateFilter = 'All';
let _trackerAISuggestions = [];
let _trackerAILoading = false;

async function _renderAPITracker(body) {
    body.innerHTML = '<div style="color:var(--text-muted);font-size:13px;">Loading trackers...</div>';
    const [r, tplResp] = await Promise.all([
        apiRequest('GET_API_TRACKERS'),
        _trackerTemplates.length ? Promise.resolve({status:'success',templates:_trackerTemplates}) : apiRequest('GET_API_TEMPLATES')
    ]);
    const trackers = r.trackers || [];
    if (tplResp.status === 'success' && tplResp.templates) _trackerTemplates = tplResp.templates;

    const catIcons = {All:'📡',Sports:'⚽',Gaming:'🎮',Crypto:'💰',Weather:'🌤️',Fun:'🎲',Dev:'💻',Finance:'📊',Science:'🔬',Testing:'🧪'};
    const categories = ['All','Sports','Gaming','Crypto','Weather','Fun','Dev','Finance','Science','Testing'];

    // -- Filter templates by category
    const filtered = _trackerTemplateFilter === 'All' ? _trackerTemplates : _trackerTemplates.filter(t => t.category === _trackerTemplateFilter);

    let html = `<div style="display:flex;flex-direction:column;gap:16px;max-width:640px;">
        <h2 style="color:white;margin:0;font-size:18px;font-weight:700;">📡 API Tracker</h2>
        <p style="color:var(--text-muted);font-size:12px;margin:0;">Monitor any API endpoint. Add up to 20 trackers to check uptime, latency, and status codes.</p>

        <!-- AI Suggestion Bar -->
        <div style="padding:12px;background:rgba(88,101,242,0.08);border-radius:10px;border:1px solid rgba(88,101,242,0.25);">
            <div style="color:var(--accent-blue);font-size:12px;font-weight:600;margin-bottom:8px;">✨ AI API Finder</div>
            <div style="display:flex;gap:6px;">
                <input type="text" id="ai-api-query" placeholder="What do you want to track? (e.g. crypto prices, weather, news...)" style="flex:1;padding:8px 10px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;border-radius:6px;font-size:12px;" onkeydown="if(event.key==='Enter')_suggestAPIs()">
                <button onclick="_suggestAPIs()" id="ai-api-btn" style="background:var(--accent-blue);color:white;border:none;padding:8px 14px;border-radius:6px;cursor:pointer;font-weight:600;font-size:12px;white-space:nowrap;">${_trackerAILoading ? '...' : 'Suggest'}</button>
            </div>
            <div id="ai-api-results" style="margin-top:8px;display:flex;flex-direction:column;gap:6px;">`;

    // Show AI suggestions if any
    _trackerAISuggestions.forEach((s, i) => {
        html += `<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 10px;background:rgba(0,0,0,0.25);border-radius:6px;border:1px solid var(--glass-border);">
            <div style="flex:1;min-width:0;">
                <div style="color:white;font-size:12px;font-weight:600;">${_escAttr(s.name||'')}</div>
                <div style="color:var(--text-muted);font-size:10px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${_escAttr(s.description||'')}</div>
                <div style="color:var(--text-muted);font-size:9px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;margin-top:2px;">${_escAttr(s.url||'')}</div>
            </div>
            <button onclick="_addFromSuggestion(${i},'ai')" style="background:#23a559;color:white;border:none;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:11px;margin-left:8px;white-space:nowrap;">+ Add</button>
        </div>`;
    });
    html += `</div></div>

        <!-- Template Gallery -->
        <div style="padding:12px;background:rgba(0,0,0,0.2);border-radius:10px;border:1px solid var(--glass-border);">
            <div style="color:white;font-size:13px;font-weight:600;margin-bottom:8px;">📋 Popular API Templates</div>
            <div style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:10px;">
                ${categories.map(c => `<button onclick="_setTrackerFilter('${c}')" style="padding:4px 10px;border-radius:12px;border:1px solid ${_trackerTemplateFilter===c?'var(--accent-blue)':'var(--glass-border)'};background:${_trackerTemplateFilter===c?'rgba(88,101,242,0.2)':'rgba(0,0,0,0.2)'};color:${_trackerTemplateFilter===c?'var(--accent-blue)':'var(--text-muted)'};cursor:pointer;font-size:11px;white-space:nowrap;">${catIcons[c]||'📦'} ${c}</button>`).join('')}
            </div>
            <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:8px;">
                ${filtered.map((t,i) => {
                    const idx = _trackerTemplates.indexOf(t);
                    return `<div style="padding:10px;background:rgba(0,0,0,0.25);border-radius:8px;border:1px solid var(--glass-border);cursor:pointer;transition:border-color .15s;" onmouseenter="this.style.borderColor='var(--accent-blue)'" onmouseleave="this.style.borderColor='var(--glass-border)'" onclick="_addFromSuggestion(${idx},'tpl')">
                    <div style="display:flex;justify-content:space-between;align-items:start;">
                        <span style="font-size:16px;">${catIcons[t.category]||'📦'}</span>
                        <span style="color:var(--text-muted);font-size:9px;background:rgba(255,255,255,0.06);padding:2px 6px;border-radius:4px;">${_escAttr(t.category)}</span>
                    </div>
                    <div style="color:white;font-size:12px;font-weight:600;margin-top:6px;">${_escAttr(t.name)}</div>
                    <div style="color:var(--text-muted);font-size:10px;margin-top:2px;">${_escAttr(t.description)}</div>
                </div>`}).join('')}
            </div>
        </div>

        <!-- Manual Add -->
        <div style="display:flex;flex-direction:column;gap:8px;padding:12px;background:rgba(0,0,0,0.2);border-radius:10px;border:1px solid var(--glass-border);">
            <div style="color:white;font-size:13px;font-weight:600;margin-bottom:2px;">➕ Add Custom API</div>
            <div style="display:flex;gap:6px;">
                <input type="text" id="tracker-name" placeholder="Name (e.g. My API)" style="width:120px;padding:8px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;border-radius:6px;font-size:12px;">
                <input type="text" id="tracker-url" placeholder="https://api.example.com/health" style="flex:1;padding:8px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;border-radius:6px;font-size:12px;">
            </div>
            <div style="display:flex;gap:6px;align-items:center;">
                <select id="tracker-method" style="padding:8px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;border-radius:6px;font-size:12px;">
                    <option value="GET">GET</option>
                    <option value="POST">POST</option>
                    <option value="HEAD">HEAD</option>
                </select>
                <button onclick="_addTracker()" style="background:#23a559;color:white;border:none;padding:8px 16px;border-radius:6px;cursor:pointer;font-weight:600;font-size:12px;white-space:nowrap;">+ Add Tracker</button>
            </div>
        </div>

        <!-- Tracked APIs List -->
        <div style="color:white;font-size:13px;font-weight:600;">📊 Your Tracked APIs (${trackers.length}/20)</div>`;

    if (!trackers.length) {
        html += '<div style="color:var(--text-muted);font-size:13px;text-align:center;padding:20px;">No trackers yet. Add one above or pick a template!</div>';
    }

    trackers.forEach(t => {
        const last = t.last_check || {};
        const uptime = t.history ? Math.round(t.history.filter(h => h.up).length / Math.max(t.history.length, 1) * 100) : 0;
        const statusColor = last.up ? '#23a559' : (last.status_code ? '#ed4245' : 'var(--text-muted)');
        const statusText = last.up ? `✓ ${last.status_code} (${last.latency_ms}ms)` : (last.status_code ? `✗ ${last.status_code}` : (last.error ? `✗ ${last.error.substring(0,30)}` : 'Not checked'));

        html += `
            <div style="padding:12px;background:rgba(0,0,0,0.2);border-radius:10px;border:1px solid var(--glass-border);">
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
                    <div>
                        <span style="color:white;font-weight:600;font-size:14px;">${_escAttr(t.name)}</span>
                        <span style="color:var(--text-muted);font-size:10px;margin-left:6px;">${t.method}</span>
                    </div>
                    <div style="display:flex;gap:4px;">
                        <button onclick="_pingTracker('${t.id}')" style="background:rgba(88,101,242,0.15);color:var(--accent-blue);border:none;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:11px;">Ping</button>
                        <button onclick="_deleteTracker('${t.id}')" style="background:rgba(237,66,69,0.1);color:#ed4245;border:none;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:11px;">✗</button>
                    </div>
                </div>
                <div style="color:var(--text-muted);font-size:11px;margin-bottom:6px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${_escAttr(t.url)}</div>
                <div style="display:flex;justify-content:space-between;align-items:center;">
                    <span style="color:${statusColor};font-size:12px;font-weight:600;">${statusText}</span>
                    <span style="color:var(--text-muted);font-size:10px;">Uptime: ${uptime}% (${(t.history||[]).length} checks)</span>
                </div>
                ${(t.history||[]).length > 1 ? `
                <div style="display:flex;gap:1px;margin-top:6px;height:20px;align-items:flex-end;">
                    ${t.history.slice(-30).map(h => `<div style="flex:1;background:${h.up?'#23a559':'#ed4245'};border-radius:1px;min-height:4px;height:${h.up?Math.max(20,Math.min(100,100-h.latency_ms/10))+'%':'20%'};" title="${h.status_code} ${h.latency_ms}ms"></div>`).join('')}
                </div>` : ''}
            </div>`;
    });

    html += '</div>';
    body.innerHTML = html;
}

async function _addTracker() {
    const name = document.getElementById('tracker-name')?.value?.trim() || '';
    const url = document.getElementById('tracker-url')?.value?.trim();
    const method = document.getElementById('tracker-method')?.value || 'GET';
    if (!url) { alert('Enter a URL'); return; }
    const r = await apiRequest('ADD_API_TRACKER', { name: name || url.substring(0, 40), url, method });
    if (r.status === 'success') _renderAPITracker(document.getElementById('settings-body'));
    else alert(r.message || 'Failed');
}

async function _pingTracker(id) {
    const r = await apiRequest('PING_API_TRACKER', { tracker_id: id });
    if (r.result) {
        const res = r.result;
        alert(res.up ? `✓ UP — ${res.status_code} (${res.latency_ms}ms)` : `✗ DOWN — ${res.error || 'Status ' + res.status_code}`);
    }
    _renderAPITracker(document.getElementById('settings-body'));
}

async function _deleteTracker(id) {
    if (!confirm('Delete this tracker?')) return;
    await apiRequest('DELETE_API_TRACKER', { tracker_id: id });
    _renderAPITracker(document.getElementById('settings-body'));
}

function _setTrackerFilter(cat) {
    _trackerTemplateFilter = cat;
    _renderAPITracker(document.getElementById('settings-body'));
}

async function _suggestAPIs() {
    const q = document.getElementById('ai-api-query')?.value?.trim();
    if (!q) return;
    _trackerAILoading = true;
    const btn = document.getElementById('ai-api-btn');
    if (btn) { btn.textContent = '...'; btn.disabled = true; }
    try {
        const r = await apiRequest('SUGGEST_APIS', { query: q });
        _trackerAISuggestions = (r.status === 'success' && Array.isArray(r.suggestions)) ? r.suggestions : [];
        if (r.status !== 'success') alert(r.message || 'AI suggestion failed');
    } catch(e) { alert('AI suggestion failed'); }
    _trackerAILoading = false;
    _renderAPITracker(document.getElementById('settings-body'));
}

async function _addFromSuggestion(idx, src) {
    const item = src === 'ai' ? _trackerAISuggestions[idx] : _trackerTemplates[idx];
    if (!item) return;
    const r = await apiRequest('ADD_API_TRACKER', { name: item.name, url: item.url, method: 'GET' });
    if (r.status === 'success') _renderAPITracker(document.getElementById('settings-body'));
    else alert(r.message || 'Failed to add tracker');
}

