// Roadmap §9 fix — was previously also named _checkAppUpdate, silently overriding the
// topbar handler at line ~18413. The topbar 🔄 button would crash because the override
// targets DOM elements (#check-update-btn, #update-result) that only exist in the
// settings panel, and the override's GitHub-API path sometimes returns malformed
// release.body / null asset arrays that broke the UI mid-render. Renamed for clarity.
async function _checkAppUpdateFromSettings() {
    const btn = document.getElementById('check-update-btn');
    const result = document.getElementById('update-result');
    if (btn) btn.textContent = 'Checking...';
    if (btn) btn.disabled = true;

    try {
        const res = await fetch('https://api.github.com/repos/exile-tenshi/Tenshi/releases/latest', {
            headers: { 'Accept': 'application/vnd.github.v3+json' }
        });
        const release = await res.json();
        const latestTag = (release.tag_name || '').replace(/^v/, '');
        const currentVersion = (window.tenshiApp && window.tenshiApp.version) || localStorage.getItem('tenshi_app_version') || '0';

        if (result) result.style.display = 'block';

        if (latestTag && latestTag !== currentVersion) {
            const asset = (release.assets || []).find(a => a.name.endsWith('.exe') && a.browser_download_url);
            const downloadUrl = asset ? asset.browser_download_url : release.html_url;

            if (result) result.innerHTML = `
                <div style="margin-bottom:10px;">
                    <span style="color:#faa61a;font-weight:700;font-size:14px;">Update Available!</span>
                    <span style="color:var(--text-muted);font-size:12px;margin-left:8px;">v${currentVersion} → v${latestTag}</span>
                </div>
                <p style="color:var(--text-muted);font-size:12px;margin:0 0 12px;line-height:1.5;">${(release.body || '').substring(0, 300).replace(/\n/g, '<br>')}</p>
                <a href="${downloadUrl}" target="_blank" style="display:block;width:100%;padding:12px;background:#23a559;color:white;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer;text-align:center;text-decoration:none;">
                    Download v${latestTag}
                </a>
                <p style="color:var(--text-muted);font-size:11px;margin:8px 0 0;text-align:center;">After downloading, close this app and run the installer.</p>
                <p style="color:var(--text-muted);font-size:11px;margin:4px 0 0;text-align:center;">You will be asked to review and accept the updated Terms of Service and Privacy Policy after updating.</p>`;
        } else {
            if (result) result.innerHTML = `
                <span style="color:#23a559;font-weight:600;font-size:14px;">✓ You're up to date!</span>
                <span style="color:var(--text-muted);font-size:12px;margin-left:8px;">v${currentVersion}</span>`;
        }
    } catch (e) {
        if (result) {
            result.style.display = 'block';
            result.innerHTML = '<span style="color:#ed4245;font-size:13px;">Failed to check for updates. Please try again.</span>';
        }
    }

    if (btn) { btn.textContent = 'Check for Updates'; btn.disabled = false; }
}

function _forceReviewTOS() {
    localStorage.removeItem('tenshi_tos_accepted');
    _checkTOSAcceptance();
}

// MUSIC PLAYER — shared music in voice channels
// ══════════════════════════════════════════════════════════════
let _musicPanelOpen = false;
let _musicPollInterval = null;
let _currentMusic = null;
let _musicAudio = null;
let _musicTunedIn = false;
let _musicListeners = [];

function _toggleMusicPanel() {
    if (!_voiceChannelName) { alert('Join a voice channel first'); return; }
    // Render music controls inside the music bot participant box
    const remoteDiv = document.getElementById('remote-videos');
    if (!remoteDiv) return;

    const existing = document.getElementById('vc-music-controls');
    if (existing) { existing.remove(); _musicPanelOpen = false; return; }
    _musicPanelOpen = true;

    // Ensure music bot box exists
    _showMusicParticipant(_currentMusic || {title:'No song',requester:currentUser});

    const panel = document.createElement('div');
    panel.id = 'vc-music-controls';
    panel.style.cssText = 'display:flex;flex-direction:column;gap:4px;width:240px;padding:8px;background:rgba(35,165,89,0.06);border:1px solid rgba(35,165,89,0.15);border-radius:10px;';
    panel.innerHTML = `
        <div id="music-now-playing"></div>
        <div style="display:flex;gap:4px;">
            <input type="text" id="music-url-input" placeholder="YouTube/SoundCloud URL..." style="flex:1;padding:6px 10px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;border-radius:6px;font-size:11px;">
            <button onclick="_musicPlay()" style="background:#23a559;color:white;border:none;padding:6px 10px;border-radius:6px;cursor:pointer;font-weight:600;font-size:11px;white-space:nowrap;">▶</button>
        </div>
        <div style="display:flex;gap:4px;">
            <button onclick="_musicAddToQueue()" style="flex:1;background:rgba(88,101,242,0.15);color:var(--accent-blue);border:none;padding:4px;border-radius:4px;cursor:pointer;font-size:10px;">+ Queue</button>
            <button onclick="_musicSkip()" style="flex:1;background:rgba(255,255,255,0.06);color:white;border:none;padding:4px;border-radius:4px;cursor:pointer;font-size:10px;">⏭ Skip</button>
            <button onclick="_musicStop()" style="flex:1;background:rgba(237,66,69,0.15);color:#ed4245;border:none;padding:4px;border-radius:4px;cursor:pointer;font-size:10px;">⏹ Stop</button>
        </div>
        <div style="display:flex;gap:4px;">
            <button id="music-tune-btn" onclick="_toggleTuneIn()" style="flex:1;background:rgba(88,101,242,0.15);color:var(--accent-blue);border:none;padding:4px;border-radius:4px;cursor:pointer;font-size:10px;">🎧 Tune In</button>
        </div>
        <div id="music-listeners"></div>
        <div id="music-queue-list" style="max-height:80px;overflow-y:auto;"></div>
    `;

    // Insert after the music bot box
    const musicBot = document.getElementById('vc-music-bot');
    if (musicBot) {
        musicBot.insertAdjacentElement('afterend', panel);
    } else {
        const meBox = document.getElementById('vc-participant-me');
        if (meBox) remoteDiv.insertBefore(panel, meBox);
        else remoteDiv.appendChild(panel);
    }

    _loadMusicState();
    _loadMusicQueue();
}

function _parseUrlTitle(url) {
    // Extract video/playlist ID or title from various platforms
    url = url.trim();
    // YouTube playlist
    if (url.includes('youtube.com/playlist') || (url.includes('youtube.com') && url.includes('list='))) {
        const listMatch = url.match(/[?&]list=([a-zA-Z0-9_-]+)/);
        const vidMatch = url.match(/(?:v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
        if (listMatch) {
            return { platform: 'youtube_playlist', playlistId: listMatch[1], id: vidMatch?.[1] || '', url };
        }
    }
    // YouTube single video
    if (url.includes('youtube.com/watch') || url.includes('youtu.be/')) {
        const match = url.match(/(?:v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
        return { platform: 'youtube', id: match?.[1] || '', url };
    }
    // YouTube Music
    if (url.includes('music.youtube.com/')) {
        const match = url.match(/(?:v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
        const listMatch = url.match(/[?&]list=([a-zA-Z0-9_-]+)/);
        if (listMatch) return { platform: 'youtube_playlist', playlistId: listMatch[1], id: match?.[1] || '', url };
        if (match) return { platform: 'youtube', id: match[1], url };
    }
    // Spotify track
    if (url.includes('spotify.com/track/')) {
        return { platform: 'spotify', url };
    }
    // Spotify playlist/album
    if (url.includes('spotify.com/playlist/') || url.includes('spotify.com/album/')) {
        const match = url.match(/spotify\.com\/(playlist|album)\/([a-zA-Z0-9]+)/);
        return { platform: 'spotify_playlist', type: match?.[1] || 'playlist', spotifyId: match?.[2] || '', url };
    }
    // SoundCloud (tracks and sets/playlists)
    if (url.includes('soundcloud.com/')) {
        return { platform: 'soundcloud', url };
    }
    // Apple Music
    if (url.includes('music.apple.com/')) {
        return { platform: 'apple', url };
    }
    // Treat as search query
    return { platform: 'search', query: url, url: '' };
}

async function _musicPlay() {
    const input = document.getElementById('music-url-input');
    if (!input) return;
    const val = input.value.trim();
    if (!val) return;
    input.value = '';
    const parsed = _parseUrlTitle(val);
    const title = parsed.query || parsed.id || val.substring(0, 60);
    const r = await apiRequest('SET_MUSIC', {
        url: parsed.url || val,
        title: title,
        artist: parsed.platform || '',
        thumbnail: '',
        playing: true
    });
    if (r.status === 'success') {
        _loadMusicState();
        playNotif('join');
    }
}

async function _musicAddToQueue() {
    const input = document.getElementById('music-url-input');
    if (!input) return;
    const val = input.value.trim();
    if (!val) return;
    input.value = '';
    const parsed = _parseUrlTitle(val);
    const title = parsed.query || parsed.id || val.substring(0, 60);
    const r = await apiRequest('MUSIC_QUEUE_ADD', {
        url: parsed.url || val,
        title: title,
        artist: parsed.platform || '',
        thumbnail: ''
    });
    if (r.status === 'success') _loadMusicQueue();
}

async function _musicSkip() {
    const r = await apiRequest('MUSIC_QUEUE_SKIP');
    _loadMusicState();
    _loadMusicQueue();
}

async function _musicStop() {
    await apiRequest('CLEAR_MUSIC');
    _currentMusic = null;
    _musicTunedIn = false;
    _musicListeners = [];
    _loadMusicState();
    _removeMusicParticipant();
    if (_musicAudio) { _musicAudio.pause(); _musicAudio = null; }
}

async function _musicTuneIn() {
    const r = await apiRequest('MUSIC_TUNE_IN');
    if (r.status === 'success') {
        _musicTunedIn = true;
        _musicListeners = r.listeners || [];
        _updateTuneButton();
        _updateListenersDisplay();
        _loadMusicState(); // Refresh music player to show for this user
    }
}

async function _musicTuneOut() {
    await apiRequest('MUSIC_TUNE_OUT');
    _musicTunedIn = false;
    _updateTuneButton();
    _updateListenersDisplay();
    _loadMusicState(); // Refresh to update listener count
}

function _toggleTuneIn() {
    if (_musicTunedIn) _musicTuneOut();
    else _musicTuneIn();
}

function _updateTuneButton() {
    const btn = document.getElementById('music-tune-btn');
    if (!btn) return;
    if (_musicTunedIn) {
        btn.style.background = 'rgba(35,165,89,0.3)';
        btn.style.color = '#23a559';
        btn.innerHTML = '🎧 Tuned In';
    } else {
        btn.style.background = 'rgba(88,101,242,0.15)';
        btn.style.color = 'var(--accent-blue)';
        btn.innerHTML = '🎧 Tune In';
    }
}

function _updateListenersDisplay() {
    const el = document.getElementById('music-listeners');
    if (!el) return;
    if (!_musicListeners.length) {
        el.innerHTML = '';
        return;
    }
    el.innerHTML = `<div style="display:flex;align-items:center;gap:4px;flex-wrap:wrap;padding:4px 0;">
        <span style="font-size:10px;color:var(--text-muted);">🎧</span>
        ${_musicListeners.map(u => `<span style="font-size:10px;color:#23a559;background:rgba(35,165,89,0.1);padding:1px 6px;border-radius:8px;">${_escAttr(u)}</span>`).join('')}
        <span style="font-size:10px;color:var(--text-muted);">listening</span>
    </div>`;
}

function _setMusicVolume(val) {
    const label = document.getElementById('music-vol-label');
    if (label) label.textContent = val + '%';
    if (_musicAudio) _musicAudio.volume = val / 100;
}

function _extractYouTubeId(url) {
    if (!url) return null;
    const m = url.match(/(?:v=|youtu\.be\/|embed\/)([a-zA-Z0-9_-]{11})/);
    return m ? m[1] : null;
}

function _extractYouTubePlaylistId(url) {
    if (!url) return null;
    const m = url.match(/[?&]list=([a-zA-Z0-9_-]+)/);
    return m ? m[1] : null;
}

function _extractSpotifyEmbed(url) {
    if (!url) return null;
    // spotify.com/track/ID → embed
    const trackMatch = url.match(/spotify\.com\/track\/([a-zA-Z0-9]+)/);
    if (trackMatch) return `https://open.spotify.com/embed/track/${trackMatch[1]}?theme=0`;
    // spotify.com/playlist/ID → embed
    const plMatch = url.match(/spotify\.com\/playlist\/([a-zA-Z0-9]+)/);
    if (plMatch) return `https://open.spotify.com/embed/playlist/${plMatch[1]}?theme=0`;
    // spotify.com/album/ID → embed
    const alMatch = url.match(/spotify\.com\/album\/([a-zA-Z0-9]+)/);
    if (alMatch) return `https://open.spotify.com/embed/album/${alMatch[1]}?theme=0`;
    return null;
}

function _extractSoundCloudUrl(url) {
    if (url && url.includes('soundcloud.com/')) return url;
    return null;
}

async function _loadMusicState() {
    const r = await apiRequest('GET_MUSIC');
    const el = document.getElementById('music-now-playing');
    if (r.music) {
        const isNew = !_currentMusic || _currentMusic.url !== r.music.url;
        _currentMusic = r.music;
        if (el && isNew) {
            const ytId = _extractYouTubeId(r.music.url);
            const ytPlaylistId = _extractYouTubePlaylistId(r.music.url);
            const spotifyEmbed = _extractSpotifyEmbed(r.music.url);
            const scUrl = _extractSoundCloudUrl(r.music.url);
            let playerHtml = '';
            if (ytPlaylistId && !ytId) {
                // YouTube playlist (no specific video) — use iframe with enablejsapi for volume
                playerHtml = `<iframe id="music-yt-playlist-iframe" src="https://www.youtube.com/embed/videoseries?list=${ytPlaylistId}&autoplay=1&enablejsapi=1&origin=${encodeURIComponent(location.origin)}" style="width:100%;height:80px;border:none;border-radius:8px;margin-top:4px;" allow="autoplay; encrypted-media" allowfullscreen></iframe>`;
            } else if (ytId) {
                // YouTube video (possibly with playlist) — use YT Player API
                playerHtml = `<div id="music-yt-container" style="margin-top:4px;border-radius:8px;overflow:hidden;"></div>`;
            } else if (spotifyEmbed) {
                // Spotify track/playlist/album embed
                playerHtml = `<iframe src="${spotifyEmbed}" style="width:100%;height:${spotifyEmbed.includes('track')?'80':'152'}px;border:none;border-radius:8px;margin-top:4px;" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy"></iframe>`;
            } else if (scUrl) {
                // SoundCloud track or set
                playerHtml = `<iframe src="https://w.soundcloud.com/player/?url=${encodeURIComponent(scUrl)}&auto_play=true&color=%2323a559&hide_related=true&show_comments=false&show_user=false" style="width:100%;height:${scUrl.includes('/sets/')?'120':'80'}px;border:none;border-radius:8px;margin-top:4px;"></iframe>`;
            }
            const savedVol = parseInt(localStorage.getItem('tenshi_music_vol'));
            const vol = isNaN(savedVol) ? 50 : savedVol;
            el.innerHTML = `
                <div style="background:rgba(35,165,89,0.08);border:1px solid rgba(35,165,89,0.2);border-radius:8px;padding:6px;">
                    <div style="display:flex;align-items:center;gap:10px;">
                        <div style="width:40px;height:40px;border-radius:8px;background:rgba(35,165,89,0.2);display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;">🎵</div>
                        <div style="flex:1;min-width:0;">
                            <div style="color:white;font-size:13px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${_escAttr(r.music.title)}</div>
                            <div style="color:var(--text-muted);font-size:11px;">${_escAttr(r.music.artist)} — requested by ${_escAttr(r.music.requester)}</div>
                        </div>
                        <div style="font-size:10px;color:#23a559;font-weight:600;">NOW PLAYING</div>
                    </div>
                    <div style="display:flex;align-items:center;gap:6px;margin-top:8px;">
                        <span style="font-size:11px;color:var(--text-muted);">🔊</span>
                        <input type="range" min="0" max="100" value="${vol}" style="flex:1;accent-color:#23a559;" oninput="_setMusicPlayerVolume(this.value)">
                        <input type="number" min="0" max="100" value="${vol}" style="width:42px;background:rgba(0,0,0,0.4);border:1px solid var(--glass-border);color:white;padding:3px;border-radius:4px;font-size:11px;text-align:center;" oninput="_setMusicPlayerVolume(this.value);this.previousElementSibling.value=this.value">
                    </div>
                    ${playerHtml}
                </div>`;
            // Load YouTube IFrame API and create player
            if (ytId) _initYTPlayer(ytId, vol, ytPlaylistId);
            else if (ytPlaylistId) {
                // For playlist iframes, set volume via postMessage once loaded
                const plIframe = document.getElementById('music-yt-playlist-iframe');
                if (plIframe) {
                    plIframe.onload = () => {
                        setTimeout(() => {
                            try { plIframe.contentWindow.postMessage(JSON.stringify({event:'command',func:'setVolume',args:[vol]}), '*'); } catch {}
                        }, 1000);
                    };
                }
            }
        }
        _musicListeners = r.listeners || [];
        _musicTunedIn = _musicListeners.includes(currentUser);
        _updateTuneButton();
        _updateListenersDisplay();
        _showMusicParticipant(r.music, _musicListeners);
    } else {
        _currentMusic = null;
        _musicTunedIn = false;
        _musicListeners = [];
        if (el) el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;text-align:center;padding:8px;">No music playing. Paste a URL above to start!</div>';
        _removeMusicParticipant();
    }
}

// ══════════════════════════════════════════════════════════════
// VOICE CHANNEL USER RIGHT-CLICK CONTEXT MENU
// ══════════════════════════════════════════════════════════════
function _showVcUserMenu(event, username, displayName) {
    if (event) { event.preventDefault(); event.stopPropagation(); event.stopImmediatePropagation(); }
    document.querySelector('.vc-user-menu')?.remove();

    const safe = _escAttr(username);
    const isSelf = username === currentUser;
    const serverId = _voiceServerId;
    const isOwner = currentManagingServer && currentManagingServer.owner === currentUser;
    const isAdminUser = isAdmin;
    const currentVol = _vcUserVolumes[username] || 60;

    const menu = document.createElement('div');
    menu.className = 'vc-user-menu';
    menu.style.cssText = `position:fixed;top:${Math.min(event.clientY, window.innerHeight-400)}px;left:${Math.min(event.clientX, window.innerWidth-220)}px;z-index:600;background:var(--bg-secondary,#1e1f22);border:1px solid rgba(255,255,255,0.1);border-radius:10px;padding:6px;min-width:200px;box-shadow:0 8px 24px rgba(0,0,0,0.5);`;

    let html = `<div style="padding:8px 12px;border-bottom:1px solid rgba(255,255,255,0.06);margin-bottom:4px;">
        <div style="color:white;font-weight:600;font-size:13px;">${_escAttr(displayName)}</div>
        <div style="color:var(--text-muted);font-size:10px;">${safe}</div>
    </div>`;

    const item = (icon, label, onclick, color) => `<div onclick="${onclick};document.querySelector('.vc-user-menu')?.remove();" style="padding:7px 12px;cursor:pointer;color:${color||'white'};font-size:13px;border-radius:6px;display:flex;align-items:center;gap:8px;" onmouseover="this.style.background='rgba(255,255,255,0.08)'" onmouseout="this.style.background=''">${icon} ${label}</div>`;

    if (!isSelf) {
        // Volume control
        html += `<div style="padding:6px 12px;">
            <div style="color:var(--text-muted);font-size:10px;text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px;">User Volume</div>
            <div style="display:flex;align-items:center;gap:6px;">
                <input type="range" min="0" max="200" value="${currentVol}" style="flex:1;accent-color:var(--accent-blue);" oninput="_vcSetUserVolume('${safe}',this.value);this.nextElementSibling.textContent=this.value+'%'">
                <span style="color:white;font-size:11px;min-width:32px;">${currentVol}%</span>
            </div>
        </div>`;
        html += `<div style="border-bottom:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>`;

        // Enlarge
        html += item('🔍', 'Enlarge Camera', `_enlargeUserByName('${safe}')`, 'white');
        // Basic actions
        html += item('🔇', 'Mute for Me', `_vcToggleUserMute('${safe}')`, 'white');
        html += item('💬', 'Message', `openChat('${safe}')`, 'white');
        html += item('👤', 'View Profile', `_showUserProfileCard('${safe}')`, 'white');
        html += item('📝', 'Set Note', `showUserNote('${safe}')`, 'white');

        // Server owner/admin actions
        if (serverId && (isOwner || isAdminUser)) {
            html += `<div style="border-bottom:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>`;
            html += `<div style="padding:4px 12px;font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px;">Moderation</div>`;
            html += item('🔇', 'Server Mute', `_forceMuteUser('${safe}')`, '#f0b132');
            html += item('📵', 'Disable Camera', `_forceCamOffUser('${safe}')`, '#f0b132');
            html += item('🔕', 'Force Noise Suppression', `suppressUser('${serverId}','${safe}')`, '#f0b132');
            html += item('⚠️', 'Warn', `warnUser('${serverId}','${safe}')`, '#f0b132');
            html += item('⏱️', 'Timeout', `timeoutUser('${serverId}','${safe}')`, '#f0b132');
            html += item('📋', 'View Warnings', `viewWarnings('${safe}')`, 'var(--text-muted)');
            html += `<div style="border-bottom:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>`;
            html += item('👢', 'Kick from Server', `kickFromServer('${serverId}','${safe}')`, '#ed4245');
            html += item('🔨', 'Ban from Server', `banFromServer('${serverId}','${safe}')`, '#ed4245');
        }

        // Role assignment (server owner)
        if (serverId && isOwner && currentManagingServer?.roles) {
            const roles = currentManagingServer.roles;
            if (Object.keys(roles).length) {
                html += `<div style="border-bottom:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>`;
                html += `<div style="padding:4px 12px;font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px;">Assign Role</div>`;
                for (const [rid, role] of Object.entries(roles)) {
                    html += item(`<span style="color:${role.color||'white'};">●</span>`, role.name, `apiRequest('ASSIGN_ROLE',{server_id:'${serverId}',target:'${safe}',role_id:'${rid}'}).then(r=>alert(r.message||'Done'))`, 'white');
                }
            }
        }

        // Global admin
        if (isAdminUser) {
            html += `<div style="border-bottom:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>`;
            html += `<div style="padding:4px 12px;font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px;">Admin</div>`;
            html += item('🔨', 'Global Ban', `adminBan('${safe}')`, '#ed4245');
        }

        html += `<div style="border-bottom:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>`;
        html += item('🚩', 'Report User', `flagContent('${safe}')`, '#ed4245');
        html += item('🚫', 'Block', `blockUser('${safe}')`, '#ed4245');
    } else {
        // Self actions
        html += item('🔍', 'Enlarge Camera', `_enlargeUserByName('${safe}')`, 'white');
        html += item('🎤', _isMuted ? 'Unmute' : 'Mute', 'toggleMute()', 'white');
        html += item('🎧', _isDeafened ? 'Undeafen' : 'Deafen', 'toggleDeafen()', 'white');
        html += item('📷', 'Toggle Camera', 'toggleCamera()', 'white');

        // Mic threshold slider
        html += `<div style="border-bottom:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>`;
        html += `<div style="padding:4px 12px;font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px;">Mic Threshold</div>`;
        html += `<div style="padding:4px 12px;display:flex;align-items:center;gap:6px;">
            <input type="range" min="0" max="100" value="${_myVoiceThreshold}" style="flex:1;accent-color:var(--accent-blue);" oninput="_setMyThreshold(this.value);this.nextElementSibling.textContent=this.value">
            <span style="color:white;font-size:11px;min-width:20px;">${_myVoiceThreshold}</span>
        </div>
        <div style="padding:0 12px 4px;font-size:9px;color:var(--text-muted);">Higher = more noise gate (cuts quiet sounds)</div>`;

        // Noise suppression selector
        const currentMode = _vqSettings.noiseMode || 'off';
        html += `<div style="border-bottom:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>`;
        html += `<div style="padding:4px 12px;font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px;">Noise Suppression</div>`;
        const modes = [
            {id:'off', label:'Off', icon:'🔇', desc:'No processing'},
            {id:'rnnoise', label:'RNNoise', icon:'🧠', desc:'Best isolation'},
            {id:'deepxi', label:'DeepXi', icon:'🔬', desc:'Preserves detail'},
            {id:'nrt', label:'NRT', icon:'🛡️', desc:'Aggressive'},
            {id:'ss', label:'Spectral', icon:'📊', desc:'Steady noise'},
            {id:'wavenet', label:'WaveNet', icon:'🌊', desc:'Natural voice'},
        ];
        modes.forEach(m => {
            const active = currentMode === m.id;
            html += `<div onclick="_setNoiseMode('${m.id}');document.querySelector('.vc-user-menu')?.remove();" style="padding:6px 12px;cursor:pointer;color:${active?'#23a559':'white'};font-size:12px;border-radius:6px;display:flex;align-items:center;gap:8px;${active?'background:rgba(35,165,89,0.1);':''}" onmouseover="this.style.background='rgba(255,255,255,0.08)'" onmouseout="this.style.background='${active?'rgba(35,165,89,0.1)':''}'">
                ${m.icon} ${m.label} <span style="color:var(--text-muted);font-size:10px;margin-left:auto;">${m.desc}${active?' ✓':''}</span>
            </div>`;
        });

        html += `<div style="border-bottom:1px solid rgba(255,255,255,0.06);margin:4px 0;"></div>`;
        html += item('🎛️', 'Switch Devices', "_showQuickDeviceSwitcher()", 'white');
        html += item('⚙️', 'Voice Settings', "mobileTab('settings');showSettingsTab('voice_video')", 'white');
        html += item('👤', 'Edit Profile', "mobileTab('settings');showSettingsTab('profile')", 'white');
    }

    menu.innerHTML = html;
    document.body.appendChild(menu);
    // Close only when clicking outside the menu (not on sliders/inputs inside it)
    setTimeout(() => document.addEventListener('mousedown', function rem(e) {
        if (!menu.contains(e.target)) { menu.remove(); document.removeEventListener('mousedown', rem); }
    }), 50);
}

// YouTube IFrame Player API for volume control
let _ytPlayer = null;

function _initYTPlayer(videoId, volume, playlistId) {
    // Load YT API script if not already
    if (!window.YT) {
        const tag = document.createElement('script');
        tag.src = 'https://www.youtube.com/iframe_api';
        document.head.appendChild(tag);
        window.onYouTubeIframeAPIReady = () => _createYTPlayer(videoId, volume, playlistId);
    } else {
        _createYTPlayer(videoId, volume, playlistId);
    }
}

function _createYTPlayer(videoId, volume, playlistId) {
    if (_ytPlayer) { try { _ytPlayer.destroy(); } catch {} }
    const vars = { autoplay: 1, controls: 1 };
    if (playlistId) {
        vars.list = playlistId;
        vars.listType = 'playlist';
    }
    if (videoId) {
        vars.loop = 1;
        if (!playlistId) vars.playlist = videoId;
    }
    const opts = {
        height: '80',
        width: '100%',
        playerVars: vars,
        events: {
            onReady: (e) => {
                e.target.setVolume(volume);
                e.target.playVideo();
            }
        }
    };
    if (videoId) opts.videoId = videoId;
    _ytPlayer = new YT.Player('music-yt-container', opts);
}

function _setMusicPlayerVolume(val) {
    val = parseInt(val);
    if (isNaN(val)) val = 50;
    localStorage.setItem('tenshi_music_vol', val);
    if (_ytPlayer && _ytPlayer.setVolume) _ytPlayer.setVolume(val);
    // Also try playlist iframe volume via postMessage
    const plIframe = document.getElementById('music-yt-playlist-iframe');
    if (plIframe) { try { plIframe.contentWindow.postMessage(JSON.stringify({event:'command',func:'setVolume',args:[val]}), '*'); } catch {} }
    // Sync slider and input
    const panel = document.getElementById('music-now-playing');
    if (panel) {
        const slider = panel.querySelector('input[type="range"]');
        const numInput = panel.querySelector('input[type="number"]');
        if (slider) slider.value = val;
        if (numInput) numInput.value = val;
    }
}

async function _loadMusicQueue() {
    const r = await apiRequest('MUSIC_QUEUE_GET');
    const el = document.getElementById('music-queue-list');
    if (!el) return;
    const queue = r.queue || [];
    if (!queue.length) { el.innerHTML = ''; return; }
    el.innerHTML = `<div style="font-size:10px;font-weight:600;color:var(--text-muted);text-transform:uppercase;margin-bottom:4px;">Queue (${queue.length})</div>` +
        queue.map((s, i) => `<div style="display:flex;align-items:center;gap:8px;padding:4px 0;border-bottom:1px solid rgba(255,255,255,0.04);">
            <span style="color:var(--text-muted);font-size:11px;min-width:16px;">${i+1}.</span>
            <span style="color:white;font-size:12px;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${_escAttr(s.title)}</span>
            <span style="color:var(--text-muted);font-size:10px;">${_escAttr(s.requester)}</span>
        </div>`).join('');
}

function _showMusicParticipant(music, listeners) {
    const remoteDiv = document.getElementById('remote-videos');
    if (!remoteDiv) return;
    listeners = listeners || _musicListeners || [];
    let box = document.getElementById('vc-music-bot');
    if (box) {
        // Update existing
        const titleEl = box.querySelector('.music-bot-title');
        if (titleEl) titleEl.textContent = music.title;
        const listenersEl = box.querySelector('.music-bot-listeners');
        if (listenersEl) {
            listenersEl.innerHTML = listeners.length
                ? `🎧 ${listeners.length} listening`
                : '';
        }
        return;
    }
    box = document.createElement('div');
    box.id = 'vc-music-bot';
    box.style.cssText = 'display:flex;flex-direction:column;align-items:center;gap:6px;';
    box.innerHTML = `
        <div style="color:#23a559;font-size:13px;font-weight:600;">🎵 Music</div>
        <div style="position:relative;width:140px;height:140px;border-radius:16px;">
            <div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;background:rgba(35,165,89,0.1);border-radius:16px;border:3px solid #23a559;">
                <div style="font-size:48px;margin-bottom:4px;">🎵</div>
                <div class="music-bot-title" style="font-size:10px;color:white;text-align:center;padding:0 8px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:120px;">${_escAttr(music.title)}</div>
            </div>
        </div>
        <div style="font-size:10px;color:var(--text-muted);">by ${_escAttr(music.requester)}</div>
        <div style="display:flex;gap:4px;">
            <div class="music-eq-bar" style="width:3px;height:12px;background:#23a559;border-radius:2px;animation:eq-bounce 0.4s ease infinite alternate;"></div>
            <div class="music-eq-bar" style="width:3px;height:12px;background:#23a559;border-radius:2px;animation:eq-bounce 0.6s ease infinite alternate;"></div>
            <div class="music-eq-bar" style="width:3px;height:12px;background:#23a559;border-radius:2px;animation:eq-bounce 0.5s ease infinite alternate;"></div>
            <div class="music-eq-bar" style="width:3px;height:12px;background:#23a559;border-radius:2px;animation:eq-bounce 0.7s ease infinite alternate;"></div>
        </div>
        <div class="music-bot-listeners" style="font-size:10px;color:#23a559;margin-top:2px;">${listeners.length ? '🎧 ' + listeners.length + ' listening' : ''}</div>
    `;
    // Insert before "me" box
    const meBox = document.getElementById('vc-participant-me');
    if (meBox) remoteDiv.insertBefore(box, meBox);
    else remoteDiv.appendChild(box);

    // Inject eq animation if not present
    if (!document.getElementById('eq-style')) {
        const s = document.createElement('style');
        s.id = 'eq-style';
        s.textContent = '@keyframes eq-bounce { 0%{transform:scaleY(0.3)} 100%{transform:scaleY(1)} } .music-eq-bar{transform-origin:bottom;}';
        document.head.appendChild(s);
    }
}

function _removeMusicParticipant() {
    const box = document.getElementById('vc-music-bot');
    if (box) box.remove();
}

// Poll music state alongside voice channel polling
(function() {
    const _origPoll = window._pollVoiceChannelUsers;
    if (_origPoll) {
        // Can't easily override, so use heartbeat instead
    }
    // Poll music state every 3 seconds when in a voice channel
    setInterval(async () => {
        if (!_voiceChannelName) {
            _removeMusicParticipant();
            return;
        }
        try {
            const r = await apiRequest('GET_MUSIC');
            if (r.music) {
                _currentMusic = r.music;
                _musicListeners = r.listeners || [];
                _musicTunedIn = _musicListeners.includes(currentUser);
                _showMusicParticipant(r.music, _musicListeners);
                _updateTuneButton();
                _updateListenersDisplay();
            } else if (_currentMusic) {
                _currentMusic = null;
                _musicTunedIn = false;
                _musicListeners = [];
                _removeMusicParticipant();
            }
        } catch {}
    }, 3000);
})();

// ══════════════════════════════════════════════════════════════
// TENSHI DANCE — DDR rhythm game synced to voice channel music
// ══════════════════════════════════════════════════════════════
function renderTenshiDance(container) {
    let score = 0, combo = 0, maxCombo = 0, misses = 0, hits = 0;
    let gameRunning = true;
    let arrows = []; // {lane: 0-3, y: number, hit: bool}
    let bpm = 120;
    let spawnInterval = null;
    let animFrame = null;
    const LANES = ['←','↓','↑','→'];
    const LANE_KEYS_ARROW = ['ArrowLeft','ArrowDown','ArrowUp','ArrowRight'];
    const LANE_KEYS_WASD = ['a','s','w','d'];
    const LANE_COLORS = ['#ed4245','#5865F2','#23a559','#f0b132'];
    const HIT_ZONE_Y = 85; // % from top
    const HIT_TOLERANCE = 8; // % tolerance for a hit

    // Get current music info for title
    const songTitle = _currentMusic?.title || 'No Music Playing';
    const songArtist = _currentMusic?.requester || '';

    container.innerHTML = `
        <div id="dance-game" style="position:relative;width:100%;height:100%;min-height:500px;background:linear-gradient(180deg,#0a0a1a,#1a1b2e);overflow:hidden;user-select:none;">
            <!-- Header -->
            <div style="position:absolute;top:0;left:0;right:0;z-index:10;display:flex;justify-content:space-between;align-items:center;padding:12px 20px;background:rgba(0,0,0,0.5);">
                <div>
                    <div style="color:white;font-size:16px;font-weight:bold;">💃 Tenshi Dance</div>
                    <div style="color:var(--text-muted);font-size:11px;">🎵 ${_escAttr(songTitle)}</div>
                </div>
                <div style="text-align:right;">
                    <div style="color:#f0b132;font-size:20px;font-weight:bold;" id="dance-score">0</div>
                    <div style="color:#23a559;font-size:11px;" id="dance-combo">Combo: 0</div>
                </div>
            </div>
            <!-- Lane dividers -->
            <div style="position:absolute;inset:0;display:flex;pointer-events:none;">
                ${[0,1,2,3].map(i => `<div style="flex:1;border-right:1px solid rgba(255,255,255,0.05);"></div>`).join('')}
            </div>
            <!-- Hit zone -->
            <div style="position:absolute;top:${HIT_ZONE_Y}%;left:0;right:0;height:4px;background:rgba(255,255,255,0.3);z-index:5;"></div>
            <div style="position:absolute;top:${HIT_ZONE_Y}%;left:0;right:0;display:flex;z-index:5;transform:translateY(-50%);">
                ${LANES.map((l,i) => `<div style="flex:1;text-align:center;font-size:24px;color:${LANE_COLORS[i]};opacity:0.3;font-weight:bold;" id="dance-target-${i}">${l}</div>`).join('')}
            </div>
            <!-- Arrow canvas -->
            <canvas id="dance-canvas" style="position:absolute;inset:0;width:100%;height:100%;z-index:3;"></canvas>
            <!-- Hit feedback -->
            <div id="dance-feedback" style="position:absolute;top:70%;left:50%;transform:translateX(-50%);font-size:24px;font-weight:bold;color:white;z-index:10;opacity:0;transition:opacity 0.2s;"></div>
            <!-- Controls hint -->
            <div style="position:absolute;bottom:12px;left:0;right:0;text-align:center;z-index:10;">
                <span style="color:rgba(255,255,255,0.3);font-size:11px;">WASD or Arrow Keys | </span>
                <button onclick="_endDanceGame()" style="background:rgba(237,66,69,0.3);color:#ed4245;border:none;padding:4px 12px;border-radius:4px;cursor:pointer;font-size:11px;">End Game</button>
            </div>
            <!-- Stats -->
            <div style="position:absolute;top:50px;right:12px;z-index:10;text-align:right;">
                <div style="color:var(--text-muted);font-size:10px;">Hits: <span id="dance-hits" style="color:#23a559;">0</span></div>
                <div style="color:var(--text-muted);font-size:10px;">Miss: <span id="dance-misses" style="color:#ed4245;">0</span></div>
                <div style="color:var(--text-muted);font-size:10px;">Max: <span id="dance-max-combo" style="color:#f0b132;">0</span></div>
            </div>
        </div>`;

    const canvas = document.getElementById('dance-canvas');
    const ctx = canvas.getContext('2d');

    function resize() {
        const parent = canvas.parentElement;
        canvas.width = parent.clientWidth;
        canvas.height = parent.clientHeight;
    }
    resize();
    window.addEventListener('resize', resize);

    // Spawn arrows at random lanes
    function spawnArrow() {
        if (!gameRunning) return;
        const lane = Math.floor(Math.random() * 4);
        arrows.push({ lane, y: -5, hit: false, missed: false });
    }

    // Adjust BPM based on score (gets harder)
    function getSpawnRate() {
        if (score > 5000) return 300;
        if (score > 2000) return 400;
        if (score > 500) return 550;
        return 700;
    }

    let lastSpawn = 0;
    function gameLoop(timestamp) {
        if (!gameRunning) return;
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        // Spawn logic
        if (timestamp - lastSpawn > getSpawnRate()) {
            spawnArrow();
            // Occasionally spawn doubles
            if (Math.random() < 0.15 && score > 200) {
                const lane2 = Math.floor(Math.random() * 4);
                arrows.push({ lane: lane2, y: -5, hit: false, missed: false });
            }
            lastSpawn = timestamp;
        }

        // Move and draw arrows
        const speed = 0.4 + score / 10000;
        for (let i = arrows.length - 1; i >= 0; i--) {
            const a = arrows[i];
            a.y += speed;

            if (a.hit) {
                arrows.splice(i, 1);
                continue;
            }

            // Miss detection
            if (a.y > HIT_ZONE_Y + HIT_TOLERANCE && !a.missed) {
                a.missed = true;
                misses++;
                combo = 0;
                _danceFeedback('MISS', '#ed4245');
                document.getElementById('dance-misses').textContent = misses;
                document.getElementById('dance-combo').textContent = 'Combo: 0';
            }

            // Remove off-screen
            if (a.y > 105) {
                arrows.splice(i, 1);
                continue;
            }

            // Draw arrow
            if (!a.missed) {
                const x = (a.lane + 0.5) / 4 * canvas.width;
                const y = a.y / 100 * canvas.height;
                ctx.save();
                ctx.font = 'bold 32px Arial';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillStyle = LANE_COLORS[a.lane];
                ctx.shadowColor = LANE_COLORS[a.lane];
                ctx.shadowBlur = 12;
                ctx.fillText(LANES[a.lane], x, y);
                ctx.restore();
            }
        }

        animFrame = requestAnimationFrame(gameLoop);
    }

    // Key handler
    function onKey(e) {
        if (!gameRunning) return;
        let lane = LANE_KEYS_ARROW.indexOf(e.key);
        if (lane === -1) lane = LANE_KEYS_WASD.indexOf(e.key.toLowerCase());
        if (lane === -1) return;
        e.preventDefault();

        // Flash the target
        const target = document.getElementById('dance-target-' + lane);
        if (target) { target.style.opacity = '1'; setTimeout(() => target.style.opacity = '0.3', 150); }

        // Check for hit
        let bestArrow = null;
        let bestDist = Infinity;
        for (const a of arrows) {
            if (a.lane === lane && !a.hit && !a.missed) {
                const dist = Math.abs(a.y - HIT_ZONE_Y);
                if (dist < HIT_TOLERANCE && dist < bestDist) {
                    bestArrow = a;
                    bestDist = dist;
                }
            }
        }

        if (bestArrow) {
            bestArrow.hit = true;
            hits++;
            combo++;
            if (combo > maxCombo) maxCombo = combo;

            // Score based on accuracy
            const accuracy = 1 - (bestDist / HIT_TOLERANCE);
            let points = 100;
            let label = 'GOOD';
            let color = '#5865F2';
            if (accuracy > 0.8) { points = 300; label = 'PERFECT!'; color = '#f0b132'; }
            else if (accuracy > 0.5) { points = 200; label = 'GREAT'; color = '#23a559'; }

            points += combo * 10; // Combo bonus
            score += points;

            _danceFeedback(label + (combo > 2 ? ` x${combo}` : ''), color);
            document.getElementById('dance-score').textContent = score;
            document.getElementById('dance-combo').textContent = 'Combo: ' + combo;
            document.getElementById('dance-hits').textContent = hits;
            document.getElementById('dance-max-combo').textContent = maxCombo;

            tenshiAudio.message(); // Subtle hit sound
        }
    }

    document.addEventListener('keydown', onKey);
    animFrame = requestAnimationFrame(gameLoop);

    // Store cleanup function
    window._endDanceGame = function() {
        gameRunning = false;
        document.removeEventListener('keydown', onKey);
        window.removeEventListener('resize', resize);
        if (animFrame) cancelAnimationFrame(animFrame);
        container.innerHTML = `
            <div style="text-align:center;padding:40px;color:white;">
                <div style="font-size:48px;margin-bottom:12px;">💃</div>
                <h2 style="margin:0 0 8px;">Tenshi Dance — Game Over!</h2>
                <div style="font-size:11px;color:var(--text-muted);margin-bottom:16px;">🎵 ${_escAttr(songTitle)}</div>
                <div style="display:inline-grid;grid-template-columns:1fr 1fr;gap:12px 24px;text-align:left;margin-bottom:20px;">
                    <div><span style="color:var(--text-muted);font-size:12px;">Score</span><br><span style="color:#f0b132;font-size:24px;font-weight:bold;">${score}</span></div>
                    <div><span style="color:var(--text-muted);font-size:12px;">Max Combo</span><br><span style="color:#23a559;font-size:24px;font-weight:bold;">${maxCombo}</span></div>
                    <div><span style="color:var(--text-muted);font-size:12px;">Hits</span><br><span style="color:#5865F2;font-size:18px;font-weight:bold;">${hits}</span></div>
                    <div><span style="color:var(--text-muted);font-size:12px;">Misses</span><br><span style="color:#ed4245;font-size:18px;font-weight:bold;">${misses}</span></div>
                </div>
                <div style="color:var(--text-muted);font-size:12px;margin-bottom:16px;">Accuracy: ${hits+misses>0?Math.round(hits/(hits+misses)*100):0}%</div>
                <button onclick="renderTenshiDance(document.getElementById('message-container'))" style="background:#5865F2;color:white;border:none;padding:10px 24px;border-radius:8px;cursor:pointer;font-weight:bold;margin-right:8px;">Play Again</button>
                <button onclick="document.getElementById('message-container').innerHTML='<div style=text-align:center;padding:40px;color:var(--text-muted)>Select a channel</div>'" style="background:rgba(255,255,255,0.08);color:white;border:none;padding:10px 24px;border-radius:8px;cursor:pointer;">Close</button>
            </div>`;
        // Report score to server
        apiRequest('UPDATE_GAME_STATS', { game: 'Tenshi Dance', stats: [`Score: ${score}`, `Max Combo: ${maxCombo}`, `Accuracy: ${hits+misses>0?Math.round(hits/(hits+misses)*100):0}%`] }).catch(()=>{});
    };
}

function _danceFeedback(text, color) {
    const el = document.getElementById('dance-feedback');
    if (!el) return;
    el.textContent = text;
    el.style.color = color;
    el.style.opacity = '1';
    setTimeout(() => el.style.opacity = '0', 400);
}

